class AdminApprovedTelegramBridgeRunbookProgress {
  final String clientId;
  final String siteId;
  final bool vendorValidated;
  final bool cctvPolled;
  final bool operationsOpened;

  const AdminApprovedTelegramBridgeRunbookProgress({
    required this.clientId,
    required this.siteId,
    this.vendorValidated = false,
    this.cctvPolled = false,
    this.operationsOpened = false,
  });

  bool matchesPrefill(AdminApprovedTelegramOnboardingPrefill prefill) {
    return clientId.trim() == prefill.clientId.trim() &&
        siteId.trim() == prefill.siteId.trim();
  }

  AdminApprovedTelegramBridgeRunbookProgress copyWith({
    String? clientId,
    String? siteId,
    bool? vendorValidated,
    bool? cctvPolled,
    bool? operationsOpened,
  }) {
    return AdminApprovedTelegramBridgeRunbookProgress(
      clientId: clientId ?? this.clientId,
      siteId: siteId ?? this.siteId,
      vendorValidated: vendorValidated ?? this.vendorValidated,
      cctvPolled: cctvPolled ?? this.cctvPolled,
      operationsOpened: operationsOpened ?? this.operationsOpened,
    );
  }
}

