  _AdminCommandReceipt? _initialCommandReceiptFromWidget() {
    final headline = widget.initialCommandHeadline?.trim() ?? '';
    if (headline.isEmpty) {
      return null;
    }
    final label = widget.initialCommandLabel?.trim();
    final detail = widget.initialCommandDetail?.trim();
    return _AdminCommandReceipt(
      label: (label == null || label.isEmpty) ? 'GUARDS WAR ROOM' : label,
      headline: headline,
      detail: (detail == null || detail.isEmpty)
          ? 'Planner intent stays pinned here while you make the change.'
          : detail,
      accent: widget.initialCommandAccent ?? const Color(0xFF8FD1FF),
    );
  }

  bool _initialCommandReceiptChanged(covariant AdministrationPage oldWidget) {
    return oldWidget.initialCommandLabel != widget.initialCommandLabel ||
        oldWidget.initialCommandHeadline != widget.initialCommandHeadline ||
        oldWidget.initialCommandDetail != widget.initialCommandDetail ||
        oldWidget.initialCommandAccent != widget.initialCommandAccent;
  }

  _GuardRosterPlannerMode? _resolvedInitialGuardsPlannerMode() {
    return switch ((widget.initialGuardsPlannerAction ?? '').trim()) {
      'create-roster' => _GuardRosterPlannerMode.createMonth,
      'edit-roster' => _GuardRosterPlannerMode.fillGaps,
      'publish-roster' => _GuardRosterPlannerMode.publishRoster,
      'open-month-planner' => _GuardRosterPlannerMode.openMonthPlanner,
      _ => null,
    };
  }

  bool _initialGuardsPlannerLaunchChanged(
    covariant AdministrationPage oldWidget,
  ) {
    return oldWidget.initialGuardsPlannerAction !=
            widget.initialGuardsPlannerAction ||
        oldWidget.initialGuardsPlannerDate != widget.initialGuardsPlannerDate;
  }

