  String _adminWorkspaceTitle() {
    if (_activeTab != AdministrationPageTab.system) {
      return _adminEntityTabTitle(_activeTab);
    }
    return switch (_activeSystemSection) {
      _AdminSystemSection.aiCommunications => 'AI Queue',
      _AdminSystemSection.systemControls => 'Control Board',
      _AdminSystemSection.watchIdentity => 'Watch Identity',
    };
  }

  String _adminWorkspaceSubtitle() {
    if (_activeTab != AdministrationPageTab.system) {
      return 'Roster controls, search pivots, and create commands stay pinned in Admin Desk.';
    }
    return switch (_activeSystemSection) {
      _AdminSystemSection.aiCommunications =>
        'Telegram learning, staged drafts, and Client Comms oversight stay pinned in Admin Desk.',
      _AdminSystemSection.systemControls =>
        'Runtime controls, SLA posture, partner links, and system health stay pinned in Admin Desk.',
      _AdminSystemSection.watchIdentity =>
        'Watch recovery, scene suppression, and identity policy controls stay pinned in Watch Identity.',
    };
  }

  String _adminEntityTabTitle(AdministrationPageTab tab) {
    return switch (tab) {
      AdministrationPageTab.guards => 'Guards',
      AdministrationPageTab.sites => 'Sites',
      AdministrationPageTab.clients => 'Clients',
      AdministrationPageTab.system => 'Entity Management',
    };
  }

  Color _adminWorkspaceAccent() {
    if (_activeTab != AdministrationPageTab.system) {
      return switch (_activeTab) {
        AdministrationPageTab.guards => const Color(0xFF8FD1FF),
        AdministrationPageTab.sites => const Color(0xFF7FD8A5),
        AdministrationPageTab.clients => const Color(0xFFF1B872),
        AdministrationPageTab.system => const Color(0xFF8FD1FF),
      };
    }
    return switch (_activeSystemSection) {
      _AdminSystemSection.aiCommunications => const Color(0xFFF1B872),
      _AdminSystemSection.systemControls => const Color(0xFF7FD8A5),
      _AdminSystemSection.watchIdentity => const Color(0xFF22D3EE),
    };
  }

  bool _usesDesktopWorkspace(BuildContext currentContext) {
    final layoutWidth =
        currentContext.size?.width ??
        context.size?.width ??
        MediaQuery.sizeOf(currentContext).width;
    return layoutWidth >= 1180;
  }

  void _handleAdminFeedback({
    required BuildContext feedbackContext,
    required String message,
    String? sourceLabel,
    String? detail,
    Color? accent,
  }) {
    if (!mounted) return;
    if (_usesDesktopWorkspace(feedbackContext)) {
      setState(() {
        _commandReceipt = _AdminCommandReceipt(
          label: sourceLabel ?? _adminWorkspaceTitle().toUpperCase(),
          headline: message,
          detail:
              detail ??
              'Latest admin activity stays pinned in the Context Rail while you continue working.',
          accent: accent ?? _adminWorkspaceAccent(),
        );
      });
      return;
    }
    _showAdminFeedbackSnackBar(feedbackContext, message);
  }

  void _focusSystemControlAnchor({
    required GlobalKey targetKey,
    required String message,
    required String detail,
    String sourceLabel = 'SYSTEM RUNTIME',
    Color accent = const Color(0xFF7FD8A5),
  }) {
    final targetContext = targetKey.currentContext;
    if (targetContext != null) {
      Scrollable.ensureVisible(
        targetContext,
        duration: const Duration(milliseconds: 220),
        curve: Curves.easeOutCubic,
        alignment: 0.08,
      );
    }
    _handleAdminFeedback(
      feedbackContext: context,
      message: message,
      sourceLabel: sourceLabel,
      detail: detail,
      accent: accent,
    );
  }

  // ignore: unused_element
  void _focusClientCommsAuditQueue() {
    if (_activeSystemSection != _AdminSystemSection.aiCommunications) {
      setState(() {
        _activeSystemSection = _AdminSystemSection.aiCommunications;
      });
    }
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) {
        return;
      }
      final targetContext = _clientCommsAuditPanelScrollKey.currentContext;
      if (targetContext != null) {
        Scrollable.ensureVisible(
          targetContext,
          duration: const Duration(milliseconds: 220),
          curve: Curves.easeOutCubic,
          alignment: 0.08,
        );
      }
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Focused client comms audit queue.',
        sourceLabel: 'AI DRAFT QUEUE',
        detail:
            'Pending client comms drafts stay pinned in the audit panel so review can continue without hunting through admin surfaces.',
        accent: const Color(0xFF00D4FF),
      );
    });
  }

  Widget _adminHeaderChip({
    required String label,
    required Color foreground,
    required Color background,
    required Color border,
  }) {
    final softenedForeground = _adminAccentTextColor(foreground, strength: 0.5);
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 4),
      decoration: BoxDecoration(
        color: Color.alphaBlend(
          const Color(0xFF1A1A2E).withValues(alpha: 0.46),
          background,
        ),
        borderRadius: BorderRadius.circular(999),
        border: Border.all(color: border.withValues(alpha: 0.58)),
      ),
      child: Text(
        label,
        style: GoogleFonts.inter(
          color: softenedForeground,
          fontSize: 8.7,
          fontWeight: FontWeight.w700,
        ),
      ),
    );
  }

  @override
  void initState() {
    super.initState();
    _operatorIdController = TextEditingController(text: widget.operatorId);
    _partnerEndpointLabelController = TextEditingController(
      text: 'PARTNER • Response',
    );
    _partnerChatIdController = TextEditingController();
    _partnerThreadIdController = TextEditingController();
    _partnerRuntimeDraftListenable = Listenable.merge(<Listenable>[
      _partnerEndpointLabelController,
      _partnerChatIdController,
      _partnerThreadIdController,
    ]);
    _activeTab = widget.initialTab;
    if (_activeTab != AdministrationPageTab.system) {
      _lastEntityTab = _activeTab;
    }
    _commandReceipt =
        _initialCommandReceiptFromWidget() ?? _defaultCommandReceipt;
    _pendingGuardsPlannerMode = _resolvedInitialGuardsPlannerMode();
    _pendingGuardsPlannerDate = widget.initialGuardsPlannerDate;
    _activeWatchActionDrilldown = widget.initialWatchActionDrilldown;
    _monitoringIdentityPolicyService = widget.monitoringIdentityPolicyService;
    _syncActiveIdentityPolicyScopeKey(_monitoringIdentityPolicyService.entries);
    _identityPolicyAuditHistory =
        widget.initialMonitoringIdentityRuleAuditHistory;
    _activeIdentityPolicyAuditSource =
        widget.initialMonitoringIdentityRuleAuditSourceFilter;
    _identityPolicyAuditExpanded =
        widget.initialMonitoringIdentityRuleAuditExpanded;
    _telegramIdentityIntakes = widget.initialTelegramIdentityIntakes;
    _clientPartnerEndpointCounts = widget.initialClientPartnerEndpointCounts;
    _clientPartnerLanePreview = widget.initialClientPartnerLanePreview;
    _clientPartnerChatcheckStatus = widget.initialClientPartnerChatcheckStatus;
    _clientPartnerLaneDetails = widget.initialClientPartnerLaneDetails;
    _sitePartnerEndpointCounts = widget.initialSitePartnerEndpointCounts;
    _sitePartnerChatcheckStatus = widget.initialSitePartnerChatcheckStatus;
    _sitePartnerLaneDetails = widget.initialSitePartnerLaneDetails;
    _cameraBridgeLocalState = _cameraBridgeLocalState.syncSnapshot(
      widget.onyxAgentCameraBridgeHealthSnapshot,
    );
    final partnerScope = _resolvePartnerRuntimeScope(
      clients: _clients,
      sites: _sites,
    );
    _partnerRuntimeClientId = partnerScope.clientId;
    _partnerRuntimeSiteId = partnerScope.siteId;
    if (widget.supabaseReady) {
      unawaited(_refreshDirectoryAfterApprovedTelegramSeedApply());
      _loadTelegramIdentityIntakesFromSupabase();
    } else {
      _directorySyncMessage = 'Supabase offline. Using local seed data.';
      _applyApprovedTelegramDirectorySeeds();
    }
    if (_pendingGuardsPlannerMode != null &&
        _activeTab == AdministrationPageTab.guards) {
      _scheduleInitialGuardsPlannerLaunch();
    }
  }

  Future<void> _refreshDirectoryAfterApprovedTelegramSeedApply() async {
    if (widget.approvedTelegramClientSeeds.isEmpty &&
        widget.approvedTelegramSiteSeeds.isEmpty) {
      await _loadDirectoryFromSupabase();
      return;
    }
    if (widget.supabaseReady) {
      await _loadDirectoryFromSupabase();
      return;
    }
    if (!mounted) {
      return;
    }
    setState(() {
      _applyApprovedTelegramDirectorySeeds();
    });
  }

  void _applyApprovedTelegramDirectorySeeds() {
    if (widget.approvedTelegramClientSeeds.isEmpty &&
        widget.approvedTelegramSiteSeeds.isEmpty) {
      return;
    }
    final mergedSites = _mergeApprovedTelegramSiteSeeds(
      _sites,
      widget.approvedTelegramSiteSeeds,
    );
    final mergedClients = _mergeApprovedTelegramClientSeeds(
      _clients,
      widget.approvedTelegramClientSeeds,
    );
    _sites = mergedSites;
    _clients = _recomputeClientSiteCounts(mergedClients, mergedSites);
    final latestClientId = widget.approvedTelegramClientSeeds.isEmpty
        ? ''
        : widget.approvedTelegramClientSeeds.last.id;
    final latestSiteId = widget.approvedTelegramSiteSeeds.isEmpty
        ? ''
        : widget.approvedTelegramSiteSeeds.last.id;
    if (latestClientId.isNotEmpty || latestSiteId.isNotEmpty) {
      final scopeSummary = [
        if (latestClientId.isNotEmpty) latestClientId,
        if (latestSiteId.isNotEmpty) latestSiteId,
      ].join(' / ');
      _directorySyncMessage =
          'Telegram onboarding synced locally: '
          '$scopeSummary.';
    }
  }

  List<_ClientAdminRow> _mergeApprovedTelegramClientSeeds(
    List<_ClientAdminRow> base,
    List<AdminDirectoryClientSeed> seeds,
  ) {
    if (seeds.isEmpty) {
      return base;
    }
    final rowsById = <String, _ClientAdminRow>{
      for (final row in base) row.id: row,
    };
    for (final seed in seeds) {
      rowsById[seed.id] = _ClientAdminRow(
        id: seed.id,
        name: seed.name,
        code: seed.id,
        contactPerson: seed.contactPerson,
        contactEmail: rowsById[seed.id]?.contactEmail ?? '-',
        contactPhone: seed.contactPhone,
        slaTier: seed.slaTier,
        contractStart: rowsById[seed.id]?.contractStart ?? '-',
        contractEnd: rowsById[seed.id]?.contractEnd ?? '-',
        sites: rowsById[seed.id]?.sites ?? 0,
        status: _AdminStatus.active,
      );
    }
    return rowsById.values.toList(growable: false);
  }

  List<_SiteAdminRow> _mergeApprovedTelegramSiteSeeds(
    List<_SiteAdminRow> base,
    List<AdminDirectorySiteSeed> seeds,
  ) {
    if (seeds.isEmpty) {
      return base;
    }
    final rowsById = <String, _SiteAdminRow>{
      for (final row in base) row.id: row,
    };
    for (final seed in seeds) {
      rowsById[seed.id] = _SiteAdminRow(
        id: seed.id,
        name: seed.name,
        code: seed.id,
        clientId: seed.clientId,
        address: seed.address,
        lat: rowsById[seed.id]?.lat ?? Site.defaultLatitude,
        lng: rowsById[seed.id]?.lng ?? Site.defaultLongitude,
        contactPerson: rowsById[seed.id]?.contactPerson ?? '-',
        contactPhone: rowsById[seed.id]?.contactPhone ?? '-',
        fskNumber: rowsById[seed.id]?.fskNumber,
        geofenceRadiusMeters: seed.geofenceRadiusMeters,
        status: _AdminStatus.active,
      );
    }
    return rowsById.values.toList(growable: false);
  }

  void _scheduleInitialGuardsPlannerLaunch() {
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted ||
          _guardPlannerDialogOpen ||
          _activeTab != AdministrationPageTab.guards) {
        return;
      }
      final mode = _pendingGuardsPlannerMode;
      if (mode == null) {
        return;
      }
      final date = _pendingGuardsPlannerDate;
      _pendingGuardsPlannerMode = null;
      _pendingGuardsPlannerDate = null;
      unawaited(
        _showGuardRosterPlannerDialog(
          mode: mode,
          date: date,
          launchedFromHandoff: true,
        ),
      );
    });
  }

  void _setActiveWatchActionDrilldown(
    VideoFleetWatchActionDrilldown? value, {
    bool notify = true,
  }) {
    if (_activeWatchActionDrilldown == value) {
      return;
    }
    setState(() {
      _activeWatchActionDrilldown = value;
    });
    if (notify) {
      widget.onWatchActionDrilldownChanged?.call(value);
    }
  }

  void _setActiveTab(AdministrationPageTab value, {bool notify = true}) {
    if (_activeTab == value) {
      return;
    }
    setState(() {
      _activeTab = value;
      if (value != AdministrationPageTab.system) {
        _lastEntityTab = value;
      }
    });
    if (notify) {
      widget.onTabChanged?.call(value);
    }
  }

  String _normalizeIdentityRuleValue(String raw) {
    return raw.trim().toUpperCase();
  }

  Set<String> _identityRuleValues(
    MonitoringIdentityScopePolicy policy,
    _IdentityRuleBucket bucket,
  ) {
    return switch (bucket) {
      _IdentityRuleBucket.flaggedFaces => policy.flaggedFaceMatchIds,
      _IdentityRuleBucket.flaggedPlates => policy.flaggedPlateNumbers,
      _IdentityRuleBucket.allowedFaces => policy.allowedFaceMatchIds,
      _IdentityRuleBucket.allowedPlates => policy.allowedPlateNumbers,
    };
  }

  MonitoringIdentityScopePolicy _identityRulePolicyWithValues(
    MonitoringIdentityScopePolicy policy,
    _IdentityRuleBucket bucket,
    Set<String> values,
  ) {
    return switch (bucket) {
      _IdentityRuleBucket.flaggedFaces => policy.copyWith(
        flaggedFaceMatchIds: values,
      ),
      _IdentityRuleBucket.flaggedPlates => policy.copyWith(
        flaggedPlateNumbers: values,
      ),
      _IdentityRuleBucket.allowedFaces => policy.copyWith(
        allowedFaceMatchIds: values,
      ),
      _IdentityRuleBucket.allowedPlates => policy.copyWith(
        allowedPlateNumbers: values,
      ),
    };
  }

  String _identityRuleLabel(_IdentityRuleBucket bucket) {
    return switch (bucket) {
      _IdentityRuleBucket.flaggedFaces => 'Flagged faces',
      _IdentityRuleBucket.flaggedPlates => 'Flagged plates',
      _IdentityRuleBucket.allowedFaces => 'Allowed faces',
      _IdentityRuleBucket.allowedPlates => 'Allowed plates',
    };
  }

  String _identityRuleSingularLabel(_IdentityRuleBucket bucket) {
    return switch (bucket) {
      _IdentityRuleBucket.flaggedFaces => 'flagged face',
      _IdentityRuleBucket.flaggedPlates => 'flagged plate',
      _IdentityRuleBucket.allowedFaces => 'allowed face',
      _IdentityRuleBucket.allowedPlates => 'allowed plate',
    };
  }

  Color _identityRuleBucketColor(_IdentityRuleBucket bucket) {
    return switch (bucket) {
      _IdentityRuleBucket.flaggedFaces => const Color(0xFFFF7A7A),
      _IdentityRuleBucket.flaggedPlates => const Color(0xFFFFB36B),
      _IdentityRuleBucket.allowedFaces => const Color(0xFF58D68D),
      _IdentityRuleBucket.allowedPlates => const Color(0xFF4FD1C5),
    };
  }

  String _identityPolicyScopeKey({
    required String clientId,
    required String siteId,
  }) {
    return '$clientId|$siteId';
  }

  String _identityPolicyEntryScopeKey(
    MonitoringIdentityScopePolicyEntry entry,
  ) {
    return _identityPolicyScopeKey(
      clientId: entry.clientId,
      siteId: entry.siteId,
    );
  }

  void _syncActiveIdentityPolicyScopeKey(
    List<MonitoringIdentityScopePolicyEntry> entries,
  ) {
    if (entries.isEmpty) {
      _activeIdentityPolicyScopeKey = '';
      return;
    }
    final hasActive = entries.any(
      (entry) =>
          _identityPolicyEntryScopeKey(entry) == _activeIdentityPolicyScopeKey,
    );
    if (!hasActive) {
      _activeIdentityPolicyScopeKey = _identityPolicyEntryScopeKey(
        entries.first,
      );
    }
  }

  MonitoringIdentityScopePolicyEntry? _activeIdentityPolicyEntry(
    List<MonitoringIdentityScopePolicyEntry> entries,
  ) {
    if (entries.isEmpty) {
      return null;
    }
    for (final entry in entries) {
      if (_identityPolicyEntryScopeKey(entry) ==
          _activeIdentityPolicyScopeKey) {
        return entry;
      }
    }
    return entries.first;
  }

  void _focusIdentityPolicyEntry(MonitoringIdentityScopePolicyEntry entry) {
    final nextKey = _identityPolicyEntryScopeKey(entry);
    if (nextKey == _activeIdentityPolicyScopeKey) {
      return;
    }
    setState(() {
      _activeIdentityPolicyScopeKey = nextKey;
    });
  }

  Color _identityPolicyAccent(MonitoringIdentityScopePolicy policy) {
    final flaggedCount =
        policy.flaggedFaceMatchIds.length + policy.flaggedPlateNumbers.length;
    final allowlistedCount =
        policy.allowedFaceMatchIds.length + policy.allowedPlateNumbers.length;
    if (flaggedCount > 0) {
      return const Color(0xFFFFB36B);
    }
    if (allowlistedCount > 0) {
      return const Color(0xFF4FD1C5);
    }
    return const Color(0xFF67E8F9);
  }

  String _identityPolicyRecommendedMove(MonitoringIdentityScopePolicy policy) {
    final flaggedCount =
        policy.flaggedFaceMatchIds.length + policy.flaggedPlateNumbers.length;
    final allowlistedCount =
        policy.allowedFaceMatchIds.length + policy.allowedPlateNumbers.length;
    if (flaggedCount > 0) {
      return 'Review flagged rules';
    }
    if (allowlistedCount > 0) {
      return 'Copy selected site';
    }
    return 'Import site JSON';
  }

  String _identityPolicyValuePreview({
    required String emptyLabel,
    required Iterable<String> values,
  }) {
    final items = values.take(3).toList(growable: false);
    if (items.isEmpty) {
      return emptyLabel;
    }
    final preview = items.join(' • ');
    final extraCount = values.length - items.length;
    if (extraCount <= 0) {
      return preview;
    }
    return '$preview • +$extraCount more';
  }

  void _commitMonitoringIdentityPolicyService(
    MonitoringIdentityPolicyService nextService,
  ) {
    setState(() {
      _monitoringIdentityPolicyService = nextService;
      _syncActiveIdentityPolicyScopeKey(nextService.entries);
    });
    widget.onMonitoringIdentityPolicyServiceChanged?.call(nextService);
  }

  void _recordIdentityPolicyAudit(
    String message, {
    required MonitoringIdentityPolicyAuditSource source,
  }) {
    final nextHistory = <MonitoringIdentityPolicyAuditRecord>[
      MonitoringIdentityPolicyAuditRecord(
        recordedAtUtc: DateTime.now().toUtc(),
        source: source,
        message: message,
      ),
      ..._identityPolicyAuditHistory,
    ].take(8).toList(growable: false);
    setState(() {
      _identityPolicyAuditHistory = nextHistory;
    });
    widget.onMonitoringIdentityRuleAuditHistoryChanged?.call(nextHistory);
  }

  void _setActiveIdentityPolicyAuditSource(
    MonitoringIdentityPolicyAuditSource? source,
  ) {
    if (_activeIdentityPolicyAuditSource == source) {
      return;
    }
    setState(() {
      _activeIdentityPolicyAuditSource = source;
    });
    widget.onMonitoringIdentityRuleAuditSourceFilterChanged?.call(source);
  }

  void _setIdentityPolicyAuditExpanded(bool value) {
    if (_identityPolicyAuditExpanded == value) {
      return;
    }
    setState(() {
      _identityPolicyAuditExpanded = value;
    });
    widget.onMonitoringIdentityRuleAuditExpandedChanged?.call(value);
  }

  Future<void> _loadTelegramIdentityIntakesFromSupabase() async {
    if (!widget.supabaseReady) {
      return;
    }
    setState(() {
      _telegramIdentityIntakesLoading = true;
    });
    try {
      final repository = _siteIdentityRegistryRepository();
      final records = await repository.listPendingTelegramIntakes();
      if (!mounted) {
        return;
      }
      setState(() {
        _telegramIdentityIntakes = records;
      });
    } catch (error) {
      if (!mounted) {
        return;
      }
      _snack('Failed to load Telegram visitor proposals: $error');
    } finally {
      if (mounted) {
        setState(() {
          _telegramIdentityIntakesLoading = false;
        });
      }
    }
  }

  void _setTelegramIdentityIntakeBusy(String intakeId, bool busy) {
    final normalized = intakeId.trim();
    if (normalized.isEmpty) {
      return;
    }
    final next = {..._telegramIdentityIntakeBusyIds};
    if (busy) {
      next.add(normalized);
    } else {
      next.remove(normalized);
    }
    setState(() {
      _telegramIdentityIntakeBusyIds = next;
    });
  }

  String _telegramIntakeDisplayName(TelegramIdentityIntakeRecord intake) {
    if (intake.parsedDisplayName.trim().isNotEmpty) {
      return intake.parsedDisplayName.trim();
    }
    if (intake.parsedFaceMatchId.trim().isNotEmpty) {
      return 'Face ${intake.parsedFaceMatchId.trim()}';
    }
    if (intake.parsedPlateNumber.trim().isNotEmpty) {
      return 'Plate ${intake.parsedPlateNumber.trim()}';
    }
    return 'Unnamed visitor';
  }

  String _telegramIntakeSummary(TelegramIdentityIntakeRecord intake) {
    final details = <String>[
      intake.category.code.toUpperCase(),
      if (intake.parsedFaceMatchId.trim().isNotEmpty)
        'Face ${intake.parsedFaceMatchId.trim()}',
      if (intake.parsedPlateNumber.trim().isNotEmpty)
        'Plate ${intake.parsedPlateNumber.trim()}',
      if (intake.validUntilUtc != null)
        'Until ${intake.validUntilUtc!.toUtc().hour.toString().padLeft(2, '0')}:${intake.validUntilUtc!.toUtc().minute.toString().padLeft(2, '0')} UTC',
    ];
    return details.join(' • ');
  }

  DateTime _telegramIntakeApprovalExpiry(TelegramIdentityIntakeRecord intake) {
    final fromUtc = intake.validFromUtc?.toUtc() ?? intake.createdAtUtc.toUtc();
    final untilUtc = intake.validUntilUtc?.toUtc();
    if (untilUtc != null && untilUtc.isAfter(fromUtc)) {
      return untilUtc;
    }
    return DateTime.now().toUtc().add(const Duration(hours: 12));
  }

  String _telegramIntakeExpiryLabel(DateTime utc) {
    final year = utc.year.toString().padLeft(4, '0');
    final month = utc.month.toString().padLeft(2, '0');
    final day = utc.day.toString().padLeft(2, '0');
    final hour = utc.hour.toString().padLeft(2, '0');
    final minute = utc.minute.toString().padLeft(2, '0');
    return '$year-$month-$day $hour:$minute UTC';
  }

  String _telegramIntakeCreatedAtLabel(TelegramIdentityIntakeRecord intake) {
    final value = intake.createdAtUtc.toUtc();
    final year = value.year.toString().padLeft(4, '0');
    final month = value.month.toString().padLeft(2, '0');
    final day = value.day.toString().padLeft(2, '0');
    final hour = value.hour.toString().padLeft(2, '0');
    final minute = value.minute.toString().padLeft(2, '0');
    return '$year-$month-$day $hour:$minute UTC';
  }

  Future<void> _approveTelegramIdentityIntakeOnce(
    TelegramIdentityIntakeRecord intake,
  ) async {
    if (!widget.supabaseReady) {
      _snack('Supabase required to action Telegram visitor proposals.');
      return;
    }
    _setTelegramIdentityIntakeBusy(intake.intakeId, true);
    try {
      final repository = _siteIdentityRegistryRepository();
      final nowUtc = DateTime.now().toUtc();
      final validUntilUtc = _telegramIntakeApprovalExpiry(intake);
      final displayName = _telegramIntakeDisplayName(intake);
      final faceId = intake.parsedFaceMatchId.trim().toUpperCase();
      final plate = intake.parsedPlateNumber.trim().toUpperCase();
      final summary =
          'Admin approved one-time Telegram visitor proposal for '
          '${displayName.isEmpty ? intake.siteId : displayName} until '
          '${_telegramIntakeExpiryLabel(validUntilUtc)}.';

      final profileType = plate.isNotEmpty && faceId.isEmpty
          ? SiteIdentityType.vehicle
          : SiteIdentityType.person;
      final profile = SiteIdentityProfile(
        clientId: intake.clientId,
        siteId: intake.siteId,
        identityType: profileType,
        category: intake.category,
        status: SiteIdentityStatus.allowed,
        displayName: displayName,
        faceMatchId: faceId,
        plateNumber: plate,
        externalReference: intake.intakeId,
        notes: 'Approved once from Telegram visitor proposal.',
        validFromUtc: intake.validFromUtc?.toUtc() ?? nowUtc,
        validUntilUtc: validUntilUtc,
        createdAtUtc: nowUtc,
        updatedAtUtc: nowUtc,
        metadata: <String, Object?>{
          'source': 'telegram_identity_intake',
          'intake_id': intake.intakeId,
          'temporary_approval': true,
        },
      );
      await repository.upsertProfile(profile);
      await repository.insertApprovalDecision(
        SiteIdentityApprovalDecisionRecord(
          clientId: intake.clientId,
          siteId: intake.siteId,
          decision: SiteIdentityDecision.approveOnce,
          source: SiteIdentityDecisionSource.admin,
          decidedBy: 'ONYX Admin',
          decisionSummary: summary,
          decidedAtUtc: nowUtc,
          metadata: <String, Object?>{
            'intake_id': intake.intakeId,
            'raw_text': intake.rawText,
            'valid_until': validUntilUtc.toIso8601String(),
          },
        ),
      );
      await repository.updateTelegramIntakeApprovalState(
        intakeId: intake.intakeId,
        approvalState: 'approved_once',
      );
      if (widget.onRegisterTemporaryIdentityApprovalProfile != null) {
        await widget.onRegisterTemporaryIdentityApprovalProfile!(profile);
      }
      if (!mounted) {
        return;
      }
      setState(() {
        _telegramIdentityIntakes = _telegramIdentityIntakes
            .where((record) => record.intakeId != intake.intakeId)
            .toList(growable: false);
      });
      _snack(
        'Telegram visitor proposal approved once until ${_telegramIntakeExpiryLabel(validUntilUtc)}.',
      );
    } catch (error) {
      if (!mounted) {
        return;
      }
      _snack('Failed to approve one-time Telegram visitor proposal: $error');
    } finally {
      if (mounted) {
        _setTelegramIdentityIntakeBusy(intake.intakeId, false);
      }
    }
  }

  Future<void> _approveTelegramIdentityIntakeAlways(
    TelegramIdentityIntakeRecord intake,
  ) async {
    if (!widget.supabaseReady) {
      _snack('Supabase required to action Telegram visitor proposals.');
      return;
    }
    _setTelegramIdentityIntakeBusy(intake.intakeId, true);
    try {
      final repository = _siteIdentityRegistryRepository();
      final nowUtc = DateTime.now().toUtc();
      final faceId = intake.parsedFaceMatchId.trim().toUpperCase();
      final plate = intake.parsedPlateNumber.trim().toUpperCase();
      final displayName = _telegramIntakeDisplayName(intake);
      final summary =
          'Admin approved Telegram visitor proposal for '
          '${displayName.isEmpty ? intake.siteId : displayName}.';

      if (faceId.isNotEmpty) {
        await repository.upsertProfile(
          SiteIdentityProfile(
            clientId: intake.clientId,
            siteId: intake.siteId,
            identityType: SiteIdentityType.person,
            category: intake.category,
            status: SiteIdentityStatus.allowed,
            displayName: displayName,
            faceMatchId: faceId,
            externalReference: intake.intakeId,
            notes: 'Approved from Telegram visitor proposal.',
            validFromUtc: intake.validFromUtc ?? nowUtc,
            createdAtUtc: nowUtc,
            updatedAtUtc: nowUtc,
            metadata: <String, Object?>{
              'source': 'telegram_identity_intake',
              'intake_id': intake.intakeId,
            },
          ),
        );
      }
      if (plate.isNotEmpty) {
        await repository.upsertProfile(
          SiteIdentityProfile(
            clientId: intake.clientId,
            siteId: intake.siteId,
            identityType: SiteIdentityType.vehicle,
            category: intake.category,
            status: SiteIdentityStatus.allowed,
            displayName: plate,
            plateNumber: plate,
            externalReference: intake.intakeId,
            notes: 'Approved from Telegram visitor proposal.',
            validFromUtc: intake.validFromUtc ?? nowUtc,
            createdAtUtc: nowUtc,
            updatedAtUtc: nowUtc,
            metadata: <String, Object?>{
              'source': 'telegram_identity_intake',
              'intake_id': intake.intakeId,
            },
          ),
        );
      }

      await repository.insertApprovalDecision(
        SiteIdentityApprovalDecisionRecord(
          clientId: intake.clientId,
          siteId: intake.siteId,
          decision: SiteIdentityDecision.approveAlways,
          source: SiteIdentityDecisionSource.admin,
          decidedBy: 'ONYX Admin',
          decisionSummary: summary,
          decidedAtUtc: nowUtc,
          metadata: <String, Object?>{
            'intake_id': intake.intakeId,
            'raw_text': intake.rawText,
          },
        ),
      );
      await repository.updateTelegramIntakeApprovalState(
        intakeId: intake.intakeId,
        approvalState: 'approved',
      );

      if (faceId.isNotEmpty || plate.isNotEmpty) {
        final current = _monitoringIdentityPolicyService.policyFor(
          clientId: intake.clientId,
          siteId: intake.siteId,
        );
        _commitMonitoringIdentityPolicyService(
          _monitoringIdentityPolicyService.updateScopePolicy(
            clientId: intake.clientId,
            siteId: intake.siteId,
            policy: current.copyWith(
              allowedFaceMatchIds: faceId.isEmpty
                  ? current.allowedFaceMatchIds
                  : <String>{...current.allowedFaceMatchIds, faceId},
              allowedPlateNumbers: plate.isEmpty
                  ? current.allowedPlateNumbers
                  : <String>{...current.allowedPlateNumbers, plate},
            ),
          ),
        );
        _recordIdentityPolicyAudit(
          'Approved Telegram visitor proposal for ${intake.siteId} (${_telegramIntakeSummary(intake)}).',
          source: MonitoringIdentityPolicyAuditSource.manualEdit,
        );
      }

      if (!mounted) {
        return;
      }
      setState(() {
        _telegramIdentityIntakes = _telegramIdentityIntakes
            .where((record) => record.intakeId != intake.intakeId)
            .toList(growable: false);
      });
      _snack(
        faceId.isEmpty && plate.isEmpty
            ? 'Proposal approved into the registry. Add a stable face or plate later for automatic matching.'
            : 'Telegram visitor proposal allowlisted.',
      );
    } catch (error) {
      if (!mounted) {
        return;
      }
      _snack('Failed to approve Telegram visitor proposal: $error');
    } finally {
      if (mounted) {
        _setTelegramIdentityIntakeBusy(intake.intakeId, false);
      }
    }
  }

  Future<void> _rejectTelegramIdentityIntake(
    TelegramIdentityIntakeRecord intake,
  ) async {
    if (!widget.supabaseReady) {
      _snack('Supabase required to action Telegram visitor proposals.');
      return;
    }
    _setTelegramIdentityIntakeBusy(intake.intakeId, true);
    try {
      final repository = _siteIdentityRegistryRepository();
      await repository.insertApprovalDecision(
        SiteIdentityApprovalDecisionRecord(
          clientId: intake.clientId,
          siteId: intake.siteId,
          decision: SiteIdentityDecision.review,
          source: SiteIdentityDecisionSource.admin,
          decidedBy: 'ONYX Admin',
          decisionSummary:
              'Admin rejected Telegram visitor proposal and left it out of the allowlist.',
          decidedAtUtc: DateTime.now().toUtc(),
          metadata: <String, Object?>{
            'intake_id': intake.intakeId,
            'raw_text': intake.rawText,
          },
        ),
      );
      await repository.updateTelegramIntakeApprovalState(
        intakeId: intake.intakeId,
        approvalState: 'rejected',
      );
      if (!mounted) {
        return;
      }
      setState(() {
        _telegramIdentityIntakes = _telegramIdentityIntakes
            .where((record) => record.intakeId != intake.intakeId)
            .toList(growable: false);
      });
      _snack('Telegram visitor proposal rejected.');
    } catch (error) {
      if (!mounted) {
        return;
      }
      _snack('Failed to reject Telegram visitor proposal: $error');
    } finally {
      if (mounted) {
        _setTelegramIdentityIntakeBusy(intake.intakeId, false);
      }
    }
  }

