  Future<String?> _showAdminTextEntryDialog({
    required String title,
    required String fieldLabel,
    required String confirmLabel,
    String initialText = '',
    Key? fieldKey,
    String? hintText,
    TextStyle? hintStyle,
    TextStyle? fieldStyle,
    TextStyle? cancelTextStyle,
    TextStyle? confirmTextStyle,
    ButtonStyle? confirmButtonStyle,
    double? contentWidth,
    int minLines = 1,
    int maxLines = 1,
    bool autofocus = false,
  }) async {
    final controller = TextEditingController(text: initialText);
    final result = await showDialog<String>(
      context: context,
      builder: (dialogContext) {
        final textField = TextField(
          key: fieldKey,
          controller: controller,
          autofocus: autofocus,
          minLines: minLines,
          maxLines: maxLines,
          style: fieldStyle ?? GoogleFonts.inter(color: _adminDialogTitleColor),
          decoration: _adminDialogInputDecoration(
            fieldLabel,
          ).copyWith(hintText: hintText, hintStyle: hintStyle),
          onSubmitted: (value) => Navigator.of(dialogContext).pop(value),
        );
        return AlertDialog(
          backgroundColor: _adminDialogSurfaceColor,
          shape: _adminDialogShape(),
          title: Text(
            title,
            style: GoogleFonts.inter(
              color: _adminDialogTitleColor,
              fontWeight: FontWeight.w700,
            ),
          ),
          content: contentWidth == null
              ? textField
              : SizedBox(width: contentWidth, child: textField),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(dialogContext).pop(),
              child: Text(
                'Cancel',
                style:
                    cancelTextStyle ??
                    GoogleFonts.inter(
                      color: _adminDialogMutedColor,
                      fontWeight: FontWeight.w700,
                    ),
              ),
            ),
            FilledButton(
              onPressed: () => Navigator.of(dialogContext).pop(controller.text),
              style: confirmButtonStyle,
              child: Text(
                confirmLabel,
                style:
                    confirmTextStyle ??
                    GoogleFonts.inter(fontWeight: FontWeight.w700),
              ),
            ),
          ],
        );
      },
    );
    WidgetsBinding.instance.addPostFrameCallback((_) {
      controller.dispose();
    });
    return result;
  }

  void _disposeTextControllersAfterDialogFrame(
    Iterable<TextEditingController> controllers,
  ) {
    final pending = controllers.toList(growable: false);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      for (final controller in pending) {
        controller.dispose();
      }
    });
  }

  Future<void> _importMonitoringIdentityRulesJson() async {
    final rawJson = await _showAdminTextEntryDialog(
      title: 'Import Identity Rules JSON',
