                          style: GoogleFonts.inter(
                            color: muted,
                            fontSize: 12,
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 12),
                  Text(
                    '$count',
                    style: GoogleFonts.inter(
                      color: active
                          ? const Color(0xFF00D4FF)
                          : const Color(0xFF8EA4C2),
                      fontSize: 22,
                      fontWeight: FontWeight.w900,
