  AdminDirectoryClientSeed? get _latestApprovedTelegramClientSeed =>
      widget.approvedTelegramClientSeeds.isEmpty
      ? null
      : widget.approvedTelegramClientSeeds.last;

  AdminDirectorySiteSeed? get _latestApprovedTelegramSiteSeed =>
      widget.approvedTelegramSiteSeeds.isEmpty
      ? null
      : widget.approvedTelegramSiteSeeds.last;

  AdminApprovedTelegramOnboardingPrefill?
  get _latestApprovedTelegramOnboardingPrefill =>
      widget.approvedTelegramOnboardingPrefill;

  AdminApprovedTelegramBridgeRunbookProgress?
  get _latestApprovedTelegramBridgeRunbookProgress {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    final progress = widget.approvedTelegramBridgeRunbookProgress;
    if (prefill == null ||
        progress == null ||
        !progress.matchesPrefill(prefill)) {
      return null;
    }
    return progress;
  }

  Future<void> _rememberTelegramBridgeRunbookProgress(
    AdminApprovedTelegramBridgeRunbookProgress Function(
      AdminApprovedTelegramBridgeRunbookProgress progress,
    )
    update,
  ) async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    final onUpdate = widget.onUpdateApprovedTelegramBridgeRunbookProgress;
    if (prefill == null || onUpdate == null) {
      return;
    }
    final current =
        _latestApprovedTelegramBridgeRunbookProgress ??
        AdminApprovedTelegramBridgeRunbookProgress(
          clientId: prefill.clientId,
          siteId: prefill.siteId,
        );
    await onUpdate(update(current));
  }

  String _buildTelegramCameraBridgeSeedBrief(
    AdminApprovedTelegramOnboardingPrefill prefill,
  ) {
    final buffer = StringBuffer()
      ..writeln('Telegram-approved camera bridge seed')
      ..writeln('Client: ${prefill.clientId} (${prefill.clientName})')
      ..writeln('Site: ${prefill.siteId} (${prefill.siteName})');
    if (prefill.cameraCount != null) {
      buffer.writeln('Camera count: ${prefill.cameraCount}');
    }
    if (prefill.vendor.trim().isNotEmpty) {
      buffer.writeln('Vendor: ${prefill.vendor.trim()}');
    }
    if (prefill.contactName.trim().isNotEmpty) {
      buffer.writeln('Contact: ${prefill.contactName.trim()}');
    }
    if (prefill.wantsTelegramBinding) {
      buffer.writeln('Telegram binding: requested');
    }
    if (prefill.inviteLinks.isNotEmpty) {
      buffer.writeln('Invite links: ${prefill.inviteLinks.join(' | ')}');
    }
    buffer.write(
      'Next move: validate the local camera bridge, confirm vendor reachability, and open CCTV review for the staged site.',
    );
    return buffer.toString();
  }

  String _buildTelegramCctvReviewBrief(
    AdminApprovedTelegramOnboardingPrefill prefill,
  ) {
    final vendor = prefill.vendor.trim();
    final cameraCount = prefill.cameraCount;
    final lines = <String>[
      'Telegram-seeded CCTV review brief',
      'Client: ${prefill.clientId} (${prefill.clientName})',
      'Site: ${prefill.siteId} (${prefill.siteName})',
      if (cameraCount != null) 'Expected cameras: $cameraCount',
      if (vendor.isNotEmpty) 'Vendor: $vendor',
      'Review focus:',
      '1. Confirm live reachability on the staged site scope.',
      '2. Check for missing or stale feeds before opening the main review desk.',
      '3. Note any offline cameras, auth gaps, or bridge mismatches for follow-up.',
    ];
    return lines.join('\n');
  }

  String _buildTelegramVendorValidationBrief(
    AdminApprovedTelegramOnboardingPrefill prefill,
  ) {
    final vendor = prefill.vendor.trim().isEmpty
        ? 'Pending vendor'
        : prefill.vendor.trim();
    final lines = <String>[
      'Telegram-seeded vendor validation brief',
      'Site: ${prefill.siteId} (${prefill.siteName})',
      'Vendor: $vendor',
      if (prefill.cameraCount != null)
        'Camera pack: ${prefill.cameraCount} staged cameras',
      'Validation focus:',
      '1. Confirm vendor endpoint, auth path, and bridge compatibility.',
      '2. Verify the first live packet can traverse the local camera bridge.',
      '3. Record any vendor-specific blockers before opening CCTV review.',
    ];
    return lines.join('\n');
  }

  Future<void> _copyTelegramCameraBridgeSeedBrief() async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    if (prefill == null) {
      return;
    }
    await Clipboard.setData(
      ClipboardData(text: _buildTelegramCameraBridgeSeedBrief(prefill)),
    );
    if (!mounted) {
      return;
    }
    _showAdminFeedbackSnackBar(
      context,
      'Copied telegram camera bridge brief for ${prefill.siteId}.',
    );
  }

  Future<void> _copyTelegramCctvReviewBrief() async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    if (prefill == null) {
      return;
    }
    await Clipboard.setData(
      ClipboardData(text: _buildTelegramCctvReviewBrief(prefill)),
    );
    if (!mounted) {
      return;
    }
    _showAdminFeedbackSnackBar(
      context,
      'Copied CCTV review brief for ${prefill.siteId}.',
    );
  }

  Future<void> _runTelegramSeededVendorValidation() async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    if (prefill != null) {
      await Clipboard.setData(
        ClipboardData(text: _buildTelegramVendorValidationBrief(prefill)),
      );
    }
    final endpoint = widget.onyxAgentCameraBridgeStatus.endpoint;
    if (endpoint == null) {
      if (!mounted) {
        return;
      }
      _showAdminFeedbackSnackBar(
        context,
        prefill == null
            ? describeOnyxAgentCameraBridgeEndpointMissingMessage()
            : 'Copied vendor validation brief for ${prefill.siteId}. ${describeOnyxAgentCameraBridgeEndpointMissingMessage()}',
      );
      return;
    }
    try {
      await runOnyxCameraBridgeValidationAction(
        currentState: _cameraBridgeLocalState,
        status: widget.onyxAgentCameraBridgeStatus,
        service: widget.onyxAgentCameraBridgeHealthService,
        operatorId: widget.operatorId,
        onLocalStateChanged: (state) {
          setState(() {
            _cameraBridgeLocalState = state;
          });
        },
        isMounted: () => mounted,
        onSnapshotChanged: (snapshot) {
          widget.onOnyxAgentCameraBridgeHealthSnapshotChanged?.call(snapshot);
        },
        onMessage: (message) {
          if (prefill == null) {
            _showAdminFeedbackSnackBar(context, message);
            return;
          }
          final combinedMessage = switch (message) {
            'Camera bridge health check complete.' =>
              'Copied vendor validation brief and validated camera bridge.',
            'Camera bridge health check failed.' =>
              'Copied vendor validation brief and camera bridge health check failed.',
            _ => message,
          };
          _showAdminFeedbackSnackBar(context, combinedMessage);
        },
      );
    } catch (_) {
      if (mounted) {
        _showAdminFeedbackSnackBar(
          context,
          prefill == null
              ? 'Camera bridge health check failed.'
              : 'Copied vendor validation brief and camera bridge health check failed.',
        );
      }
    } finally {
      await _rememberTelegramBridgeRunbookProgress(
        (progress) => progress.copyWith(vendorValidated: true),
      );
    }
  }

  Future<void> _openTelegramCameraBridgeOperationsScope() async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    final callback = widget.onOpenOperationsForScope;
    if (prefill == null) {
      return;
    }
    if (callback == null) {
      await _copyTelegramCctvReviewBrief();
      return;
    }
    await _rememberTelegramBridgeRunbookProgress(
      (progress) => progress.copyWith(operationsOpened: true),
    );
    callback(prefill.clientId, prefill.siteId);
  }

  Widget _telegramCameraBridgeSeedPanel() {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    if (prefill == null) {
      return const SizedBox.shrink();
    }
    final progress = _latestApprovedTelegramBridgeRunbookProgress;
    final receiptState = _cameraBridgePresentation.surfaceState.receiptState;
    final detailChips = <String>[
      'Source telegram-approved',
      if (prefill.cameraCount != null) '${prefill.cameraCount} cameras',
      if (prefill.vendor.trim().isNotEmpty) prefill.vendor.trim(),
      if (prefill.wantsTelegramBinding) 'Telegram bind requested',
    ];
    final stepOneComplete =
        progress?.vendorValidated == true ||
        receiptState == OnyxAgentCameraBridgeReceiptState.current;
    final stepOneStatus = stepOneComplete
        ? 'Done'
        : receiptState == OnyxAgentCameraBridgeReceiptState.stale
        ? 'Re-validate'
        : 'Next';
    final stepTwoStatus = progress?.cctvPolled == true
        ? 'Done'
        : widget.onRunCctvPoll == null
        ? 'Unavailable'
        : stepOneComplete
        ? 'Next'
        : 'After step 1';
    final stepThreeStatus = progress?.operationsOpened == true
        ? 'Done'
        : widget.onOpenOperationsForScope == null
        ? 'Unavailable'
        : stepOneComplete
        ? 'Then open'
        : 'After step 2';
    final runbookSteps =
        <
          ({
            String keySuffix,
            String step,
            String title,
            String detail,
            String status,
          })
        >[
          (
            keySuffix: 'validate',
            step: '1',
            title: 'Validate Bridge + Vendor Brief',
            detail: 'Copy the vendor brief and run the bridge health check.',
            status: stepOneStatus,
          ),
          (
            keySuffix: 'poll',
            step: '2',
            title: 'Poll ${widget.videoOpsLabel} Now',
            detail:
                'Copy the CCTV review brief and refresh live video telemetry.',
            status: stepTwoStatus,
          ),
          (
            keySuffix: 'ops',
            step: '3',
            title: 'Open Command Scope',
            detail: 'Move into the scoped Command desk for the staged site.',
            status: stepThreeStatus,
          ),
        ];
    return Container(
      key: const ValueKey('admin-system-camera-bridge-telegram-seed'),
      padding: const EdgeInsets.all(18),
      decoration: BoxDecoration(
        color: const Color(0xFFF9FCFF),
        borderRadius: BorderRadius.circular(20),
        border: Border.all(color: const Color(0xFFD8E7F2)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(
