  Widget _systemQueueHintPanel() {
    final resetAvailable = widget.onResetLiveOperationsQueueHint != null;
    final opsPollReady = _opsPollHealthEntries().isNotEmpty;
    final runtimeReady =
        !_radioIntentPhraseValidationError && !_demoRouteCueValidationError;
    final nextMove = _liveOperationsQueueHintResetBusy
        ? 'Reset queue hint'
        : !resetAvailable
        ? 'Queue hint offline'
        : !runtimeReady
        ? 'Repair runtime drafts'
        : opsPollReady
        ? 'Review ops poll health'
        : 'Reset queue hint';
    return Container(
      key: const ValueKey('admin-system-runtime-command'),
      width: double.infinity,
