  Widget _systemCameraBridgePanel() {
    final presentation = _cameraBridgePresentation;
    final stagingLabel = (widget.onyxAgentCameraBridgeStagingLabel ?? '')
        .trim();
    final stagingDetail = (widget.onyxAgentCameraBridgeStagingDetail ?? '')
        .trim();
    return KeyedSubtree(
      key: _systemCameraBridgePanelKey,
      child: OnyxCameraBridgeShellPanel(
        cardKey: const ValueKey('admin-system-camera-bridge-command'),
        status: widget.onyxAgentCameraBridgeStatus,
        surfaceState: presentation.surfaceState,
        snapshot: presentation.displaySnapshot,
        accents: presentation.accents,
        stagingIndicatorKey: const ValueKey(
          'admin-system-camera-staging-indicator',
        ),
        stagingIndicatorLabel: stagingLabel.isNotEmpty
            ? stagingLabel
            : 'Camera control in staging mode',
        stagingIndicatorDetail: stagingDetail.isNotEmpty
            ? stagingDetail
            : 'Execution remains operator-gated while the local bridge is validated for approved ONYX camera packets.',
        summaryPanelKey: const ValueKey('admin-system-camera-bridge-next-move'),
        healthCardKey: const ValueKey(
          'admin-system-camera-bridge-health-result',
        ),
        validateButtonKey: const ValueKey(
          'admin-system-camera-bridge-validate',
        ),
        onValidate: _validateCameraBridge,
        validateBusy: _cameraBridgeLocalState.validationInFlight,
        clearButtonKey: const ValueKey(
          'admin-system-camera-bridge-clear-health',
        ),
        onClear: _clearCameraBridgeHealthSnapshot,
        clearBusy: _cameraBridgeLocalState.resetInFlight,
        copyButtonKey: const ValueKey('admin-system-camera-bridge-copy'),
        onCopy: _copyCameraBridgeSetup,
        variant: OnyxCameraBridgeShellPanelVariant.admin,
      ),
    );
  }

  OnyxCameraBridgeSurfacePresentation get _cameraBridgePresentation =>
      resolveOnyxCameraBridgeSurfacePresentation(
        status: widget.onyxAgentCameraBridgeStatus,
        localSnapshot: _cameraBridgeLocalState.snapshot,
        fallbackSnapshot: widget.onyxAgentCameraBridgeHealthSnapshot,
        healthProbeConfigured:
            widget.onyxAgentCameraBridgeHealthService.isConfigured,
        validationInFlight: _cameraBridgeLocalState.validationInFlight,
        resetInFlight: _cameraBridgeLocalState.resetInFlight,
        variant: OnyxCameraBridgeSurfaceToneVariant.admin,
      );

  Future<void> _validateCameraBridge() async {
    await runOnyxCameraBridgeValidationAction(
      currentState: _cameraBridgeLocalState,
      status: widget.onyxAgentCameraBridgeStatus,
      service: widget.onyxAgentCameraBridgeHealthService,
      operatorId: widget.operatorId,
      onLocalStateChanged: (state) {
        setState(() {
          _cameraBridgeLocalState = state;
        });
      },
      isMounted: () => mounted,
      onSnapshotChanged: (snapshot) {
        widget.onOnyxAgentCameraBridgeHealthSnapshotChanged?.call(snapshot);
      },
      onMessage: (message) => _showAdminFeedbackSnackBar(context, message),
    );
  }

  Future<void> _clearCameraBridgeHealthSnapshot() async {
    await runOnyxCameraBridgeClearAction(
      currentState: _cameraBridgeLocalState,
      snapshot: _cameraBridgeLocalState.snapshot,
      onClearReceipt: widget.onClearOnyxAgentCameraBridgeHealthSnapshot,
      onLocalStateChanged: (state) {
        setState(() {
          _cameraBridgeLocalState = state;
        });
      },
      isMounted: () => mounted,
      onMessage: (message) => _showAdminFeedbackSnackBar(context, message),
    );
  }

  Future<void> _copyCameraBridgeSetup() async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    await runOnyxCameraBridgeCopyAction(
      status: widget.onyxAgentCameraBridgeStatus,
      presentation: _cameraBridgePresentation,
      isMounted: () => mounted,
      onMessage: (message) => _showAdminFeedbackSnackBar(context, message),
      leadingText: prefill == null
          ? null
          : _buildTelegramCameraBridgeSeedBrief(prefill),
    );
  }

  Widget _demoStoryboardPanel() {
    final clientReady = (_demoStoryClientId ?? '').isNotEmpty;
    final siteReady = (_demoStorySiteId ?? '').isNotEmpty;
    final employeeReady = (_demoStoryEmployeeCode ?? '').isNotEmpty;
    final vehicleReady = (_demoStoryVehicleCallsign ?? '').isNotEmpty;
    final incidentReady = (_demoStoryIncidentEventUid ?? '').isNotEmpty;
    final stackReady = clientReady && siteReady && employeeReady;
    final opsReady = stackReady && vehicleReady && incidentReady;
    final clientId = (_demoStoryClientId ?? '').trim();
    final siteId = (_demoStorySiteId ?? '').trim();
    final incidentRef = (_demoStoryIncidentEventUid ?? '').trim();
    final storyboardProgress = [
      clientReady,
      siteReady,
      employeeReady,
      vehicleReady,
      incidentReady,
    ].where((ready) => ready).length;
    final stackProfileLabel = _demoStackProfileLabel(_demoStackProfile);
    final commandAccent = opsReady
        ? const Color(0xFF34D399)
        : (stackReady ? const Color(0xFF67E8F9) : const Color(0xFF8EA4C2));
    final commandHeadline = opsReady
        ? 'Incident $incidentRef ready for full route replay.'
        : stackReady
        ? 'Core stack is ready for fleet and incident seeding.'
        : storyboardProgress == 0
        ? 'Build the demo stack or start the first onboarding step.'
        : 'Complete the next onboarding step to unlock live route handoffs.';
    final commandDetail = opsReady
        ? 'Security Desk, tactical track, governance desk, sovereign ledger, client comms, and reports workspace pivots are all live from this scope.'
        : stackReady
        ? 'Client, site, and response readiness are in place. Add fleet and incident data to expose the full control-room route story.'
        : 'This storyboard keeps the operator surface simple while every downstream demo handoff stays wired underneath.';
    final nextMove = opsReady
        ? 'Launch live route'
        : stackReady
        ? 'Seed fleet + incident'
        : 'Build story stack';
    final openOperationsAction = _openOperationsAction(
      clientId: clientId,
      siteId: siteId,
      incidentReference: incidentRef,
    );
    final openTacticalAction = _openTacticalAction(
      clientId: clientId,
      siteId: siteId,
      incidentReference: incidentRef,
    );
    final openGovernanceAction = _openGovernanceAction(
      clientId: clientId,
      siteId: siteId,
    );
    final openDispatchesAction = _openDispatchesAction(
      clientId: clientId,
      siteId: siteId,
      incidentReference: incidentRef,
    );
    final openClientViewAction = _openClientLaneAction(
      clientId: clientId,
      siteId: siteId,
    );
    final openReportsAction = _openReportsAction(
      clientId: clientId,
      siteId: siteId,
    );
    final commandPrimaryLabel = !opsReady
        ? 'Build Demo Stack'
        : openOperationsAction != null
        ? 'OPEN SECURITY DESK'
        : openDispatchesAction != null
        ? 'OPEN DISPATCH BOARD'
        : 'Copy Runbook';
    final runbookText =
        'ONYX Client Demo Runbook\n'
        'Date: ${DateTime.now().toLocal()}\n'
        'Profile: $stackProfileLabel\n'
        'Status: ${opsReady ? 'Ops-ready' : (stackReady ? 'Core-ready' : 'Setup in progress')}\n\n'
        'Demo IDs\n'
        '- Client: ${_demoStoryClientId ?? 'Pending'}\n'
        '- Site: ${_demoStorySiteId ?? 'Pending'}\n'
        '- Employee: ${_demoStoryEmployeeCode ?? 'Pending'}\n'
        '- Vehicle: ${_demoStoryVehicleCallsign ?? 'Pending'}\n'
        '- Incident Ref: ${_demoStoryIncidentEventUid ?? 'Pending'}\n\n'
        'Live Route Flow\n'
        '1. Admin: confirm Storyboard readiness and mention compliance fields.\n'
        '2. Trigger Run Demo Autopilot for a fast combat-window walkthrough.\n'
        '3. Trigger Run Full Demo Tour for end-to-end executive replay.\n'
        '4. Events Scope: replay immutable incident timeline evidence.\n'
        '5. Sovereign Ledger: confirm immutable chain entry focus.\n'
        '6. Governance Desk: show readiness/compliance dashboard and handover discipline.\n'
        '7. Client Comms: show client-facing context and confidence posture.\n'
        '8. Reports Workspace: show sovereign reporting/export readiness.\n\n'
        'Close\n'
        '- Reconfirm focused incident ref and promised response workflow.\n'
        '- Optionally run Reset Demo Data before next client.';
    Future<void> copyRunbook() async {
      await Clipboard.setData(ClipboardData(text: runbookText));
      if (!mounted) return;
      _snack(
        'Storyboard runbook copied for command review.',
        sourceLabel: 'RUNBOOK HANDOFF',
        accent: const Color(0xFF8FD1FF),
        detail:
            'The storyboard keeps the seeded runbook pinned in the desktop command rail while you continue routing through the live demo path.',
      );
    }

    Future<void> copyIncidentReference() async {
      if (incidentRef.isEmpty) return;
      await Clipboard.setData(ClipboardData(text: incidentRef));
      if (!mounted) return;
      _snack(
        'Incident focus copied for command review: $incidentRef',
        sourceLabel: 'INCIDENT FOCUS',
        accent: const Color(0xFFBFD7F2),
        detail:
            'The storyboard keeps the seeded incident reference pinned in the desktop command rail while you continue routing from the live scope.',
      );
    }

    void runDemoAutopilot() {
      if (widget.onRunDemoAutopilotForIncident == null || incidentRef.isEmpty) {
        return;
