                              eventIds.first,
                            );
                          },
                          style: partnerDetailOutlineStyle(
                            foreground: const Color(0xFF2B5E93),
                            borderColor: const Color(0xFFB8CCE0),
                          ),
                          child: Text(
                            'OPEN EVENTS SCOPE',
                            style: GoogleFonts.inter(
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                      if (normalizedSiteId.isNotEmpty &&
                          widget.onOpenFleetDispatchScope != null)
                        FilledButton(
                          key: const ValueKey(
                            'admin-partner-detail-open-dispatch',
                          ),
                          onPressed: () {
                            Navigator.of(dialogContext).pop();
                            widget.onOpenFleetDispatchScope!.call(
                              normalizedClientId,
                              normalizedSiteId,
                              null,
                            );
                          },
                          style: FilledButton.styleFrom(
                            backgroundColor: const Color(0xFF2B5E93),
                            foregroundColor: Colors.white,
                          ),
                          child: Text(
                            'OPEN DISPATCH BOARD',
                            style: GoogleFonts.inter(
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        )
                      else if (_openDispatchesAction(
                            clientId: normalizedClientId,
                            siteId: normalizedSiteId,
                            incidentReference: '',
                          ) !=
                          null)
                        FilledButton(
                          key: const ValueKey(
                            'admin-partner-detail-open-dispatch',
                          ),
                          onPressed: () {
                            Navigator.of(dialogContext).pop();
                            _openDispatchesAction(
                              clientId: normalizedClientId,
                              siteId: normalizedSiteId,
                              incidentReference: '',
                            )?.call();
                          },
                          style: FilledButton.styleFrom(
                            backgroundColor: const Color(0xFF2B5E93),
                            foregroundColor: Colors.white,
                          ),
                          child: Text(
                            'OPEN DISPATCH BOARD',
                            style: GoogleFonts.inter(
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                      TextButton(
                        onPressed: () => Navigator.of(dialogContext).pop(),
                        style: TextButton.styleFrom(
                          foregroundColor: _adminDialogTitleColor,
                        ),
                        child: Text(
                          'Close',
                          style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                        ),
                      ),
                    ],
                  ),
                ],
              ),
            );
          },
        );
      },
    );
  }

