  Widget _sitesTable() {
    final filtered = _sites
        .where((row) {
          final q = _query.toLowerCase();
          return q.isEmpty ||
              row.name.toLowerCase().contains(q) ||
              row.code.toLowerCase().contains(q);
        })
        .toList(growable: false);

    return Column(
      children: filtered
          .map((row) {
            final siteChatcheck =
                _siteTelegramChatcheckStatus[_siteScopeKey(
                      row.clientId,
                      row.id,
                    )]
                    ?.trim() ??
                '';
            final sitePartnerChatcheck =
                _sitePartnerChatcheckStatus[_siteScopeKey(row.clientId, row.id)]
                    ?.trim() ??
                '';
            final sitePartnerLaneCount =
                _sitePartnerEndpointCounts[_siteScopeKey(
                  row.clientId,
                  row.id,
                )] ??
                0;
            final hasPartnerDrillIn =
                sitePartnerLaneCount > 0 ||
                sitePartnerChatcheck.isNotEmpty ||
                _recentPartnerActionsForScope(
                  row.clientId,
                  siteId: row.id,
                ).isNotEmpty;
            return Padding(
              padding: const EdgeInsets.only(bottom: 8),
              child: _dataCard(
                title: '${row.name} (${row.code})',
                lines: [
                  'Command Owner: ${_clientName(row.clientId)}',
                  'Site Address: ${row.address}',
                  'Geo Anchor: ${row.lat.toStringAsFixed(4)}, ${row.lng.toStringAsFixed(4)}',
                  'Command Contact: ${row.contactPerson} • ${row.contactPhone}',
                  'Response Anchor: ${row.fskNumber ?? '-'} • Geofence: ${row.geofenceRadiusMeters}m',
                  if (siteChatcheck.isNotEmpty) 'Bridge Health: $siteChatcheck',
                  if (sitePartnerLaneCount > 0)
                    'Partner Network: $sitePartnerLaneCount',
                  if (sitePartnerChatcheck.isNotEmpty)
                    'Partner Health: $sitePartnerChatcheck',
                ],
                status: row.status,
                isDemo:
                    _isDemoIdentifier(row.id) || _isDemoIdentifier(row.code),
                headerBadges: [
                  if (siteChatcheck.isNotEmpty) _chatcheckBadge(siteChatcheck),
                  if (sitePartnerChatcheck.isNotEmpty)
                    _partnerDispatchBadge(sitePartnerChatcheck),
                ],
                onTap: !hasPartnerDrillIn
                    ? null
                    : () => _showPartnerDispatchDetailDialog(
                        clientId: row.clientId,
                        siteId: row.id,
                      ),
                onEdit: () => _showSiteEditDialog(row),
                editKey: ValueKey('admin-edit-site-${row.id}'),
                onDelete: () => _deleteSite(row.id),
              ),
            );
          })
          .toList(growable: false),
    );
  }

