    final slippingCount = rows
        .where((row) => row.trendLabel == 'SLIPPING')
        .length;
    final criticalCount = rows
        .where((row) => row.currentScoreLabel == 'CRITICAL')
        .length;
    final improvingCount = rows
        .where((row) => row.trendLabel == 'IMPROVING')
        .length;
    return Container(
      key: const ValueKey('admin-partner-scorecard-card'),
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: _panelDecoration(),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _subTitle('Partner Scorecard'),
          const SizedBox(height: 8),
          Text(
            '7-day partner performance across active client/site scopes.',
            style: GoogleFonts.inter(
              color: const Color(0xFF9AB1CF),
              fontSize: 12,
              fontWeight: FontWeight.w600,
            ),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _partnerScorecardChip(
                label: 'Slipping',
                value: '$slippingCount',
                color: const Color(0xFFF97316),
              ),
              _partnerScorecardChip(
                label: 'Critical',
                value: '$criticalCount',
                color: const Color(0xFFEF4444),
              ),
              _partnerScorecardChip(
                label: 'Improving',
                value: '$improvingCount',
                color: const Color(0xFF34D399),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              if (_openGovernanceAction(
                    clientId: rows.length == 1 ? rows.first.clientId : '',
                    siteId: rows.length == 1 ? rows.first.siteId : '',
                  ) !=
                  null)
                OutlinedButton.icon(
                  onPressed: () {
                    final action = _openGovernanceAction(
                      clientId: rows.length == 1 ? rows.first.clientId : '',
                      siteId: rows.length == 1 ? rows.first.siteId : '',
                    );
                    action?.call();
                    final siteId = rows.length == 1 ? rows.first.siteId : '';
                    _snack(
                      siteId.trim().isNotEmpty
                          ? 'Opening Governance Desk for scope: $siteId'
                          : 'Opening Governance Desk',
                    );
                  },
                  icon: const Icon(Icons.verified_user_rounded, size: 16),
                  style: OutlinedButton.styleFrom(
                    foregroundColor: const Color(0xFF8FD1FF),
                    side: const BorderSide(color: Color(0xFF35506F)),
                  ),
                  label: Text(
                    'OPEN GOVERNANCE DESK',
                    style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                  ),
                ),
              FilledButton.icon(
                onPressed: rows.isEmpty ? null : _copyPartnerScorecardJson,
                icon: const Icon(Icons.copy_all_rounded, size: 16),
                style: FilledButton.styleFrom(
                  backgroundColor: const Color(0xFF1D4ED8),
                  foregroundColor: const Color(0xFFEAF4FF),
                ),
                label: Text(
                  'Copy Scorecard JSON',
                  style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                ),
              ),
              OutlinedButton.icon(
                onPressed: rows.isEmpty ? null : _copyPartnerScorecardCsv,
                icon: const Icon(Icons.table_rows_rounded, size: 16),
                style: OutlinedButton.styleFrom(
                  foregroundColor: const Color(0xFF9AB1CF),
                  side: const BorderSide(color: Color(0xFF35506F)),
                ),
                label: Text(
                  'Copy Scorecard CSV',
                  style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                ),
              ),
            ],
          ),
          const SizedBox(height: 10),
          if (rows.isEmpty)
            Text(
              'No partner scorecard history is available yet.',
              style: GoogleFonts.inter(
                color: const Color(0xFF8EA4C2),
                fontSize: 11,
                fontWeight: FontWeight.w600,
              ),
            )
