                    ),
                    onTap: () => _showPartnerDispatchDetailDialog(
                      clientId: row.clientId,
                      siteId: row.siteId,
                    ),
                    borderRadius: BorderRadius.circular(10),
                    child: _adminPartnerTrendCard(row),
                  ),
              ],
            ),
        ],
      ),
    );
  }

  Widget _listenerAlarmSummaryCard() {
    final cycles = [
      ...widget.events.whereType<ListenerAlarmFeedCycleRecorded>(),
    ]..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
    final advisories = [
      ...widget.events.whereType<ListenerAlarmAdvisoryRecorded>(),
    ]..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
    final latestCycle = cycles.isEmpty ? null : cycles.first;
    final parities = [
      ...widget.events.whereType<ListenerAlarmParityCycleRecorded>(),
    ]..sort((a, b) => b.occurredAt.compareTo(a.occurredAt));
    final latestParity = parities.isEmpty ? null : parities.first;
    final clearCount = advisories
        .where((event) => event.dispositionLabel == 'clear')
        .length;
    final suspiciousCount = advisories
        .where((event) => event.dispositionLabel == 'suspicious')
        .length;
    final unavailableCount = advisories
        .where((event) => event.dispositionLabel == 'unavailable')
        .length;
    final latestAdvisory = advisories.isEmpty ? null : advisories.first;
    final latestCycleSummary = latestCycle == null
        ? 'No listener alarm feed cycles have been recorded yet.'
        : 'Latest cycle • mapped ${latestCycle.mappedCount}/${latestCycle.acceptedCount} • '
              'missed ${latestCycle.unmappedCount + latestCycle.rejectedCount + latestCycle.failedCount} • '
              'clear ${latestCycle.clearCount} • suspicious ${latestCycle.suspiciousCount}';
    final latestAdvisorySummary = latestAdvisory == null
        ? 'No listener alarm advisories have been delivered yet.'
        : 'Latest advisory • ${latestAdvisory.siteId} • ${latestAdvisory.eventLabel} • '
              '${latestAdvisory.summary}';
    final latestParitySummary = latestParity == null
        ? 'No listener parity comparison has been recorded yet.'
        : '${latestParity.statusLabel.toUpperCase()} • matched ${latestParity.matchedCount}/${latestParity.legacyCount} • '
              'serial-only ${latestParity.unmatchedSerialCount} • legacy-only ${latestParity.unmatchedLegacyCount} • '
              'max skew ${latestParity.maxSkewSecondsObserved}s';
    final resolvedFocus = _resolvedListenerAlarmFocus(
      hasFeed: latestCycle != null,
      hasAdvisory: latestAdvisory != null,
      hasParity: latestParity != null,
    );
    final advisoryScope = latestAdvisory == null
        ? null
        : _resolveListenerAlarmScope(latestAdvisory);
    final openReports = advisoryScope == null
        ? _openReportsAction(clientId: '', siteId: '')
        : _openReportsAction(
            clientId: advisoryScope.clientId,
            siteId: advisoryScope.id,
          );
    final openGovernance = advisoryScope == null
        ? _openGovernanceAction(clientId: '', siteId: '')
        : _openGovernanceAction(
            clientId: advisoryScope.clientId,
            siteId: advisoryScope.id,
          );
    final selectedAccent = _listenerAlarmFocusAccent(resolvedFocus);
    final selectedHeadline = switch (resolvedFocus) {
      _ListenerAlarmSummaryFocus.feed =>
        latestCycle == null
            ? 'Feed intake is waiting for first alarm traffic'
            : '${latestCycle.sourceLabel} feed intake remains aligned',
      _ListenerAlarmSummaryFocus.advisory =>
        latestAdvisory == null
            ? 'Partner advisory scope is waiting for first delivery'
            : '${advisoryScope?.name ?? latestAdvisory.siteId} advisory remains hot',
      _ListenerAlarmSummaryFocus.parity =>
        latestParity == null
            ? 'Parity scope is waiting for first comparison cycle'
            : '${latestParity.sourceLabel} parity remains in view',
    };
    final selectedDetail = switch (resolvedFocus) {
      _ListenerAlarmSummaryFocus.feed =>
        latestCycle == null
            ? 'No feed cycle has landed yet, so the listener command board is standing by for first intake.'
            : latestCycleSummary,
      _ListenerAlarmSummaryFocus.advisory =>
        latestAdvisory == null
            ? 'No advisory has landed yet, so the partner alarm scope is standing by for the first delivered verdict.'
            : latestAdvisorySummary,
      _ListenerAlarmSummaryFocus.parity =>
        latestParity == null
            ? 'No parity comparison has landed yet, so cross-source listener verification is still standing by.'
            : latestParitySummary,
    };
    final selectedOccurredAt = switch (resolvedFocus) {
      _ListenerAlarmSummaryFocus.feed => _listenerAlarmOccurredAtLabel(
        latestCycle?.occurredAt,
      ),
      _ListenerAlarmSummaryFocus.advisory => _listenerAlarmOccurredAtLabel(
        latestAdvisory?.occurredAt,
      ),
      _ListenerAlarmSummaryFocus.parity => _listenerAlarmOccurredAtLabel(
        latestParity?.occurredAt,
      ),
    };
    final selectedScopeLabel = switch (resolvedFocus) {
      _ListenerAlarmSummaryFocus.feed =>
        latestCycle?.sourceLabel ?? 'Listener feed',
      _ListenerAlarmSummaryFocus.advisory =>
        advisoryScope?.name ?? latestAdvisory?.siteId ?? 'Partner advisory',
      _ListenerAlarmSummaryFocus.parity =>
        latestParity?.sourceLabel ?? 'Parity verification',
    };
    final selectedSupportLabel = switch (resolvedFocus) {
      _ListenerAlarmSummaryFocus.feed =>
        latestCycle == null
            ? 'Queued'
            : '${latestCycle.clearCount} clear • ${latestCycle.suspiciousCount} suspicious',
      _ListenerAlarmSummaryFocus.advisory =>
        latestAdvisory == null ? 'Queued' : latestAdvisory.dispositionLabel,
      _ListenerAlarmSummaryFocus.parity =>
        latestParity == null
            ? 'Queued'
            : latestParity.statusLabel.toUpperCase(),
    };
    final nextMoveLabel = switch (resolvedFocus) {
      _ListenerAlarmSummaryFocus.feed =>
        latestAdvisory != null ? 'Review advisory' : 'Copy snapshot',
      _ListenerAlarmSummaryFocus.advisory =>
        openGovernance != null
            ? 'Open governance'
            : openReports != null
            ? 'Open reports'
            : 'Copy snapshot',
      _ListenerAlarmSummaryFocus.parity =>
        openReports != null ? 'Open reports' : 'Copy snapshot',
    };

    void focusSummary(
      _ListenerAlarmSummaryFocus focus, {
      bool pinReceipt = false,
    }) {
      final nextFocus = switch (focus) {
        _ListenerAlarmSummaryFocus.feed when latestCycle == null =>
          resolvedFocus,
        _ListenerAlarmSummaryFocus.advisory when latestAdvisory == null =>
          resolvedFocus,
        _ListenerAlarmSummaryFocus.parity when latestParity == null =>
          resolvedFocus,
        _ => focus,
      };
      if (_activeListenerAlarmSummaryFocus != nextFocus) {
        setState(() {
          _activeListenerAlarmSummaryFocus = nextFocus;
        });
      }
      if (!pinReceipt) {
        return;
      }
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Focused listener ${_listenerAlarmFocusLabel(nextFocus)}.',
        sourceLabel: 'LISTENER ALARM',
        detail:
            '${_listenerAlarmFocusLabel(nextFocus)} now stays pinned in the alarm command deck while the surrounding system board remains available.',
        accent: _listenerAlarmFocusAccent(nextFocus),
      );
    }

    Future<void> copySelectedSnapshot() async {
      final payload = switch (resolvedFocus) {
        _ListenerAlarmSummaryFocus.feed => latestCycleSummary,
        _ListenerAlarmSummaryFocus.advisory => latestAdvisorySummary,
        _ListenerAlarmSummaryFocus.parity => latestParitySummary,
      };
      await Clipboard.setData(ClipboardData(text: payload));
      if (!mounted) {
        return;
      }
      _handleAdminFeedback(
        feedbackContext: context,
        message:
            'Listener ${_listenerAlarmFocusLabel(resolvedFocus)} copied for command review.',
        sourceLabel: 'LISTENER ALARM',
        detail:
            '$selectedScopeLabel at $selectedOccurredAt is ready to paste into escalation notes, partner handoff, or report review.',
        accent: selectedAccent,
      );
    }

    void openListenerReports() {
      final action = openReports;
      if (action == null) {
        copySelectedSnapshot();
        return;
      }
      action();
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Opened listener alarm reports for $selectedScopeLabel.',
        sourceLabel: 'REPORTS WORKSPACE',
        detail:
            '$selectedScopeLabel is now foregrounded in Reports Workspace from the listener alarm desk.',
        accent: const Color(0xFF67E8F9),
      );
    }

    void openListenerGovernance() {
      final action = openGovernance;
      if (action == null) {
        copySelectedSnapshot();
        return;
      }
      action();
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Opened listener governance for $selectedScopeLabel.',
        sourceLabel: 'GOVERNANCE DESK',
        detail:
            '$selectedScopeLabel is now foregrounded in Governance Desk from the listener alarm desk.',
        accent: const Color(0xFFFBBF24),
      );
    }

    return Container(
      key: _listenerAlarmSummaryCardKey,
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: _panelDecoration(),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _subTitle('Listener Alarm'),
          const SizedBox(height: 8),
          Text(
            'Parallel alarm intake health, verdict mix, and the latest partner advisory outcome.',
            style: GoogleFonts.inter(
              color: const Color(0xFF9AB1CF),
              fontSize: 12,
              fontWeight: FontWeight.w600,
            ),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _partnerScorecardChip(
                label: 'Cycles',
                value: '${cycles.length}',
                color: const Color(0xFF8FD1FF),
              ),
              _partnerScorecardChip(
                label: 'Advisories',
                value: '${advisories.length}',
                color: const Color(0xFF22D3EE),
              ),
              _partnerScorecardChip(
                label: 'Clear',
