  Widget _radioIntentPhraseCard() {
    return ListenableBuilder(
      listenable: _radioIntentPhrasesController,
      builder: (context, child) {
        final hasOverride = widget.initialRadioIntentPhrasesJson
            .trim()
            .isNotEmpty;
        final rawDraft = _radioIntentPhrasesController.text.trim();
        var bucketCount = 0;
        var phraseCount = 0;
        var leadBucket = 'defaults';
        var leadBucketPreview = 'Default runtime phrase coverage is active.';
        var draftValid = rawDraft.isEmpty;
        if (rawDraft.isNotEmpty) {
          try {
            final decoded = jsonDecode(rawDraft);
            if (decoded is! Map) {
              throw const FormatException(
                'Radio intent draft must be a JSON object.',
              );
            }
            bucketCount = decoded.length;
            if (decoded.isNotEmpty) {
              final firstEntry = decoded.entries.first;
              leadBucket = '${firstEntry.key}';
              final firstValues = firstEntry.value;
              if (firstValues is Iterable) {
                final previewValues = firstValues
                    .map((value) => '$value')
                    .where((value) => value.trim().isNotEmpty)
                    .toList(growable: false);
                leadBucketPreview = previewValues.isEmpty
                    ? '$leadBucket is present but currently empty.'
                    : '$leadBucket listens for ${previewValues.take(3).join(' • ')}'
                          '${previewValues.length > 3 ? ' • +${previewValues.length - 3} more' : ''}.';
              } else {
                leadBucketPreview =
                    '$leadBucket is present in the current runtime draft.';
              }
            }
            for (final value in decoded.values) {
              if (value is Iterable) {
                phraseCount += value.length;
              }
            }
          } catch (_) {
            draftValid = false;
            leadBucket = 'repair required';
            leadBucketPreview =
                'The current draft needs valid JSON before it can shape runtime phrase detection.';
          }
        }
        final validationTone = _radioIntentPhraseValidationError
            ? 'needs repair'
            : _radioIntentPhraseValidation == null
            ? (draftValid ? 'ready' : 'unchecked')
            : 'validated';
        final validationColor = _radioIntentPhraseValidationError
            ? const Color(0xFFF87171)
            : const Color(0xFF67E8F9);
        final nextMove = _radioIntentPhrasesSaving
            ? 'Saving runtime'
            : _radioIntentPhraseValidationError || !draftValid
            ? 'Fix JSON'
            : widget.onSaveRadioIntentPhrasesJson == null
            ? 'Stage draft'
            : 'Save runtime';
        return Container(
          width: double.infinity,
          padding: const EdgeInsets.all(12),
          decoration: _panelDecoration(),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              _subTitle('Radio Intent Dictionary'),
              const SizedBox(height: 8),
              Text(
                'Tune panic/duress/all-clear/status phrase detection at runtime.',
                style: GoogleFonts.inter(
                  color: _adminDialogBodyColor,
                  fontSize: 12,
                  fontWeight: FontWeight.w600,
                ),
              ),
              const SizedBox(height: 8),
              Container(
                key: const ValueKey('admin-radio-intent-command'),
                width: double.infinity,
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: _adminDialogAltColor,
                  borderRadius: BorderRadius.circular(10),
