  Widget _demoRouteCueCard() {
    return ListenableBuilder(
      listenable: _demoRouteCuesController,
      builder: (context, child) {
        final hasOverride = widget.initialDemoRouteCuesJson.trim().isNotEmpty;
        final rawDraft = _demoRouteCuesController.text.trim();
        var routeCount = 0;
        var leadRoute = 'defaults';
        var leadRoutePreview = 'Default autoplay route cues are active.';
        var draftValid = rawDraft.isEmpty;
        if (rawDraft.isNotEmpty) {
          try {
            final decoded = jsonDecode(rawDraft);
            if (decoded is! Map) {
              throw const FormatException(
                'Demo route cue draft must be a JSON object.',
              );
            }
            routeCount = decoded.length;
            if (decoded.isNotEmpty) {
              final firstEntry = decoded.entries.first;
              leadRoute = '${firstEntry.key}';
              final cue = '${firstEntry.value}'.trim();
              leadRoutePreview = cue.isEmpty
                  ? '$leadRoute is present but currently empty.'
                  : '$leadRoute narrates: $cue';
            }
          } catch (_) {
            draftValid = false;
            leadRoute = 'repair required';
            leadRoutePreview =
                'The current route cue draft needs valid JSON before it can drive autoplay narration.';
          }
        }
        final validationTone = _demoRouteCueValidationError
            ? 'needs repair'
            : _demoRouteCueValidation == null
            ? (draftValid ? 'ready' : 'unchecked')
            : 'validated';
        final validationColor = _demoRouteCueValidationError
            ? const Color(0xFFF87171)
            : const Color(0xFF8FD1FF);
        final nextMove = _demoRouteCuesSaving
            ? 'Saving runtime'
            : _demoRouteCueValidationError || !draftValid
            ? 'Fix JSON'
            : widget.onSaveDemoRouteCuesJson == null
            ? 'Stage draft'
            : 'Save runtime';
        return Container(
          width: double.infinity,
          padding: const EdgeInsets.all(12),
          decoration: _panelDecoration(),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              _subTitle('Demo Route Cues'),
              const SizedBox(height: 8),
              Text(
                'Customize autoplay presenter narration per route at runtime.',
                style: GoogleFonts.inter(
                  color: _adminDialogBodyColor,
                  fontSize: 12,
                  fontWeight: FontWeight.w600,
                ),
              ),
              const SizedBox(height: 8),
              Container(
                key: const ValueKey('admin-demo-route-command'),
                width: double.infinity,
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: _adminDialogAltColor,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: const Color(0x338FD1FF)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Row(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Expanded(
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(
                                'DEMO ROUTE COMMAND',
                                style: GoogleFonts.inter(
                                  color: const Color(0xFF8FD1FF),
                                  fontSize: 9.5,
                                  fontWeight: FontWeight.w800,
                                  letterSpacing: 0.8,
                                ),
                              ),
                              const SizedBox(height: 4),
                              Text(
                                draftValid
                                    ? 'Lead route: $leadRoute'
                                    : 'Draft requires repair',
                                style: GoogleFonts.inter(
                                  color: _adminDialogTitleColor,
                                  fontSize: 11.5,
                                  fontWeight: FontWeight.w800,
                                ),
                              ),
                              const SizedBox(height: 4),
                              Text(
                                leadRoutePreview,
                                style: GoogleFonts.inter(
                                  color: const Color(0xFFB5C7DD),
                                  fontSize: 10.5,
                                  fontWeight: FontWeight.w600,
                                  height: 1.35,
                                ),
                              ),
                            ],
                          ),
                        ),
                        const SizedBox(width: 12),
                        Container(
                          key: const ValueKey('admin-demo-route-next-move'),
                          padding: const EdgeInsets.symmetric(
                            horizontal: 10,
                            vertical: 8,
                          ),
                          decoration: BoxDecoration(
                            color: validationColor.withValues(alpha: 0.12),
                            borderRadius: BorderRadius.circular(9),
                            border: Border.all(
                              color: validationColor.withValues(alpha: 0.35),
                            ),
                          ),
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.end,
                            children: [
