  Widget _systemInfoCard() {
    final fleetPanelKey = GlobalKey();
    final suppressedPanelKey = GlobalKey();
    final suppressedEntries = _suppressedSceneReviewEntries();
    final opsPollEntries = _opsPollHealthEntries();
    final showSuppressedPrimary =
        _activeWatchActionDrilldown ==
            VideoFleetWatchActionDrilldown.filtered &&
        suppressedEntries.isNotEmpty;
    final showEscalatedPrimary =
        _activeWatchActionDrilldown == VideoFleetWatchActionDrilldown.escalated;
    void openWatchActionDrilldown(VideoFleetWatchActionDrilldown drilldown) {
      if (_activeWatchActionDrilldown == drilldown) {
        _setActiveWatchActionDrilldown(null);
        return;
      }
      _setActiveWatchActionDrilldown(drilldown);
      final targetContext =
          drilldown == VideoFleetWatchActionDrilldown.filtered &&
              suppressedEntries.isNotEmpty
          ? suppressedPanelKey.currentContext
          : fleetPanelKey.currentContext;
      if (targetContext == null) {
        return;
      }
      Scrollable.ensureVisible(
        targetContext,
        duration: const Duration(milliseconds: 220),
        curve: Curves.easeOutCubic,
      );
    }

    void openLatestWatchActionDetail(VideoFleetScopeHealthView scope) {
      if (_activeWatchActionDrilldown ==
              VideoFleetWatchActionDrilldown.filtered &&
          suppressedEntries.isNotEmpty) {
        final targetContext = suppressedPanelKey.currentContext;
        if (targetContext != null) {
          Scrollable.ensureVisible(
            targetContext,
            duration: const Duration(milliseconds: 220),
            curve: Curves.easeOutCubic,
          );
        }
        return;
      }
      final primaryOpenFleetScope = scope.hasIncidentContext
          ? (widget.onOpenFleetTacticalScope ?? widget.onOpenFleetDispatchScope)
          : null;
      if (primaryOpenFleetScope == null) {
        return;
      }
      primaryOpenFleetScope.call(
        scope.clientId,
        scope.siteId,
        scope.latestIncidentReference,
      );
    }

    void openFleetHealthCommand() {
      if (_activeWatchActionDrilldown != null) {
        _setActiveWatchActionDrilldown(null);
      }
      final targetContext = fleetPanelKey.currentContext;
      if (targetContext != null) {
        Scrollable.ensureVisible(
          targetContext,
          duration: const Duration(milliseconds: 220),
          curve: Curves.easeOutCubic,
          alignment: 0.12,
        );
      }
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Focused fleet health command.',
        sourceLabel: 'VIDEO OPS',
        detail:
            'Fleet health is now foregrounded from the ops poll command deck so video telemetry can pivot straight into the watch workspace.',
        accent: const Color(0xFF93C5FD),
      );
    }

    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: _panelDecoration(),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _subTitle('System Information'),
          if (showEscalatedPrimary && widget.fleetScopeHealth.isNotEmpty) ...[
            const SizedBox(height: 8),
            KeyedSubtree(
              key: fleetPanelKey,
              child: _fleetScopeHealthPanel(
                onOpenWatchActionDrilldown: openWatchActionDrilldown,
                onOpenLatestWatchActionDetail: openLatestWatchActionDetail,
              ),
            ),
          ],
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _sysInfoMini('Guard Roster', _guards.length.toString()),
              _sysInfoMini('Site Footprint', _sites.length.toString()),
              _sysInfoMini('Client Portfolio', _clients.length.toString()),
            ],
          ),
          const SizedBox(height: 12),
          _telegramBridgeStatusPanel(),
          const SizedBox(height: 12),
          _operatorRuntimePanel(),
          const SizedBox(height: 12),
          _partnerDispatchRuntimePanel(),
          const SizedBox(height: 12),
          _telegramAiAssistantPanel(),
          const SizedBox(height: 12),
          _clientCommsAuditPanel(),
          if (_hasVideoIntegrityCertificatePreview()) ...[
            const SizedBox(height: 12),
            _videoIntegrityCertificatePanel(),
          ],
          if (opsPollEntries.isNotEmpty) ...[
            const SizedBox(height: 12),
            _subTitle('Ops Integration Poll Health'),
            const SizedBox(height: 8),
            KeyedSubtree(
              key: _systemOpsPollCommandKey,
              child: _opsPollHealthCommandDeck(
                opsPollEntries,
                onOpenFleetHealth: widget.fleetScopeHealth.isEmpty
                    ? null
                    : openFleetHealthCommand,
              ),
            ),
            const SizedBox(height: 8),
            _opsPollHealthFocusBoard(
              opsPollEntries,
              onOpenFleetHealth: widget.fleetScopeHealth.isEmpty
                  ? null
                  : openFleetHealthCommand,
            ),
            const SizedBox(height: 8),
            ..._opsPollHealthRows(),
            if (widget.monitoringWatchAuditHistory.isNotEmpty) ...[
              const SizedBox(height: 8),
              _monitoringWatchAuditTrailPanel(),
            ],
          ],
          if (showSuppressedPrimary) ...[
            const SizedBox(height: 8),
            KeyedSubtree(
              key: suppressedPanelKey,
              child: _suppressedSceneReviewPanel(suppressedEntries),
            ),
          ],
          if (!showEscalatedPrimary && widget.fleetScopeHealth.isNotEmpty) ...[
            const SizedBox(height: 8),
            KeyedSubtree(
              key: fleetPanelKey,
              child: _fleetScopeHealthPanel(
                onOpenWatchActionDrilldown: openWatchActionDrilldown,
                onOpenLatestWatchActionDetail: openLatestWatchActionDetail,
              ),
            ),
          ],
          if (!showSuppressedPrimary && suppressedEntries.isNotEmpty) ...[
            const SizedBox(height: 8),
            KeyedSubtree(
              key: suppressedPanelKey,
              child: _suppressedSceneReviewPanel(suppressedEntries),
            ),
          ],
          if (_monitoringIdentityPolicyService.entries.isNotEmpty) ...[
            const SizedBox(height: 8),
            _identityPolicyPanel(),
          ],
          if (widget.supabaseReady || _telegramIdentityIntakes.isNotEmpty) ...[
            const SizedBox(height: 8),
            _telegramIdentityIntakePanel(),
          ],
          const SizedBox(height: 8),
          _opsQueueActionButtons(),
        ],
      ),
    );
  }

  Widget _opsPollHealthCommandDeck(
    List<_OpsPollHealthEntry> entries, {
    VoidCallback? onOpenFleetHealth,
  }) {
    final resolvedFocus = _resolvedOpsPollHealthFocus(entries);
    final focusEntries = entries
        .where((entry) => entry.focus == resolvedFocus)
        .toList(growable: false);
    final leadEntry = focusEntries.isEmpty ? entries.first : focusEntries.first;
    final accent = _opsPollHealthFocusAccent(resolvedFocus);
    final nextMoveLabel = _opsPollHealthNextMoveLabel(
      resolvedFocus,
      hasFleetHealth: onOpenFleetHealth != null,
    );
    final headline = switch (resolvedFocus) {
      _OpsPollHealthFocus.queue =>
        'Queue pressure stays pinned in Radio Runtime',
      _OpsPollHealthFocus.radio =>
        'Radio polling stays pinned in Radio Runtime',
      _OpsPollHealthFocus.video =>
        '${widget.videoOpsLabel} telemetry stays pinned in Ops Poll',
      _OpsPollHealthFocus.spool =>
        'Incident spool health stays pinned in Ops Poll',
      _OpsPollHealthFocus.wearable =>
        'Wearable telemetry stays pinned in Ops Poll',
      _OpsPollHealthFocus.listener =>
        'Listener alarm telemetry stays pinned in Ops Poll',
      _OpsPollHealthFocus.news => 'News telemetry stays pinned in Ops Poll',
      _OpsPollHealthFocus.watchAudit =>
        'Watch recovery telemetry stays pinned in Ops Poll',
    };

    return Container(
      key: const ValueKey('admin-ops-poll-command'),
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: _adminDialogAltColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: accent.withValues(alpha: 0.28)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'OPS POLL COMMAND',
                      style: GoogleFonts.inter(
                        color: accent,
                        fontSize: 9.5,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      headline,
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 11.5,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                    const SizedBox(height: 2),
                    Text(
                      leadEntry.value,
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 10.5,
                        fontWeight: FontWeight.w600,
                        height: 1.35,
                      ),
                    ),
                  ],
                ),
              ),
              const SizedBox(width: 12),
              Container(
                key: const ValueKey('admin-ops-poll-next-move'),
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 8,
                ),
                decoration: BoxDecoration(
                  color: accent.withValues(alpha: 0.12),
                  borderRadius: BorderRadius.circular(9),
                  border: Border.all(color: accent.withValues(alpha: 0.35)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.end,
                  children: [
                    Text(
                      'NEXT MOVE',
                      style: GoogleFonts.inter(
                        color: accent,
                        fontSize: 9,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      nextMoveLabel,
                      style: GoogleFonts.inter(
                        color: const Color(0xFFEAF4FF),
                        fontSize: 10.5,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Wrap(
            spacing: 6,
            runSpacing: 6,
            children: [
              _watchAuditChip(
                'Focus',
                _opsPollHealthFocusLabel(resolvedFocus).toUpperCase(),
                color: accent,
              ),
              _watchAuditChip(
                'Rows',
                '${focusEntries.length}',
                color: const Color(0xFFBFD7F2),
              ),
              _watchAuditChip(
                'Lead',
