  Widget _opsPollHealthFocusBoard(
    List<_OpsPollHealthEntry> entries, {
    VoidCallback? onOpenFleetHealth,
  }) {
    final resolvedFocus = _resolvedOpsPollHealthFocus(entries);
    final focusEntries = entries
        .where((entry) => entry.focus == resolvedFocus)
        .toList(growable: false);
    final leadEntry = focusEntries.isEmpty ? entries.first : focusEntries.first;
    final accent = _opsPollHealthFocusAccent(resolvedFocus);
    final uniqueFocuses = <_OpsPollHealthFocus>[];
    for (final entry in entries) {
      if (!uniqueFocuses.contains(entry.focus)) {
        uniqueFocuses.add(entry.focus);
      }
    }
    final boardTitle = switch (resolvedFocus) {
      _OpsPollHealthFocus.queue => 'RADIO QUEUE SCOPE',
      _OpsPollHealthFocus.radio => 'RADIO SCOPE',
      _OpsPollHealthFocus.video =>
        '${widget.videoOpsLabel.toUpperCase()} SCOPE',
      _OpsPollHealthFocus.spool => 'INCIDENT SPOOL SCOPE',
      _OpsPollHealthFocus.wearable => 'WEARABLE SCOPE',
      _OpsPollHealthFocus.listener => 'LISTENER SCOPE',
      _OpsPollHealthFocus.news => 'NEWS SCOPE',
      _OpsPollHealthFocus.watchAudit => 'WATCH RECOVERY SCOPE',
    };
    final boardSummary = switch (resolvedFocus) {
      _OpsPollHealthFocus.queue =>
        'Queue pressure, failure memory, and retry posture stay pinned together so radio recovery feels immediate instead of buried in telemetry.',
      _OpsPollHealthFocus.radio =>
        'Polling health, ACK mix, and the latest radio state stay surfaced together so the operator can steer radio recovery without scanning the full stack.',
      _OpsPollHealthFocus.video =>
        '${widget.videoOpsLabel} capability, evidence, and camera health stay surfaced together so video watch pressure reads like one command surface.',
      _OpsPollHealthFocus.spool =>
        'Incident buffering and replay pressure stay visible together so queue recovery does not fragment across the system tab.',
      _OpsPollHealthFocus.wearable =>
        'Wearable ingest health stays surfaced as one scope so recovery remains simple when telemetry thins out.',
      _OpsPollHealthFocus.listener =>
        'Listener feed, advisory, and parity posture stay surfaced together so upstream ingest drift feels like one operating problem instead of three.',
      _OpsPollHealthFocus.news =>
        'News ingest stays surfaced as one scope so outer-world drift does not disappear behind quieter system telemetry.',
      _OpsPollHealthFocus.watchAudit =>
        'Watch recovery stays pinned as one scope so the latest resync story is always reachable from the system shell.',
    };
    final recommendedLabel = _opsPollHealthNextMoveLabel(
      resolvedFocus,
      hasFleetHealth: onOpenFleetHealth != null,
    );

    return Container(
      key: const ValueKey('admin-ops-poll-focus-board'),
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: accent.withValues(alpha: 0.28)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'OPS POLL FOCUS BOARD',
                      style: GoogleFonts.inter(
                        color: accent,
                        fontSize: 9.5,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      boardTitle,
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 12,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.2,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      boardSummary,
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 10.5,
                        fontWeight: FontWeight.w600,
                        height: 1.35,
                      ),
                    ),
                  ],
                ),
              ),
              const SizedBox(width: 12),
              Container(
                key: const ValueKey('admin-ops-poll-focus-recommendation'),
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 8,
                ),
                decoration: BoxDecoration(
                  color: accent.withValues(alpha: 0.12),
                  borderRadius: BorderRadius.circular(9),
                  border: Border.all(color: accent.withValues(alpha: 0.35)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.end,
                  children: [
                    Text(
                      'RECOMMENDED',
                      style: GoogleFonts.inter(
                        color: accent,
                        fontSize: 9,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      recommendedLabel,
                      style: GoogleFonts.inter(
                        color: const Color(0xFFEAF4FF),
                        fontSize: 10.5,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: uniqueFocuses
                .map(
                  (focus) => _opsPollFocusPivotButton(
                    key: ValueKey('admin-ops-poll-focus-pivot-${focus.name}'),
                    label: _opsPollHealthFocusLabel(focus).toUpperCase(),
                    color: _opsPollHealthFocusAccent(focus),
                    selected: focus == resolvedFocus,
                    onTap: () {
                      if (_activeOpsPollHealthFocus != focus) {
                        setState(() {
                          _activeOpsPollHealthFocus = focus;
                        });
                      }
                      final focusLead = entries.firstWhere(
                        (entry) => entry.focus == focus,
                        orElse: () => leadEntry,
                      );
                      _handleAdminFeedback(
                        feedbackContext: context,
                        message: 'Focused ${_opsPollHealthFocusLabel(focus)}.',
                        sourceLabel: 'OPS POLL',
                        detail:
                            '${focusLead.label} is now pinned into the ops poll focus board so the system board can stay simple while the deeper telemetry remains visible underneath.',
                        accent: _opsPollHealthFocusAccent(focus),
                      );
                    },
                  ),
                )
                .toList(growable: false),
          ),
          const SizedBox(height: 10),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _watchAuditChip('Lead signal', leadEntry.label, color: accent),
              _watchAuditChip(
                'Pinned rows',
                '${focusEntries.length}',
                color: const Color(0xFFBFD7F2),
              ),
              _watchAuditChip(
                'Next move',
                recommendedLabel,
                color: const Color(0xFF67E8F9),
              ),
            ],
          ),
          const SizedBox(height: 10),
          ...focusEntries
              .take(4)
              .map(
                (entry) => Container(
                  key: ValueKey('admin-ops-poll-focus-entry-${entry.id}'),
                  width: double.infinity,
                  margin: const EdgeInsets.only(bottom: 8),
                  padding: const EdgeInsets.all(10),
                  decoration: BoxDecoration(
                    color: entry.accent.withValues(alpha: 0.08),
                    borderRadius: BorderRadius.circular(9),
                    border: Border.all(
                      color: entry.accent.withValues(alpha: 0.28),
                    ),
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        entry.label.toUpperCase(),
                        style: GoogleFonts.inter(
                          color: entry.accent,
                          fontSize: 9.5,
                          fontWeight: FontWeight.w800,
                          letterSpacing: 0.8,
                        ),
                      ),
                      const SizedBox(height: 4),
                      Text(
                        entry.value,
                        style: GoogleFonts.robotoMono(
                          color: const Color(0xFFEAF4FF),
                          fontSize: 10.5,
                          fontWeight: FontWeight.w600,
                          height: 1.35,
                        ),
                      ),
                    ],
                  ),
                ),
              ),
          if (focusEntries.length > 4)
            Text(
              '${focusEntries.length - 4} more ${_opsPollHealthFocusLabel(resolvedFocus)} signals remain visible in the telemetry stack below.',
              style: GoogleFonts.inter(
                color: const Color(0xFF718198),
                fontSize: 10,
                fontWeight: FontWeight.w600,
              ),
            ),
        ],
      ),
    );
  }

  bool _hasVideoIntegrityCertificatePreview() {
    return (widget.videoIntegrityCertificateStatus ?? '').trim().isNotEmpty ||
        (widget.videoIntegrityCertificateSummary ?? '').trim().isNotEmpty ||
        (widget.videoIntegrityCertificateJsonPreview ?? '').trim().isNotEmpty ||
        (widget.videoIntegrityCertificateMarkdownPreview ?? '')
