  ({String label, Color accent, Color fill, Color border})
  _telegramWiringStatusTone(String state) {
    return switch (state) {
      'ready' => (
        label: 'READY',
        accent: const Color(0xFF0F9F6E),
        fill: const Color(0xFFEAFBF3),
        border: const Color(0xFFB8E9CF),
      ),
      'review' => (
        label: 'REVIEW',
        accent: const Color(0xFFB45309),
        fill: const Color(0xFFFFF6E8),
        border: const Color(0xFFF4D8A7),
      ),
      'optional' => (
        label: 'OPTIONAL',
        accent: const Color(0xFF64748B),
        fill: const Color(0xFF1A1A2E),
        border: const Color(0x269D4BFF),
      ),
      'missing' => (
        label: 'MISSING',
        accent: const Color(0xFFB91C1C),
        fill: const Color(0xFFFFF1F2),
        border: const Color(0xFFF6C3C8),
      ),
      _ => (
        label: 'REVIEW',
        accent: const Color(0xFF3C79BB),
        fill: const Color(0xFFEAF4FF),
        border: const Color(0xFFC6DAF1),
      ),
    };
  }

  String _telegramWiringScopeLabel(String clientId, String siteId) {
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    if (normalizedClientId.isEmpty && normalizedSiteId.isEmpty) {
      return 'Scope not bound yet';
    }
    if (normalizedClientId.isEmpty) {
      return normalizedSiteId;
    }
    if (normalizedSiteId.isEmpty) {
      return normalizedClientId;
    }
    return '$normalizedClientId / $normalizedSiteId';
  }

  String _telegramWiringThreadLabel(int? threadId) {
    if (threadId == null) {
      return 'No topic thread';
    }
    return 'Thread $threadId';
  }

  String _telegramWiringEnvSnippet(TelegramWiringChecklistView checklist) {
    final lines = <String>[
      'ONYX_TELEGRAM_ADMIN_CHAT_ID=${checklist.adminChatId.trim().isEmpty ? '<missing>' : checklist.adminChatId.trim()}',
      if (checklist.adminThreadId != null)
        'ONYX_TELEGRAM_ADMIN_THREAD_ID=${checklist.adminThreadId}',
      'ONYX_TELEGRAM_CHAT_ID=${checklist.clientChatId.trim().isEmpty ? '<missing>' : checklist.clientChatId.trim()}',
      if (checklist.clientThreadId != null)
        'ONYX_TELEGRAM_MESSAGE_THREAD_ID=${checklist.clientThreadId}',
      if (checklist.partnerChatId.trim().isNotEmpty)
        'ONYX_TELEGRAM_PARTNER_CHAT_ID=${checklist.partnerChatId.trim()}',
      if (checklist.partnerThreadId != null)
        'ONYX_TELEGRAM_PARTNER_THREAD_ID=${checklist.partnerThreadId}',
      if (checklist.partnerClientId.trim().isNotEmpty)
        'ONYX_TELEGRAM_PARTNER_CLIENT_ID=${checklist.partnerClientId.trim()}',
      if (checklist.partnerSiteId.trim().isNotEmpty)
        'ONYX_TELEGRAM_PARTNER_SITE_ID=${checklist.partnerSiteId.trim()}',
    ];
    return lines.join('\n');
  }

  String _telegramWiringSnippetCaption(TelegramWiringChecklistView checklist) {
    if (checklist.adminChatInheritedFromClient) {
      return 'Effective runtime values below include legacy fallback behavior. ONYX Admin is currently inheriting the client chat.';
    }
    return 'Effective runtime values below reflect the live app state, including legacy bridge wiring and active overrides.';
  }

  Future<void> _copyTelegramChecklistCommand(String command) async {
    await Clipboard.setData(ClipboardData(text: command));
    if (!mounted) {
      return;
    }
    _snack('Telegram command copied.');
  }

