  String _telegramRecentPromptAgeLabel(DateTime handledAtUtc) {
    final age = DateTime.now().difference(handledAtUtc.toLocal());
    if (age.inMinutes < 1) {
      return 'just now';
    }
    if (age.inMinutes < 60) {
      return '${age.inMinutes}m ago';
    }
    if (age.inHours < 24) {
      return '${age.inHours}h ago';
    }
    return '${age.inDays}d ago';
  }

  String _telegramRecentPromptClockLabel(DateTime handledAtUtc) {
    final local = handledAtUtc.toLocal();
    final hh = local.hour.toString().padLeft(2, '0');
    final mm = local.minute.toString().padLeft(2, '0');
    return '$hh:$mm';
  }

  ({Color fill, Color border, Color text}) _telegramRecentPromptOutcomeTone(
    String outcomeLabel,
  ) {
    switch (outcomeLabel.trim().toLowerCase()) {
      case 'quick action':
        return (
          fill: const Color(0xFFE8F7F1),
          border: const Color(0xFFB7E4CF),
          text: const Color(0xFF0F6A52),
        );
      case 'onboarding intake':
        return (
          fill: const Color(0xFFFFF4E5),
          border: const Color(0xFFFACD8A),
          text: const Color(0xFF9A5B00),
        );
      case 'assistant reply':
        return (
          fill: const Color(0xFFF1ECFF),
          border: const Color(0xFFD7C9FF),
          text: const Color(0xFF6A4BC4),
        );
      case 'denied':
        return (
          fill: const Color(0xFFFFEFEF),
          border: const Color(0xFFF6C7C7),
          text: const Color(0xFFB42318),
        );
      case 'send failed':
        return (
          fill: const Color(0xFFFFF7ED),
          border: const Color(0xFFFBD38D),
          text: const Color(0xFFB45309),
        );
      case 'answered':
      default:
        return (
          fill: const Color(0xFFF0F7FF),
          border: const Color(0xFFC7DCF7),
          text: const Color(0xFF245D9B),
        );
    }
  }

  Widget _telegramRecentPromptPanel() {
    final rows = widget.telegramWiringChecklist.recentHandledPrompts;
    final groupedRows = <String, List<TelegramRecentPromptView>>{};
    for (final entry in rows) {
      groupedRows
          .putIfAbsent(entry.roomLabel, () => <TelegramRecentPromptView>[])
          .add(entry);
    }
    for (final group in groupedRows.values) {
      group.sort((a, b) => b.handledAtUtc.compareTo(a.handledAtUtc));
    }
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(12),
