  String _telegramAiLastHandledLabel() {
    final at = widget.telegramAiLastHandledAtUtc?.toLocal();
    if (at == null) {
      return 'AI handoff is standing by for the next message.';
    }
    final hh = at.hour.toString().padLeft(2, '0');
    final mm = at.minute.toString().padLeft(2, '0');
    final summary = (widget.telegramAiLastHandledSummary ?? '').trim();
    if (summary.isEmpty) {
      return 'Last handled at $hh:$mm';
    }
    return 'Last: $summary • $hh:$mm';
  }

  String _humanizeOpsScopeLabel(String raw, {required String fallback}) {
    final cleaned = raw
        .trim()
        .replaceFirst(RegExp(r'^(CLIENT|SITE|REGION)-'), '')
        .replaceAll(RegExp(r'[_\-]+'), ' ')
        .replaceAll(RegExp(r'[^A-Za-z0-9 ]+'), ' ')
        .replaceAll(RegExp(r'\s+'), ' ')
        .trim();
    if (cleaned.isEmpty) {
      return fallback;
    }
    final stopWords = <String>{'and', 'of', 'the'};
    return cleaned
        .split(' ')
        .where((token) => token.trim().isNotEmpty)
        .toList(growable: false)
        .asMap()
        .entries
        .map((entry) {
          final lower = entry.value.toLowerCase();
          if (entry.key > 0 && stopWords.contains(lower)) {
            return lower;
          }
          return '${lower[0].toUpperCase()}${lower.substring(1)}';
        })
        .join(' ');
  }

  bool _adminContainsAny(String text, List<String> needles) {
    for (final needle in needles) {
      if (text.contains(needle)) {
        return true;
      }
    }
    return false;
  }

  bool _isResidentialTelegramAiScope({
    required String clientId,
    required String siteId,
  }) {
    final combined = '$clientId\n$siteId'.toLowerCase();
    return _adminContainsAny(combined, const [
      'vallee',
      'residence',
      'residential',
      'estate',
      'home',
      'house',
      'villa',
    ]);
  }

  List<String> _suggestedTelegramAiLearnedStyleTags({
    required String clientId,
    required String siteId,
    required String currentTag,
    required String learnedText,
  }) {
    final baseTags =
        _isResidentialTelegramAiScope(clientId: clientId, siteId: siteId)
        ? const <String>[
            'Warm reassurance',
            'Camera validation',
            'ETA crisp',
            'Operations formal',
          ]
        : const <String>[
            'Operations formal',
            'ETA crisp',
            'Camera validation',
            'Warm reassurance',
          ];
    final signals =
        '${currentTag.trim().toLowerCase()}\n${learnedText.trim().toLowerCase()}';
    String? preferredTag;
    if (_adminContainsAny(signals, const [
      'reassurance',
      'comfort',
      'you are not alone',
      'treating this as live',
      'stay close',
      'protective',
    ])) {
      preferredTag = 'Warm reassurance';
    } else if (_adminContainsAny(signals, const [
      'camera',
      'daylight',
      'visual',
      'camera check',
      'validation',
    ])) {
      preferredTag = 'Camera validation';
    } else if (_adminContainsAny(signals, const [
      'eta',
      'arrival',
      'how long',
      'confirmed arrival',
    ])) {
      preferredTag = 'ETA crisp';
    } else if (_adminContainsAny(signals, const [
      'actively checking',
      'operations',
      'formal',
      'monitoring',
      'close review',
      'taking this seriously',
    ])) {
      preferredTag = 'Operations formal';
    }
    if (preferredTag == null) {
      return baseTags;
    }
    return <String>[
      preferredTag,
      ...baseTags.where((tag) => tag != preferredTag),
    ];
  }

  String _telegramAiAudienceLabel(TelegramAiPendingDraftView draft) {
    switch (draft.audience.trim().toLowerCase()) {
      case 'admin':
        return 'Admin Desk';
      case 'client':
      default:
        return 'Client Comms';
    }
  }

  Color _telegramAiAudienceAccent(TelegramAiPendingDraftView draft) {
    switch (draft.audience.trim().toLowerCase()) {
      case 'admin':
        return const Color(0xFFF59E0B);
      case 'client':
      default:
        return const Color(0xFF22D3EE);
    }
  }

  VoidCallback? _openClientLaneAction({
    required String clientId,
    required String siteId,
  }) {
    final scopedCallback = widget.onOpenClientViewForScope;
    if (scopedCallback != null) {
      return () => scopedCallback(clientId, siteId);
