  String _telegramAiProviderLabel(String raw) {
    final normalized = raw.trim();
    if (normalized.isEmpty) {
      return 'Fallback responder';
    }
    if (normalized.startsWith('openai:')) {
      final model = normalized.substring('openai:'.length).trim();
      return model.isEmpty ? 'OpenAI' : 'OpenAI • $model';
    }
    if (normalized == 'fallback') {
      return 'Fallback responder';
    }
    return normalized.replaceAll(':', ' • ');
  }

  String _telegramAiAgeLabel(DateTime createdAtUtc) {
    final now = DateTime.now();
    final local = createdAtUtc.toLocal();
    final age = now.difference(local);
    final hh = local.hour.toString().padLeft(2, '0');
    final mm = local.minute.toString().padLeft(2, '0');
    if (age.inMinutes < 1) {
      return 'just now • $hh:$mm';
    }
    if (age.inMinutes < 60) {
      return '${age.inMinutes}m ago • $hh:$mm';
    }
    if (age.inHours < 24) {
      return '${age.inHours}h ago • $hh:$mm';
    }
    return '${age.inDays}d ago • $hh:$mm';
  }

  String _telegramAiLearnedStyleMetaLabel({
    required int approvalCount,
    DateTime? lastApprovedAtUtc,
    DateTime? lastUsedAtUtc,
  }) {
    if (approvalCount <= 0 &&
        lastApprovedAtUtc == null &&
        lastUsedAtUtc == null) {
      return '';
    }
    final parts = <String>[
      approvalCount <= 1 ? 'Approved 1x' : 'Approved ${approvalCount}x',
    ];
    if (lastUsedAtUtc != null) {
      parts.add('Last used ${_telegramAiAgeLabel(lastUsedAtUtc)}');
    } else if (lastApprovedAtUtc != null) {
      parts.add('Last approved ${_telegramAiAgeLabel(lastApprovedAtUtc)}');
    }
    return parts.join(' • ');
  }

