  Future<void> _editTelegramAiDraft(TelegramAiPendingDraftView draft) async {
    if (widget.onUpdateTelegramAiDraftText == null ||
        _telegramAiDraftEditBusyIds.contains(draft.updateId)) {
      return;
    }
    final controller = TextEditingController(text: draft.draftText);
    late final String? nextText;
    try {
      nextText = await showDialog<String>(
        context: context,
        builder: (context) {
          return _adminDialogShell(
            width: 520,
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  'Refine ONYX Draft',
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 17,
                    fontWeight: FontWeight.w800,
                  ),
                ),
                const SizedBox(height: 12),
                TextField(
                  controller: controller,
                  minLines: 5,
                  maxLines: 9,
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 12.5,
                    fontWeight: FontWeight.w600,
                  ),
                  decoration: _adminDialogInputDecoration('Draft Text')
                      .copyWith(
                        hintText: 'Shape the final client-facing wording here.',
                        hintStyle: GoogleFonts.inter(
                          color: _adminDialogMutedColor,
                          fontSize: 12,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                ),
                const SizedBox(height: 16),
                Row(
                  mainAxisAlignment: MainAxisAlignment.end,
                  children: [
                    TextButton(
                      onPressed: () => Navigator.of(context).pop(),
                      style: TextButton.styleFrom(
                        foregroundColor: _adminDialogMutedColor,
                      ),
                      child: Text(
                        'Cancel',
                        style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                      ),
                    ),
                    const SizedBox(width: 8),
                    FilledButton(
                      onPressed: () =>
                          Navigator.of(context).pop(controller.text.trim()),
                      style: FilledButton.styleFrom(
                        backgroundColor: const Color(0xFF2E7D5B),
                        foregroundColor: const Color(0xFFEAF4FF),
                      ),
                      child: Text(
                        'Save Draft',
                        style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          );
        },
      );
    } finally {
      _disposeTextControllersAfterDialogFrame([controller]);
    }
    final normalizedText = (nextText ?? '').trim();
    if (!mounted ||
        normalizedText.isEmpty ||
        normalizedText == draft.draftText.trim()) {
      return;
    }
    setState(() {
      _telegramAiDraftEditBusyIds = {
        ..._telegramAiDraftEditBusyIds,
        draft.updateId,
      };
    });
    try {
      await widget.onUpdateTelegramAiDraftText!.call(
        draft.updateId,
        normalizedText,
      );
      _snack('Draft wording updated for approval.');
    } catch (_) {
      _snack('Failed to update AI draft ${draft.updateId}.');
    } finally {
      if (mounted) {
        setState(() {
          _telegramAiDraftEditBusyIds = _telegramAiDraftEditBusyIds
              .where((entry) => entry != draft.updateId)
              .toSet();
        });
      }
    }
  }

