  Widget _operatorRuntimePanel() {
    return ListenableBuilder(
      listenable: _operatorIdController,
      builder: (context, child) {
        final canSave = widget.onSetOperatorId != null;
        final draftOperatorId = _operatorIdController.text.trim();
        final hasRuntimeDraft =
            draftOperatorId.isNotEmpty && draftOperatorId != widget.operatorId;
        final operatorNextMove = _operatorIdSaving
            ? 'Saving runtime'
            : hasRuntimeDraft
            ? 'Apply runtime'
            : 'Revert default';
        return Container(
          width: double.infinity,
          padding: const EdgeInsets.all(10),
          decoration: BoxDecoration(
            color: const Color(0xFF13131E),
            borderRadius: BorderRadius.circular(9),
            border: Border.all(color: _adminDialogBorderColor),
