              ),
              const SizedBox(height: 8),
              Text(
                'Affects new execution and review events. Leave blank to revert to the default runtime operator.',
                style: GoogleFonts.inter(
                  color: _adminDialogBodyColor,
                  fontSize: 11,
                  fontWeight: FontWeight.w600,
