  Widget _partnerDispatchRuntimePanel() {
    return ListenableBuilder(
      listenable: _partnerRuntimeDraftListenable,
      builder: (context, child) {
        final clientScope = (_partnerRuntimeClientId ?? '').trim();
        final siteScope = (_partnerRuntimeSiteId ?? '').trim();
        final sitesForClient = _partnerRuntimeSitesForClient(clientScope);
        final canMutate = widget.onBindPartnerTelegramEndpoint != null;
        final canCheck = widget.onCheckPartnerTelegramEndpoint != null;
        final canUnlink = widget.onUnlinkPartnerTelegramEndpoint != null;
        final endpointLabel = _partnerEndpointLabelController.text.trim();
        final chatId = _partnerChatIdController.text.trim();
        final threadId = _partnerThreadIdController.text.trim();
        String clientScopeLabel = clientScope.isEmpty
            ? 'No client selected'
            : clientScope;
        for (final client in _clients) {
          if (client.id == clientScope) {
            clientScopeLabel = client.name;
            break;
          }
        }
        String siteScopeLabel = siteScope.isEmpty
            ? 'No site selected'
            : siteScope;
        for (final site in _sites) {
          if (site.id == siteScope) {
            siteScopeLabel = site.name;
            break;
          }
        }
        final statusPreview = ((_partnerRuntimeStatus ?? '').trim())
            .split('\n')
            .first
            .trim();
        final hasRuntimeScope = clientScope.isNotEmpty && siteScope.isNotEmpty;
        final runtimeNextMove = _partnerRuntimeBusy
            ? 'Working runtime'
            : !hasRuntimeScope
            ? 'Choose scope'
            : chatId.isEmpty
            ? 'Fill Telegram bridge'
            : statusPreview.isEmpty
            ? 'Bind runtime'
            : 'Verify runtime';

        return Container(
          width: double.infinity,
          padding: const EdgeInsets.all(10),
          decoration: BoxDecoration(
            color: const Color(0xFF13131E),
            borderRadius: BorderRadius.circular(9),
            border: Border.all(color: _adminDialogBorderColor),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  const Icon(
                    Icons.local_shipping_rounded,
                    size: 16,
                    color: Color(0xFFF59E0B),
                  ),
                  const SizedBox(width: 6),
                  Text(
                    'Partner Dispatch Runtime',
                    style: GoogleFonts.inter(
