  Widget _opsQueueActionButtons() {
    final hasPending = widget.radioQueueHasPending;
    final availablePolls = <String>[
      if (widget.onRunOpsIntegrationPoll != null) 'Ops',
      if (widget.onRunRadioPoll != null) 'Radio',
      if (widget.onRunCctvPoll != null) widget.videoOpsLabel,
      if (widget.onRunWearablePoll != null) 'Wearable',
      if (widget.onRunNewsPoll != null) 'News',
    ];
    final recoveryCount = <bool>[
      hasPending && widget.onRetryRadioQueue != null,
      hasPending && widget.onClearRadioQueue != null,
      widget.onClearRadioQueueFailureSnapshot != null,
    ].where((enabled) => enabled).length;
    final recommendedMove = hasPending
        ? 'Retry radio queue'
        : 'Run ops poll now';

    return Container(
      key: const ValueKey('admin-ops-recovery-deck'),
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: _adminDialogBorderColor),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'MANUAL RECOVERY DECK',
                      style: GoogleFonts.inter(
                        color: const Color(0xFF7DD3FC),
                        fontSize: 9.5,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      'Last-line controls stay simple here while the deeper poll scopes above keep the raw telemetry story intact.',
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 10.5,
                        fontWeight: FontWeight.w600,
                        height: 1.35,
                      ),
                    ),
                  ],
                ),
              ),
              const SizedBox(width: 12),
              Container(
                key: const ValueKey('admin-ops-recovery-next-move'),
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 8,
                ),
                decoration: BoxDecoration(
                  color: const Color(0x147DD3FC),
                  borderRadius: BorderRadius.circular(9),
                  border: Border.all(color: const Color(0x337DD3FC)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.end,
                  children: [
                    Text(
                      'NEXT MOVE',
                      style: GoogleFonts.inter(
                        color: const Color(0xFF7DD3FC),
                        fontSize: 9,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      recommendedMove,
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 10.5,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _watchAuditChip(
                'Poll sweep',
                availablePolls.isEmpty ? 'offline' : availablePolls.join(' • '),
                color: const Color(0xFF7DD3FC),
              ),
              _watchAuditChip(
                'Queue pressure',
                hasPending ? 'pending' : 'clear',
                color: hasPending
                    ? const Color(0xFF67E8F9)
                    : const Color(0xFF86EFAC),
              ),
              _watchAuditChip(
                'Recovery actions',
                '$recoveryCount live',
                color: const Color(0xFFF59E0B),
              ),
            ],
          ),
          const SizedBox(height: 12),
          Text(
            'POLL SWEEP',
            style: GoogleFonts.inter(
              color: const Color(0xFF7DD3FC),
              fontSize: 9.5,
              fontWeight: FontWeight.w800,
              letterSpacing: 0.8,
            ),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-run-ops'),
                label: 'Run Ops Poll Now',
                color: const Color(0xFF7DD3FC),
                onTap: widget.onRunOpsIntegrationPoll == null
                    ? null
                    : () {
                        _runOpsIntegrationPollFromCommand();
                      },
              ),
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-run-radio'),
                label: 'Poll Radio',
                color: const Color(0xFF67E8F9),
                onTap: widget.onRunRadioPoll == null
                    ? null
                    : () {
                        _runRadioPollFromCommand();
                      },
              ),
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-run-video'),
                label: 'Poll ${widget.videoOpsLabel}',
                color: const Color(0xFF93C5FD),
                onTap: widget.onRunCctvPoll == null
                    ? null
                    : () {
                        _runVideoPollFromCommand();
                      },
              ),
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-run-wearable'),
                label: 'Poll Wearable',
                color: const Color(0xFF34D399),
                onTap: widget.onRunWearablePoll == null
