            ],
          ),
          const SizedBox(height: 12),
          Text(
            'QUEUE OVERRIDE',
            style: GoogleFonts.inter(
              color: const Color(0xFF67E8F9),
              fontSize: 9.5,
              fontWeight: FontWeight.w800,
              letterSpacing: 0.8,
            ),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-retry-queue'),
                label: 'Retry Radio Queue',
                color: const Color(0xFF67E8F9),
                onTap: !(hasPending && widget.onRetryRadioQueue != null)
                    ? null
                    : () {
                        _retryRadioQueueFromCommand();
                      },
              ),
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-clear-queue'),
                label: 'Clear Radio Queue',
                color: const Color(0xFFF87171),
                onTap: !(hasPending && widget.onClearRadioQueue != null)
                    ? null
                    : () {
                        _clearRadioQueueFromCommand();
                      },
              ),
              _opsPollActionButton(
                key: const ValueKey('admin-ops-recovery-clear-failure'),
                label: 'Clear Last Failure',
                color: const Color(0xFFF59E0B),
                onTap: widget.onClearRadioQueueFailureSnapshot == null
                    ? null
                    : () {
                        _clearRadioFailureSnapshotFromCommand();
                      },
              ),
            ],
          ),
        ],
      ),
    );
  }

  Future<bool> _confirmClearRadioQueue() async {
    if (!widget.radioQueueHasPending || widget.onClearRadioQueue == null) {
      return false;
    }
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (dialogContext) {
        return AlertDialog(
          backgroundColor: _adminDialogSurfaceColor,
          shape: _adminDialogShape(),
          title: Text(
            'Clear Radio Queue?',
            style: GoogleFonts.inter(
              color: _adminDialogTitleColor,
              fontSize: 16,
              fontWeight: FontWeight.w700,
            ),
          ),
          content: Text(
            'This removes all pending automated radio responses from the queue.',
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 12,
              fontWeight: FontWeight.w600,
            ),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(dialogContext).pop(false),
              child: Text(
                'Cancel',
                style: GoogleFonts.inter(
                  color: _adminDialogMutedColor,
                  fontWeight: FontWeight.w700,
                ),
              ),
            ),
            FilledButton(
              onPressed: () => Navigator.of(dialogContext).pop(true),
              style: FilledButton.styleFrom(
                backgroundColor: const Color(0xFFB91C1C),
                foregroundColor: const Color(0xFFFFFFFF),
              ),
              child: Text(
                'Confirm Clear',
                style: GoogleFonts.inter(fontWeight: FontWeight.w700),
              ),
            ),
          ],
        );
      },
    );
    if (confirmed == true) {
      await widget.onClearRadioQueue!.call();
      return true;
    }
    return false;
  }

  Future<bool> _confirmClearRadioFailureSnapshot() async {
    if (widget.onClearRadioQueueFailureSnapshot == null) {
      return false;
    }
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (dialogContext) {
        return AlertDialog(
          backgroundColor: _adminDialogSurfaceColor,
          shape: _adminDialogShape(),
          title: Text(
            'Clear Last Failure Snapshot?',
            style: GoogleFonts.inter(
              color: _adminDialogTitleColor,
              fontSize: 16,
              fontWeight: FontWeight.w700,
            ),
          ),
          content: Text(
            'This clears the persisted last radio failure snapshot from system diagnostics.',
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 12,
              fontWeight: FontWeight.w600,
            ),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(dialogContext).pop(false),
              child: Text(
                'Cancel',
                style: GoogleFonts.inter(
                  color: _adminDialogMutedColor,
                  fontWeight: FontWeight.w700,
                ),
              ),
            ),
            FilledButton(
              onPressed: () => Navigator.of(dialogContext).pop(true),
              style: FilledButton.styleFrom(
                backgroundColor: const Color(0xFFB45309),
                foregroundColor: const Color(0xFFFFFFFF),
              ),
              child: Text(
                'Confirm Clear',
                style: GoogleFonts.inter(fontWeight: FontWeight.w700),
              ),
            ),
          ],
        );
      },
    );
    if (confirmed == true) {
      await widget.onClearRadioQueueFailureSnapshot!.call();
      return true;
    }
    return false;
  }

