  List<Widget> _opsPollHealthRows() {
    final rows = _opsPollHealthEntries();
    final resolvedFocus = _resolvedOpsPollHealthFocus(rows);
    return rows
        .map((row) {
          final isWatchAuditRow =
              row.id == 'watch-audit' &&
              widget.monitoringWatchAuditHistory.isNotEmpty;
          final isListenerAlarmRow =
              row.id == 'listener-alarm' && _listenerAlarmHasSignals();
          final isSelected = row.focus == resolvedFocus;
          final body = Container(
            width: double.infinity,
            margin: const EdgeInsets.only(bottom: 8),
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
            decoration: BoxDecoration(
              color: isSelected
                  ? row.accent.withValues(alpha: 0.12)
                  : isWatchAuditRow || isListenerAlarmRow
                  ? const Color(0x1410B981)
                  : const Color(0xFF13131E),
              borderRadius: BorderRadius.circular(9),
              border: Border.all(
                color: isSelected
                    ? row.accent.withValues(alpha: 0.4)
                    : isWatchAuditRow || isListenerAlarmRow
                    ? const Color(0x334AD2A0)
                    : _adminDialogBorderColor,
              ),
            ),
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                SizedBox(
                  width: 74,
                  child: Text(
                    row.label.toUpperCase(),
                    maxLines: 2,
                    overflow: TextOverflow.ellipsis,
                    style: GoogleFonts.inter(
                      color: isSelected ? row.accent : _adminDialogMutedColor,
                      fontSize: 11,
                      fontWeight: FontWeight.w700,
                      height: 1.15,
                    ),
                  ),
                ),
                const SizedBox(width: 8),
                Expanded(
                  child: Text(
                    row.value,
                    style: GoogleFonts.robotoMono(
                      color: const Color(0xFF67E8F9),
                      fontSize: 11,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ),
                if (isWatchAuditRow || isListenerAlarmRow) ...[
                  const SizedBox(width: 8),
                  Icon(
                    Icons.arrow_downward_rounded,
                    color: const Color(0xFF86EFAC),
                    size: 16,
                  ),
                ],
              ],
            ),
          );
          return Material(
            color: Colors.transparent,
            child: InkWell(
              key: ValueKey(
                isWatchAuditRow
                    ? 'admin-ops-poll-watch-audit-row'
                    : isListenerAlarmRow
                    ? 'admin-ops-poll-listener-alarm-row'
                    : 'admin-ops-poll-row-${row.id}',
              ),
              borderRadius: BorderRadius.circular(9),
              onTap: () {
                if (_activeOpsPollHealthFocus != row.focus) {
                  setState(() {
                    _activeOpsPollHealthFocus = row.focus;
                  });
                }
                if (isWatchAuditRow) {
                  _focusWatchAuditTrailFromSummary();
                  return;
                }
                if (isListenerAlarmRow) {
                  _focusListenerAlarmSummaryFromOps();
                }
              },
              child: body,
            ),
          );
        })
        .toList(growable: false);
  }

  bool _listenerAlarmHasSignals() {
    return widget.events.any(
      (event) =>
          event is ListenerAlarmFeedCycleRecorded ||
          event is ListenerAlarmAdvisoryRecorded ||
          event is ListenerAlarmParityCycleRecorded,
    );
  }

  _OpsPollHealthFocus _resolvedOpsPollHealthFocus(
    List<_OpsPollHealthEntry> entries,
  ) {
    if (entries.any((entry) => entry.focus == _activeOpsPollHealthFocus)) {
      return _activeOpsPollHealthFocus;
    }
    for (final preferred in const <_OpsPollHealthFocus>[
      _OpsPollHealthFocus.queue,
      _OpsPollHealthFocus.radio,
      _OpsPollHealthFocus.video,
      _OpsPollHealthFocus.listener,
      _OpsPollHealthFocus.watchAudit,
      _OpsPollHealthFocus.spool,
      _OpsPollHealthFocus.wearable,
      _OpsPollHealthFocus.news,
    ]) {
      if (entries.any((entry) => entry.focus == preferred)) {
        return preferred;
      }
    }
    return _OpsPollHealthFocus.queue;
  }

  String _opsPollHealthFocusLabel(_OpsPollHealthFocus focus) {
    return switch (focus) {
      _OpsPollHealthFocus.radio => 'radio scope',
      _OpsPollHealthFocus.queue => 'queue scope',
      _OpsPollHealthFocus.video => 'video scope',
      _OpsPollHealthFocus.spool => 'spool scope',
      _OpsPollHealthFocus.wearable => 'wearable scope',
      _OpsPollHealthFocus.listener => 'listener scope',
      _OpsPollHealthFocus.news => 'news scope',
      _OpsPollHealthFocus.watchAudit => 'watch recovery',
    };
  }

  String _opsPollHealthNextMoveLabel(
    _OpsPollHealthFocus focus, {
    required bool hasFleetHealth,
  }) {
    return switch (focus) {
      _OpsPollHealthFocus.queue =>
        widget.radioQueueHasPending ? 'Retry queue' : 'Run ops poll',
      _OpsPollHealthFocus.radio => 'Poll radio',
      _OpsPollHealthFocus.video =>
        hasFleetHealth ? 'Open fleet' : 'Poll ${widget.videoOpsLabel}',
      _OpsPollHealthFocus.spool => 'Focus queue',
      _OpsPollHealthFocus.wearable => 'Poll wearable',
      _OpsPollHealthFocus.listener => 'Open listener',
      _OpsPollHealthFocus.news => 'Poll news',
      _OpsPollHealthFocus.watchAudit => 'Open recovery',
    };
  }

  Color _opsPollHealthFocusAccent(_OpsPollHealthFocus focus) {
    return switch (focus) {
      _OpsPollHealthFocus.radio => const Color(0xFF67E8F9),
      _OpsPollHealthFocus.queue => const Color(0xFF8FD1FF),
      _OpsPollHealthFocus.video => const Color(0xFF93C5FD),
      _OpsPollHealthFocus.spool => const Color(0xFF34D399),
      _OpsPollHealthFocus.wearable => const Color(0xFF34D399),
      _OpsPollHealthFocus.listener => const Color(0xFFF59E0B),
      _OpsPollHealthFocus.news => const Color(0xFFF59E0B),
      _OpsPollHealthFocus.watchAudit => const Color(0xFF86EFAC),
    };
  }

  Future<void> _runOpsCommandDeckAction({
    required Future<void> Function() action,
    required String successMessage,
    required String successSourceLabel,
    required String successDetail,
    required Color successAccent,
    required String failureMessage,
    required String failureDetail,
    String? failureSourceLabel,
    Color failureAccent = const Color(0xFFFFD6A5),
  }) async {
    try {
      await action();
    } catch (_) {
      if (!mounted) {
        return;
      }
      _handleAdminFeedback(
        feedbackContext: context,
        message: failureMessage,
        sourceLabel: failureSourceLabel ?? successSourceLabel,
        detail: failureDetail,
        accent: failureAccent,
      );
      return;
    }
    if (!mounted) {
      return;
    }
    _handleAdminFeedback(
      feedbackContext: context,
      message: successMessage,
      sourceLabel: successSourceLabel,
      detail: successDetail,
      accent: successAccent,
    );
  }

  Future<void> _runOpsIntegrationPollFromCommand() async {
    if (widget.onRunOpsIntegrationPoll == null) {
