  Future<void> _runTelegramSeededVideoPoll() async {
    final prefill = _latestApprovedTelegramOnboardingPrefill;
    if (widget.onRunCctvPoll == null) {
      return;
    }
    if (prefill != null) {
      await Clipboard.setData(
        ClipboardData(text: _buildTelegramCctvReviewBrief(prefill)),
      );
    }
    await _runOpsCommandDeckAction(
      action: () async {
        await widget.onRunCctvPoll!.call();
        await _rememberTelegramBridgeRunbookProgress(
          (progress) => progress.copyWith(cctvPolled: true),
        );
      },
      successMessage: prefill == null
          ? 'Polled ${widget.videoOpsLabel} telemetry.'
          : 'Copied ${widget.videoOpsLabel} review brief and polled ${widget.videoOpsLabel} telemetry.',
      successSourceLabel: '${widget.videoOpsLabel.toUpperCase()} POLL',
      successDetail: prefill == null
          ? '${widget.videoOpsLabel} capability, evidence, and camera telemetry has been refreshed from the ops command deck.'
          : '${widget.videoOpsLabel} review context for ${prefill.siteId} was copied before the live telemetry refresh.',
      successAccent: const Color(0xFF93C5FD),
      failureMessage:
          '${widget.videoOpsLabel} telemetry poll could not complete right now.',
      failureDetail: prefill == null
          ? 'The ops command deck stayed in place. Retry the ${widget.videoOpsLabel.toLowerCase()} poll without losing the current runtime focus.'
          : 'The review brief was prepared, but the live ${widget.videoOpsLabel.toLowerCase()} poll did not complete. Retry it without losing the onboarding runtime context.',
    );
  }

