  void _focusListenerAlarmSummaryFromOps() {
    final resolvedFocus = _resolvedListenerAlarmFocus(
      hasFeed: widget.events.any(
        (event) => event is ListenerAlarmFeedCycleRecorded,
      ),
      hasAdvisory: widget.events.any(
        (event) => event is ListenerAlarmAdvisoryRecorded,
      ),
      hasParity: widget.events.any(
        (event) => event is ListenerAlarmParityCycleRecorded,
      ),
    );
    if (_activeListenerAlarmSummaryFocus != resolvedFocus) {
      setState(() {
        _activeListenerAlarmSummaryFocus = resolvedFocus;
      });
    }
    _handleAdminFeedback(
      feedbackContext: context,
      message: 'Focused listener alarm command.',
      sourceLabel: 'LISTENER ALARM',
      detail:
          'Alarm intake command is now pinned above the wider system board so the active alarm scope stays easy to review and route.',
      accent: _listenerAlarmFocusAccent(resolvedFocus),
    );
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final summaryContext = _listenerAlarmSummaryCardKey.currentContext;
      if (summaryContext == null) {
        return;
      }
      Scrollable.ensureVisible(
        summaryContext,
        duration: const Duration(milliseconds: 220),
        curve: Curves.easeOutCubic,
        alignment: 0.1,
      );
    });
  }

  void _focusWatchAuditTrailFromSummary() {
    if (_selectedWatchAuditEntryIndex != 0) {
      setState(() {
        _selectedWatchAuditEntryIndex = 0;
      });
    }
    _handleAdminFeedback(
      feedbackContext: context,
      message: 'Focused the watch recovery trail.',
      sourceLabel: 'WATCH RECOVERY',
      detail:
          'Latest watch recovery alignment is now pinned in the Watch Recovery Trail while the full trail stays in view below.',
      accent: const Color(0xFF86EFAC),
    );
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final trailContext = _watchAuditTrailPanelKey.currentContext;
      if (trailContext == null) {
        return;
      }
      Scrollable.ensureVisible(
        trailContext,
        duration: const Duration(milliseconds: 220),
        curve: Curves.easeOutCubic,
        alignment: 0.12,
      );
    });
  }

  Widget _monitoringWatchAuditTrailPanel() {
    final history = widget.monitoringWatchAuditHistory
        .map((entry) => entry.trim())
        .where((entry) => entry.isNotEmpty)
        .map(
          (entry) =>
              (raw: entry, record: _watchRecoveryStore.parseAuditRecord(entry)),
        )
        .toList(growable: false);
    if (history.isEmpty) {
      return const SizedBox.shrink();
    }
    final selectedIndex = _selectedWatchAuditEntryIndex >= history.length
        ? 0
        : _selectedWatchAuditEntryIndex;
    final selectedAudit = history[selectedIndex];
    final selectedRecord = selectedAudit.record;
    final selectedScope = selectedRecord == null || !selectedRecord.isValid
        ? null
        : _watchAuditSiteRow(selectedRecord.siteLabel);
    final selectedAccent = _watchAuditOutcomeAccent(
      selectedRecord?.outcome ?? '',
    );
    final openSelectedReports = selectedScope == null
        ? null
        : _openReportsAction(
            clientId: selectedScope.clientId,
            siteId: selectedScope.id,
          );
    final openSelectedGovernance = selectedScope == null
        ? null
        : _openGovernanceAction(
            clientId: selectedScope.clientId,
            siteId: selectedScope.id,
          );
    final selectedSiteLabel =
        selectedRecord?.siteLabel.trim().isNotEmpty ?? false
        ? selectedRecord!.siteLabel.trim()
        : 'Watch recovery trail';
    final selectedActor = selectedRecord?.actor.trim().isNotEmpty ?? false
        ? selectedRecord!.actor.trim()
        : 'SYSTEM';
    final selectedOutcome = selectedRecord?.outcome.trim().isNotEmpty ?? false
        ? selectedRecord!.outcome.trim()
        : 'Recorded';
    final selectedRecordedAt = selectedRecord == null
        ? 'Unknown'
        : _watchAuditRecordedAtLabel(selectedRecord);
    final nextMoveLabel = selectedIndex == 0
        ? openSelectedReports != null
              ? 'Open reports'
              : openSelectedGovernance != null
              ? 'Open governance'
              : 'Copy audit'
        : 'Return latest';

    void selectAuditEntry(int index, {bool pinReceipt = false}) {
      final boundedIndex = math.max(0, math.min(index, history.length - 1));
      if (_selectedWatchAuditEntryIndex != boundedIndex) {
        setState(() {
          _selectedWatchAuditEntryIndex = boundedIndex;
        });
      }
      if (!pinReceipt) {
        return;
      }
      final audit = history[boundedIndex];
      final record = audit.record;
      final siteLabel = record?.siteLabel.trim().isNotEmpty ?? false
          ? record!.siteLabel.trim()
          : 'Watch recovery trail';
      final outcome = record?.outcome.trim().isNotEmpty ?? false
          ? record!.outcome.trim()
          : 'Recorded';
      final actor = record?.actor.trim().isNotEmpty ?? false
          ? record!.actor.trim()
          : 'SYSTEM';
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Pinned $siteLabel audit entry.',
        sourceLabel: 'WATCH RECOVERY',
        detail:
            '$actor last left the watch recovery trail at $outcome, and the selected recovery record now stays docked in Context Rail.',
        accent: _watchAuditOutcomeAccent(record?.outcome ?? ''),
      );
    }

    void focusLatestAudit() {
      selectAuditEntry(0, pinReceipt: true);
    }

    void focusPreviousAudit() {
      if (history.length == 1) {
        focusLatestAudit();
        return;
      }
      final nextIndex = (selectedIndex + 1) % history.length;
      selectAuditEntry(nextIndex, pinReceipt: true);
    }

    void copySelectedAuditRecord() {
      Clipboard.setData(ClipboardData(text: selectedAudit.raw));
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Watch audit copied for $selectedSiteLabel.',
        sourceLabel: 'WATCH RECOVERY',
        detail:
            '$selectedOutcome by $selectedActor is ready to paste into a partner handoff, review note, or escalation trail.',
        accent: selectedAccent,
      );
    }

    void openSelectedReportsScope() {
      final action = openSelectedReports;
      if (action == null) {
        copySelectedAuditRecord();
        return;
      }
      action();
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Opened watch recovery reports for $selectedSiteLabel.',
        sourceLabel: 'REPORTS WORKSPACE',
        detail:
            '$selectedSiteLabel is now foregrounded in Reports Workspace from Watch Identity.',
        accent: const Color(0xFF67E8F9),
      );
    }

    void openSelectedGovernanceScope() {
      final action = openSelectedGovernance;
      if (action == null) {
        copySelectedAuditRecord();
        return;
      }
      action();
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Opened watch recovery governance for $selectedSiteLabel.',
        sourceLabel: 'GOVERNANCE DESK',
        detail:
            '$selectedSiteLabel is now foregrounded in Governance Desk from Watch Identity.',
        accent: const Color(0xFFFBBF24),
      );
    }

    return Container(
      key: _watchAuditTrailPanelKey,
      width: double.infinity,
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: const Color(0xFF13131E),
        borderRadius: BorderRadius.circular(9),
        border: Border.all(color: _adminDialogBorderColor),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Text(
                'Watch Recovery Trail',
                style: GoogleFonts.inter(
                  color: _adminDialogTitleColor,
                  fontSize: 12,
                  fontWeight: FontWeight.w700,
                ),
              ),
              const SizedBox(width: 8),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                decoration: BoxDecoration(
                  color: const Color(0x1422D3EE),
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: const Color(0x3322D3EE)),
                ),
                child: Text(
