  String _watchAuditRecordedAtLabel(MonitoringWatchAuditRecord audit) {
    final recordedAtUtc = audit.recordedAtUtc;
    if (recordedAtUtc == null) {
      return 'Unknown';
    }
    final year = recordedAtUtc.year.toString().padLeft(4, '0');
    final month = recordedAtUtc.month.toString().padLeft(2, '0');
    final day = recordedAtUtc.day.toString().padLeft(2, '0');
    final hour = recordedAtUtc.hour.toString().padLeft(2, '0');
    final minute = recordedAtUtc.minute.toString().padLeft(2, '0');
    return '$year-$month-$day $hour:$minute UTC';
  }

  _ListenerAlarmSummaryFocus _resolvedListenerAlarmFocus({
    required bool hasFeed,
    required bool hasAdvisory,
    required bool hasParity,
  }) {
    final preferred = _activeListenerAlarmSummaryFocus;
    if (preferred == _ListenerAlarmSummaryFocus.advisory && hasAdvisory) {
      return preferred;
    }
    if (preferred == _ListenerAlarmSummaryFocus.feed && hasFeed) {
      return preferred;
    }
    if (preferred == _ListenerAlarmSummaryFocus.parity && hasParity) {
      return preferred;
    }
    if (hasAdvisory) {
      return _ListenerAlarmSummaryFocus.advisory;
    }
    if (hasFeed) {
      return _ListenerAlarmSummaryFocus.feed;
    }
    if (hasParity) {
      return _ListenerAlarmSummaryFocus.parity;
    }
    return _ListenerAlarmSummaryFocus.advisory;
  }

  String _listenerAlarmFocusLabel(_ListenerAlarmSummaryFocus focus) {
    return switch (focus) {
      _ListenerAlarmSummaryFocus.feed => 'feed scope',
      _ListenerAlarmSummaryFocus.advisory => 'advisory scope',
      _ListenerAlarmSummaryFocus.parity => 'parity scope',
    };
  }

  Color _listenerAlarmFocusAccent(_ListenerAlarmSummaryFocus focus) {
    return switch (focus) {
      _ListenerAlarmSummaryFocus.feed => const Color(0xFF8FD1FF),
      _ListenerAlarmSummaryFocus.advisory => const Color(0xFFF59E0B),
      _ListenerAlarmSummaryFocus.parity => const Color(0xFFFDE68A),
    };
  }

  String _listenerAlarmOccurredAtLabel(DateTime? occurredAt) {
    if (occurredAt == null) {
      return 'Unknown';
    }
    final utc = occurredAt.toUtc();
    final year = utc.year.toString().padLeft(4, '0');
    final month = utc.month.toString().padLeft(2, '0');
    final day = utc.day.toString().padLeft(2, '0');
    final hour = utc.hour.toString().padLeft(2, '0');
    final minute = utc.minute.toString().padLeft(2, '0');
    return '$year-$month-$day $hour:$minute UTC';
  }

  _SiteAdminRow? _resolveListenerAlarmScope(
    ListenerAlarmAdvisoryRecorded advisory,
  ) {
    final byTelemetry = _resolveSiteRowByTelemetryLabel(advisory.siteId);
    if (byTelemetry != null) {
      return byTelemetry;
    }
    final normalizedClientId = advisory.clientId.trim();
    if (normalizedClientId.isEmpty) {
      return null;
    }
    for (final site in _sites) {
      if (site.clientId == normalizedClientId) {
        return site;
      }
    }
    return null;
  }

  _SiteAdminRow? _watchAuditSiteRow(String siteLabel) {
    return _resolveSiteRowByTelemetryLabel(siteLabel);
  }

  _SiteAdminRow? _resolveSiteRowByTelemetryLabel(String rawLabel) {
    final normalized = rawLabel.trim().toLowerCase();
    final compact = _compactTelemetryLabel(rawLabel);
    if (normalized.isEmpty || compact.isEmpty) {
      return null;
    }
    for (final site in _sites) {
      final candidates = <String>[
        site.name,
        site.id,
        site.code,
        _clientName(site.clientId),
      ];
      for (final candidate in candidates) {
        final normalizedCandidate = candidate.trim().toLowerCase();
        final compactCandidate = _compactTelemetryLabel(candidate);
        if (normalizedCandidate == normalized ||
            compactCandidate == compact ||
            normalizedCandidate.contains(normalized) ||
            normalized.contains(normalizedCandidate) ||
            compactCandidate.contains(compact) ||
            compact.contains(compactCandidate)) {
          return site;
        }
      }
    }
    return null;
  }

  String _compactTelemetryLabel(String raw) {
    return raw.trim().toLowerCase().replaceAll(RegExp(r'[^a-z0-9]+'), '');
  }

  Color _watchAuditOutcomeAccent(String outcome) {
    final normalized = outcome.trim().toLowerCase();
    if (normalized.contains('resync') || normalized.contains('restore')) {
      return const Color(0xFF86EFAC);
    }
    if (normalized.contains('aligned') || normalized.contains('stable')) {
      return const Color(0xFFFDE68A);
    }
    if (normalized.contains('fail') || normalized.contains('error')) {
      return const Color(0xFFFCA5A5);
    }
    return const Color(0xFF67E8F9);
  }

