  List<_SuppressedSceneReviewEntry> _suppressedSceneReviewEntries() {
    final output = <_SuppressedSceneReviewEntry>[];
    for (final scope in widget.fleetScopeHealth) {
      if (!scope.hasSuppressedSceneAction) {
        continue;
      }
      final intelligenceId = (scope.latestIncidentReference ?? '').trim();
      if (intelligenceId.isEmpty) {
        continue;
      }
      final review = widget.sceneReviewByIntelligenceId[intelligenceId];
      if (review == null) {
        continue;
      }
      output.add(_SuppressedSceneReviewEntry(scope: scope, review: review));
    }
    output.sort(
      (a, b) => b.review.reviewedAtUtc.compareTo(a.review.reviewedAtUtc),
    );
    return output;
  }

  Widget _suppressedSceneReviewPanel(
    List<_SuppressedSceneReviewEntry> entries,
  ) {
    final visibleEntries = entries.take(6).toList(growable: false);
    final leadEntry = visibleEntries.first;
    final leadScope = leadEntry.scope;
    final leadReview = leadEntry.review;
    final leadIncidentRef = (leadScope.latestIncidentReference ?? '').trim();
    final canOpenLeadEvents =
        leadIncidentRef.isNotEmpty && widget.onOpenEventsForIncident != null;
    final canOpenLeadLedger =
        leadIncidentRef.isNotEmpty && widget.onOpenLedgerForIncident != null;
    final leadActionLabel = canOpenLeadEvents
        ? 'Open events'
        : canOpenLeadLedger
        ? 'Open ledger'
        : 'Keep filtered';

    void focusFilteredLane() {
      if (_activeWatchActionDrilldown !=
          VideoFleetWatchActionDrilldown.filtered) {
        _setActiveWatchActionDrilldown(VideoFleetWatchActionDrilldown.filtered);
      }
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Focused Suppressed Review.',
        sourceLabel: 'SUPPRESSED REVIEW',
        detail:
            'Suppressed scene reviews stay pinned at the top of the system tab while ONYX keeps the filtered watch scope in focus.',
        accent: const Color(0xFF9AB1CF),
      );
    }

    void openLeadEvents() {
      if (!canOpenLeadEvents) {
        focusFilteredLane();
        return;
      }
      widget.onOpenEventsForIncident!.call(leadIncidentRef);
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Opened filtered review events for ${leadScope.siteName}.',
        sourceLabel: 'EVENTS HANDOFF',
        detail:
            '${leadScope.siteName} is now foregrounded in the scoped events review from the suppressed review board.',
        accent: const Color(0xFF67E8F9),
      );
    }

    void openLeadLedger() {
      if (!canOpenLeadLedger) {
        focusFilteredLane();
        return;
      }
      widget.onOpenLedgerForIncident!.call(leadIncidentRef);
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Opened filtered review ledger for ${leadScope.siteName}.',
        sourceLabel: 'LEDGER HANDOFF',
        detail:
            '${leadScope.siteName} is now foregrounded in the continuity ledger from the suppressed review board.',
        accent: const Color(0xFFFBBF24),
      );
    }

    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(9),
        border: Border.all(color: _adminDialogBorderColor),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Text(
                'Suppressed Scene Reviews',
                style: GoogleFonts.inter(
                  color: _adminDialogTitleColor,
                  fontSize: 12,
                  fontWeight: FontWeight.w700,
                ),
              ),
