                        borderRadius: BorderRadius.circular(9),
                        border: Border.all(color: const Color(0x339AB1CF)),
                      ),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.end,
                        children: [
                          Text(
                            'NEXT MOVE',
                            style: GoogleFonts.inter(
                              color: const Color(0xFF9AB1CF),
                              fontSize: 9,
                              fontWeight: FontWeight.w800,
                              letterSpacing: 0.8,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            leadActionLabel,
                            style: GoogleFonts.inter(
                              color: _adminDialogTitleColor,
                              fontSize: 10.5,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 10),
                Wrap(
                  spacing: 6,
                  runSpacing: 6,
                  children: [
                    _watchAuditChip(
                      'Site',
                      leadScope.siteName,
                      color: const Color(0xFFBFD7F2),
                    ),
                    _watchAuditChip(
                      'Reviewed',
                      _suppressedReviewedAtLabel(leadReview.reviewedAtUtc),
                      color: const Color(0xFF67E8F9),
                    ),
                    _watchAuditChip(
                      'Posture',
                      leadReview.postureLabel,
                      color: const Color(0xFF86EFAC),
                    ),
                    _watchAuditChip(
                      'Source',
                      leadReview.sourceLabel,
                      color: const Color(0xFFFDE68A),
                    ),
                  ],
                ),
                const SizedBox(height: 10),
                Wrap(
                  spacing: 8,
                  runSpacing: 8,
                  children: [
                    _fleetActionButton(
                      key: const ValueKey(
                        'admin-suppressed-scene-focus-filtered',
                      ),
                      label: 'Filtered scope',
                      color: const Color(0xFF9AB1CF),
                      onPressed: focusFilteredLane,
                    ),
                    if (canOpenLeadEvents)
                      _fleetActionButton(
                        key: const ValueKey(
                          'admin-suppressed-scene-open-events',
                        ),
                        label: 'Events',
                        color: const Color(0xFF67E8F9),
                        onPressed: openLeadEvents,
                      ),
                    if (canOpenLeadLedger)
                      _fleetActionButton(
                        key: const ValueKey(
                          'admin-suppressed-scene-open-ledger',
                        ),
                        label: 'Ledger',
                        color: const Color(0xFFFBBF24),
                        onPressed: openLeadLedger,
                      ),
                  ],
                ),
              ],
            ),
          ),
          const SizedBox(height: 10),
          ...visibleEntries.asMap().entries.map((entry) {
            final item = entry.value;
            final scope = item.scope;
            final review = item.review;
            final incidentRef = (scope.latestIncidentReference ?? '').trim();
            final decisionSummary = review.decisionSummary.trim();
            final reviewSummary = review.summary.trim();

            void openEntryEvents() {
              if (widget.onOpenEventsForIncident == null ||
                  incidentRef.isEmpty) {
                return;
              }
              widget.onOpenEventsForIncident!.call(incidentRef);
              _handleAdminFeedback(
                feedbackContext: context,
                message: 'Opened filtered review events for ${scope.siteName}.',
                sourceLabel: 'EVENTS HANDOFF',
                detail:
                    '${scope.siteName} is now foregrounded in the scoped events review from the suppressed review row.',
                accent: const Color(0xFF67E8F9),
              );
            }

            void openEntryLedger() {
              if (widget.onOpenLedgerForIncident == null ||
                  incidentRef.isEmpty) {
                return;
              }
              widget.onOpenLedgerForIncident!.call(incidentRef);
              _handleAdminFeedback(
                feedbackContext: context,
                message: 'Opened filtered review ledger for ${scope.siteName}.',
                sourceLabel: 'LEDGER HANDOFF',
                detail:
                    '${scope.siteName} is now foregrounded in the continuity ledger from the suppressed review row.',
                accent: const Color(0xFFFBBF24),
              );
            }

            return Container(
              width: double.infinity,
              margin: EdgeInsets.only(
                bottom: entry.key == visibleEntries.length - 1 ? 0 : 8,
              ),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
              decoration: BoxDecoration(
                color: const Color(0xFF13131E),
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: _adminDialogBorderColor),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Expanded(
                        child: Text(
                          scope.siteName,
                          style: GoogleFonts.inter(
                            color: _adminDialogTitleColor,
                            fontSize: 12,
                            fontWeight: FontWeight.w700,
                          ),
                        ),
                      ),
                      const SizedBox(width: 8),
                      Text(
                        _suppressedReviewedAtLabel(review.reviewedAtUtc),
                        style: GoogleFonts.robotoMono(
                          color: _adminDialogMutedColor,
                          fontSize: 10,
                          fontWeight: FontWeight.w600,
                        ),
                      ),
                    ],
                  ),
                  const SizedBox(height: 6),
                  Wrap(
                    spacing: 6,
                    runSpacing: 6,
                    children: [
                      _watchAuditChip(
                        'Action',
                        review.decisionLabel.trim().isEmpty
                            ? 'Suppressed'
                            : review.decisionLabel,
                        color: const Color(0xFFBFD7F2),
                      ),
                      if ((scope.latestCameraLabel ?? '').trim().isNotEmpty)
                        _watchAuditChip(
                          'Camera',
                          scope.latestCameraLabel!,
                          color: const Color(0xFF67E8F9),
                        ),
                      _watchAuditChip(
                        'Source',
                        review.sourceLabel,
                        color: const Color(0xFFFDE68A),
                      ),
                      _watchAuditChip(
                        'Posture',
                        review.postureLabel,
                        color: const Color(0xFF86EFAC),
                      ),
                    ],
                  ),
                  if (decisionSummary.isNotEmpty) ...[
                    const SizedBox(height: 8),
                    Text(
                      decisionSummary,
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 12,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  ],
                  if (reviewSummary.isNotEmpty) ...[
                    const SizedBox(height: 4),
                    Text(
                      'Scene review: $reviewSummary',
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 11,
                        fontWeight: FontWeight.w500,
                      ),
                    ),
                  ],
                  if (incidentRef.isNotEmpty &&
                      (widget.onOpenEventsForIncident != null ||
                          widget.onOpenLedgerForIncident != null)) ...[
                    const SizedBox(height: 8),
                    Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: [
                        if (widget.onOpenEventsForIncident != null)
                          _fleetActionButton(
                            key: ValueKey(
                              'admin-suppressed-scene-row-events-${scope.siteId}',
                            ),
                            label: 'Events',
                            color: const Color(0xFF67E8F9),
                            onPressed: openEntryEvents,
                          ),
                        if (widget.onOpenLedgerForIncident != null)
                          _fleetActionButton(
                            key: ValueKey(
                              'admin-suppressed-scene-row-ledger-${scope.siteId}',
                            ),
                            label: 'Ledger',
                            color: const Color(0xFFFBBF24),
                            onPressed: openEntryLedger,
                          ),
                      ],
                    ),
                  ],
                ],
              ),
            );
          }),
        ],
      ),
    );
  }

  Widget _identityPolicyPanel() {
    final entries = _monitoringIdentityPolicyService.entries;
    final hasOverride = widget.initialMonitoringIdentityRulesJson
        .trim()
        .isNotEmpty;
    final activeEntry = _activeIdentityPolicyEntry(entries);
    final activePolicy =
        activeEntry?.policy ?? const MonitoringIdentityScopePolicy();
    final activeAccent = _identityPolicyAccent(activePolicy);
    final activeNextMove = _identityPolicyRecommendedMove(activePolicy);
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(10),
