                                    fontWeight: FontWeight.w600,
                                  ),
                                ),
                              ],
                            ),
                          );
                        }),
                      ],
                    ],
                  ),
                );
              },
            ),
          ],
        ],
      ),
    );
  }

  Widget _telegramIdentityIntakePanel() {
    final hasIntakes = _telegramIdentityIntakes.isNotEmpty;
    final leadIntake = hasIntakes ? _telegramIdentityIntakes.first : null;
    final leadBusy =
        leadIntake != null &&
        _telegramIdentityIntakeBusyIds.contains(leadIntake.intakeId.trim());
    final leadActionLabel = leadIntake == null
        ? 'Queue clear'
        : leadIntake.aiConfidence >= 0.9 &&
              (leadIntake.parsedFaceMatchId.trim().isNotEmpty ||
                  leadIntake.parsedPlateNumber.trim().isNotEmpty)
        ? 'Lead always'
        : 'Lead once';
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(10),
