  Widget _identityRuleChip(String label, Color color) {
    final chipTextColor = _telegramAiAccentTextColor(color, strength: 0.46);
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
      decoration: BoxDecoration(
        color: color.withValues(alpha: 0.15),
        borderRadius: BorderRadius.circular(999),
        border: Border.all(color: color.withValues(alpha: 0.24)),
      ),
      child: Text(
        label,
        style: GoogleFonts.inter(
          color: chipTextColor,
          fontSize: 9.6,
          fontWeight: FontWeight.w700,
        ),
      ),
    );
  }

  Widget _identityRuleLine({
    required String clientId,
    required String siteId,
    required MonitoringIdentityScopePolicy policy,
    required _IdentityRuleBucket bucket,
  }) {
    final values = _identityRuleValues(policy, bucket).toList(growable: false)
      ..sort();
    final label = _identityRuleLabel(bucket);
    final color = _identityRuleBucketColor(bucket);
    return Padding(
      padding: const EdgeInsets.only(bottom: 6),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Expanded(
                child: Text(
                  label,
                  style: GoogleFonts.inter(
                    color: _adminDialogBodyColor,
                    fontSize: 10,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
              TextButton(
                key: ValueKey('identity-rule-add-${bucket.name}-$siteId'),
                onPressed: () => _promptAddIdentityRuleValue(
                  clientId: clientId,
                  siteId: siteId,
                  policy: policy,
                  bucket: bucket,
                ),
                style: TextButton.styleFrom(
                  foregroundColor: color,
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 4,
                  ),
                  minimumSize: Size.zero,
                  tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                ),
                child: const Text('Add'),
              ),
            ],
          ),
          const SizedBox(height: 4),
          if (values.isEmpty)
            Text(
              'None configured',
              style: GoogleFonts.inter(
                color: _adminDialogBodyColor,
                fontSize: 10,
                fontWeight: FontWeight.w600,
              ),
            )
          else
            Wrap(
              spacing: 6,
              runSpacing: 6,
              children: values
                  .map(
                    (value) => InputChip(
                      key: ValueKey(
                        'identity-rule-chip-${bucket.name}-$siteId-$value',
                      ),
                      label: Text(value),
                      deleteIconColor: color,
                      deleteButtonTooltipMessage: 'Remove $value',
                      onDeleted: () => _removeIdentityRuleValue(
                        clientId: clientId,
                        siteId: siteId,
                        policy: policy,
                        bucket: bucket,
                        value: value,
                      ),
                      backgroundColor: color.withValues(alpha: 0.12),
                      side: BorderSide(color: color.withValues(alpha: 0.35)),
                      labelStyle: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 10,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                  )
                  .toList(growable: false),
            ),
        ],
      ),
    );
  }

  String _suppressedReviewedAtLabel(DateTime reviewedAtUtc) {
    final value = reviewedAtUtc.toUtc();
    final year = value.year.toString().padLeft(4, '0');
    final month = value.month.toString().padLeft(2, '0');
    final day = value.day.toString().padLeft(2, '0');
    final hour = value.hour.toString().padLeft(2, '0');
    final minute = value.minute.toString().padLeft(2, '0');
    return '$year-$month-$day $hour:$minute UTC';
  }

  Widget _fleetScopeHealthCard(
    VideoFleetScopeHealthView scope, {
    required void Function(VideoFleetScopeHealthView scope)
    onOpenLatestWatchActionDetail,
  }) {
    final statusColor = switch (scope.statusLabel.toUpperCase()) {
      'LIVE' => const Color(0xFF10B981),
      'ACTIVE WATCH' => const Color(0xFF22D3EE),
      'LIMITED WATCH' => const Color(0xFFF59E0B),
      'WATCH READY' => const Color(0xFFF59E0B),
      _ => const Color(0xFF8EA4C2),
    };
    final watchColor = scope.watchLabel == 'LIMITED'
        ? const Color(0xFFF59E0B)
        : const Color(0xFF67E8F9);
    final phaseColor = (scope.watchWindowStateLabel ?? '').contains('LIMITED')
        ? const Color(0xFFF59E0B)
        : scope.watchWindowStateLabel == 'IN WINDOW'
        ? const Color(0xFF86EFAC)
        : const Color(0xFFFBBF24);
    final hasTacticalLane =
        scope.hasIncidentContext && widget.onOpenFleetTacticalScope != null;
    final hasDispatchLane =
        scope.hasIncidentContext && widget.onOpenFleetDispatchScope != null;
    final canRecoverCoverage =
        scope.hasWatchActivationGap && widget.onRecoverFleetWatchScope != null;
    final commandAccent = _fleetScopeCommandAccent(scope);
    final commandHeadline = _fleetScopeCommandHeadline(scope);
    final commandDetail = _fleetScopeCommandDetail(scope);
    final primaryActionLabel = canRecoverCoverage
        ? 'Resync coverage'
        : hasTacticalLane
        ? 'TACTICAL TRACK'
        : hasDispatchLane
        ? 'DISPATCH BOARD'
        : 'Latest detail';
    final primaryActionColor = canRecoverCoverage
        ? const Color(0xFFFCA5A5)
        : hasTacticalLane
        ? const Color(0xFF67E8F9)
        : hasDispatchLane
        ? const Color(0xFFFDE68A)
        : const Color(0xFF8FD1FF);

    void openFleetDetail() {
      onOpenLatestWatchActionDetail(scope);
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Focused fleet scope detail for ${scope.siteName}.',
        sourceLabel: 'FLEET DETAIL',
        detail:
            '${scope.siteName} stays pinned in the system fleet rail while the latest signal detail opens below it.',
        accent: const Color(0xFF8FD1FF),
      );
    }

    void openFleetTactical() {
      if (!hasTacticalLane) {
        openFleetDetail();
        return;
      }
      widget.onOpenFleetTacticalScope!.call(
        scope.clientId,
        scope.siteId,
        scope.latestIncidentReference,
      );
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Tactical track warmed for ${scope.siteName}.',
        sourceLabel: 'TACTICAL TRACK',
        detail:
            '${scope.siteName} is now foregrounded in the scoped tactical track.',
        accent: const Color(0xFF67E8F9),
      );
    }

    void openFleetDispatch() {
      if (!hasDispatchLane) {
        openFleetDetail();
        return;
      }
      widget.onOpenFleetDispatchScope!.call(
        scope.clientId,
        scope.siteId,
        scope.latestIncidentReference,
      );
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Dispatch board warmed for ${scope.siteName}.',
        sourceLabel: 'DISPATCH BOARD',
        detail:
            '${scope.siteName} is now foregrounded in the incident-backed dispatch board.',
        accent: const Color(0xFFFDE68A),
      );
    }

    void recoverFleetScope() {
      if (!canRecoverCoverage) {
        openFleetDetail();
        return;
      }
      widget.onRecoverFleetWatchScope!.call(scope.clientId, scope.siteId);
      _handleAdminFeedback(
        feedbackContext: context,
        message: 'Triggered coverage resync for ${scope.siteName}.',
        sourceLabel: 'COVERAGE RESYNC',
        detail:
            '${scope.siteName} has been queued for watch-window recovery from the fleet command card.',
        accent: const Color(0xFFFCA5A5),
      );
    }

    return VideoFleetScopeHealthCard(
      key: ValueKey('admin-fleet-scope-card-${scope.siteId}'),
      headerChild: Container(
        key: ValueKey('admin-fleet-scope-command-${scope.siteId}'),
        width: double.infinity,
        padding: const EdgeInsets.all(10),
        decoration: BoxDecoration(
          color: _adminDialogAltColor,
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: commandAccent.withValues(alpha: 0.24)),
        ),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Expanded(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    'SYSTEM FLEET COMMAND',
                    style: GoogleFonts.inter(
                      color: commandAccent,
                      fontSize: 9.5,
                      fontWeight: FontWeight.w800,
                      letterSpacing: 0.8,
                    ),
                  ),
                  const SizedBox(height: 4),
                  Text(
                    commandHeadline,
                    style: GoogleFonts.inter(
                      color: _adminDialogTitleColor,
                      fontSize: 11.5,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                  const SizedBox(height: 2),
                  Text(
                    commandDetail,
                    style: GoogleFonts.inter(
                      color: _adminDialogBodyColor,
                      fontSize: 10.5,
                      fontWeight: FontWeight.w600,
