  Widget _fleetSummaryTile(
    String label,
    String value, {
    required String detail,
    required Color accent,
    bool isActive = false,
    VoidCallback? onTap,
    Key? key,
  }) {
    final title = '$label $value';
    final tile = Container(
      constraints: const BoxConstraints(minWidth: 150, maxWidth: 188),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: isActive ? accent.withValues(alpha: 0.16) : _adminDialogAltColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(
          color: isActive
              ? accent.withValues(alpha: 0.6)
              : _adminDialogBorderColor,
        ),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Expanded(
                child: Text(
                  title,
                  style: GoogleFonts.inter(
                    color: isActive ? accent : _adminDialogTitleColor,
                    fontSize: 10,
                    fontWeight: FontWeight.w800,
                    letterSpacing: 0.2,
                  ),
                ),
              ),
              if (isActive)
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 4,
                  ),
                  decoration: BoxDecoration(
                    color: accent.withValues(alpha: 0.18),
                    borderRadius: BorderRadius.circular(999),
                    border: Border.all(color: accent.withValues(alpha: 0.4)),
                  ),
                  child: Text(
                    'FOCUSED',
                    style: GoogleFonts.inter(
                      color: accent,
                      fontSize: 8.5,
                      fontWeight: FontWeight.w800,
                      letterSpacing: 0.7,
                    ),
                  ),
                ),
            ],
          ),
          const SizedBox(height: 6),
          Text(
            detail,
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 10,
              fontWeight: FontWeight.w600,
              height: 1.3,
            ),
          ),
        ],
      ),
    );
    if (onTap == null) {
      return KeyedSubtree(key: key, child: tile);
    }
    return Material(
      key: key,
      color: Colors.transparent,
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(10),
        child: tile,
      ),
    );
  }

  Color _fleetRiskColor(int score) {
    if (score >= 85) {
      return const Color(0xFFF87171);
    }
    if (score >= 70) {
      return const Color(0xFFFBBF24);
    }
    if (score >= 40) {
      return const Color(0xFF67E8F9);
    }
    return const Color(0xFF9AB1CF);
  }

  String _fleetRiskLabel(int score) {
    if (score >= 85) {
      return 'Critical';
    }
    if (score >= 70) {
      return 'High';
    }
    if (score >= 40) {
      return 'Watch';
    }
    return 'Routine';
  }

  Color _fleetFreshnessColor(VideoFleetScopeHealthView scope) {
    return switch (scope.freshnessLabel) {
      'Fresh' => const Color(0xFF10B981),
      'Recent' => const Color(0xFF67E8F9),
      'Stale' => const Color(0xFFF87171),
      'Quiet' => const Color(0xFFFBBF24),
      _ => const Color(0xFF9AB1CF),
    };
  }

  Widget _fleetBadge(
    String label,
    String value,
    Color color, {
    VoidCallback? onTap,
    bool isActive = false,
  }) {
    final foreground = _adminAccentTextColor(color, strength: 0.46);
    final badge = Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 5),
      decoration: BoxDecoration(
        color: color.withValues(alpha: isActive ? 0.18 : 0.10),
        borderRadius: BorderRadius.circular(999),
        border: Border.all(
          color: color.withValues(alpha: isActive ? 0.42 : 0.24),
        ),
      ),
      child: Text(
        '$label $value',
        style: GoogleFonts.inter(
          color: foreground,
          fontSize: 10,
          fontWeight: FontWeight.w700,
        ),
      ),
    );
    if (onTap == null) {
      return badge;
    }
    return InkWell(
      onTap: onTap,
      borderRadius: BorderRadius.circular(999),
      child: badge,
    );
  }

  Widget _watchActionFocusBanner(VideoFleetScopeHealthView? focusedScope) {
    final active = _activeWatchActionDrilldown;
    if (active == null) {
      return const SizedBox.shrink();
    }
    final bannerBackground = active.focusBannerBackgroundColor.withValues(alpha: 0.18);
    final bannerActionColor = _adminAccentTextColor(
      active.focusBannerActionColor,
      strength: 0.56,
    );
    final canMutateTemporaryApproval =
        active == VideoFleetWatchActionDrilldown.temporaryIdentity &&
        focusedScope != null;
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
      decoration: BoxDecoration(
        color: bannerBackground,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(
          color: active.focusBannerBorderColor.withValues(alpha: 0.38),
        ),
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  active.focusBannerTitle,
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 10.6,
                    fontWeight: FontWeight.w700,
                  ),
                ),
                const SizedBox(height: 2),
                Text(
                  focusDetailForWatchAction(widget.fleetScopeHealth, active),
                  style: GoogleFonts.inter(
                    color: _adminDialogBodyColor,
                    fontSize: 9.8,
                    fontWeight: FontWeight.w600,
                    height: 1.36,
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(width: 8),
          Wrap(
            spacing: 6,
            runSpacing: 6,
            children: [
              if (canMutateTemporaryApproval &&
                  widget.onExtendTemporaryIdentityApproval != null)
                TextButton(
                  onPressed: () async {
                    final message = await widget
                        .onExtendTemporaryIdentityApproval!(focusedScope);
                    if (!mounted) {
                      return;
                    }
                    _snack(message);
                  },
                  child: Text(
                    'Extend 2h',
                    style: GoogleFonts.inter(
                      color: bannerActionColor,
                      fontSize: 10.5,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ),
              if (canMutateTemporaryApproval &&
                  widget.onExpireTemporaryIdentityApproval != null)
                TextButton(
                  onPressed: () async {
                    final confirmed =
                        await _confirmExpireTemporaryIdentityApproval(
                          focusedScope,
                        );
                    if (!confirmed) {
                      return;
                    }
                    final message = await widget
                        .onExpireTemporaryIdentityApproval!(focusedScope);
                    if (!mounted) {
                      return;
                    }
                    _snack(message);
                  },
                  child: Text(
                    'Expire now',
                    style: GoogleFonts.inter(
                      color: const Color(0xFFB95D5D),
                      fontSize: 10.5,
                      fontWeight: FontWeight.w700,
                    ),
                  ),
                ),
              TextButton(
                onPressed: () => _setActiveWatchActionDrilldown(null),
                child: Text(
                  'Clear',
                  style: GoogleFonts.inter(
                    color: bannerActionColor,
                    fontSize: 10.5,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Future<bool> _confirmExpireTemporaryIdentityApproval(
    VideoFleetScopeHealthView scope,
  ) async {
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (dialogContext) {
        return AlertDialog(
          backgroundColor: _adminDialogSurfaceColor,
          title: Text(
            'Expire Temporary Approval?',
            style: GoogleFonts.inter(
              color: _adminDialogTitleColor,
              fontWeight: FontWeight.w700,
            ),
          ),
          content: Text(
            'This immediately removes the temporary identity approval for ${scope.siteName}. Future matches will no longer be treated as approved.',
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 13,
              fontWeight: FontWeight.w600,
            ),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(dialogContext).pop(false),
              child: const Text('Cancel'),
            ),
            FilledButton(
              onPressed: () => Navigator.of(dialogContext).pop(true),
              style: FilledButton.styleFrom(
                backgroundColor: const Color(0xFFFFF1F1),
                foregroundColor: const Color(0xFFB42318),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(10),
                  side: const BorderSide(color: Color(0xFFE8B6B6)),
                ),
              ),
              child: const Text('Expire now'),
            ),
          ],
        );
      },
    );
    return confirmed == true;
  }

