  Widget _dataCard({
    required String title,
    required List<String> lines,
    required _AdminStatus status,
    bool isDemo = false,
    List<Widget> headerBadges = const [],
    VoidCallback? onTap,
    required VoidCallback onEdit,
    Key? editKey,
    String editTooltip = 'Edit',
    IconData editIcon = Icons.edit_rounded,
    Color editIconColor = const Color(0xFF60A5FA),
    required VoidCallback onDelete,
  }) {
    final body = Container(
      width: double.infinity,
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(
          color: isDemo ? const Color(0xFF8FD1FF) : _adminDialogBorderColor,
        ),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Expanded(
                child: Text(
                  title,
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 13,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
              if (isDemo) ...[
                Container(
                  margin: const EdgeInsets.only(right: 8),
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 3,
                  ),
                  decoration: BoxDecoration(
                    color: const Color(0x223C79BB),
                    borderRadius: BorderRadius.circular(999),
                    border: Border.all(color: const Color(0x663C79BB)),
                  ),
                  child: Text(
                    'DEMO',
                    style: GoogleFonts.inter(
                      color: const Color(0xFF8FD1FF),
                      fontSize: 10,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
              ],
              ...headerBadges,
              _statusChip(status),
              const SizedBox(width: 8),
              IconButton(
                key: editKey,
                onPressed: onEdit,
                tooltip: editTooltip,
                icon: Icon(editIcon, size: 16, color: editIconColor),
                visualDensity: VisualDensity.compact,
              ),
              IconButton(
                onPressed: onDelete,
                tooltip: 'Delete',
                icon: const Icon(
                  Icons.delete_rounded,
                  size: 16,
                  color: Color(0xFFF87171),
                ),
                visualDensity: VisualDensity.compact,
              ),
            ],
          ),
          const SizedBox(height: 4),
          ...lines.map(
            (line) => Padding(
              padding: const EdgeInsets.only(bottom: 2),
              child: Text(
                line,
                style: GoogleFonts.inter(
                  color: _adminDialogBodyColor,
                  fontSize: 12,
                  fontWeight: FontWeight.w600,
                ),
              ),
            ),
          ),
        ],
      ),
    );
    if (onTap == null) {
      return body;
    }
    return Material(
      color: Colors.transparent,
      child: InkWell(
        borderRadius: BorderRadius.circular(10),
        onTap: onTap,
        child: body,
      ),
    );
  }

  Widget _statusChip(_AdminStatus status) {
    final (label, fg, bg, border) = switch (status) {
      _AdminStatus.active => (
        'ACTIVE',
        const Color(0xFF10B981),
        const Color(0x1A10B981),
        const Color(0x6610B981),
      ),
      _AdminStatus.inactive => (
        'INACTIVE',
        const Color(0xFF94A3B8),
        const Color(0x1A94A3B8),
        const Color(0x6694A3B8),
      ),
      _AdminStatus.suspended => (
        'SUSPENDED',
        const Color(0xFFEF4444),
        const Color(0x1AEF4444),
        const Color(0x66EF4444),
      ),
    };

    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(999),
        border: Border.all(color: border),
      ),
      child: Text(
        label,
        style: GoogleFonts.inter(
          color: fg,
          fontSize: 10,
          fontWeight: FontWeight.w800,
        ),
      ),
    );
  }

