  String _siteName(String id) {
    for (final site in _sites) {
      if (site.id == id) return site.name;
    }
    return 'Unassigned';
  }

  String _clientName(String id) {
    for (final client in _clients) {
      if (client.id == id) return client.name;
    }
    return 'Unknown Client';
  }

  Future<void> _openClientCreateFlow({
    AdminApprovedTelegramOnboardingPrefill? initialPrefill,
  }) async {
    final draft = await showDialog<_ClientOnboardingDraft>(
      context: context,
      builder: (dialogContext) => _ClientOnboardingDialog(
        adminFeedbackContext: context,
        demoMode: _demoMode,
        initialPrefill: initialPrefill,
        onOpenTacticalForIncident: widget.onOpenTacticalForIncident,
        onOpenOperationsForIncident: widget.onOpenOperationsForIncident,
        onOpenFleetTacticalScope: widget.onOpenFleetTacticalScope,
        onOpenOperationsForScope: widget.onOpenOperationsForScope,
      ),
    );
    if (!mounted || draft == null) return;
    await _createClientRecord(draft);
  }

  Future<void> _openSiteCreateFlow({
    AdminApprovedTelegramOnboardingPrefill? initialPrefill,
  }) async {
    if (_clients.isEmpty) {
      _snack('Create a client before adding a site.');
      return;
    }
    final draft = await showDialog<_SiteOnboardingDraft>(
      context: context,
      builder: (dialogContext) => _SiteOnboardingDialog(
        clients: _clients,
        adminFeedbackContext: context,
        demoMode: _demoMode,
        initialPrefill: initialPrefill,
        onOpenTacticalForIncident: widget.onOpenTacticalForIncident,
        onOpenOperationsForIncident: widget.onOpenOperationsForIncident,
        onOpenFleetTacticalScope: widget.onOpenFleetTacticalScope,
        onOpenOperationsForScope: widget.onOpenOperationsForScope,
        onOpenCameraBridgeSystemSetup: _openSystemCameraBridgeFromTelegramSeed,
      ),
    );
    if (!mounted || draft == null) return;
    await _createSiteRecord(draft);
  }

  void _openSystemCameraBridgeFromTelegramSeed(
    String siteId,
    String siteName,
    String vendor,
    int? cameraCount,
  ) {
    _focusAdminSystemSection(_AdminSystemSection.systemControls);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      final intakeSummary = <String>[
        if (cameraCount != null) '$cameraCount cameras',
        if (vendor.trim().isNotEmpty) vendor.trim(),
      ].join(', ');
      _focusSystemControlAnchor(
        targetKey: _systemCameraBridgePanelKey,
        message: 'Focused camera bridge setup for $siteId.',
        detail: intakeSummary.isEmpty
            ? 'Camera bridge validation is now pinned for $siteName so CCTV routing can be checked without leaving system controls.'
            : 'Camera bridge validation is now pinned for $siteName. Captured Telegram intake: $intakeSummary.',
        sourceLabel: 'CAMERA BRIDGE',
        accent: const Color(0xFF67E8F9),
      );
    });
  }

  Future<void> _openEmployeeCreateFlow() async {
    if (_clients.isEmpty) {
      _snack('Create a client before adding an employee.');
      return;
    }
    final draft = await showDialog<_EmployeeOnboardingDraft>(
      context: context,
      builder: (dialogContext) => _EmployeeOnboardingDialog(
        clients: _clients,
        sites: _sites,
        adminFeedbackContext: context,
        demoMode: _demoMode,
        onOpenTacticalForIncident: widget.onOpenTacticalForIncident,
        onOpenOperationsForIncident: widget.onOpenOperationsForIncident,
        onOpenFleetTacticalScope: widget.onOpenFleetTacticalScope,
        onOpenOperationsForScope: widget.onOpenOperationsForScope,
      ),
    );
    if (!mounted || draft == null) return;
    await _createEmployeeRecord(draft);
  }

