                    light: true,
                    onTap: () => Navigator.of(
                      dialogContext,
                    ).pop(_AdminSystemLaunchTarget.chatLane),
                  ),
                  _systemLaunchFlowActionCard(
                    key: const ValueKey(
                      'admin-system-launch-flow-watch-identity',
                    ),
                    icon: Icons.shield_outlined,
                    accent: const Color(0xFFA855F7),
                    title: 'Review Watch & Identity',
                    detail:
                        'Jump straight into the watch recovery and identity intake board.',
                    enabled: true,
                    light: true,
                    onTap: () => Navigator.of(
                      dialogContext,
                    ).pop(_AdminSystemLaunchTarget.watchIdentity),
                  ),
                ],
              ),
              const SizedBox(height: 16),
              Align(
                alignment: Alignment.centerRight,
                child: TextButton(
                  key: const ValueKey('admin-system-launch-flow-close'),
                  onPressed: () => Navigator.of(dialogContext).pop(),
