          detail:
              'Temporary approvals, watch recovery, and identity intake controls are now pinned in the active admin board.',
          accent: const Color(0xFFA855F7),
        );
        return;
    }
  }

  Future<void> _openCreateFlow() async {
    switch (_activeTab) {
      case AdministrationPageTab.clients:
        await _openClientCreateFlow();
        return;
      case AdministrationPageTab.sites:
        await _openSiteCreateFlow();
        return;
      case AdministrationPageTab.guards:
        await _openEmployeeCreateFlow();
        return;
      case AdministrationPageTab.system:
        await _openSystemLaunchFlow();
        return;
    }
