            ) !=
            null)
          _SuccessDialogQuickAction(
            icon: Icons.hub_rounded,
            label: 'OPEN DISPATCH BOARD',
            onTap: _openDispatchesAction(
              clientId: clientId,
              siteId: siteId,
              incidentReference: seededIncidentRef ?? '',
            )!,
            foregroundColor: const Color(0xFF93C5FD),
            borderColor: const Color(0xFF35506F),
          ),
        if (_openTacticalAction(
              clientId: clientId,
              siteId: siteId,
              incidentReference: seededIncidentRef ?? '',
            ) !=
            null)
          _SuccessDialogQuickAction(
            icon: Icons.map_rounded,
            label: 'OPEN TACTICAL TRACK',
            onTap: _openTacticalAction(
              clientId: clientId,
              siteId: siteId,
              incidentReference: seededIncidentRef ?? '',
            )!,
            foregroundColor: const Color(0xFF67E8F9),
            borderColor: const Color(0xFF2B5E93),
          ),
        if (seededIncidentRef != null &&
            seededIncidentRef.trim().isNotEmpty &&
            widget.onOpenEventsForIncident != null)
          _SuccessDialogQuickAction(
            icon: Icons.timeline_rounded,
            label: 'OPEN EVENTS SCOPE',
            onTap: () =>
                widget.onOpenEventsForIncident!.call(seededIncidentRef),
            foregroundColor: const Color(0xFFBFD7F2),
            borderColor: const Color(0xFF35506F),
          ),
        if (seededIncidentRef != null &&
            seededIncidentRef.trim().isNotEmpty &&
            widget.onOpenLedgerForIncident != null)
          _SuccessDialogQuickAction(
            icon: Icons.receipt_long_rounded,
            label: 'OPEN SOVEREIGN LEDGER',
            onTap: () =>
                widget.onOpenLedgerForIncident!.call(seededIncidentRef),
            foregroundColor: const Color(0xFFFDE68A),
            borderColor: const Color(0xFF5B3A16),
          ),
        if (_openGovernanceAction(clientId: clientId, siteId: siteId) != null)
          _SuccessDialogQuickAction(
            icon: Icons.fact_check_rounded,
            label: 'OPEN GOVERNANCE DESK',
            onTap: _openGovernanceAction(clientId: clientId, siteId: siteId)!,
            foregroundColor: const Color(0xFF86EFAC),
            borderColor: const Color(0xFF2F5949),
          ),
        if (_openClientLaneAction(clientId: clientId, siteId: siteId) != null)
          _SuccessDialogQuickAction(
            icon: Icons.person_outline_rounded,
            label: 'OPEN CLIENT COMMS',
            onTap: _openClientLaneAction(clientId: clientId, siteId: siteId)!,
            foregroundColor: const Color(0xFFBFD7F2),
            borderColor: const Color(0xFF35506F),
          ),
        if (_openReportsAction(clientId: clientId, siteId: siteId) != null)
          _SuccessDialogQuickAction(
            icon: Icons.assessment_rounded,
            label: 'OPEN REPORTS WORKSPACE',
            onTap: _openReportsAction(clientId: clientId, siteId: siteId)!,
            foregroundColor: const Color(0xFFFFDDAA),
            borderColor: const Color(0xFF5B3A16),
          ),
      ];
      final continueOperationsAction = _openOperationsAction(
        clientId: clientId,
        siteId: siteId,
        incidentReference: seededIncidentRef ?? '',
      );
      final continueLaunchesOperations = continueOperationsAction != null;
      if (autoOpenOperations && continueLaunchesOperations) {
        continueOperationsAction();
        _snack(
          'Security Desk opened with focus: ${seededIncidentRef ?? siteId}',
          sourceLabel: 'SECURITY DESK',
          accent: const Color(0xFF67E8F9),
          detail:
              'The seeded demo route stays pinned in the desktop command rail while Security Desk opens with the live scope focus.',
        );
        return;
      }
      final dialogOutcome = await _showCreateSuccessDialog(
        title: 'Demo Stack Ready',
        subtitle:
            '$profileLabel profile seeded for client, site, employee, and operations.',
        highlights: [
          'Profile: $profileLabel',
          'Client: $clientId',
          'Site: $siteId',
          'Employee: $employeeCode',
          if ((opsSeed.vehicleCallsign ?? '').isNotEmpty)
            'Vehicle: ${opsSeed.vehicleCallsign}',
          if ((opsSeed.incidentEventUid ?? '').isNotEmpty)
            'Incident: ${opsSeed.incidentEventUid}',
          if (opsSeed.warnings.isNotEmpty)
            'Ops seed warnings captured in sync status.',
        ],
        onContinueDemo: continueOperationsAction,
        continueLabel: continueLaunchesOperations
            ? 'Continue to Security Desk'
            : 'Continue Demo',
        focusReference: (seededIncidentRef ?? siteId).trim(),
        quickActions: quickActions,
      );
      if (opsSeed.warnings.isEmpty) {
        _snack('Demo stack ($profileLabel) completed.');
      } else {
        _snack('Demo stack ($profileLabel) completed with ops-seed warnings.');
      }
      final launchedRouteFromDialog =
          dialogOutcome == _SuccessDialogOutcome.quickAction ||
          (dialogOutcome == _SuccessDialogOutcome.continued &&
              continueLaunchesOperations);
      if (!launchedRouteFromDialog && mounted) {
        setState(() {
          _activeTab = AdministrationPageTab.sites;
          _query = siteId;
        });
        widget.onTabChanged?.call(AdministrationPageTab.sites);
        _searchController.text = siteId;
      }
    } finally {
      if (mounted) {
        setState(() => _demoScriptRunning = false);
      }
    }
  }

  Future<_DemoOperationsSeedResult> _seedDemoOperationsData({
    required String suffix,
    required String clientId,
    required String siteId,
    required String employeeCode,
  }) async {
    if (!widget.supabaseReady) {
      return const _DemoOperationsSeedResult(
        warnings: <String>[
          'Ops seed skipped: Supabase is not connected in this session.',
        ],
      );
    }

    final warnings = <String>[];
    final supabase = Supabase.instance.client;
    String? employeeId;
    String? vehicleCallsign;
    String? incidentEventUid;

    try {
      final employeeRowsRaw = await supabase
          .from('employees')
          .select('id')
          .eq('client_id', clientId)
          .eq('employee_code', employeeCode)
          .limit(1);
      final employeeRows = List<Map<String, dynamic>>.from(employeeRowsRaw);
      if (employeeRows.isNotEmpty) {
        final value = (employeeRows.first['id'] ?? '').toString();
        employeeId = value.isEmpty ? null : value;
      }
    } catch (error) {
      warnings.add('Unable to resolve seeded employee UUID for ops links.');
    }

    try {
      vehicleCallsign = 'DEMO-ECHO-$suffix';
      final plateSuffix = suffix.padLeft(5, '0');
      await supabase.from('vehicles').upsert({
        'client_id': clientId,
        'site_id': siteId,
        'vehicle_callsign': vehicleCallsign,
        'license_plate': 'DEMO-$plateSuffix',
        'vehicle_type': 'armed_response_vehicle',
        'maintenance_status': 'ok',
        'service_due_date': DateTime.now()
            .add(const Duration(days: 120))
            .toIso8601String(),
        'roadworthy_expiry': DateTime.now()
            .add(const Duration(days: 300))
            .toIso8601String(),
        'odometer_km': 48210,
        'fuel_percent': 76.5,
        'assigned_employee_id': employeeId,
        'metadata': {
          'demo_seed': true,
          'seed_source': 'admin_demo_script',
          'unit_label': 'Delta-1',
        },
        'is_active': true,
      }, onConflict: 'client_id,vehicle_callsign');
    } catch (error) {
      vehicleCallsign = null;
      warnings.add('Vehicle demo seed failed.');
    }

    try {
      final signal = DateTime.now().toUtc();
      incidentEventUid = 'DEMO-EVT-$suffix';
      await supabase.from('incidents').upsert({
        'event_uid': incidentEventUid,
        'client_id': clientId,
        'site_id': siteId,
        'incident_type': 'breach',
        'priority': 'p2',
        'status': 'dispatched',
        'signal_received_at': signal.toIso8601String(),
        'triage_time': signal
            .add(const Duration(seconds: 22))
            .toIso8601String(),
        'dispatch_time': signal
            .add(const Duration(minutes: 1))
            .toIso8601String(),
        'controller_notes':
            'Demo breach detected at North Gate perimeter. Delta-1 pre-alert issued.',
        'field_report': 'Demo unit acknowledged dispatch. ETA under 3 minutes.',
        'media_attachments': <String>[],
        'evidence_hash': 'demo-evidence-$suffix',
        'linked_employee_id': employeeId,
        'linked_guard_ops_event_id': 'DEMO-GOPS-$suffix',
        'metadata': {
          'demo_seed': true,
          'seed_source': 'admin_demo_script',
          'incident_cluster': 'demo-cluster-a',
        },
      }, onConflict: 'event_uid');
    } catch (error) {
      incidentEventUid = null;
      warnings.add('Incident demo seed failed.');
    }

    return _DemoOperationsSeedResult(
      vehicleCallsign: vehicleCallsign,
      incidentEventUid: incidentEventUid,
      warnings: warnings,
    );
  }

  bool _isDemoIdentifier(String value) {
    return value.trim().toUpperCase().startsWith('DEMO-');
  }

  Future<void> _clearDemoData() async {
    if (_directorySaving || _demoScriptRunning || _demoCleanupRunning) return;
    final confirmed = await showDialog<bool>(
      context: context,
      builder: (dialogContext) {
        return AlertDialog(
          key: _adminDemoResetDialogKey,
          backgroundColor: _adminDialogSurfaceColor,
          shape: _adminDialogShape(borderColor: const Color(0xFFF3B0B8)),
          titlePadding: const EdgeInsets.fromLTRB(24, 20, 24, 0),
          contentPadding: const EdgeInsets.fromLTRB(24, 16, 24, 0),
          title: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Text(
                'DEMO CLEANUP',
                style: GoogleFonts.inter(
                  color: const Color(0xFFB91C1C),
                  fontSize: 10,
                  fontWeight: FontWeight.w800,
                  letterSpacing: 0.9,
                ),
              ),
              const SizedBox(height: 6),
              Text(
                'Reset Demo Data?',
                style: GoogleFonts.inter(
                  color: _adminDialogTitleColor,
                  fontSize: 16,
                  fontWeight: FontWeight.w700,
                ),
              ),
              const SizedBox(height: 10),
              Container(
                key: _adminDemoResetStatusKey,
                padding: const EdgeInsets.symmetric(
                  horizontal: 10,
                  vertical: 8,
                ),
                decoration: BoxDecoration(
                  color: const Color(0xFFFFF4E8),
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: const Color(0x66F97316)),
                ),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'NEXT MOVE',
                      style: GoogleFonts.inter(
                        color: const Color(0xFFB45309),
                        fontSize: 9.5,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.8,
                      ),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      'Seal cleanup and return the storyboard to an unseeded state.',
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 11,
                        fontWeight: FontWeight.w700,
                        height: 1.3,
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
          content: Text(
            'This clears every DEMO-* client, site, employee, assignment, vehicle, and incident record, then returns the storyboard to a clean command surface.',
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 12,
              fontWeight: FontWeight.w600,
              height: 1.4,
            ),
          ),
          actions: [
            TextButton(
              onPressed: () => Navigator.of(dialogContext).pop(false),
              child: Text(
                'Hold State',
                style: GoogleFonts.inter(
                  color: _adminDialogMutedColor,
                  fontWeight: FontWeight.w700,
                ),
              ),
            ),
            FilledButton.icon(
              key: _adminDemoResetConfirmButtonKey,
              onPressed: () => Navigator.of(dialogContext).pop(true),
              icon: const Icon(Icons.delete_sweep_rounded, size: 16),
              style: FilledButton.styleFrom(
                backgroundColor: const Color(0xFFFFF1F1),
                foregroundColor: const Color(0xFFB42318),
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(10),
                  side: const BorderSide(color: Color(0xFFE8B6B6)),
                ),
              ),
              label: Text(
                'Seal Cleanup',
                style: GoogleFonts.inter(fontWeight: FontWeight.w700),
              ),
            ),
          ],
        );
      },
    );
    if (confirmed != true) return;

    setState(() => _demoCleanupRunning = true);
    var clearedClients = 0;
    var clearedSites = 0;
    var clearedEmployees = 0;
    try {
      if (widget.supabaseReady) {
        final supabase = Supabase.instance.client;
        final demoClientsRaw = await supabase
            .from('clients')
            .select('client_id')
            .ilike('client_id', 'DEMO-%');
        final demoClientIds = List<Map<String, dynamic>>.from(demoClientsRaw)
            .map((row) => (row['client_id'] ?? '').toString())
            .where((id) {
              return id.isNotEmpty;
            })
            .toList(growable: false);

        final demoEmployeesRaw = await supabase
            .from('employees')
            .select('id, employee_code')
            .ilike('employee_code', 'DEMO-%');
        final demoEmployeeIds =
            List<Map<String, dynamic>>.from(demoEmployeesRaw)
                .map((row) => (row['id'] ?? '').toString())
                .where((id) {
                  return id.isNotEmpty;
                })
                .toList(growable: false);

        final demoSitesRaw = await supabase
            .from('sites')
            .select('site_id')
            .ilike('site_id', 'DEMO-%');
        final demoSiteIds = List<Map<String, dynamic>>.from(demoSitesRaw)
            .map((row) => (row['site_id'] ?? '').toString())
            .where((id) {
              return id.isNotEmpty;
            })
            .toList(growable: false);
        clearedClients = demoClientIds.length;
        clearedSites = demoSiteIds.length;
        clearedEmployees = demoEmployeeIds.length;

        Future<void> tryDeleteByFilter({
          required String table,
          required String column,
          required List<String> values,
        }) async {
          if (values.isEmpty) return;
          try {
            await supabase.from(table).delete().inFilter(column, values);
          } catch (_) {
            // Best-effort cleanup for optional legacy/expanded tables.
          }
        }

        await tryDeleteByFilter(
          table: 'employee_site_assignments',
          column: 'employee_id',
          values: demoEmployeeIds,
        );
        await tryDeleteByFilter(
          table: 'guards',
          column: 'source_employee_id',
          values: demoEmployeeIds,
        );
        await tryDeleteByFilter(
          table: 'controllers',
          column: 'source_employee_id',
          values: demoEmployeeIds,
        );
        await tryDeleteByFilter(
          table: 'staff',
          column: 'source_employee_id',
          values: demoEmployeeIds,
        );
        await tryDeleteByFilter(
          table: 'guards',
          column: 'client_id',
          values: demoClientIds,
        );
        await tryDeleteByFilter(
          table: 'controllers',
          column: 'client_id',
          values: demoClientIds,
        );
        await tryDeleteByFilter(
          table: 'staff',
          column: 'client_id',
          values: demoClientIds,
        );
        await tryDeleteByFilter(
          table: 'incidents',
          column: 'site_id',
          values: demoSiteIds,
        );
        await tryDeleteByFilter(
          table: 'vehicles',
          column: 'site_id',
          values: demoSiteIds,
        );
        await tryDeleteByFilter(
          table: 'vehicles',
          column: 'client_id',
          values: demoClientIds,
        );
        await tryDeleteByFilter(
          table: 'client_contact_endpoint_subscriptions',
          column: 'client_id',
          values: demoClientIds,
        );
        await tryDeleteByFilter(
          table: 'client_messaging_endpoints',
          column: 'client_id',
          values: demoClientIds,
        );
        await tryDeleteByFilter(
          table: 'client_contacts',
          column: 'client_id',
          values: demoClientIds,
        );

        if (demoEmployeeIds.isNotEmpty) {
          await supabase
              .from('employees')
              .delete()
              .inFilter('id', demoEmployeeIds);
        }
        if (demoSiteIds.isNotEmpty) {
          await supabase
              .from('sites')
              .delete()
              .inFilter('site_id', demoSiteIds);
        }
        if (demoClientIds.isNotEmpty) {
          await supabase
              .from('clients')
              .delete()
              .inFilter('client_id', demoClientIds);
        }
        await _loadDirectoryFromSupabase();
      } else {
        final beforeClients = _clients.length;
        final beforeSites = _sites.length;
        final beforeEmployees = _guards.length;
        setState(() {
          _clients = _clients
              .where((row) => !_isDemoIdentifier(row.id))
              .toList(growable: false);
          _sites = _sites
              .where((row) => !_isDemoIdentifier(row.id))
              .toList(growable: false);
          _guards = _guards
              .where(
                (row) =>
                    !_isDemoIdentifier(row.id) &&
                    !_isDemoIdentifier(row.employeeId),
              )
              .toList(growable: false);
          _directorySyncMessage = 'Demo records cleared from local directory.';
        });
        clearedClients = beforeClients - _clients.length;
        clearedSites = beforeSites - _sites.length;
        clearedEmployees = beforeEmployees - _guards.length;
      }
      if (!mounted) return;
      setState(() {
        _query = '';
        _searchController.clear();
        _demoStoryClientId = null;
        _demoStorySiteId = null;
        _demoStoryEmployeeCode = null;
        _demoStoryVehicleCallsign = null;
        _demoStoryIncidentEventUid = null;
        _demoStoryUpdatedAt = null;
      });
      _snack(
        'Demo data cleared: $clearedClients client(s), $clearedSites site(s), $clearedEmployees employee(s).',
        sourceLabel: 'DEMO CLEANUP',
        accent: const Color(0xFFFDA4AF),
        detail:
            'The cleanup result stays pinned in the desktop command rail while the storyboard returns to an unseeded state.',
      );
    } catch (error) {
      if (!mounted) return;
      _snack(
        'Failed to clear demo data.',
        sourceLabel: 'DEMO CLEANUP',
        accent: const Color(0xFFF59E0B),
        detail:
            'The cleanup failure stays pinned in the desktop command rail so you can retry without losing the current demo context.',
      );
      setState(() {
        _directorySyncMessage = 'Demo cleanup failed: $error';
      });
    } finally {
      if (mounted) {
        setState(() => _demoCleanupRunning = false);
      }
    }
  }

  Future<bool> _createClientRecord(
    _ClientOnboardingDraft draft, {
    bool showFeedback = true,
  }) async {
    setState(() => _directorySaving = true);
    var chatcheckSummary = 'Telegram bridge disabled or in-app only.';
    String? chatcheckResult;
    var clientSaved = false;
    AdminWriteFollowUpOutcome? postWriteOutcome;
    try {
      if (widget.supabaseReady) {
        final supabase = Supabase.instance.client;
        await supabase.from('clients').upsert({
          'client_id': draft.clientId,
          'display_name': draft.legalName,
          'legal_name': draft.legalName,
          'client_type': draft.clientType,
          'billing_address': draft.billingAddress.isEmpty
              ? null
              : draft.billingAddress,
          'vat_number': draft.vatNumber.isEmpty ? null : draft.vatNumber,
          'sovereign_contact': draft.sovereignContact.isEmpty
              ? null
              : draft.sovereignContact,
          'contact_name': draft.contactName.isEmpty ? null : draft.contactName,
          'contact_email': draft.contactEmail.isEmpty
              ? null
              : draft.contactEmail,
          'contact_phone': draft.contactPhone.isEmpty
              ? null
              : draft.contactPhone,
          'contract_start': draft.contractStart?.toIso8601String(),
          'metadata': {'sla_tier': draft.slaTier, 'code': draft.clientId},
          'is_active': true,
        }, onConflict: 'client_id');
        clientSaved = true;
        final messagingRepository = _clientMessagingBridgeRepository(
          client: supabase,
        );
        await messagingRepository.upsertOnboardingSetup(
          ClientMessagingOnboardingSetup(
            clientId: draft.clientId,
            contactName: _resolvedClientContactName(draft),
            contactRole: 'sovereign_contact',
            contactPhone: draft.contactPhone,
            contactEmail: draft.contactEmail,
            contactConsentConfirmed: draft.contactConsentConfirmed,
            provider: draft.messagingProvider,
            endpointLabel: draft.messagingEndpointLabel,
            telegramChatId: draft.telegramChatId,
            telegramThreadId: draft.telegramThreadId,
            incidentPriorities: _incidentPrioritiesForPolicy(
              draft.incidentRoutingPolicy,
            ),
            incidentTypes: const <String>[],
          ),
        );
        if (draft.messagingProvider == 'telegram' &&
            draft.telegramChatId.trim().isNotEmpty) {
          final runChatcheck = widget.onRunSiteTelegramChatcheck;
          if (runChatcheck != null) {
            final threadId = int.tryParse(draft.telegramThreadId.trim());
            try {
              final check = await runChatcheck(
                clientId: draft.clientId,
                siteId: null,
                chatId: draft.telegramChatId.trim(),
                threadId: threadId,
                endpointLabel: draft.messagingEndpointLabel.trim().isEmpty
                    ? 'Primary Client Telegram'
                    : draft.messagingEndpointLabel.trim(),
              );
              chatcheckResult = check;
              chatcheckSummary = 'Telegram chatcheck: $check';
            } catch (error) {
              chatcheckResult = 'FAIL ($error)';
              chatcheckSummary = 'Telegram chatcheck: FAIL ($error)';
            }
          } else {
            chatcheckResult = 'SKIP (runtime hook missing)';
            chatcheckSummary =
                'Telegram chatcheck: SKIP (runtime hook missing)';
          }
        } else if (draft.messagingProvider == 'telegram') {
          chatcheckResult = 'SKIP (chat ID missing)';
          chatcheckSummary = 'Telegram chatcheck: SKIP (chat ID missing)';
        }
        try {
          await _loadDirectoryFromSupabase();
        } catch (error) {
          final refreshOutcome = resolveAdminWriteFollowUpOutcome(
            primaryWriteCompleted: true,
            failureMessage: 'Failed to save client.',
            successWarningMessage:
                'Client ${draft.clientId} saved with follow-up warning.',
            successWarningDetail:
                'The client record was saved before the directory refresh failed',
            failureDetailPrefix: 'Client save failed',
            error: error,
          );
          postWriteOutcome = refreshOutcome;
          if (mounted) {
            setState(() {
              _directorySyncMessage = refreshOutcome.detail;
            });
          }
        }
      } else {
        final row = _ClientAdminRow(
          id: draft.clientId,
          name: draft.legalName,
          code: draft.clientId,
          contactPerson: draft.contactName.isEmpty
              ? draft.sovereignContact
              : draft.contactName,
          contactEmail: draft.contactEmail,
          contactPhone: draft.contactPhone,
          slaTier: draft.slaTier,
          contractStart: _dateLabel(draft.contractStart),
          contractEnd: '-',
          sites: 0,
          status: _AdminStatus.active,
        );
        setState(() {
          _clients = [..._clients, row];
          _directorySyncMessage = 'Client ${draft.clientId} saved locally.';
        });
        if (draft.messagingProvider == 'telegram') {
          chatcheckResult = 'SKIP (Supabase/runtime bridge required)';
          chatcheckSummary =
              'Telegram chatcheck: SKIP (Supabase/runtime bridge required)';
        }
      }
      if (chatcheckResult != null) {
        _recordChatcheckResult(
          clientId: draft.clientId,
          siteId: null,
          result: chatcheckResult,
        );
      }
      if (_demoMode) {
        _recordDemoStoryboard(clientId: draft.clientId);
      }
      if (showFeedback && _demoMode && mounted) {
        final quickActions = _buildDirectoryCreateQuickActions(
          focusReference: draft.clientId.trim(),
          clientId: draft.clientId,
          includeTours: false,
          includeClientView: true,
          includeReports: true,
        );
        await _showCreateSuccessDialog(
          title: 'Client Demo Ready',
          subtitle: '${draft.legalName} has been onboarded.',
          highlights: [
            'Client ID: ${draft.clientId}',
            'Service: ${draft.clientType.replaceAll('_', ' ')}',
            'SLA Tier: ${draft.slaTier.toUpperCase()}',
            'Messaging: ${draft.messagingProvider}${draft.messagingProvider == 'telegram' && draft.telegramChatId.trim().isNotEmpty ? ' (${draft.telegramChatId.trim()})' : ''}',
            chatcheckSummary,
          ],
          focusReference: draft.clientId.trim(),
          quickActions: quickActions,
        );
      }
      if (showFeedback && mounted) {
        _snack(postWriteOutcome?.message ?? 'Client ${draft.clientId} saved.');
      }
      return true;
    } catch (error) {
      postWriteOutcome = resolveAdminWriteFollowUpOutcome(
        primaryWriteCompleted: clientSaved,
        failureMessage: 'Failed to save client.',
        successWarningMessage:
            'Client ${draft.clientId} saved with follow-up warning.',
        successWarningDetail:
            'The client record was saved before a later follow-up step failed',
        failureDetailPrefix: 'Client save failed',
        error: error,
      );
      final outcome = postWriteOutcome;
      if (showFeedback && mounted) {
        _snack(outcome.message, detail: outcome.detail);
      }
      if (mounted) {
        setState(() {
          _directorySyncMessage = outcome.detail;
        });
      }
      return outcome.treatAsSuccess;
    } finally {
      if (mounted) {
        setState(() => _directorySaving = false);
      }
    }
  }

  String _resolvedClientContactName(_ClientOnboardingDraft draft) {
    final primary = draft.contactName.trim();
    if (primary.isNotEmpty) return primary;
    final sovereign = draft.sovereignContact.trim();
    if (sovereign.isNotEmpty) return sovereign;
    return '${draft.legalName.trim()} Contact';
  }

  List<String> _incidentPrioritiesForPolicy(String policy) {
    return switch (policy.trim().toLowerCase()) {
      'p1_only' => const <String>['p1'],
      'p1_p2' => const <String>['p1', 'p2'],
      _ => const <String>['p1', 'p2', 'p3', 'p4'],
    };
  }

  DvrHttpAuthConfig _siteCameraAuthConfigFromDraft(_SiteOnboardingDraft draft) {
    return DvrHttpAuthConfig(
      mode: parseDvrHttpAuthMode(draft.cameraAuthMode),
      username: draft.cameraUsername.trim().isEmpty
          ? null
          : draft.cameraUsername.trim(),
      password: draft.cameraPassword.isEmpty ? null : draft.cameraPassword,
      bearerToken: draft.cameraBearerToken.trim().isEmpty
          ? null
          : draft.cameraBearerToken.trim(),
    );
  }

  DvrHttpAuthConfig _siteCameraAuthConfigFromRow(_SiteAdminRow row) {
    return row.cameraAuthConfig;
  }

  Map<String, dynamic> _siteMetadataWithCameraControl({
    required Map<String, dynamic> baseMetadata,
    required DvrHttpAuthConfig credentials,
  }) {
    final metadata = Map<String, dynamic>.from(baseMetadata);
    if (credentials.configured) {
      metadata['camera_control_auth'] = credentials.toJsonMap();
    } else {
      metadata.remove('camera_control_auth');
    }
    return metadata;
  }

  Future<void> _rememberSiteCameraAuthConfig({
    required String clientId,
    required String siteId,
    required DvrHttpAuthConfig credentials,
  }) async {
    final callback = widget.onSaveSiteCameraAuthConfig;
    if (callback == null) {
      return;
    }
    await callback(
      clientId: clientId,
      siteId: siteId,
      credentials: credentials,
    );
  }

  Future<bool> _createSiteRecord(
    _SiteOnboardingDraft draft, {
    bool showFeedback = true,
  }) async {
    final siteLatitude = draft.latitude ?? Site.defaultLatitude;
    final siteLongitude = draft.longitude ?? Site.defaultLongitude;
    final cameraAuthConfig = _siteCameraAuthConfigFromDraft(draft);
    setState(() => _directorySaving = true);
    var chatcheckSummary = 'Telegram bridge inherits client default.';
    String? chatcheckResult;
    var siteSaved = false;
    AdminWriteFollowUpOutcome? postWriteOutcome;
    try {
      if (widget.supabaseReady) {
        final supabase = Supabase.instance.client;
        await supabase.from('sites').upsert({
          'site_id': draft.siteId,
          'client_id': draft.clientId,
          'site_name': draft.siteName,
          'site_code': draft.siteCode.isEmpty ? null : draft.siteCode,
          'timezone': 'Africa/Johannesburg',
          'physical_address': draft.address,
          'latitude': siteLatitude,
          'longitude': siteLongitude,
          'geofence_radius_meters': draft.geofenceRadiusMeters.toDouble(),
          'entry_protocol': draft.entryProtocol.isEmpty
              ? null
              : draft.entryProtocol,
          'site_layout_map_url': draft.siteLayoutMapUrl.isEmpty
              ? null
              : draft.siteLayoutMapUrl,
          'risk_profile': draft.riskProfile,
          'risk_rating': _riskRatingFromProfile(draft.riskProfile),
          'guard_nudge_frequency_minutes': draft.guardNudgeFrequencyMinutes,
          'escalation_trigger_minutes': draft.escalationTriggerMinutes,
          'metadata': _siteMetadataWithCameraControl(
            baseMetadata: <String, dynamic>{
              'onboarding_source': 'admin_stepper',
              'risk_profile': draft.riskProfile,
            },
            credentials: cameraAuthConfig,
          ),
          'is_active': true,
        }, onConflict: 'site_id');
        siteSaved = true;
        await _rememberSiteCameraAuthConfig(
          clientId: draft.clientId,
          siteId: draft.siteId,
          credentials: cameraAuthConfig,
        );
        if (draft.enableTelegramBridge &&
            draft.telegramChatId.trim().isNotEmpty) {
          final messagingRepository = _clientMessagingBridgeRepository(
            client: supabase,
          );
          await messagingRepository.upsertOnboardingSetup(
            ClientMessagingOnboardingSetup(
              clientId: draft.clientId,
              siteId: draft.siteId,
              contactName: '${draft.siteName} Site Desk',
              contactRole: 'site_control',
              contactConsentConfirmed: true,
              provider: 'telegram',
              endpointLabel: draft.messagingEndpointLabel,
              telegramChatId: draft.telegramChatId,
              telegramThreadId: draft.telegramThreadId,
              incidentPriorities: const <String>['p1', 'p2', 'p3', 'p4'],
              incidentTypes: const <String>[],
            ),
          );
          final runChatcheck = widget.onRunSiteTelegramChatcheck;
          if (runChatcheck != null) {
            final threadId = int.tryParse(draft.telegramThreadId.trim());
            try {
              final check = await runChatcheck(
                clientId: draft.clientId,
                siteId: draft.siteId,
                chatId: draft.telegramChatId.trim(),
                threadId: threadId,
                endpointLabel: draft.messagingEndpointLabel.trim().isEmpty
                    ? 'Primary Site Telegram'
                    : draft.messagingEndpointLabel.trim(),
              );
              chatcheckResult = check;
              chatcheckSummary = 'Telegram chatcheck: $check';
            } catch (error) {
              chatcheckResult = 'FAIL ($error)';
              chatcheckSummary = 'Telegram chatcheck: FAIL ($error)';
            }
          } else {
            chatcheckResult = 'SKIP (runtime hook missing)';
            chatcheckSummary =
                'Telegram chatcheck: SKIP (runtime hook missing)';
          }
        } else if (draft.enableTelegramBridge) {
          chatcheckResult = 'SKIP (chat ID missing)';
          chatcheckSummary = 'Telegram chatcheck: SKIP (chat ID missing)';
        }
        try {
          await _loadDirectoryFromSupabase();
        } catch (error) {
          final refreshOutcome = resolveAdminWriteFollowUpOutcome(
            primaryWriteCompleted: true,
            failureMessage: 'Failed to save site.',
            successWarningMessage:
                'Site ${draft.siteId} saved with follow-up warning.',
            successWarningDetail:
                'The site record was saved before the directory refresh failed',
            failureDetailPrefix: 'Site save failed',
            error: error,
          );
          postWriteOutcome = refreshOutcome;
          if (mounted) {
            setState(() {
              _directorySyncMessage = refreshOutcome.detail;
            });
          }
        }
      } else {
        final row = _SiteAdminRow(
          id: draft.siteId,
          name: draft.siteName,
          code: draft.siteCode.isEmpty ? draft.siteId : draft.siteCode,
          clientId: draft.clientId,
          address: draft.address,
          lat: siteLatitude,
          lng: siteLongitude,
          contactPerson: '-',
          contactPhone: '-',
          geofenceRadiusMeters: draft.geofenceRadiusMeters,
          cameraAuthMode: draft.cameraAuthMode,
          cameraUsername: draft.cameraUsername,
          cameraPassword: draft.cameraPassword,
          cameraBearerToken: draft.cameraBearerToken,
          status: _AdminStatus.active,
        );
        setState(() {
          _sites = [..._sites, row];
          _clients = _clients
              .map(
                (client) => client.id == draft.clientId
                    ? _ClientAdminRow(
                        id: client.id,
                        name: client.name,
                        code: client.code,
                        contactPerson: client.contactPerson,
                        contactEmail: client.contactEmail,
                        contactPhone: client.contactPhone,
                        slaTier: client.slaTier,
                        contractStart: client.contractStart,
                        contractEnd: client.contractEnd,
                        sites: client.sites + 1,
                        status: client.status,
                      )
                    : client,
              )
              .toList(growable: false);
          _directorySyncMessage = 'Site ${draft.siteId} saved locally.';
        });
        await _rememberSiteCameraAuthConfig(
          clientId: draft.clientId,
          siteId: draft.siteId,
          credentials: cameraAuthConfig,
        );
        if (draft.enableTelegramBridge) {
          chatcheckResult = 'SKIP (Supabase/runtime bridge required)';
          chatcheckSummary =
              'Telegram chatcheck: SKIP (Supabase/runtime bridge required)';
        }
      }
      if (chatcheckResult != null) {
        _recordChatcheckResult(
          clientId: draft.clientId,
          siteId: draft.siteId,
          result: chatcheckResult,
        );
      }
      if (_demoMode) {
        _recordDemoStoryboard(siteId: draft.siteId);
      }
      if (showFeedback && _demoMode && mounted) {
        final quickActions = _buildDirectoryCreateQuickActions(
          focusReference: draft.siteId.trim(),
          clientId: draft.clientId,
          siteId: draft.siteId,
          includeTours: false,
        );
        await _showCreateSuccessDialog(
          title: 'Site Demo Ready',
          subtitle: '${draft.siteName} is now deployable.',
          highlights: [
            'Site ID: ${draft.siteId}',
            'Risk Profile: ${draft.riskProfile.replaceAll('_', ' ')}',
            'Nudge/Escalation: ${draft.guardNudgeFrequencyMinutes}/${draft.escalationTriggerMinutes} min',
            'Messaging: ${draft.enableTelegramBridge ? 'telegram (${draft.telegramChatId.trim().isEmpty ? 'pending chat id' : draft.telegramChatId.trim()})' : 'inherit Client Comms default'}',
            chatcheckSummary,
          ],
          focusReference: draft.siteId.trim(),
          quickActions: quickActions,
        );
      }
      if (showFeedback && mounted) {
        _snack(postWriteOutcome?.message ?? 'Site ${draft.siteId} saved.');
      }
      return true;
    } catch (error) {
      postWriteOutcome = resolveAdminWriteFollowUpOutcome(
        primaryWriteCompleted: siteSaved,
        failureMessage: 'Failed to save site.',
        successWarningMessage:
            'Site ${draft.siteId} saved with follow-up warning.',
        successWarningDetail:
            'The site record was saved before a later follow-up step failed',
        failureDetailPrefix: 'Site save failed',
        error: error,
      );
      final outcome = postWriteOutcome;
      if (showFeedback && mounted) {
        _snack(outcome.message, detail: outcome.detail);
      }
      if (mounted) {
        setState(() {
          _directorySyncMessage = outcome.detail;
        });
      }
      return outcome.treatAsSuccess;
    } finally {
      if (mounted) {
        setState(() => _directorySaving = false);
      }
    }
  }

  Future<bool> _createEmployeeRecord(
    _EmployeeOnboardingDraft draft, {
    bool showFeedback = true,
  }) async {
    setState(() => _directorySaving = true);
    var employeeSaved = false;
    AdminWriteFollowUpOutcome? postWriteOutcome;
    try {
      if (widget.supabaseReady) {
        final employee = await Supabase.instance.client
            .from('employees')
            .upsert({
              'client_id': draft.clientId,
              'employee_code': draft.employeeCode,
              'full_name': draft.fullName,
              'surname': draft.surname,
              'id_number': draft.idNumber,
              'date_of_birth': draft.dateOfBirth?.toIso8601String(),
              'primary_role': draft.role,
              'psira_number': draft.psiraNumber.isEmpty
                  ? null
                  : draft.psiraNumber,
              'psira_grade': draft.psiraGrade.isEmpty ? null : draft.psiraGrade,
              'psira_expiry': draft.psiraExpiry?.toIso8601String(),
              'has_driver_license': draft.hasDriverLicense,
              'driver_license_code': draft.hasDriverLicense
                  ? draft.driverLicenseCode
                  : null,
              'driver_license_expiry': draft.driverLicenseExpiry
                  ?.toIso8601String(),
              'has_pdp': draft.hasPdp,
              'pdp_expiry': draft.pdpExpiry?.toIso8601String(),
              'device_uid': draft.deviceUid.isEmpty ? null : draft.deviceUid,
              'contact_phone': draft.contactPhone.isEmpty
                  ? null
                  : draft.contactPhone,
              'contact_email': draft.contactEmail.isEmpty
                  ? null
                  : draft.contactEmail,
              'employment_status': 'active',
              'metadata': {
                'onboarding_source': 'admin_stepper',
                'biometric_hash_captured': false,
              },
              'firearm_competency': {},
              'issued_firearm_serials': <String>[],
            }, onConflict: 'client_id,employee_code')
            .select('id')
            .single();
        employeeSaved = true;

        if (draft.assignedSiteId.isNotEmpty) {
          await Supabase.instance.client
              .from('employee_site_assignments')
              .upsert({
                'client_id': draft.clientId,
                'employee_id': employee['id'],
                'site_id': draft.assignedSiteId,
                'is_primary': true,
                'assignment_status': 'active',
              }, onConflict: 'employee_id,site_id');
        }
        try {
          await _loadDirectoryFromSupabase();
        } catch (error) {
          final refreshOutcome = resolveAdminWriteFollowUpOutcome(
            primaryWriteCompleted: true,
            failureMessage: 'Failed to save employee.',
            successWarningMessage:
                'Employee ${draft.employeeCode} saved with follow-up warning.',
            successWarningDetail:
                'The employee record was saved before the directory refresh failed',
            failureDetailPrefix: 'Employee save failed',
            error: error,
          );
          postWriteOutcome = refreshOutcome;
          if (mounted) {
            setState(() {
              _directorySyncMessage = refreshOutcome.detail;
            });
          }
        }
      } else {
        final row = _GuardAdminRow(
          id: draft.employeeCode,
          name: '${draft.fullName} ${draft.surname}'.trim(),
          role: draft.role,
          employeeId: draft.employeeCode,
          phone: draft.contactPhone,
          email: draft.contactEmail,
          psiraNumber: draft.psiraNumber,
          psiraExpiry: _dateLabel(draft.psiraExpiry),
          certifications: [
            if (draft.psiraGrade.isNotEmpty) 'PSIRA ${draft.psiraGrade}',
            if (draft.hasDriverLicense)
              'Driver License ${draft.driverLicenseCode}',
            if (draft.hasPdp) 'PDP',
          ],
          assignedSite: draft.assignedSiteId,
          shiftPattern: 'Unassigned',
          emergencyContact: '-',
          status: _AdminStatus.active,
        );
        setState(() {
          _guards = [..._guards, row];
          _directorySyncMessage =
              'Employee ${draft.employeeCode} saved locally.';
        });
      }
      if (_demoMode) {
        _recordDemoStoryboard(employeeCode: draft.employeeCode);
      }
      if (showFeedback && _demoMode && mounted) {
        final focusReference = draft.assignedSiteId.trim().isEmpty
            ? draft.employeeCode.trim()
            : draft.assignedSiteId.trim();
        final quickActions = _buildDirectoryCreateQuickActions(
          focusReference: focusReference,
          clientId: draft.clientId,
          siteId: draft.assignedSiteId,
          includeTours: false,
        );
        await _showCreateSuccessDialog(
          title: 'Employee Demo Ready',
          subtitle: '${draft.fullName} ${draft.surname} added to registry.',
          highlights: [
            'Employee Code: ${draft.employeeCode}',
            'Role: ${draft.role.replaceAll('_', ' ')}',
            'Assignment: ${draft.assignedSiteId.isEmpty ? 'Unassigned' : draft.assignedSiteId}',
          ],
          focusReference: focusReference,
          quickActions: quickActions,
        );
      }
      if (showFeedback && mounted) {
        _snack(
          postWriteOutcome?.message ?? 'Employee ${draft.employeeCode} saved.',
        );
      }
      return true;
    } catch (error) {
      postWriteOutcome = resolveAdminWriteFollowUpOutcome(
        primaryWriteCompleted: employeeSaved,
        failureMessage: 'Failed to save employee.',
        successWarningMessage:
            'Employee ${draft.employeeCode} saved with follow-up warning.',
        successWarningDetail:
            'The employee record was saved before a later follow-up step failed',
        failureDetailPrefix: 'Employee save failed',
        error: error,
      );
      final outcome = postWriteOutcome;
      if (showFeedback && mounted) {
        _snack(outcome.message, detail: outcome.detail);
      }
      if (mounted) {
        setState(() {
          _directorySyncMessage = outcome.detail;
        });
      }
      return outcome.treatAsSuccess;
    } finally {
      if (mounted) {
        setState(() => _directorySaving = false);
      }
    }
  }

  Future<void> _loadDirectoryFromSupabase() async {
    if (!widget.supabaseReady) return;
    setState(() {
      _directoryLoading = true;
      _directorySyncMessage = 'Syncing directory from Supabase…';
    });
    try {
      final snapshot = await widget.adminDirectoryService.loadDirectory(
        supabase: Supabase.instance.client,
        partnerEndpointLabelPrefix: _partnerEndpointLabelPrefix,
      );

      if (!mounted) return;
      final partnerScope = _resolvePartnerRuntimeScope(
        clients: snapshot.clients,
        sites: snapshot.sites,
        preferredClientId: _partnerRuntimeClientId,
        preferredSiteId: _partnerRuntimeSiteId,
      );
      setState(() {
        _clients = snapshot.clients;
        _sites = snapshot.sites;
        _guards = snapshot.guards;
        _partnerRuntimeClientId = partnerScope.clientId;
        _partnerRuntimeSiteId = partnerScope.siteId;
        _clientMessagingEndpointCounts = snapshot.clientMessagingEndpointCounts;
        _clientTelegramEndpointCounts = snapshot.clientTelegramEndpointCounts;
        _clientMessagingContactCounts = snapshot.clientMessagingContactCounts;
        _clientPartnerEndpointCounts = snapshot.clientPartnerEndpointCounts;
        _clientMessagingLanePreview = snapshot.clientMessagingLanePreview;
        _clientPartnerLanePreview = snapshot.clientPartnerLanePreview;
        _clientPartnerLaneDetails = snapshot.clientPartnerLaneDetails;
        _clientTelegramChatcheckStatus = snapshot.clientTelegramChatcheckStatus;
        _siteTelegramChatcheckStatus = snapshot.siteTelegramChatcheckStatus;
        _clientPartnerChatcheckStatus = snapshot.clientPartnerChatcheckStatus;
        _sitePartnerEndpointCounts = snapshot.sitePartnerEndpointCounts;
        _sitePartnerChatcheckStatus = snapshot.sitePartnerChatcheckStatus;
        _sitePartnerLaneDetails = snapshot.sitePartnerLaneDetails;
        _directoryLoadedFromSupabase = true;
        _directorySyncMessage =
            'Directory synced: ${snapshot.clients.length} clients, ${snapshot.sites.length} sites, ${snapshot.guards.length} employees.';
      });
    } catch (error) {
      if (!mounted) return;
      setState(() {
        _directoryLoadedFromSupabase = false;
        _clientMessagingEndpointCounts = const {};
        _clientTelegramEndpointCounts = const {};
        _clientMessagingContactCounts = const {};
        _clientPartnerEndpointCounts = const {};
        _clientMessagingLanePreview = const {};
        _clientPartnerLanePreview = const {};
        _clientPartnerLaneDetails = const {};
        _clientTelegramChatcheckStatus = const {};
        _siteTelegramChatcheckStatus = const {};
        _clientPartnerChatcheckStatus = const {};
        _sitePartnerEndpointCounts = const {};
        _sitePartnerChatcheckStatus = const {};
        _sitePartnerLaneDetails = const {};
        _directorySyncMessage = 'Directory sync failed: $error';
      });
    } finally {
      if (mounted) {
        setState(() {
          _directoryLoading = false;
        });
      }
    }
  }

  int _riskRatingFromProfile(String profile) {
    return switch (profile) {
      'industrial' => 5,
      'commercial' => 4,
      'mixed_use' => 4,
      _ => 3,
    };
  }

  List<_SuccessDialogQuickAction> _buildDirectoryCreateQuickActions({
    required String focusReference,
    String incidentReference = '',
    String clientId = '',
    String siteId = '',
    bool includeClientView = false,
    bool includeReports = false,
    bool includeTours = true,
    int maxActions = 4,
  }) {
    final incidentRef = incidentReference.trim();
    final normalizedClientId = clientId.trim();
    final normalizedSiteId = siteId.trim();
    final actions = <_SuccessDialogQuickAction>[];

    _SuccessDialogQuickAction? runAutopilotAction() {
      if (!includeTours ||
          incidentRef.isEmpty ||
          widget.onRunDemoAutopilotForIncident == null) {
        return null;
      }
      return _SuccessDialogQuickAction(
        icon: Icons.auto_mode_rounded,
        label: 'Run Autopilot',
        onTap: () => widget.onRunDemoAutopilotForIncident!.call(incidentRef),
        foregroundColor: const Color(0xFF93C5FD),
        borderColor: const Color(0xFF2B5E93),
      );
    }

    _SuccessDialogQuickAction? runFullTourAction() {
      if (!includeTours ||
          incidentRef.isEmpty ||
          widget.onRunFullDemoAutopilotForIncident == null) {
        return null;
      }
      return _SuccessDialogQuickAction(
        icon: Icons.route_rounded,
        label: 'Run Full Tour',
        onTap: () =>
            widget.onRunFullDemoAutopilotForIncident!.call(incidentRef),
        foregroundColor: const Color(0xFFBFD7F2),
        borderColor: const Color(0xFF35506F),
      );
    }

    _SuccessDialogQuickAction? openOperationsAction() {
      final action = _openOperationsAction(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
        incidentReference: incidentRef,
      );
      if (action == null) return null;
      return _SuccessDialogQuickAction(
        icon: Icons.space_dashboard_rounded,
        label: 'OPEN SECURITY DESK',
        onTap: action,
        foregroundColor: const Color(0xFFBFD7F2),
        borderColor: const Color(0xFF35506F),
      );
    }

    _SuccessDialogQuickAction? openTacticalAction() {
      final action = _openTacticalAction(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
        incidentReference: incidentRef,
      );
      if (action == null) return null;
      return _SuccessDialogQuickAction(
        icon: Icons.map_rounded,
        label: 'OPEN TACTICAL TRACK',
        onTap: action,
        foregroundColor: const Color(0xFF9FE8FF),
        borderColor: const Color(0xFF2B5E93),
      );
    }

    _SuccessDialogQuickAction? openDispatchesAction() {
      final action = _openDispatchesAction(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
        incidentReference: incidentRef,
      );
      if (action == null) return null;
      return _SuccessDialogQuickAction(
        icon: Icons.hub_rounded,
        label: 'OPEN DISPATCH BOARD',
        onTap: action,
        foregroundColor: const Color(0xFF93C5FD),
        borderColor: const Color(0xFF35506F),
      );
    }

    _SuccessDialogQuickAction? openClientViewAction() {
      if (!includeClientView) return null;
      final action = _openClientLaneAction(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
      );
      if (action == null) return null;
      return _SuccessDialogQuickAction(
        icon: Icons.person_outline_rounded,
        label: 'OPEN CLIENT COMMS',
        onTap: action,
        foregroundColor: const Color(0xFFBFD7F2),
        borderColor: const Color(0xFF35506F),
      );
    }

    _SuccessDialogQuickAction? openGovernanceAction() {
      final action = _openGovernanceAction(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
      );
      if (action == null) return null;
      return _SuccessDialogQuickAction(
        icon: Icons.fact_check_rounded,
        label: 'OPEN GOVERNANCE DESK',
        onTap: action,
        foregroundColor: const Color(0xFF86EFAC),
        borderColor: const Color(0xFF2F5949),
      );
    }

    _SuccessDialogQuickAction? openReportsAction() {
      if (!includeReports) return null;
      final action = _openReportsAction(
        clientId: normalizedClientId,
        siteId: normalizedSiteId,
      );
      if (action == null) return null;
      return _SuccessDialogQuickAction(
        icon: Icons.assessment_rounded,
        label: 'OPEN REPORTS WORKSPACE',
        onTap: action,
        foregroundColor: const Color(0xFFFFDDAA),
        borderColor: const Color(0xFF5B3A16),
      );
    }

    final isClientEntity = includeClientView || includeReports;
    if (isClientEntity) {
      final prioritizedClient = <_SuccessDialogQuickAction?>[
        runFullTourAction(),
        openClientViewAction(),
        openGovernanceAction(),
        openOperationsAction(),
        openReportsAction(),
        runAutopilotAction(),
        openTacticalAction(),
        openDispatchesAction(),
      ];
      for (final action in prioritizedClient) {
        if (action != null) actions.add(action);
      }
    } else {
      final prioritizedOps = <_SuccessDialogQuickAction?>[
        runAutopilotAction(),
        runFullTourAction(),
        openOperationsAction(),
        openTacticalAction(),
        openDispatchesAction(),
      ];
      for (final action in prioritizedOps) {
        if (action != null) actions.add(action);
      }
    }

    if (actions.length <= maxActions) return actions;
    return actions.take(maxActions).toList(growable: false);
  }

  String _dateLabel(DateTime? date) {
    if (date == null) return '-';
    final month = date.month.toString().padLeft(2, '0');
    final day = date.day.toString().padLeft(2, '0');
    return '${date.year}-$month-$day';
  }

  void _deleteGuard(String id) {
    setState(() {
      _guards = _guards
          .where((guard) => guard.id != id)
          .toList(growable: false);
    });
    _snack('Guard $id deleted');
  }

  void _deleteSite(String id) {
    setState(() {
      _sites = _sites.where((site) => site.id != id).toList(growable: false);
    });
    _snack('Site $id deleted');
  }

  void _deleteClient(String id) {
    setState(() {
      _clients = _clients
          .where((client) => client.id != id)
          .toList(growable: false);
    });
    _snack('Client $id deleted');
  }

  Widget _adminEditTextField(
    TextEditingController controller,
    String label, {
    Key? key,
    TextInputType? keyboardType,
    int maxLines = 1,
    bool obscureText = false,
  }) {
    return TextFormField(
      key: key,
      controller: controller,
      keyboardType: keyboardType,
      maxLines: maxLines,
      obscureText: obscureText,
      style: GoogleFonts.inter(
        color: _adminDialogTitleColor,
        fontWeight: FontWeight.w600,
      ),
      decoration: _adminDialogInputDecoration(label),
    );
  }

  String _adminStatusLabel(_AdminStatus status) {
    return switch (status) {
      _AdminStatus.active => 'Active',
      _AdminStatus.inactive => 'Inactive',
      _AdminStatus.suspended => 'Suspended',
    };
  }

  String _guardRoleLabel(String role) {
    return role
        .replaceAll('_', ' ')
        .split(' ')
        .where((part) => part.trim().isNotEmpty)
        .map((part) => '${part[0].toUpperCase()}${part.substring(1)}')
        .join(' ');
  }

  String _guardRosterPlannerModeTitle(_GuardRosterPlannerMode mode) {
    return switch (mode) {
      _GuardRosterPlannerMode.createMonth => 'Create Month Planner',
      _GuardRosterPlannerMode.fillGaps => 'Fill Coverage Gaps',
      _GuardRosterPlannerMode.publishRoster => 'Publish Month Planner',
      _GuardRosterPlannerMode.openMonthPlanner => 'Open Month Planner',
    };
  }

  String _guardRosterPlannerPrimaryLabel(_GuardRosterPlannerMode mode) {
    return switch (mode) {
      _GuardRosterPlannerMode.createMonth => 'Create Draft',
      _GuardRosterPlannerMode.fillGaps => 'Lock Coverage',
      _GuardRosterPlannerMode.publishRoster => 'Publish Month',
      _GuardRosterPlannerMode.openMonthPlanner => 'Open Planner',
    };
  }

  String _guardRosterPlannerHint(
    _GuardRosterPlannerMode mode,
    DateTime focusDate,
  ) {
    final dayLabel = _guardRosterPlannerDateLabel(focusDate);
    return switch (mode) {
      _GuardRosterPlannerMode.createMonth =>
        'Start the month board, set the strongest site first, and keep the roster easy to publish.',
      _GuardRosterPlannerMode.fillGaps =>
        'Focus $dayLabel, cover the open posts, and keep the handoff simple for the floor.',
      _GuardRosterPlannerMode.publishRoster =>
        'Review $dayLabel one last time, then push the month live for controllers and guards.',
      _GuardRosterPlannerMode.openMonthPlanner =>
        'Jump straight to $dayLabel and keep the month board moving.',
    };
  }

  Color _guardRosterPlannerAccent(_GuardRosterPlannerMode mode) {
    return switch (mode) {
      _GuardRosterPlannerMode.publishRoster => const Color(0xFF63E6A1),
      _GuardRosterPlannerMode.fillGaps => const Color(0xFFFFC247),
      _GuardRosterPlannerMode.createMonth => const Color(0xFF8FD1FF),
      _GuardRosterPlannerMode.openMonthPlanner => const Color(0xFF8FD1FF),
    };
  }

  String _guardRosterPlannerDateLabel(DateTime date) {
    const monthLabels = <String>[
      'Jan',
      'Feb',
      'Mar',
      'Apr',
      'May',
      'Jun',
      'Jul',
      'Aug',
      'Sep',
      'Oct',
      'Nov',
      'Dec',
    ];
    return '${date.day} ${monthLabels[date.month.clamp(1, 12) - 1]} ${date.year}';
  }

  String _guardRosterPlannerReceiptMessage(_GuardRosterPlannerDraft draft) {
    return switch (draft.mode) {
      _GuardRosterPlannerMode.createMonth =>
        'Month draft opened for ${_siteName(draft.siteId)}.',
      _GuardRosterPlannerMode.fillGaps =>
        'Coverage gaps pinned for ${_guardRosterPlannerDateLabel(draft.focusDate)}.',
      _GuardRosterPlannerMode.publishRoster =>
        'Month publish review staged for ${_guardRosterPlannerDateLabel(draft.focusDate)}.',
      _GuardRosterPlannerMode.openMonthPlanner =>
        'Month planner opened for ${_guardRosterPlannerDateLabel(draft.focusDate)}.',
    };
  }

  String _guardRosterPlannerReceiptDetail(_GuardRosterPlannerDraft draft) {
    final note = draft.note.trim();
    final suffix = note.isEmpty ? '' : ' Note: $note';
    return switch (draft.mode) {
      _GuardRosterPlannerMode.createMonth =>
        'The new month board is pinned to ${_siteName(draft.siteId)} so you can keep placement and approvals moving.$suffix',
      _GuardRosterPlannerMode.fillGaps =>
        'Gap fixing for ${_siteName(draft.siteId)} stays pinned in this workspace while you reassign the floor.$suffix',
      _GuardRosterPlannerMode.publishRoster =>
        'The publish review for ${_siteName(draft.siteId)} stays visible here before the month goes live.$suffix',
      _GuardRosterPlannerMode.openMonthPlanner =>
        'Planner focus for ${_siteName(draft.siteId)} stays pinned here while you keep editing the month.$suffix',
    };
  }

  String _guardRosterPlannerSessionHeadline(
    _GuardRosterPlannerSession session,
  ) {
    return switch (session.mode) {
      _GuardRosterPlannerMode.createMonth => 'MONTH DRAFT LIVE',
      _GuardRosterPlannerMode.fillGaps => 'GAP FIX IN PLAY',
      _GuardRosterPlannerMode.publishRoster => 'MONTH READY TO PUSH',
      _GuardRosterPlannerMode.openMonthPlanner => 'PLANNER HELD OPEN',
    };
  }

  String _guardRosterPlannerSessionLabel(_GuardRosterPlannerSession session) {
    return switch (session.mode) {
      _GuardRosterPlannerMode.createMonth => 'DRAFT',
      _GuardRosterPlannerMode.fillGaps => 'GAPS',
      _GuardRosterPlannerMode.publishRoster => 'PUBLISH',
      _GuardRosterPlannerMode.openMonthPlanner => 'PLANNER',
    };
  }

  String _guardRosterWarRoomLabel(_GuardRosterPlannerMode mode) {
    return switch (mode) {
      _GuardRosterPlannerMode.fillGaps => 'ROSTER WATCH',
      _GuardRosterPlannerMode.publishRoster => 'ROSTER READY',
      _GuardRosterPlannerMode.createMonth => 'ROSTER LIVE',
      _GuardRosterPlannerMode.openMonthPlanner => 'ROSTER LIVE',
    };
  }

  bool _guardRosterWarRoomNeedsAttention(_GuardRosterPlannerMode mode) {
    return switch (mode) {
      _GuardRosterPlannerMode.fillGaps => true,
      _GuardRosterPlannerMode.publishRoster => false,
      _GuardRosterPlannerMode.createMonth => false,
      _GuardRosterPlannerMode.openMonthPlanner => false,
    };
  }

  String _guardRosterPlannerSessionDetail(_GuardRosterPlannerSession session) {
    final note = session.note.trim();
    final noteSuffix = note.isEmpty ? '' : ' Note: $note';
    final updatedHour = session.updatedAtUtc.hour.toString().padLeft(2, '0');
    final updatedMinute = session.updatedAtUtc.minute.toString().padLeft(
      2,
      '0',
    );
    return '${_siteName(session.siteId)} • ${_guardRosterPlannerDateLabel(session.focusDate)} • updated $updatedHour:$updatedMinute UTC$noteSuffix';
  }

  String _guardRosterPlannerRowNote(_GuardAdminRow row) {
    final session = _guardRosterPlannerSession;
    if (session == null || row.assignedSite.trim() != session.siteId.trim()) {
      return row.shiftPattern;
    }
    return '${row.shiftPattern} • ${_guardRosterPlannerSessionLabel(session)} ${_guardRosterPlannerDateLabel(session.focusDate)}';
  }

  Widget _guardRosterPlannerStateCard() {
    final session = _guardRosterPlannerSession;
    if (session == null) {
      return const SizedBox.shrink();
    }
    final accent = _guardRosterPlannerAccent(session.mode);
    final impactedGuards = _guards
        .where((guard) => guard.assignedSite.trim() == session.siteId.trim())
        .length;
    return Container(
      key: const ValueKey('admin-guard-planner-state-card'),
      width: double.infinity,
      margin: const EdgeInsets.only(bottom: 12),
      padding: const EdgeInsets.all(14),
      decoration: BoxDecoration(
        color: const Color(0xFF13131E),
        borderRadius: BorderRadius.circular(14),
        border: Border.all(color: _adminDialogBorderColor),
        boxShadow: const [
          BoxShadow(
            color: Color(0x050E1A2B),
            blurRadius: 8,
            offset: Offset(0, 2),
          ),
        ],
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 9, vertical: 5),
                decoration: BoxDecoration(
                  color: const Color(0xFFF2F8FD),
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: const Color(0xFFCADBEC)),
                ),
                child: Text(
                  'MONTH PLANNER',
                  style: GoogleFonts.inter(
                    color: const Color(0xFF4E7396),
                    fontSize: 10,
                    fontWeight: FontWeight.w900,
                    letterSpacing: 0.9,
                  ),
                ),
              ),
              const SizedBox(width: 8),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 9, vertical: 5),
                decoration: BoxDecoration(
                  color: _adminDialogAltColor,
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: _adminDialogBorderColor),
                ),
                child: Text(
                  '$impactedGuards GUARDS',
                  style: GoogleFonts.inter(
                    color: accent,
                    fontSize: 10,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 10),
          Text(
            _guardRosterPlannerSessionHeadline(session),
            style: GoogleFonts.inter(
              color: _adminDialogTitleColor,
              fontSize: 24,
              fontWeight: FontWeight.w800,
              height: 0.95,
            ),
          ),
          const SizedBox(height: 6),
          Text(
            _guardRosterPlannerSessionDetail(session),
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 12,
              fontWeight: FontWeight.w700,
              height: 1.35,
            ),
          ),
        ],
      ),
    );
  }

  Future<void> _showGuardRosterPlannerDialog({
    required _GuardRosterPlannerMode mode,
    DateTime? date,
    bool launchedFromHandoff = false,
  }) async {
    final session = _guardRosterPlannerSession;
    final focusDate = date ?? session?.focusDate ?? DateTime.utc(2026, 3, 27);
    final defaultSiteId = (session?.siteId.trim().isNotEmpty ?? false)
        ? session!.siteId.trim()
        : _guards
              .map((guard) => guard.assignedSite.trim())
              .firstWhere(
                (siteId) => siteId.isNotEmpty,
                orElse: () => _sites.isEmpty ? '' : _sites.first.id,
              )
              .trim();
    final noteController = TextEditingController(
      text: launchedFromHandoff
          ? 'Opened from Guards War Room for ${_guardRosterPlannerDateLabel(focusDate)}.'
          : '',
    );

    _guardPlannerDialogOpen = true;
    try {
      final draft = await showDialog<_GuardRosterPlannerDraft>(
        context: context,
        builder: (dialogContext) {
          String selectedSiteId = defaultSiteId;
          String? error;
          return StatefulBuilder(
            builder: (dialogContext, setDialogState) {
              return _adminDialogShell(
                dialogKey: _adminGuardPlannerDialogKey,
                width: _responsiveDialogWidth(context, maxWidth: 620),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      _guardRosterPlannerModeTitle(mode),
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 24,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      _guardRosterPlannerHint(mode, focusDate),
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 12,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                    const SizedBox(height: 12),
                    Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: [
                        _adminHeaderChip(
                          label:
                              'DAY ${_guardRosterPlannerDateLabel(focusDate).toUpperCase()}',
                          foreground: _guardRosterPlannerAccent(mode),
                          background: const Color(0x1A60A5FA),
                          border: const Color(0x663C79BB),
                        ),
                        if (launchedFromHandoff)
                          _adminHeaderChip(
                            label: 'OPENED FROM WAR ROOM',
                            foreground: const Color(0xFF7FD8A5),
                            background: const Color(0x1A10B981),
                            border: const Color(0x6610B981),
                          ),
                      ],
                    ),
                    const SizedBox(height: 12),
                    DropdownButtonFormField<String>(
                      key: const ValueKey('admin-guard-planner-site'),
                      initialValue: selectedSiteId.isEmpty
                          ? null
                          : selectedSiteId,
                      dropdownColor: _adminDialogSurfaceColor,
                      decoration: _adminDialogInputDecoration(
                        'Roster Focus Site',
                      ),
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontWeight: FontWeight.w600,
                      ),
                      items: _sites
                          .map(
                            (site) => DropdownMenuItem<String>(
                              value: site.id,
                              child: Text('${site.name} (${site.id})'),
                            ),
                          )
                          .toList(growable: false),
                      onChanged: (value) {
                        setDialogState(() {
                          selectedSiteId = (value ?? '').trim();
                        });
                      },
                    ),
                    const SizedBox(height: 10),
                    _adminEditTextField(
                      noteController,
                      'Planner Note',
                      key: const ValueKey('admin-guard-planner-note'),
                      maxLines: 3,
                    ),
                    if (error != null) ...[
                      const SizedBox(height: 10),
                      Text(
                        error!,
                        style: GoogleFonts.inter(
                          color: const Color(0xFFF87171),
                          fontSize: 12,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                    ],
                    const SizedBox(height: 14),
                    Row(
                      children: [
                        TextButton(
                          onPressed: () => Navigator.of(dialogContext).pop(),
                          child: Text(
                            'Cancel',
                            style: GoogleFonts.inter(
                              color: _adminDialogMutedColor,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                        const Spacer(),
                        FilledButton.icon(
                          key: _adminGuardPlannerConfirmButtonKey,
                          onPressed: () {
                            if (selectedSiteId.trim().isEmpty) {
                              setDialogState(() {
                                error = 'Pick a site before continuing.';
                              });
                              return;
                            }
                            Navigator.of(dialogContext).pop(
                              _GuardRosterPlannerDraft(
                                mode: mode,
                                siteId: selectedSiteId.trim(),
                                focusDate: focusDate,
                                note: noteController.text.trim(),
                              ),
                            );
                          },
                          icon: const Icon(
                            Icons.assignment_turned_in_rounded,
                            size: 16,
                          ),
                          style: FilledButton.styleFrom(
                            backgroundColor: _guardRosterPlannerAccent(mode),
                            foregroundColor: const Color(0xFF081018),
                          ),
                          label: Text(
                            _guardRosterPlannerPrimaryLabel(mode),
                            style: GoogleFonts.inter(
                              fontWeight: FontWeight.w800,
                            ),
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              );
            },
          );
        },
      );
      if (draft == null || !mounted) {
        return;
      }
      setState(() {
        _guardRosterPlannerSession = _GuardRosterPlannerSession(
          mode: draft.mode,
          siteId: draft.siteId,
          focusDate: draft.focusDate,
          note: draft.note,
          updatedAtUtc: DateTime.now().toUtc(),
        );
      });
      widget.onGuardRosterSignalChanged?.call(
        _guardRosterWarRoomLabel(draft.mode),
        _guardRosterPlannerSessionHeadline(_guardRosterPlannerSession!),
        _guardRosterPlannerSessionDetail(_guardRosterPlannerSession!),
        _guardRosterPlannerAccent(draft.mode),
        _guardRosterWarRoomNeedsAttention(draft.mode),
      );
      _snack(
        _guardRosterPlannerReceiptMessage(draft),
        sourceLabel: 'MONTH PLANNER',
        detail: _guardRosterPlannerReceiptDetail(draft),
        accent: _guardRosterPlannerAccent(draft.mode),
      );
    } finally {
      _guardPlannerDialogOpen = false;
      _disposeTextControllersAfterDialogFrame([noteController]);
    }
  }

  Future<void> _showGuardEditDialog(_GuardAdminRow row) async {
    final nameController = TextEditingController(text: row.name);
    final phoneController = TextEditingController(text: row.phone);
    final emailController = TextEditingController(text: row.email);
    final psiraController = TextEditingController(text: row.psiraNumber);
    final certificationsController = TextEditingController(
      text: row.certifications.join(', '),
    );
    final shiftPatternController = TextEditingController(
      text: row.shiftPattern,
    );
    final emergencyController = TextEditingController(
      text: row.emergencyContact,
    );
    var selectedRole = row.role;
    var selectedAssignedSite = row.assignedSite;
    var selectedStatus = row.status;

    late final _GuardAdminRow? updated;
    try {
      updated = await showDialog<_GuardAdminRow>(
        context: context,
        builder: (dialogContext) {
          String? error;
          return StatefulBuilder(
            builder: (dialogContext, setDialogState) {
              return _adminDialogShell(
                width: 560,
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'Guard Command Edit',
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 24,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      '${row.employeeId} • update the roster profile, duty route, and contact handoff without leaving the admin workspace.',
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 12,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                    const SizedBox(height: 12),
                    Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: [
                        _adminHeaderChip(
                          label: 'Role ${_guardRoleLabel(selectedRole)}',
                          foreground: const Color(0xFF8FD1FF),
                          background: const Color(0x1A60A5FA),
                          border: const Color(0x663C79BB),
                        ),
                        _adminHeaderChip(
                          label: 'Status ${_adminStatusLabel(selectedStatus)}',
                          foreground: const Color(0xFF7FD8A5),
                          background: const Color(0x1A10B981),
                          border: const Color(0x6610B981),
                        ),
                      ],
                    ),
                    const SizedBox(height: 12),
                    _adminEditTextField(
                      nameController,
                      'Guard Name',
                      key: const ValueKey('admin-guard-edit-name'),
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: _adminEditTextField(
                            phoneController,
                            'Phone',
                            keyboardType: TextInputType.phone,
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _adminEditTextField(
                            emailController,
                            'Email',
                            keyboardType: TextInputType.emailAddress,
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: _adminEditTextField(
                            psiraController,
                            'PSIRA Number',
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _adminEditTextField(
                            shiftPatternController,
                            'Shift Pattern',
                            key: const ValueKey(
                              'admin-guard-edit-shift-pattern',
                            ),
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    _adminEditTextField(
                      certificationsController,
                      'Certifications (comma separated)',
                    ),
                    const SizedBox(height: 10),
                    _adminEditTextField(
                      emergencyController,
                      'Emergency Contact',
                      keyboardType: TextInputType.phone,
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: DropdownButtonFormField<String>(
                            key: const ValueKey('admin-guard-edit-role'),
                            initialValue: selectedRole,
                            dropdownColor: _adminDialogSurfaceColor,
                            decoration: _adminDialogInputDecoration('Role'),
                            style: GoogleFonts.inter(
                              color: _adminDialogTitleColor,
                              fontWeight: FontWeight.w600,
                            ),
                            items:
                                const [
                                      'guard',
                                      'reaction_officer',
                                      'supervisor',
                                      'controller',
                                    ]
                                    .map((role) {
                                      return DropdownMenuItem<String>(
                                        value: role,
                                        child: Text(_guardRoleLabel(role)),
                                      );
                                    })
                                    .toList(growable: false),
                            onChanged: (value) {
                              if (value == null) return;
                              setDialogState(() => selectedRole = value);
                            },
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: DropdownButtonFormField<_AdminStatus>(
                            key: const ValueKey('admin-guard-edit-status'),
                            initialValue: selectedStatus,
                            dropdownColor: _adminDialogSurfaceColor,
                            decoration: _adminDialogInputDecoration('Status'),
                            style: GoogleFonts.inter(
                              color: _adminDialogTitleColor,
                              fontWeight: FontWeight.w600,
                            ),
                            items: _AdminStatus.values
                                .map((status) {
                                  return DropdownMenuItem<_AdminStatus>(
                                    value: status,
                                    child: Text(_adminStatusLabel(status)),
                                  );
                                })
                                .toList(growable: false),
                            onChanged: (value) {
                              if (value == null) return;
                              setDialogState(() => selectedStatus = value);
                            },
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    DropdownButtonFormField<String>(
                      key: const ValueKey('admin-guard-edit-site'),
                      initialValue: selectedAssignedSite,
                      dropdownColor: _adminDialogSurfaceColor,
                      decoration: _adminDialogInputDecoration('Assigned Site'),
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontWeight: FontWeight.w600,
                      ),
                      items: [
                        const DropdownMenuItem<String>(
                          value: '',
                          child: Text('Unassigned'),
                        ),
                        ..._sites.map((site) {
                          return DropdownMenuItem<String>(
                            value: site.id,
                            child: Text('${site.name} (${site.id})'),
                          );
                        }),
                      ],
                      onChanged: (value) {
                        if (value == null) return;
                        setDialogState(() => selectedAssignedSite = value);
                      },
                    ),
                    if (error != null) ...[
                      const SizedBox(height: 10),
                      Text(
                        error!,
                        style: GoogleFonts.inter(
                          color: const Color(0xFFF87171),
                          fontSize: 12,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                    ],
                    const SizedBox(height: 14),
                    Row(
                      children: [
                        TextButton(
                          onPressed: () => Navigator.of(dialogContext).pop(),
                          child: Text(
                            'Cancel',
                            style: GoogleFonts.inter(
                              color: _adminDialogMutedColor,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                        const Spacer(),
                        FilledButton.icon(
                          key: const ValueKey('admin-guard-edit-save'),
                          onPressed: () {
                            if (nameController.text.trim().isEmpty) {
                              setDialogState(() {
                                error = 'Guard name is required.';
                              });
                              return;
                            }
                            Navigator.of(dialogContext).pop(
                              _GuardAdminRow(
                                id: row.id,
                                name: nameController.text.trim(),
                                role: selectedRole,
                                employeeId: row.employeeId,
                                phone: phoneController.text.trim(),
                                email: emailController.text.trim(),
                                psiraNumber: psiraController.text.trim(),
                                psiraExpiry: row.psiraExpiry,
                                certifications: certificationsController.text
                                    .split(',')
                                    .map((value) => value.trim())
                                    .where((value) => value.isNotEmpty)
                                    .toList(growable: false),
                                assignedSite: selectedAssignedSite.trim(),
                                shiftPattern: shiftPatternController.text
                                    .trim(),
                                emergencyContact: emergencyController.text
                                    .trim(),
                                status: selectedStatus,
                              ),
                            );
                          },
                          icon: const Icon(Icons.save_rounded, size: 16),
                          style: FilledButton.styleFrom(
                            backgroundColor: const Color(0xFF2B5E93),
                            foregroundColor: const Color(0xFFEAF4FF),
                          ),
                          label: Text(
                            'Save Guard',
                            style: GoogleFonts.inter(
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              );
            },
          );
        },
      );
    } finally {
      _disposeTextControllersAfterDialogFrame([
        nameController,
        phoneController,
        emailController,
        psiraController,
        certificationsController,
        shiftPatternController,
        emergencyController,
      ]);
    }

    if (!mounted || updated == null) return;
    final resolvedUpdated = updated;
    setState(() {
      _guards = _guards
          .map(
            (candidate) => candidate.id == row.id ? resolvedUpdated : candidate,
          )
          .toList(growable: false);
    });
    _snack(
      'Guard ${resolvedUpdated.employeeId} updated.',
      sourceLabel: 'GUARD EDITOR',
      detail:
          'The roster update stays pinned in the desktop rail while the guard table remains in focus.',
      accent: const Color(0xFF8FD1FF),
    );
  }

  Future<void> _showSiteEditDialog(_SiteAdminRow row) async {
    final nameController = TextEditingController(text: row.name);
    final codeController = TextEditingController(text: row.code);
    final addressController = TextEditingController(text: row.address);
    final latController = TextEditingController(
      text: row.lat.toStringAsFixed(4),
    );
    final lngController = TextEditingController(
      text: row.lng.toStringAsFixed(4),
    );
    final contactController = TextEditingController(text: row.contactPerson);
    final contactPhoneController = TextEditingController(
      text: row.contactPhone,
    );
    final fskController = TextEditingController(text: row.fskNumber ?? '');
    final geofenceController = TextEditingController(
      text: row.geofenceRadiusMeters.toString(),
    );
    var cameraAuthMode = row.cameraAuthMode.trim().isEmpty
        ? 'none'
        : row.cameraAuthMode.trim().toLowerCase();
    final cameraUsernameController = TextEditingController(
      text: row.cameraUsername,
    );
    final cameraPasswordController = TextEditingController(
      text: row.cameraPassword,
    );
    final cameraBearerTokenController = TextEditingController(
      text: row.cameraBearerToken,
    );
    var selectedStatus = row.status;

    late final _SiteAdminRow? updated;
    try {
      updated = await showDialog<_SiteAdminRow>(
        context: context,
        builder: (dialogContext) {
          String? error;
          return StatefulBuilder(
            builder: (dialogContext, setDialogState) {
              return _adminDialogShell(
                width: 600,
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      'Site Command Edit',
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontSize: 24,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      '${row.id} • refine the site footprint, geofence, and contact handoff without leaving the admin workspace.',
                      style: GoogleFonts.inter(
                        color: _adminDialogBodyColor,
                        fontSize: 12,
                        fontWeight: FontWeight.w600,
                      ),
                    ),
                    const SizedBox(height: 12),
                    Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: [
                        _adminHeaderChip(
                          label: _clientName(row.clientId),
                          foreground: const Color(0xFF7FD8A5),
                          background: const Color(0x1A10B981),
                          border: const Color(0x6610B981),
                        ),
                        _adminHeaderChip(
                          label: _adminStatusLabel(selectedStatus),
                          foreground: const Color(0xFF8FD1FF),
                          background: const Color(0x1A60A5FA),
                          border: const Color(0x663C79BB),
                        ),
                      ],
                    ),
                    const SizedBox(height: 12),
                    Row(
                      children: [
                        Expanded(
                          child: _adminEditTextField(
                            nameController,
                            'Site Name',
                            key: const ValueKey('admin-site-edit-name'),
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _adminEditTextField(
                            codeController,
                            'Site Code',
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    _adminEditTextField(addressController, 'Address'),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: _adminEditTextField(
                            latController,
                            'Latitude',
                            keyboardType: const TextInputType.numberWithOptions(
                              decimal: true,
                              signed: true,
                            ),
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _adminEditTextField(
                            lngController,
                            'Longitude',
                            keyboardType: const TextInputType.numberWithOptions(
                              decimal: true,
                              signed: true,
                            ),
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: _adminEditTextField(
                            contactController,
                            'Contact Person',
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _adminEditTextField(
                            contactPhoneController,
                            'Contact Phone',
                            keyboardType: TextInputType.phone,
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: _adminEditTextField(
                            fskController,
                            'FSK / DVR Reference',
                          ),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _adminEditTextField(
                            geofenceController,
                            'Geofence Radius (m)',
                            key: const ValueKey('admin-site-edit-geofence'),
                            keyboardType: TextInputType.number,
                          ),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    DropdownButtonFormField<String>(
                      initialValue: cameraAuthMode,
                      dropdownColor: _adminDialogSurfaceColor,
                      decoration: _adminDialogInputDecoration(
                        'Camera Auth Mode',
                      ),
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontWeight: FontWeight.w600,
                      ),
                      items: const [
                        DropdownMenuItem<String>(
                          value: 'none',
                          child: Text('None / Staging'),
                        ),
                        DropdownMenuItem<String>(
                          value: 'digest',
                          child: Text('Digest'),
                        ),
                        DropdownMenuItem<String>(
                          value: 'bearer',
                          child: Text('Bearer Token'),
                        ),
                      ],
                      onChanged: (value) {
                        if (value == null) return;
                        setDialogState(() => cameraAuthMode = value);
                      },
                    ),
                    if (cameraAuthMode == 'digest') ...[
                      const SizedBox(height: 10),
                      Row(
                        children: [
                          Expanded(
                            child: _adminEditTextField(
                              cameraUsernameController,
                              'Camera Username',
                            ),
                          ),
                          const SizedBox(width: 10),
                          Expanded(
                            child: _adminEditTextField(
                              cameraPasswordController,
                              'Camera Password',
                              obscureText: true,
                            ),
                          ),
                        ],
                      ),
                    ] else if (cameraAuthMode == 'bearer') ...[
                      const SizedBox(height: 10),
                      _adminEditTextField(
                        cameraBearerTokenController,
                        'Camera Bearer Token',
                        obscureText: true,
                      ),
                    ],
                    const SizedBox(height: 10),
                    DropdownButtonFormField<_AdminStatus>(
                      key: const ValueKey('admin-site-edit-status'),
                      initialValue: selectedStatus,
                      dropdownColor: _adminDialogSurfaceColor,
                      decoration: _adminDialogInputDecoration('Status'),
                      style: GoogleFonts.inter(
                        color: _adminDialogTitleColor,
                        fontWeight: FontWeight.w600,
                      ),
                      items: _AdminStatus.values
                          .map((status) {
                            return DropdownMenuItem<_AdminStatus>(
                              value: status,
                              child: Text(_adminStatusLabel(status)),
                            );
                          })
                          .toList(growable: false),
                      onChanged: (value) {
                        if (value == null) return;
                        setDialogState(() => selectedStatus = value);
                      },
                    ),
                    if (error != null) ...[
                      const SizedBox(height: 10),
                      Text(
                        error!,
                        style: GoogleFonts.inter(
                          color: const Color(0xFFF87171),
                          fontSize: 12,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                    ],
                    const SizedBox(height: 14),
                    Row(
                      children: [
                        TextButton(
                          onPressed: () => Navigator.of(dialogContext).pop(),
                          child: Text(
                            'Cancel',
                            style: GoogleFonts.inter(
                              color: _adminDialogMutedColor,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                        const Spacer(),
                        FilledButton.icon(
                          key: const ValueKey('admin-site-edit-save'),
                          onPressed: () {
                            final lat = double.tryParse(
                              latController.text.trim(),
                            );
                            final lng = double.tryParse(
                              lngController.text.trim(),
                            );
                            final geofence = int.tryParse(
                              geofenceController.text.trim(),
                            );
                            if (nameController.text.trim().isEmpty ||
                                codeController.text.trim().isEmpty) {
                              setDialogState(() {
                                error = 'Site name and code are required.';
                              });
                              return;
                            }
                            if (lat == null || lng == null) {
                              setDialogState(() {
                                error =
                                    'Latitude and longitude must be valid numbers.';
                              });
                              return;
                            }
                            if (geofence == null || geofence <= 0) {
                              setDialogState(() {
                                error =
                                    'Geofence radius must be a positive integer.';
                              });
                              return;
                            }
                            Navigator.of(dialogContext).pop(
                              _SiteAdminRow(
                                id: row.id,
                                name: nameController.text.trim(),
                                code: codeController.text.trim().toUpperCase(),
                                clientId: row.clientId,
                                address: addressController.text.trim(),
                                lat: lat,
                                lng: lng,
                                contactPerson: contactController.text.trim(),
                                contactPhone: contactPhoneController.text
                                    .trim(),
                                fskNumber: _emptyToNull(
                                  fskController.text.trim(),
                                ),
                                geofenceRadiusMeters: geofence,
                                cameraAuthMode: cameraAuthMode,
                                cameraUsername: cameraUsernameController.text
                                    .trim(),
                                cameraPassword: cameraPasswordController.text,
                                cameraBearerToken: cameraBearerTokenController
                                    .text
                                    .trim(),
                                status: selectedStatus,
                              ),
                            );
                          },
                          icon: const Icon(Icons.save_rounded, size: 16),
                          style: FilledButton.styleFrom(
                            backgroundColor: const Color(0xFF2B5E93),
                            foregroundColor: const Color(0xFFEAF4FF),
                          ),
                          label: Text(
                            'Save Site',
                            style: GoogleFonts.inter(
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ),
                      ],
                    ),
                  ],
                ),
              );
            },
          );
        },
      );
    } finally {
      _disposeTextControllersAfterDialogFrame([
        nameController,
        codeController,
        addressController,
        latController,
        lngController,
        contactController,
        contactPhoneController,
        fskController,
        geofenceController,
        cameraUsernameController,
        cameraPasswordController,
        cameraBearerTokenController,
      ]);
    }

    if (!mounted || updated == null) return;
    final resolvedUpdated = updated;
    final cameraAuthConfig = _siteCameraAuthConfigFromRow(resolvedUpdated);
    try {
      if (widget.supabaseReady) {
        final supabase = Supabase.instance.client;
        final metadataRow = await supabase
            .from('sites')
            .select('metadata')
            .eq('site_id', row.id)
            .maybeSingle();
        final existingMetadata = metadataRow is Map<String, dynamic>
            ? metadataRow['metadata'] as Map?
            : null;
        await supabase.from('sites').upsert({
          'site_id': resolvedUpdated.id,
          'client_id': resolvedUpdated.clientId,
          'site_name': resolvedUpdated.name,
          'site_code': resolvedUpdated.code,
          'physical_address': resolvedUpdated.address,
          'latitude': resolvedUpdated.lat,
          'longitude': resolvedUpdated.lng,
          'geofence_radius_meters': resolvedUpdated.geofenceRadiusMeters
              .toDouble(),
          'metadata': _siteMetadataWithCameraControl(
            baseMetadata:
                existingMetadata?.cast<String, dynamic>() ??
                const <String, dynamic>{},
            credentials: cameraAuthConfig,
          ),
          'is_active': resolvedUpdated.status == _AdminStatus.active,
        }, onConflict: 'site_id');
      }
      await _rememberSiteCameraAuthConfig(
        clientId: resolvedUpdated.clientId,
        siteId: resolvedUpdated.id,
        credentials: cameraAuthConfig,
      );
    } catch (error) {
      if (mounted) {
        _snack(
          'Failed to save site ${resolvedUpdated.id}.',
          sourceLabel: 'SITE EDITOR',
          detail: 'Site configuration save failed: $error',
          accent: const Color(0xFFF59E0B),
        );
      }
      return;
    }
    setState(() {
      _sites = _sites
          .map(
            (candidate) => candidate.id == row.id ? resolvedUpdated : candidate,
          )
          .toList(growable: false);
    });
    _snack(
      'Site ${resolvedUpdated.id} updated.',
      sourceLabel: 'SITE EDITOR',
      detail:
          'The site footprint update stays pinned in the desktop rail while the operations directory remains in focus.',
      accent: const Color(0xFF7FD8A5),
    );
  }

  Future<_SuccessDialogOutcome> _showCreateSuccessDialog({
    required String title,
    required String subtitle,
    required List<String> highlights,
    VoidCallback? onContinueDemo,
    String continueLabel = 'Continue Demo',
    String? focusReference,
    List<_SuccessDialogQuickAction> quickActions = const [],
  }) async {
    final resolvedFocusReference = (focusReference ?? '').trim();
    final hasFocusReference = resolvedFocusReference.isNotEmpty;
    final hasContinueAction = onContinueDemo != null;
    final primaryLabel = hasContinueAction ? continueLabel : 'Close Checkpoint';
    final primaryIcon = hasContinueAction
        ? Icons.play_arrow_rounded
        : Icons.close_rounded;
    final commandAccent = hasContinueAction
        ? const Color(0xFF67E8F9)
        : quickActions.isNotEmpty
        ? quickActions.first.foregroundColor
        : const Color(0xFF8FD1FF);
    final nextMoveLabel = hasContinueAction
        ? 'Continue active route'
        : quickActions.isNotEmpty
        ? 'Review sealed handoff'
        : 'Close checkpoint';
    final headerStatus = hasContinueAction
        ? 'route live'
        : quickActions.isNotEmpty
        ? 'handoff sealed'
        : 'sealed';
    final headerHeadline = hasContinueAction
        ? 'SEALED CHECKPOINT'
        : quickActions.isNotEmpty
        ? 'HANDOFF CHECKPOINT'
        : 'CLOSED CHECKPOINT';
    final headerDetail = hasContinueAction
        ? 'The generated route is sealed and ready to continue without losing the scoped handoff below.'
        : quickActions.isNotEmpty
        ? 'The generated handoff is sealed and ready for scoped review across the actions below.'
        : 'The generated checkpoint is sealed and can be closed without losing the review state below.';
    final commandDetail = hasContinueAction
        ? 'Primary route continuation is armed, with every supporting handoff still available below.'
        : quickActions.isNotEmpty
        ? 'The strongest scoped handoffs stay visible here so the operator can review and route cleanly without losing context.'
        : 'The creation checkpoint is complete and can be closed without losing the seeded focus reference.';
    final commandSnapshotHeadline = hasContinueAction
        ? 'Active route continuation and supporting handoffs are staged.'
        : quickActions.isNotEmpty
        ? 'Scoped handoff review is sealed for command follow-through.'
        : 'Checkpoint closure is staged and fully sealed.';
    final commandSnapshotDetail = () {
      if (hasContinueAction) {
        return hasFocusReference
            ? 'Route posture, focus state, signal count, and live continuation depth stay visible here before the deeper focus and success boards.'
            : 'Route posture, signal count, and live continuation depth stay visible here before the deeper success boards.';
      }
      if (quickActions.isNotEmpty) {
        return hasFocusReference
            ? 'Handoff posture, focus state, signal count, and sealed review depth stay visible here before the deeper focus and success boards.'
            : 'Handoff posture, signal count, and sealed review depth stay visible here before the deeper success boards.';
      }
      return hasFocusReference
          ? 'Checkpoint posture, focus state, signal count, and sealed review depth stay visible here before the deeper focus and success boards.'
          : 'Checkpoint posture, signal count, and sealed review depth stay visible here before the deeper success boards.';
    }();
    final workflowHeadline = hasContinueAction
        ? '$continueLabel is armed as the primary route.'
        : quickActions.isNotEmpty
        ? 'The strongest scoped handoffs are sealed for review below.'
        : 'The creation checkpoint can be closed cleanly.';
    final workflowDetail = hasContinueAction
        ? 'The strongest continuation path stays separated from the supporting handoffs so the operator can move immediately without losing the seeded context.'
        : quickActions.isNotEmpty
        ? 'The sealed review path stays separated from the supporting handoffs so the operator can inspect and route cleanly without losing the seeded context.'
        : 'The closure path stays separated from the supporting handoffs so the operator can finish the checkpoint without losing the seeded context.';
    final workflowNextMove = hasContinueAction
        ? continueLabel
        : quickActions.isNotEmpty
        ? 'Review handoffs'
        : primaryLabel;
    final workflowSupportLabel = hasContinueAction
        ? 'SUPPORT TOOLS'
        : quickActions.isNotEmpty
        ? 'SEALED HANDOFFS'
        : 'SUPPORT TOOLS';
    final focusHeadline = hasFocusReference
        ? '$resolvedFocusReference stays pinned for follow-on routing.'
        : null;
    final focusDetail = hasFocusReference
        ? 'The seeded focus reference stays visible here so the operator can hand off, verify, or copy the scoped route without losing the sealed checkpoint.'
        : null;
    final focusNextMove = hasFocusReference ? 'Copy focus' : null;
    final primaryHighlight = highlights.isEmpty
        ? 'Creation checkpoint sealed. Live success signals will appear here as the handoff matures.'
        : highlights.first;
    final supportingHighlights = highlights.length > 1
        ? highlights.sublist(1)
        : const <String>[];
    final snapshotHeadline = hasContinueAction
        ? '$title is carrying a live route-ready success signal.'
        : quickActions.isNotEmpty
        ? '$title is staging the strongest sealed handoff signals.'
        : '$title is sealed and ready to close cleanly.';
    final snapshotDetail = supportingHighlights.isNotEmpty
        ? 'The lead success signal stays elevated while the supporting completion cues remain visible below.'
        : hasFocusReference
        ? 'The lead success signal stays elevated while the seeded focus reference remains pinned for follow-on command review.'
        : 'The lead success signal stays elevated so the operator can hold the sealed outcome at a glance.';
    final snapshotNextMove = supportingHighlights.isNotEmpty
        ? 'Review ${highlights.length} signals'
        : hasContinueAction
        ? continueLabel
        : quickActions.isNotEmpty
