  void _snack(
    String message, {
    String? sourceLabel,
    String? detail,
    Color? accent,
  }) {
    _handleAdminFeedback(
      feedbackContext: context,
      message: message,
      sourceLabel: sourceLabel,
      detail: detail,
      accent: accent,
    );
  }

  Future<void> _openAdminExportFlow() async {
    final payload = _buildAdminExportPayload();
    await Clipboard.setData(ClipboardData(text: payload.$1));
    if (!mounted) return;
    _snack(
      payload.$2,
      sourceLabel: 'DIRECTORY EXPORT',
      accent: const Color(0xFF8FD1FF),
      detail:
          'The copied directory payload stays pinned in the Context Rail for the current admin desk.',
    );
  }

  Future<void> _openAdminImportCsvFlow() async {
    final request = await _showAdminCsvImportDialog();
    if (request == null) return;
    try {
      final importedCount = _importAdminCsv(request);
      if (!mounted) return;
      final noun = switch (request.target) {
        _AdminCsvTarget.guards => 'employee',
        _AdminCsvTarget.sites => 'site',
        _AdminCsvTarget.clients => 'client',
      };
      _snack(
        'Imported $importedCount $noun${importedCount == 1 ? '' : 's'} from CSV.',
        sourceLabel: 'CSV IMPORT',
        accent: const Color(0xFF7FD8A5),
        detail:
            'The import result stays visible in the Context Rail while you continue working the directory.',
      );
    } catch (error) {
      if (!mounted) return;
      _snack(
        'CSV import failed: $error',
        sourceLabel: 'CSV IMPORT',
        accent: const Color(0xFFF59E0B),
        detail:
            'The import failure remains visible in the Context Rail so you can correct the payload without losing context.',
      );
    }
  }

  (String, String) _buildAdminExportPayload() {
    final cameraBridgePresentation = _cameraBridgePresentation;
    final cameraBridgeHealthSnapshot =
        cameraBridgePresentation.effectiveSnapshot;
    final cameraBridgeSurfaceState = cameraBridgePresentation.surfaceState;
    final cameraBridgeReceiptState = cameraBridgeSurfaceState.receiptState;
