            'assigned_site',
            'phone',
            'email',
            'psira_number',
            'psira_expiry',
            'status',
            'certifications',
            'shift_pattern',
            'emergency_contact',
          ],
          _guards
              .map(
                (guard) => <String>[
                  guard.employeeId,
                  guard.name,
                  guard.role,
                  guard.assignedSite,
                  guard.phone,
                  guard.email,
                  guard.psiraNumber,
                  guard.psiraExpiry ?? '-',
