            'code',
            'client_id',
            'address',
            'lat',
            'lng',
            'contact_person',
            'contact_phone',
            'fsk_number',
            'geofence_radius_meters',
            'status',
          ],
          _sites
              .map(
                (site) => <String>[
                  site.id,
                  site.name,
                  site.code,
