      AdministrationPageTab.clients => (
        _csvFromRows(
          const <String>[
            'client_id',
            'name',
            'code',
            'contact_person',
            'contact_email',
            'contact_phone',
            'sla_tier',
            'contract_start',
            'contract_end',
            'sites',
            'status',
          ],
          _clients
              .map(
                (client) => <String>[
                  client.id,
                  client.name,
                  client.code,
                  client.contactPerson,
                  client.contactEmail,
                  client.contactPhone,
                  client.slaTier,
                  client.contractStart,
                  client.contractEnd,
