  _AdminCsvTarget get _activeCsvImportTarget {
    return switch (_activeTab) {
      AdministrationPageTab.sites => _AdminCsvTarget.sites,
      AdministrationPageTab.clients => _AdminCsvTarget.clients,
      AdministrationPageTab.guards ||
      AdministrationPageTab.system => _AdminCsvTarget.guards,
    };
  }

  String _adminCsvImportHelperText(_AdminCsvTarget target) {
    return switch (target) {
      _AdminCsvTarget.guards =>
        'Headers: employee_code, name, role, assigned_site, phone, email, psira_number, psira_expiry, status, certifications, shift_pattern, emergency_contact',
      _AdminCsvTarget.sites =>
        'Headers: site_id, name, code, client_id, address, lat, lng, contact_person, contact_phone, fsk_number, geofence_radius_meters, status',
      _AdminCsvTarget.clients =>
        'Headers: client_id, name, code, contact_person, contact_email, contact_phone, sla_tier, contract_start, contract_end, sites, status',
    };
  }

  int _importAdminCsv(_AdminCsvImportRequest request) {
    final parsed = _parseCsvTable(request.rawCsv);
    if (parsed.isEmpty) {
      throw const FormatException('No CSV rows found.');
    }
    final header = parsed.first
        .map(_normalizeCsvHeader)
        .toList(growable: false);
    if (header.isEmpty) {
      throw const FormatException('CSV header row is missing.');
    }
    final bodyRows = parsed
        .skip(1)
        .where((row) {
          return row.any((cell) => cell.trim().isNotEmpty);
        })
        .toList(growable: false);
    if (bodyRows.isEmpty) {
      throw const FormatException(
        'Add at least one data row below the header.',
      );
    }
    return switch (request.target) {
      _AdminCsvTarget.guards => _importGuardCsvRows(header, bodyRows),
      _AdminCsvTarget.sites => _importSiteCsvRows(header, bodyRows),
      _AdminCsvTarget.clients => _importClientCsvRows(header, bodyRows),
    };
  }

  int _importGuardCsvRows(List<String> header, List<List<String>> bodyRows) {
    final imported = <_GuardAdminRow>[];
    for (final row in bodyRows) {
      final values = _csvRowMap(header, row);
      final employeeCode = _csvValue(values, const [
        'employee_code',
        'employeeid',
        'id',
      ]);
      final name = _csvValue(values, const ['name', 'full_name']);
      if (employeeCode.isEmpty || name.isEmpty) continue;
      imported.add(
        _GuardAdminRow(
          id: employeeCode,
          name: name,
          role: _csvValue(values, const ['role'], fallback: 'guard'),
          employeeId: employeeCode,
          phone: _csvValue(values, const [
            'phone',
            'contact_phone',
          ], fallback: '-'),
          email: _csvValue(values, const [
            'email',
            'contact_email',
          ], fallback: '-'),
          psiraNumber: _csvValue(values, const ['psira_number'], fallback: '-'),
          psiraExpiry: _emptyToNull(
            _csvValue(values, const ['psira_expiry'], fallback: ''),
          ),
          certifications: _csvListValue(values, const ['certifications']),
          assignedSite: _csvValue(values, const ['assigned_site', 'site_id']),
          shiftPattern: _csvValue(values, const [
            'shift_pattern',
          ], fallback: 'Unassigned'),
          emergencyContact: _csvValue(values, const [
            'emergency_contact',
          ], fallback: '-'),
          status: _adminStatusFromCsv(
            _csvValue(values, const ['status'], fallback: 'active'),
          ),
        ),
      );
    }
    if (imported.isEmpty) {
      throw const FormatException(
        'CSV did not include any employee rows with employee_code and name.',
      );
    }
    setState(() {
      _guards = _mergeById<_GuardAdminRow>(
        existing: _guards,
        incoming: imported,
        idFor: (row) => row.id,
      );
      _directorySyncMessage =
          'Imported ${imported.length} employee row(s) from CSV.';
    });
    return imported.length;
  }

  int _importSiteCsvRows(List<String> header, List<List<String>> bodyRows) {
    final imported = <_SiteAdminRow>[];
    for (final row in bodyRows) {
      final values = _csvRowMap(header, row);
      final siteId = _csvValue(values, const ['site_id', 'id']);
      final siteName = _csvValue(values, const ['name', 'site_name']);
      if (siteId.isEmpty || siteName.isEmpty) continue;
      imported.add(
        _SiteAdminRow(
          id: siteId,
          name: siteName,
          code: _csvValue(values, const [
            'code',
            'site_code',
          ], fallback: siteId),
          clientId: _csvValue(values, const [
            'client_id',
          ], fallback: 'UNASSIGNED'),
          address: _csvValue(values, const ['address'], fallback: '-'),
          lat: _csvDouble(values, const ['lat', 'latitude']),
          lng: _csvDouble(values, const ['lng', 'longitude']),
          contactPerson: _csvValue(values, const [
            'contact_person',
          ], fallback: '-'),
          contactPhone: _csvValue(values, const [
            'contact_phone',
          ], fallback: '-'),
          fskNumber: _emptyToNull(_csvValue(values, const ['fsk_number'])),
          geofenceRadiusMeters: _csvInt(values, const [
            'geofence_radius_meters',
          ], fallback: 300),
          status: _adminStatusFromCsv(
            _csvValue(values, const ['status'], fallback: 'active'),
          ),
        ),
      );
    }
    if (imported.isEmpty) {
      throw const FormatException(
        'CSV did not include any site rows with site_id and name.',
      );
    }
    setState(() {
      final mergedSites = _mergeById<_SiteAdminRow>(
        existing: _sites,
        incoming: imported,
        idFor: (row) => row.id,
      );
      _sites = mergedSites;
      _clients = _recomputeClientSiteCounts(_clients, mergedSites);
      _directorySyncMessage =
          'Imported ${imported.length} site row(s) from CSV.';
    });
    return imported.length;
  }

  int _importClientCsvRows(List<String> header, List<List<String>> bodyRows) {
    final imported = <_ClientAdminRow>[];
    for (final row in bodyRows) {
      final values = _csvRowMap(header, row);
      final clientId = _csvValue(values, const ['client_id', 'id']);
      final name = _csvValue(values, const ['name', 'legal_name']);
      if (clientId.isEmpty || name.isEmpty) continue;
      imported.add(
        _ClientAdminRow(
          id: clientId,
          name: name,
          code: _csvValue(values, const ['code'], fallback: clientId),
          contactPerson: _csvValue(values, const [
            'contact_person',
          ], fallback: '-'),
          contactEmail: _csvValue(values, const [
            'contact_email',
          ], fallback: '-'),
          contactPhone: _csvValue(values, const [
            'contact_phone',
          ], fallback: '-'),
          slaTier: _csvValue(values, const ['sla_tier'], fallback: 'gold'),
          contractStart: _csvValue(values, const [
            'contract_start',
          ], fallback: '-'),
          contractEnd: _csvValue(values, const ['contract_end'], fallback: '-'),
          sites: _csvInt(values, const ['sites'], fallback: 0),
          status: _adminStatusFromCsv(
            _csvValue(values, const ['status'], fallback: 'active'),
          ),
        ),
      );
    }
    if (imported.isEmpty) {
      throw const FormatException(
        'CSV did not include any client rows with client_id and name.',
      );
    }
    setState(() {
      final mergedClients = _mergeById<_ClientAdminRow>(
        existing: _clients,
        incoming: imported,
        idFor: (row) => row.id,
      );
      _clients = _recomputeClientSiteCounts(mergedClients, _sites);
      _directorySyncMessage =
          'Imported ${imported.length} client row(s) from CSV.';
    });
    return imported.length;
  }

  List<T> _mergeById<T>({
    required List<T> existing,
    required List<T> incoming,
    required String Function(T row) idFor,
  }) {
    final merged = <String, T>{
      for (final row in existing) idFor(row): row,
      for (final row in incoming) idFor(row): row,
    };
    return merged.values.toList(growable: false);
  }

  List<_ClientAdminRow> _recomputeClientSiteCounts(
    List<_ClientAdminRow> clients,
    List<_SiteAdminRow> sites,
  ) {
    final counts = <String, int>{};
    for (final site in sites) {
      counts.update(site.clientId, (value) => value + 1, ifAbsent: () => 1);
    }
    return clients
        .map(
          (client) => _ClientAdminRow(
            id: client.id,
            name: client.name,
            code: client.code,
            contactPerson: client.contactPerson,
            contactEmail: client.contactEmail,
            contactPhone: client.contactPhone,
            slaTier: client.slaTier,
            contractStart: client.contractStart,
            contractEnd: client.contractEnd,
            sites: counts[client.id] ?? client.sites,
            status: client.status,
          ),
        )
        .toList(growable: false);
  }

  Map<String, String> _csvRowMap(List<String> header, List<String> row) {
    final map = <String, String>{};
    for (var index = 0; index < header.length; index++) {
      map[header[index]] = index < row.length ? row[index].trim() : '';
    }
    return map;
  }

  String _csvValue(
    Map<String, String> values,
    List<String> aliases, {
    String fallback = '',
  }) {
    for (final alias in aliases) {
      final normalized = _normalizeCsvHeader(alias);
      final value = values[normalized];
      if (value != null && value.trim().isNotEmpty) {
        return value.trim();
      }
    }
    return fallback;
  }

  List<String> _csvListValue(Map<String, String> values, List<String> aliases) {
    final raw = _csvValue(values, aliases);
    if (raw.isEmpty) return const <String>[];
    return raw
        .split(RegExp(r'[|;]'))
        .map((value) => value.trim())
        .where((value) => value.isNotEmpty)
        .toList(growable: false);
  }

  int _csvInt(
    Map<String, String> values,
    List<String> aliases, {
    required int fallback,
  }) {
    final raw = _csvValue(values, aliases);
    return int.tryParse(raw) ?? fallback;
  }

  double _csvDouble(Map<String, String> values, List<String> aliases) {
    final raw = _csvValue(values, aliases);
    return double.tryParse(raw) ?? 0;
  }

  String _normalizeCsvHeader(String value) {
    return value.trim().toLowerCase().replaceAll(RegExp(r'[^a-z0-9]+'), '_');
  }

  List<List<String>> _parseCsvTable(String raw) {
    final rows = <List<String>>[];
    final currentRow = <String>[];
    var currentCell = StringBuffer();
    var inQuotes = false;
    for (var index = 0; index < raw.length; index++) {
      final char = raw[index];
      if (char == '"') {
        if (inQuotes && index + 1 < raw.length && raw[index + 1] == '"') {
          currentCell.write('"');
          index++;
        } else {
          inQuotes = !inQuotes;
        }
        continue;
      }
      if (!inQuotes && char == ',') {
        currentRow.add(currentCell.toString());
        currentCell = StringBuffer();
        continue;
      }
      if (!inQuotes && (char == '\n' || char == '\r')) {
        if (char == '\r' && index + 1 < raw.length && raw[index + 1] == '\n') {
          index++;
        }
        currentRow.add(currentCell.toString());
        currentCell = StringBuffer();
        rows.add(List<String>.from(currentRow));
        currentRow.clear();
        continue;
      }
      currentCell.write(char);
    }
    if (currentCell.length > 0 || currentRow.isNotEmpty) {
      currentRow.add(currentCell.toString());
      rows.add(List<String>.from(currentRow));
    }
    return rows
        .where((row) => row.any((cell) => cell.trim().isNotEmpty))
        .toList(growable: false);
  }

  String _csvFromRows(List<String> header, List<List<String>> rows) {
    final buffer = StringBuffer()..writeln(header.map(_csvEscape).join(','));
    for (final row in rows) {
      buffer.writeln(row.map(_csvEscape).join(','));
    }
    return buffer.toString().trimRight();
  }

  String _csvEscape(String value) {
    final needsQuotes =
        value.contains(',') || value.contains('"') || value.contains('\n');
    if (!needsQuotes) return value;
    return '"${value.replaceAll('"', '""')}"';
  }

  String _adminStatusCsvLabel(_AdminStatus status) {
    return switch (status) {
      _AdminStatus.active => 'active',
      _AdminStatus.inactive => 'inactive',
      _AdminStatus.suspended => 'suspended',
    };
  }

  _AdminStatus _adminStatusFromCsv(String raw) {
    return switch (raw.trim().toLowerCase()) {
      'inactive' => _AdminStatus.inactive,
      'suspended' => _AdminStatus.suspended,
      _ => _AdminStatus.active,
    };
  }

  String? _emptyToNull(String value) {
    final trimmed = value.trim();
    return trimmed.isEmpty || trimmed == '-' ? null : trimmed;
  }

  String _resolvedInitialRadioIntentPhrasesJson() {
    final raw = widget.initialRadioIntentPhrasesJson.trim();
    if (raw.isNotEmpty) {
      return raw;
    }
    return '';
  }

  String _resolvedInitialDemoRouteCuesJson() {
    final raw = widget.initialDemoRouteCuesJson.trim();
    if (raw.isNotEmpty) {
      return raw;
    }
    return '';
  }

  String _runtimeDraftPayload({
    required String editorLabel,
    required String rawPayload,
    required String emptyStateNote,
  }) {
    final trimmed = rawPayload.trim();
    final stateLabel = trimmed.isEmpty ? 'defaults-active' : 'override';
    final payloadBody = trimmed.isEmpty ? emptyStateNote : trimmed;
    return 'ONYX ADMIN RUNTIME DRAFT\n'
        'Editor: $editorLabel\n'
        'State: $stateLabel\n'
        'Captured At (UTC): ${DateTime.now().toUtc().toIso8601String()}\n\n'
        'Payload\n'
        '$payloadBody';
  }

  Future<void> _stageRuntimeDraft({
    required String editorLabel,
    required String rawPayload,
    required String emptyStateNote,
    required String successMessage,
    required String sourceLabel,
    required String detail,
    required Color accent,
  }) async {
    await Clipboard.setData(
      ClipboardData(
        text: _runtimeDraftPayload(
          editorLabel: editorLabel,
          rawPayload: rawPayload,
          emptyStateNote: emptyStateNote,
        ),
      ),
    );
    if (!mounted) return;
    _snack(
      successMessage,
      sourceLabel: sourceLabel,
      detail: detail,
      accent: accent,
    );
  }

  Widget _runtimeFallbackNote({
    required String message,
    required Color accent,
  }) {
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 9),
      decoration: BoxDecoration(
        color: accent.withValues(alpha: 0.10),
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: accent.withValues(alpha: 0.30)),
      ),
      child: Text(
        message,
        style: GoogleFonts.inter(
          color: accent,
          fontSize: 11,
          fontWeight: FontWeight.w700,
          height: 1.35,
        ),
      ),
    );
  }

  Future<void> _validateRadioIntentJson() async {
    final raw = _radioIntentPhrasesController.text.trim();
    if (raw.isEmpty) {
      setState(() {
        _radioIntentPhraseValidation =
            'Valid: empty config uses default phrases.';
        _radioIntentPhraseValidationError = false;
      });
      return;
    }
    final parsed = OnyxRadioIntentPhraseCatalog.tryParseJsonString(raw);
    if (parsed == null) {
      setState(() {
        _radioIntentPhraseValidation =
            'Invalid JSON or missing phrase arrays for all_clear/panic/duress/status.';
        _radioIntentPhraseValidationError = true;
      });
      return;
    }
    setState(() {
      _radioIntentPhraseValidation =
          'Valid: all_clear=${parsed.allClearPhrases.length}, panic=${parsed.panicPhrases.length}, duress=${parsed.duressPhrases.length}, status=${parsed.statusPhrases.length}.';
      _radioIntentPhraseValidationError = false;
    });
  }

  Future<void> _saveRadioIntentJson() async {
    await _validateRadioIntentJson();
    if (_radioIntentPhraseValidationError) {
      return;
    }
    if (widget.onSaveRadioIntentPhrasesJson == null) {
      if (mounted) {
        setState(() {
          _radioIntentPhraseValidation =
              'Validated locally and staged for command review while runtime persistence is offline.';
          _radioIntentPhraseValidationError = false;
        });
      }
      await _stageRuntimeDraft(
        editorLabel: 'Radio Intent Dictionary',
        rawPayload: _radioIntentPhrasesController.text,
        emptyStateNote:
            'Defaults active. Empty config uses the built-in radio phrase catalog.',
        successMessage: 'Radio intent runtime draft copied for command review.',
        sourceLabel: 'RADIO RUNTIME',
        detail:
            'Persistence hooks are offline, so the validated phrase payload was staged to the clipboard while the system workspace stays in view.',
        accent: const Color(0xFF67E8F9),
      );
      return;
    }
    setState(() {
      _radioIntentPhrasesSaving = true;
    });
    try {
      await widget.onSaveRadioIntentPhrasesJson!(
        _radioIntentPhrasesController.text,
      );
      if (!mounted) return;
      _snack('Radio intent dictionary saved.');
    } catch (error) {
      if (!mounted) return;
      setState(() {
        _radioIntentPhraseValidation = error.toString();
        _radioIntentPhraseValidationError = true;
      });
    } finally {
      if (mounted) {
        setState(() {
          _radioIntentPhrasesSaving = false;
        });
      }
    }
  }

  Future<void> _resetRadioIntentJson() async {
    final previousText = _radioIntentPhrasesController.text;
    final previousValidation = _radioIntentPhraseValidation;
    final previousValidationError = _radioIntentPhraseValidationError;
    if (widget.onResetRadioIntentPhrasesJson == null) {
      _radioIntentPhrasesController.clear();
      if (!mounted) return;
      setState(() {
        _radioIntentPhraseValidation = 'Default phrase dictionary restored.';
        _radioIntentPhraseValidationError = false;
      });
      _snack('Radio intent dictionary reset to defaults.');
      return;
    }
    setState(() {
      _radioIntentPhrasesSaving = true;
    });
    try {
      await widget.onResetRadioIntentPhrasesJson!();
      if (!mounted) return;
      _radioIntentPhrasesController.clear();
      setState(() {
        _radioIntentPhraseValidation = 'Default phrase dictionary restored.';
        _radioIntentPhraseValidationError = false;
      });
      _snack('Radio intent dictionary reset to defaults.');
    } catch (error) {
      if (!mounted) return;
      _radioIntentPhrasesController.value = TextEditingValue(
        text: previousText,
        selection: TextSelection.collapsed(offset: previousText.length),
      );
      setState(() {
        _radioIntentPhraseValidation =
            previousValidation ?? 'Failed to reset radio intent dictionary.';
        _radioIntentPhraseValidationError = previousValidationError;
      });
      _snack('Failed to reset radio intent dictionary.');
    } finally {
      if (mounted) {
        setState(() {
          _radioIntentPhrasesSaving = false;
        });
      }
    }
  }

  Future<void> _validateDemoRouteCueJson() async {
    final raw = _demoRouteCuesController.text.trim();
    if (raw.isEmpty) {
      setState(() {
        _demoRouteCueValidation = 'Valid: empty config uses default cues.';
        _demoRouteCueValidationError = false;
      });
      return;
    }
    final parsed = _parseDemoRouteCueMap(raw);
    if (parsed == null) {
      setState(() {
        _demoRouteCueValidation =
            'Invalid JSON. Expected object entries like {"dashboard":"..."} with non-empty string values.';
        _demoRouteCueValidationError = true;
      });
      return;
    }
    setState(() {
      _demoRouteCueValidation =
          'Valid: ${parsed.length} cue override${parsed.length == 1 ? '' : 's'} loaded.';
      _demoRouteCueValidationError = false;
    });
  }

  Map<String, String>? _parseDemoRouteCueMap(String raw) {
    try {
      final decoded = jsonDecode(raw);
      if (decoded is! Map) return null;
      final output = <String, String>{};
      decoded.forEach((key, value) {
        final routeKey = key.toString().trim().toLowerCase();
        final cue = value?.toString().trim() ?? '';
        if (routeKey.isEmpty || cue.isEmpty) {
          return;
        }
        output[routeKey] = cue;
      });
      return output;
    } catch (_) {
      return null;
    }
  }

  Future<void> _saveDemoRouteCueJson() async {
    await _validateDemoRouteCueJson();
    if (_demoRouteCueValidationError) {
      return;
