  @override
  Widget build(BuildContext context) {
    final compact = MediaQuery.sizeOf(context).width < 640;
    final readyCount = _previewGates.where((gate) => gate.ready).length;
    final nextGapStep = _nextIncompleteStep;
    final telegramPrefill = widget.initialPrefill;
    final telegramSeeded = telegramPrefill != null;
    final telegramVendor = (telegramPrefill?.vendor ?? '').trim();
    final telegramContact = (telegramPrefill?.contactName ?? '').trim();
    final telegramCaptureSummary = <String>[
      if (telegramPrefill?.cameraCount != null)
        '${telegramPrefill!.cameraCount} cameras',
      if (telegramVendor.isNotEmpty) telegramVendor,
      if (telegramContact.isNotEmpty) telegramContact,
      if (telegramPrefill?.wantsTelegramBinding ?? false)
        'Telegram bridge intent',
    ].join(', ');
    final clientCommandHeadline = telegramSeeded
        ? _allGatesReady
              ? 'Telegram-approved client intake is ready for live command handoff.'
              : nextGapStep != null
              ? 'Telegram-approved client intake is staged and recoverable.'
              : 'Telegram-approved client intake is staged for contract command review.'
        : _clientTemplatePending
        ? '${_clientScenarioLabel(_selectedClientScenario)} scenario is queued for contract seeding.'
        : _allGatesReady
        ? 'Client contract is ready for live command handoff.'
        : 'Client contract scaffolding is active and recoverable.';
    final clientCommandDetail = telegramSeeded
        ? telegramCaptureSummary.isEmpty
              ? 'Approved Telegram intake already staged the client scope. Verify the contract pack here, then hand straight into the next live desk.'
              : 'Approved Telegram intake already staged $telegramCaptureSummary. Verify the contract pack here, then hand straight into the next live desk.'
        : _allGatesReady
        ? 'Identity, sovereign contact, SLA posture, and messaging bridge are aligned so the operator can pivot straight into the next live desk.'
        : 'The command layer keeps the strongest next move visible while the deeper guided workflow stays open below.';
    final clientNextMoveLabel = telegramSeeded
        ? nextGapStep != null
              ? 'VERIFY TELEGRAM INTAKE'
              : _canOpenClientOperationsPreview
              ? 'SECURITY DESK'
              : _canOpenClientTacticalPreview
              ? 'TACTICAL TRACK'
              : 'Finish client setup'
        : _clientTemplatePending
        ? 'Seed scenario'
        : nextGapStep != null
        ? 'Recover Step ${nextGapStep + 1}'
        : _canOpenClientOperationsPreview
        ? 'SECURITY DESK'
        : _canOpenClientTacticalPreview
        ? 'TACTICAL TRACK'
        : 'Lock review handoff';
    final clientWorkflowHeadline = _clientTemplatePending
        ? '${_clientScenarioLabel(_selectedClientScenario)} template pack is waiting for contract seeding.'
        : nextGapStep != null
        ? 'Workflow tools are lined up around Step ${nextGapStep + 1} recovery.'
        : _canOpenClientOperationsPreview
        ? 'Workflow tools are aligned for an operations handoff.'
        : _canOpenClientTacticalPreview
        ? 'Workflow tools are aligned for a tactical handoff.'
        : 'Workflow tools are aligned for final review.';
    final clientWorkflowNextMove = _clientTemplatePending
        ? 'Apply template'
        : nextGapStep != null
        ? 'Recover Step ${nextGapStep + 1}'
        : _canOpenClientOperationsPreview
        ? 'Launch ops review'
        : _canOpenClientTacticalPreview
        ? 'Launch tactical review'
        : 'Run demo ready';
    Future<void> copyClientPitchBrief() async {
      await Clipboard.setData(ClipboardData(text: _clientPitchText()));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Client pitch copied for command review.',
      );
    }

    Future<void> copyClientSnapshotBrief() async {
      await Clipboard.setData(ClipboardData(text: _clientSnapshotText()));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Client snapshot copied for command review.',
      );
    }

    Future<void> copyTelegramClientOperationalSeedBrief() async {
      final scopeSummary = [
        _clientIdController.text.trim().toUpperCase(),
        if ((telegramPrefill?.siteId ?? '').trim().isNotEmpty)
          telegramPrefill!.siteId.trim().toUpperCase(),
      ].where((entry) => entry.isNotEmpty).join(' / ');
      final intakeSummary = <String>[
        if (telegramPrefill?.cameraCount != null)
          '${telegramPrefill!.cameraCount} cameras',
        if (telegramVendor.isNotEmpty) telegramVendor,
        if (telegramContact.isNotEmpty) telegramContact,
        if (telegramPrefill?.wantsTelegramBinding ?? false)
          'Telegram bridge requested',
      ].join(', ');
      final brief = [
        'Approved Telegram Client Intake',
        if (scopeSummary.isNotEmpty) 'Scope: $scopeSummary',
        if (intakeSummary.isNotEmpty) 'Captured: $intakeSummary',
        'Next operational setup:',
        '1. Verify contract and sovereign contact anchors.',
        '2. Confirm Messaging Bridge routing and consent.',
        '3. Link the live client Telegram room once chat or topic IDs are confirmed.',
      ].join('\n');
      await Clipboard.setData(ClipboardData(text: brief));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Telegram client setup brief copied for command review.',
      );
    }

    void focusClientNextGap() {
      final target = _nextIncompleteStep;
      if (target == null) {
        _showOnboardingSnackBar(
          context,
          'All readiness gates are already complete.',
        );
        return;
      }
      setState(() => _step = target);
      _showOnboardingSnackBar(
        context,
        'Jumped to Step ${target + 1} for missing inputs.',
      );
    }

    void focusClientMessagingBridgeFromTelegram() {
      setState(() => _step = 3);
      _showOnboardingSnackBar(
        context,
        'Jumped to Messaging Bridge to verify Telegram routing.',
      );
    }

    final clientPrimaryAction = _OnboardingCommandActionConfig(
      key: const ValueKey('client-onboarding-primary-action'),
      readyKey: _allGatesReady && _step == 3
          ? clientOnboardingCreateReadyButtonKey
          : null,
      label: telegramSeeded
          ? nextGapStep != null
                ? 'Verify Intake'
                : _canOpenClientOperationsPreview
                ? 'Ops Focus'
                : _canOpenClientTacticalPreview
                ? 'Map Focus'
                : 'Finish Setup'
          : _clientTemplatePending
          ? 'Prime Scenario'
          : nextGapStep != null
          ? 'Recover Flow'
          : _canOpenClientOperationsPreview
          ? 'Ops Focus'
          : _canOpenClientTacticalPreview
          ? 'Map Focus'
          : 'Ready Lock',
      icon: telegramSeeded
          ? nextGapStep != null
                ? Icons.verified_rounded
                : _canOpenClientOperationsPreview
                ? Icons.space_dashboard_rounded
                : _canOpenClientTacticalPreview
                ? Icons.map_rounded
                : Icons.task_alt_rounded
          : _clientTemplatePending
          ? Icons.auto_awesome_rounded
          : nextGapStep != null
          ? Icons.track_changes_rounded
          : _canOpenClientOperationsPreview
          ? Icons.space_dashboard_rounded
          : _canOpenClientTacticalPreview
          ? Icons.map_rounded
          : Icons.task_alt_rounded,
      onPressed: telegramSeeded
          ? nextGapStep != null
                ? focusClientNextGap
                : _canOpenClientOperationsPreview
                ? _openClientOperationsPreview
                : _canOpenClientTacticalPreview
                ? _openClientTacticalPreview
                : () => _showOnboardingSnackBar(
                    context,
                    'Telegram-approved client intake is staged for final setup review.',
