              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    telegramCaptureSummary.isEmpty
                        ? 'Approved Telegram intake is staged and ready for contract, contact, and bridge verification.'
                        : 'Captured: $telegramCaptureSummary.',
                    style: GoogleFonts.inter(
                      color: _adminDialogBodyColor,
