                ],
              ),
            ),
          ],
          if (widget.demoMode) ...[
            const SizedBox(height: 8),
            _onboardingWorkflowActionsShelf(
              key: const ValueKey('client-onboarding-workflow-actions'),
              accent: const Color(0xFF2A6CC6),
              label: 'WORKFLOW ACTIONS',
