              microColor: !idReady
                  ? const Color(0xFFF1B872)
                  : idAlreadyApplied
                  ? const Color(0xFF8FD1FF)
                  : const Color(0xFFBFE6FF),
              keyPrefix: 'site-onboarding-identity-suggestion-id',
            ),
            _identitySuggestionChip(
              label: 'Suggested Code',
              value: codeReady ? suggestedCode : 'Type Site Name',
              ready: codeReady,
              microValue: !codeReady
                  ? 'Name site'
                  : codeAlreadyApplied
                  ? 'Code live'
                  : 'Apply code',
              microColor: !codeReady
                  ? const Color(0xFFF1B872)
                  : codeAlreadyApplied
