  Widget _siteRiskTimerConsoleCard() {
    final nudge = int.tryParse(_nudgeController.text.trim());
    final escalation = int.tryParse(_escalationController.text.trim());
    final valid = (nudge ?? 0) > 0 && (escalation ?? 0) > 0;
    final recommendedNudge = _recommendedNudgeMinutesForProfile(_riskProfile);
    final recommendedEscalation = _recommendedEscalationMinutesForProfile(
      _riskProfile,
    );
    final matchesProfileDefaults =
        nudge == recommendedNudge && escalation == recommendedEscalation;
    final cadenceTier = _riskCadenceTierLabel(
      nudge: nudge,
      escalation: escalation,
    );
    final accent = valid
        ? _riskCadenceTierColor(cadenceTier)
        : _riskProfileAccent(_riskProfile);
    final commandHeadline = !valid
        ? 'Cadence overrides still need live timing values.'
        : matchesProfileDefaults
        ? 'Profile cadence is aligned and ready to push.'
        : 'Custom cadence is overriding the profile baseline.';
    final commandDetail = !valid
        ? 'Stage the current profile cadence first, then only keep custom timings if the SLA really needs them.'
        : matchesProfileDefaults
        ? 'The nudge and escalation windows match the selected risk profile, so one move can push the full ops pack.'
        : 'Custom timing is live here. Keep it deliberate and reset back to the profile baseline when the special case ends.';
    final nextMoveLabel = !valid
        ? 'Stage profile cadence'
        : matchesProfileDefaults
        ? 'Apply ops pack'
        : 'Reset profile cadence';
    final nudgeReady = (nudge ?? 0) > 0;
    final escalationReady = (escalation ?? 0) > 0;
    return _onboardingControlShell(
      keyPrefix: 'site-onboarding-risk-timers',
      label: 'Cadence tuning',
      modeLabel: valid
          ? matchesProfileDefaults
                ? 'PROFILE LIVE'
                : 'CUSTOM LIVE'
          : 'TIMERS QUEUE',
      icon: Icons.tune_rounded,
      detail:
          'Tune guard nudge and escalation only when the client posture needs a custom override, then push the full ops pack in one move.',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _siteOnboardingActionDeck(
            keyPrefix: 'site-onboarding-risk-timers-command',
            accent: accent,
            label: 'CADENCE COMMAND',
            headline: commandHeadline,
            detail: commandDetail,
            nextMoveLabel: nextMoveLabel,
            chips: [
              _OnboardingCommandChipData(
                label: 'Profile',
                value: _riskProfile.replaceAll('_', ' ').toUpperCase(),
                color: _riskProfileAccent(_riskProfile),
              ),
              _OnboardingCommandChipData(
                label: 'Nudge',
                value: nudgeReady ? '$nudge min' : 'queue',
                color: nudgeReady
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Escalation',
                value: escalationReady ? '$escalation min' : 'queue',
                color: escalationReady
                    ? const Color(0xFF7EF2C3)
                    : const Color(0xFFF1B872),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey('site-onboarding-risk-timers-primary-action'),
              label: 'Apply Risk Ops Pack',
              icon: Icons.auto_fix_high_rounded,
              onPressed: _applyRiskOpsPack,
              foregroundColor: const Color(0xFFEAF4FF),
              borderColor: accent.withValues(alpha: 0.85),
              backgroundColor: accent.withValues(alpha: 0.88),
              filled: true,
            ),
            secondaryActions: [
              _OnboardingCommandActionConfig(
                key: const ValueKey(
                  'site-onboarding-risk-timers-profile-action',
                ),
                label: 'Profile Cadence',
                icon: Icons.restore_rounded,
                onPressed: () =>
                    setState(() => _applyRiskDefaults(_riskProfile)),
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: accent.withValues(alpha: 0.68),
              ),
            ],
          ),
          const SizedBox(height: 8),
          _siteRiskTimerFieldCard(
            keyPrefix: 'site-onboarding-risk-timers-nudge',
            label: 'Nudge cadence',
            detail: nudgeReady
                ? 'Guard acknowledgement rhythm is active and visible for command review.'
                : 'Stage or type the acknowledgement interval that should keep the guard loop alive.',
            ready: nudgeReady,
            icon: Icons.notifications_active_rounded,
            accent: accent,
            child: _textField(
              _nudgeController,
              'Guard Nudge Frequency (min)',
              onChanged: (_) => setState(() {}),
            ),
          ),
          const SizedBox(height: 8),
          _siteRiskTimerFieldCard(
            keyPrefix: 'site-onboarding-risk-timers-escalation',
            label: 'Escalation cadence',
            detail: escalationReady
                ? 'Supervisor escalation timing is active and ready for operations handoff.'
                : 'Stage or type the supervisor trigger so escalation posture stays explicit.',
            ready: escalationReady,
            icon: Icons.warning_amber_rounded,
            accent: accent,
            child: _textField(
              _escalationController,
              'Escalation Trigger (min)',
              onChanged: (_) => setState(() {}),
            ),
          ),
          const SizedBox(height: 6),
          Text(
            'Defaults are auto-loaded from the selected risk profile. Override only when client SLA needs custom cadence.',
            style: GoogleFonts.inter(
              color: const Color(0xFF9AB1CF),
              fontSize: 11,
              fontWeight: FontWeight.w600,
            ),
          ),
        ],
      ),
    );
  }

  Widget _locationIntegrityCard() {
    final hasAddress = _addressController.text.trim().isNotEmpty;
    final hasCoords =
        double.tryParse(_latController.text.trim()) != null &&
        double.tryParse(_lngController.text.trim()) != null;
    final recommended = _recommendedGeofenceMetersForProfile(_riskProfile);
    final geofence = int.tryParse(_geofenceController.text.trim());
    final geofenceInRange =
        geofence != null && geofence >= 150 && geofence <= 1000;
    final geofenceAligned =
        geofence != null && (geofence - recommended).abs() <= 200;
    final geofenceHealthy = geofenceInRange && geofenceAligned;
    final entryProtocolText = _entryProtocolController.text.trim();
    final hasEntryProtocol = entryProtocolText.length >= 16;
    final mapUrlRaw = _mapUrlController.text.trim();
    final parsedMapUrl = Uri.tryParse(mapUrlRaw);
    final hasMap =
        parsedMapUrl != null &&
        (parsedMapUrl.scheme == 'http' || parsedMapUrl.scheme == 'https') &&
        parsedMapUrl.host.isNotEmpty;
    final suggestedMapUrl = _suggestedLayoutMapUrl();
    final recommendedProtocol = _recommendedProtocolForProfile(_riskProfile);
    final protocolAligned = entryProtocolText == recommendedProtocol;
    final mapAligned = mapUrlRaw == suggestedMapUrl;
    final readyCount = [
      hasAddress,
      hasCoords,
      geofenceHealthy,
      hasEntryProtocol,
      hasMap,
    ].where((value) => value).length;
    final nextMoveLabel = !hasAddress
        ? 'Map address'
        : !hasCoords
        ? 'Lock geo pins'
        : !geofenceHealthy
        ? 'Tune geofence'
        : !hasEntryProtocol
        ? 'Stage gate flow'
        : !hasMap
        ? 'Link field plan'
        : 'Integrity sealed';
    final nextMoveDetail = !hasAddress
        ? 'Street and client naming should anchor the footprint before handoff.'
        : !hasCoords
        ? 'Drop the coordinate pair so dispatch, tactical, and SLA views line up.'
        : !geofenceHealthy
        ? 'Use the risk baseline or a nearby radius to stabilize the perimeter.'
        : !hasEntryProtocol
        ? 'Finish the gate and auth story so field teams inherit one clean flow.'
        : !hasMap
        ? 'Attach the layout URL so crews can open site plans without leaving the board.'
        : 'Address, geo, access flow, and map evidence are aligned for deployment.';
    final locationCommandHeadline = readyCount >= 5
        ? 'Location integrity is sealed for deployment.'
        : !hasAddress
        ? 'Location integrity still needs a mapped address.'
        : !hasCoords
        ? 'Location integrity still needs geo pins.'
        : !geofenceHealthy
        ? 'Location integrity needs the risk baseline radius.'
        : !hasEntryProtocol
        ? 'Location integrity still needs a deployment-ready gate flow.'
        : !hasMap
        ? 'Location integrity still needs a live field plan link.'
        : 'Location integrity is active and recoverable in place.';
    final primaryActionLabel = !geofenceHealthy
        ? 'Risk Default'
        : !hasEntryProtocol
        ? 'Profile Protocol'
        : !hasMap
        ? 'Suggested URL'
        : 'Location Live';
    final accent = readyCount >= 4
        ? const Color(0xFF22C55E)
        : (readyCount >= 2 ? const Color(0xFF38BDF8) : const Color(0xFFF97316));
    return AnimatedContainer(
      key: const ValueKey('site-onboarding-location-integrity-card'),
      duration: const Duration(milliseconds: 200),
      curve: Curves.easeOutCubic,
      width: double.infinity,
      padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: accent.withValues(alpha: 0.8)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Icon(Icons.place_rounded, size: 15, color: accent),
              const SizedBox(width: 6),
              Expanded(
                child: Text(
                  'Location Integrity',
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 11.5,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
              Text(
                '$readyCount/5 ready',
                style: GoogleFonts.inter(
                  color: _adminDialogBodyColor,
                  fontSize: 10.4,
                  fontWeight: FontWeight.w700,
                ),
              ),
            ],
          ),
          const SizedBox(height: 7),
          Wrap(
            spacing: 7,
            runSpacing: 7,
            children: [
              _integrityPill(
                label: 'Address',
                ready: hasAddress,
                value: hasAddress ? 'Mapped' : 'Awaiting address',
                hint: 'Street and client naming',
                keyPrefix: 'site-onboarding-location-integrity-address',
                readyMicroValue: 'Address live',
                pendingMicroValue: 'Map address',
              ),
              _integrityPill(
                label: 'Geo Pins',
                ready: hasCoords,
                value: hasCoords ? 'Locked' : 'Coordinate pair missing',
                hint: 'Lat / Lng anchor',
                keyPrefix: 'site-onboarding-location-integrity-geo-pins',
                readyMicroValue: 'Pins locked',
                pendingMicroValue: 'Lock geo pins',
              ),
              _integrityPill(
                label: 'Geofence',
                ready: geofenceHealthy,
                value: geofence == null ? 'Unset' : '${geofence}m',
                hint: 'Recommended baseline ${recommended}m',
                keyPrefix: 'site-onboarding-location-integrity-geofence',
                readyMicroValue: 'Perimeter live',
                pendingMicroValue: 'Tune radius',
              ),
              _integrityPill(
                label: 'Entry Protocol',
                ready: hasEntryProtocol,
                value: hasEntryProtocol ? 'Ready' : 'Need gate flow detail',
                hint: 'Auth and after-hours fallback',
                keyPrefix: 'site-onboarding-location-integrity-entry-protocol',
                readyMicroValue: 'Flow live',
                pendingMicroValue: 'Stage gate flow',
              ),
              _integrityPill(
                label: 'Layout Map',
                ready: hasMap,
                value: hasMap ? 'Linked' : 'Missing URL',
                hint: 'Live field plan link',
                keyPrefix: 'site-onboarding-location-integrity-layout-map',
                readyMicroValue: 'Plan linked',
                pendingMicroValue: 'Link field plan',
              ),
            ],
          ),
          const SizedBox(height: 7),
          Text(
            _locationIntegrityNarrative(
              readyCount: readyCount,
              geofence: geofence,
              recommended: recommended,
              geofenceInRange: geofenceInRange,
              geofenceAligned: geofenceAligned,
              entryProtocolReady: hasEntryProtocol,
              mapReady: hasMap,
            ),
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 10.6,
              fontWeight: FontWeight.w600,
              height: 1.28,
            ),
          ),
          const SizedBox(height: 7),
          _siteOnboardingActionDeck(
            keyPrefix: 'site-onboarding-location-integrity',
            accent: accent,
            label: 'LOCATION COMMAND',
            headline: locationCommandHeadline,
            detail: nextMoveDetail,
            nextMoveLabel: nextMoveLabel,
            chips: [
              _OnboardingCommandChipData(
                label: 'Ready',
                value: '$readyCount/5',
                color: readyCount >= 4
                    ? const Color(0xFF7EF2C3)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Radius',
                value: geofence == null ? 'queue' : '${geofence}m',
                color: geofenceHealthy
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Flow',
                value: hasEntryProtocol ? 'live' : 'queue',
                color: hasEntryProtocol
                    ? const Color(0xFFBFD7F2)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Map',
                value: hasMap ? 'linked' : 'queue',
                color: hasMap
                    ? const Color(0xFF7EF2C3)
                    : const Color(0xFFF1B872),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey(
                'site-onboarding-location-integrity-primary-action',
              ),
              label: primaryActionLabel,
              icon: !geofenceHealthy
                  ? Icons.tune_rounded
                  : !hasEntryProtocol
                  ? Icons.fact_check_rounded
                  : !hasMap
                  ? Icons.link_rounded
                  : Icons.task_alt_rounded,
              onPressed: !geofenceHealthy
                  ? () => setState(
                      () => _geofenceController.text = recommended.toString(),
                    )
                  : !hasEntryProtocol
                  ? () => setState(
                      () => _entryProtocolController.text = recommendedProtocol,
                    )
                  : !hasMap
                  ? () =>
                        setState(() => _mapUrlController.text = suggestedMapUrl)
                  : null,
              foregroundColor: const Color(0xFFEAF4FF),
              borderColor: accent.withValues(alpha: 0.85),
              backgroundColor: accent.withValues(alpha: 0.88),
              filled: true,
            ),
            secondaryActions: [
              if (geofence != recommended)
                _OnboardingCommandActionConfig(
                  key: const ValueKey(
                    'site-onboarding-location-integrity-risk-action',
                  ),
                  label: 'Risk Default',
                  icon: Icons.tune_rounded,
                  onPressed: () => setState(
                    () => _geofenceController.text = recommended.toString(),
                  ),
                  foregroundColor: const Color(0xFFEAF4FF),
                  borderColor: accent.withValues(alpha: 0.68),
                ),
              if (!protocolAligned)
                _OnboardingCommandActionConfig(
                  key: const ValueKey(
                    'site-onboarding-location-integrity-protocol-action',
                  ),
                  label: 'Profile Protocol',
                  icon: Icons.fact_check_rounded,
                  onPressed: () => setState(
                    () => _entryProtocolController.text = recommendedProtocol,
                  ),
                  foregroundColor: const Color(0xFFEAF4FF),
                  borderColor: accent.withValues(alpha: 0.68),
                ),
              if (!mapAligned)
                _OnboardingCommandActionConfig(
                  key: const ValueKey(
                    'site-onboarding-location-integrity-url-action',
                  ),
                  label: 'Suggested URL',
                  icon: Icons.link_rounded,
                  onPressed: () =>
                      setState(() => _mapUrlController.text = suggestedMapUrl),
                  foregroundColor: const Color(0xFFEAF4FF),
                  borderColor: accent.withValues(alpha: 0.68),
                ),
            ],
          ),
        ],
      ),
    );
  }

  Widget _tacticalFootprintCard() {
    final lat = double.tryParse(_latController.text.trim());
    final lng = double.tryParse(_lngController.text.trim());
    final hasCoords = lat != null && lng != null;
    final geofenceMeters =
        int.tryParse(_geofenceController.text.trim()) ??
        _recommendedGeofenceMetersForProfile(_riskProfile);
    final accent = _riskProfileAccent(_riskProfile);
    const minLat = -35.0;
    const maxLat = -22.0;
    const minLng = 16.0;
    const maxLng = 33.0;
    final resolvedLat = lat ?? ((minLat + maxLat) / 2);
    final resolvedLng = lng ?? ((minLng + maxLng) / 2);
    final normalizedLng = hasCoords
        ? ((resolvedLng - minLng) / (maxLng - minLng)).clamp(0.0, 1.0)
        : 0.5;
    final normalizedLat = hasCoords
        ? ((resolvedLat - minLat) / (maxLat - minLat)).clamp(0.0, 1.0)
        : 0.5;
    final markerAlignment = Alignment(
      ((normalizedLng * 2) - 1).clamp(-0.72, 0.72),
      (((1 - normalizedLat) * 2) - 1).clamp(-0.72, 0.72),
    );
    final ringRadius = (26 * (geofenceMeters / 450)).clamp(16.0, 54.0);
    final latLabel = hasCoords ? resolvedLat.toStringAsFixed(4) : 'Pending';
    final lngLabel = hasCoords ? resolvedLng.toStringAsFixed(4) : 'Pending';
    final statusLabel = hasCoords ? 'GPS locked' : 'Awaiting coordinates';
    final canOpenTactical = _canOpenTacticalPreviewAction;
    final canOpenOperations = _canOpenOperationsPreviewAction;
    final nextMoveLabel = !hasCoords
        ? 'Prime map'
        : canOpenTactical
        ? 'TACTICAL TRACK'
        : canOpenOperations
        ? 'SECURITY DESK'
        : 'Footprint live';
    final nextMoveDetail = !hasCoords
        ? 'Set the coordinate anchor so the live footprint and response ring wake up.'
        : canOpenTactical
        ? 'Route this staged footprint into tactical while the map stays centered here.'
        : canOpenOperations
        ? 'Use the resolved footprint to brief operations without losing the geo view.'
        : 'The anchor, ring, and selected risk posture are already staged cleanly.';
    return AnimatedContainer(
      key: const ValueKey('site-onboarding-tactical-footprint-card'),
      duration: const Duration(milliseconds: 220),
      curve: Curves.easeOutCubic,
      width: double.infinity,
      padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: accent.withValues(alpha: 0.78)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Icon(Icons.map_rounded, size: 15, color: accent),
              const SizedBox(width: 6),
              Expanded(
                child: Text(
                  'Tactical Footprint',
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 11.5,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                decoration: BoxDecoration(
                  color: accent.withValues(alpha: 0.18),
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: accent.withValues(alpha: 0.7)),
                ),
                child: Text(
                  _riskProfile.replaceAll('_', ' ').toUpperCase(),
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 10.2,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 7),
          AspectRatio(
            aspectRatio: 1.9,
            child: ClipRRect(
              borderRadius: BorderRadius.circular(10),
              child: Stack(
                children: [
                  Positioned.fill(
                    child: Container(
                      decoration: const BoxDecoration(
                        gradient: LinearGradient(
                          colors: [Color(0xFFF8FBFF), Color(0xFFEAF6FF)],
                          begin: Alignment.topLeft,
                          end: Alignment.bottomRight,
                        ),
                      ),
                    ),
                  ),
                  Positioned.fill(
                    child: CustomPaint(
                      painter: _TacticalMapGridPainter(accent: accent),
                    ),
                  ),
                  Align(
                    alignment: markerAlignment,
                    child: Container(
                      width: ringRadius * 2,
                      height: ringRadius * 2,
                      decoration: BoxDecoration(
                        shape: BoxShape.circle,
                        color: accent.withValues(alpha: 0.11),
                        border: Border.all(
                          color: accent.withValues(alpha: 0.85),
                          width: 1.4,
                        ),
                      ),
                    ),
                  ),
                  Align(
                    alignment: markerAlignment,
                    child: Container(
                      width: math.max(10.0, ringRadius * 0.36),
                      height: math.max(10.0, ringRadius * 0.36),
                      decoration: const BoxDecoration(
                        shape: BoxShape.circle,
                        color: Color(0xFF7EF2C3),
                        boxShadow: [
                          BoxShadow(
                            color: Color(0x5522D3EE),
                            blurRadius: 10,
                            spreadRadius: 2,
                          ),
                        ],
                      ),
                    ),
                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 7),
          Wrap(
            spacing: 7,
            runSpacing: 7,
            children: [
              _integrityPill(
                label: 'Lat',
                ready: hasCoords,
                value: latLabel,
                hint: 'Southbound anchor',
                keyPrefix: 'site-onboarding-tactical-footprint-lat',
                readyMicroValue: 'Latitude live',
                pendingMicroValue: 'Set latitude',
              ),
              _integrityPill(
                label: 'Lng',
                ready: hasCoords,
                value: lngLabel,
                hint: 'East-west anchor',
                keyPrefix: 'site-onboarding-tactical-footprint-lng',
                readyMicroValue: 'Longitude live',
                pendingMicroValue: 'Set longitude',
              ),
              _integrityPill(
                label: 'Geofence',
                ready: geofenceMeters > 0,
                value: '${geofenceMeters}m',
                hint: 'Response radius',
                keyPrefix: 'site-onboarding-tactical-footprint-geofence',
                readyMicroValue: 'Radius live',
                pendingMicroValue: 'Set radius',
              ),
              _integrityPill(
                label: 'Status',
                ready: hasCoords,
                value: statusLabel,
                hint: 'Map posture',
                keyPrefix: 'site-onboarding-tactical-footprint-status',
                readyMicroValue: 'Footprint live',
                pendingMicroValue: 'Prime map',
              ),
            ],
          ),
          const SizedBox(height: 7),
          _siteOnboardingActionDeck(
            keyPrefix: 'site-onboarding-tactical-footprint',
            accent: accent,
            label: 'FOOTPRINT COMMAND',
            headline: !hasCoords
                ? 'Footprint is waiting for live map anchors.'
                : canOpenTactical
                ? 'Footprint is ready for tactical handoff.'
                : canOpenOperations
                ? 'Footprint is ready for operations handoff.'
                : 'Footprint is staged and holding locally.',
            detail: nextMoveDetail,
            nextMoveLabel: nextMoveLabel,
            chips: [
              _OnboardingCommandChipData(
                label: 'Profile',
                value: _riskProfile.replaceAll('_', ' ').toUpperCase(),
                color: accent,
              ),
              _OnboardingCommandChipData(
                label: 'Anchor',
                value: hasCoords ? 'live' : 'queue',
                color: hasCoords
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Route',
                value: canOpenTactical
                    ? 'tactical'
                    : canOpenOperations
                    ? 'ops-live'
                    : 'local',
                color: canOpenTactical
                    ? const Color(0xFF9FE8FF)
                    : canOpenOperations
                    ? const Color(0xFFBFD7F2)
                    : const Color(0xFFF1B872),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey(
                'site-onboarding-tactical-footprint-primary-action',
              ),
              label: !hasCoords
