  Widget _riskResponseSimulatorCard() {
    final nudge = int.tryParse(_nudgeController.text.trim());
    final escalation = int.tryParse(_escalationController.text.trim());
    final valid = (nudge ?? 0) > 0 && (escalation ?? 0) > 0;
    final cadenceTier = _riskCadenceTierLabel(
      nudge: nudge,
      escalation: escalation,
    );
    final cadenceColor = _riskCadenceTierColor(cadenceTier);
    final firstNudge = valid ? '$nudge min' : 'Pending';
    final escalationWindow = valid ? '$escalation min' : 'Pending';
    final driftCheck = valid
        ? '${math.max(2, ((nudge ?? 0) / 3).round())} min interval'
        : 'Pending';
    final canOpenOperations = _canOpenOperationsPreviewAction;
    final canOpenTactical = _canOpenTacticalPreviewAction;
    final responseNextMoveLabel = !valid
        ? 'Set timers'
        : canOpenOperations
        ? 'SECURITY DESK'
        : canOpenTactical
        ? 'TACTICAL TRACK'
        : 'Hold response posture';
    final responseCommandHeadline = !valid
        ? 'Response cadence still needs timing anchors.'
        : canOpenOperations
        ? 'Response posture is ready for operations handoff.'
        : canOpenTactical
        ? 'Response posture is ready for tactical review.'
        : 'Response posture is sealed and standing by.';
    final responseCommandDetail = !valid
        ? 'Set nudge and escalation minutes so the simulator can stage a real response posture.'
        : canOpenOperations
        ? 'Use Security Desk as the primary follow-through while the simulator stays pinned below.'
        : canOpenTactical
        ? 'Tactical is the strongest live follow-through while the staged cadence stays visible here.'
        : 'The cadence is live even without a routed handoff, so the command shell keeps the posture readable.';
    return AnimatedContainer(
      key: const ValueKey('site-onboarding-risk-response-card'),
      duration: const Duration(milliseconds: 200),
      curve: Curves.easeOutCubic,
      width: double.infinity,
      padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
