  Color _riskProfileAccent(String profile) {
    switch (profile) {
      case 'industrial':
        return const Color(0xFFF97316);
      case 'residential':
        return const Color(0xFF22C55E);
      case 'commercial':
        return const Color(0xFF38BDF8);
      case 'mixed_use':
      default:
        return const Color(0xFFA78BFA);
    }
  }

  String _riskCadenceTierLabel({
    required int? nudge,
    required int? escalation,
  }) {
    if ((nudge ?? 0) <= 0 || (escalation ?? 0) <= 0) {
      return 'Cadence Pending';
    }
    if ((escalation ?? 0) <= 1 && (nudge ?? 0) <= 10) {
      return 'Aggressive';
    }
    if ((escalation ?? 0) <= 2 && (nudge ?? 0) <= 15) {
      return 'Balanced';
    }
    return 'Conservative';
  }

  Color _riskCadenceTierColor(String tier) {
    switch (tier) {
      case 'Aggressive':
        return const Color(0xFFF97316);
      case 'Balanced':
        return const Color(0xFF22C55E);
      case 'Conservative':
        return const Color(0xFF38BDF8);
      case 'Cadence Pending':
      default:
        return const Color(0xFFA78BFA);
    }
  }

  String _riskControllerCue({
    required int? nudge,
    required int? escalation,
    required bool valid,
  }) {
    if (!valid) {
      return 'Set positive timer values to simulate escalation behavior and guard check rhythm.';
    }
    if ((escalation ?? 0) <= 1) {
      return 'Controller cue: pre-stage nearest response unit and keep client advisory hot.';
    }
    if ((nudge ?? 0) <= 12) {
      return 'Controller cue: maintain frequent guard acknowledgements and monitor checkpoint drift.';
    }
    return 'Controller cue: standard patrol rhythm active; monitor for delay accumulation during peak load.';
  }

  String _riskProfileNarrative(String profile) {
    switch (profile) {
      case 'industrial':
        return 'High-alert posture with faster escalation and tighter patrol verification cycles.';
      case 'residential':
        return 'Balanced vigilance model optimized for perimeter confidence and resident flow.';
      case 'commercial':
        return 'Traffic-aware monitoring with structured cadence for entrances and loading zones.';
      case 'mixed_use':
      default:
        return 'Hybrid policy blending residential discipline with commercial response tempo.';
    }
  }

  int _riskFirstActionSeconds(String profile) {
    switch (profile) {
      case 'industrial':
        return 18;
      case 'commercial':
        return 24;
      case 'mixed_use':
        return 26;
      case 'residential':
      default:
        return 30;
    }
  }

  int _riskBaseArrivalSeconds(String profile) {
    switch (profile) {
      case 'industrial':
        return 160;
      case 'commercial':
        return 190;
      case 'mixed_use':
        return 205;
      case 'residential':
      default:
        return 225;
    }
  }

  int _resolveGeofenceForSla() {
    return int.tryParse(_geofenceController.text.trim()) ??
        _recommendedGeofenceMetersForProfile(_riskProfile);
  }

  int _resolveNudgeForSla() {
    return int.tryParse(_nudgeController.text.trim()) ??
        _recommendedNudgeMinutesForProfile(_riskProfile);
  }

  int _resolveEscalationForSla() {
    return int.tryParse(_escalationController.text.trim()) ??
        _recommendedEscalationMinutesForProfile(_riskProfile);
  }

  String _durationLabel(int totalSeconds) {
    final minutes = totalSeconds ~/ 60;
    final seconds = totalSeconds % 60;
    return '$minutes:${seconds.toString().padLeft(2, '0')}';
  }

  String _clientPromiseNarrative({
    required int firstActionSeconds,
    required int dispatchSeconds,
    required int advisorySeconds,
    required int arrivalSeconds,
    required int geofenceMeters,
    required int escalationMinutes,
  }) {
    return 'Controller action in ${_durationLabel(firstActionSeconds)}, dispatch in ${_durationLabel(dispatchSeconds)}, client advisory by ${_durationLabel(advisorySeconds)}, and expected arrival around ${_durationLabel(arrivalSeconds)} for a ${geofenceMeters}m perimeter. Escalation lock triggers at $escalationMinutes minute${escalationMinutes == 1 ? '' : 's'}.';
  }

  String _clientPromiseScript({
    required int firstActionSeconds,
    required int dispatchSeconds,
    required int advisorySeconds,
    required int arrivalSeconds,
    required int geofenceMeters,
    required int nudgeMinutes,
    required int escalationMinutes,
  }) {
    final siteName = _siteNameController.text.trim().isEmpty
        ? 'this site'
        : _siteNameController.text.trim();
    return 'On $siteName, ONYX commits to first controller action in ${_durationLabel(firstActionSeconds)} and dispatch in ${_durationLabel(dispatchSeconds)}. '
        'Client advisory is issued by ${_durationLabel(advisorySeconds)}, with expected unit arrival around ${_durationLabel(arrivalSeconds)} across a ${geofenceMeters}m perimeter. '
        'Guard vigilance runs every $nudgeMinutes minute${nudgeMinutes == 1 ? '' : 's'} with escalation at $escalationMinutes minute${escalationMinutes == 1 ? '' : 's'} if acknowledgement is missing.';
  }

  Future<void> _copyClientPromiseScript(String text) async {
    await Clipboard.setData(ClipboardData(text: text));
    if (!mounted) return;
    _showAdminFeedback(
      context,
      'Client demo script copied for command review.',
      sourceLabel: 'CLIENT PROMISE',
      accent: const Color(0xFF7FD8A5),
      detail:
          'The promise script stays visible in the desktop rail while you keep tuning the client briefing flow.',
    );
  }

  Widget _slaPromisePreviewCard() {
    final accent = _riskProfileAccent(_riskProfile);
    final geofenceMeters = _resolveGeofenceForSla();
    final nudgeMinutes = _resolveNudgeForSla();
    final escalationMinutes = _resolveEscalationForSla();
    final firstActionSeconds = _riskFirstActionSeconds(_riskProfile);
    final dispatchSeconds = firstActionSeconds + 22;
    final advisorySeconds = dispatchSeconds + 25;
    final geofenceAdjustment = ((geofenceMeters - 300) / 14).round();
    final arrivalSeconds =
        (_riskBaseArrivalSeconds(_riskProfile) + geofenceAdjustment).clamp(
          130,
          460,
        );
    final script = _clientPromiseScript(
      firstActionSeconds: firstActionSeconds,
      dispatchSeconds: dispatchSeconds,
      advisorySeconds: advisorySeconds,
      arrivalSeconds: arrivalSeconds,
      geofenceMeters: geofenceMeters,
      nudgeMinutes: nudgeMinutes,
      escalationMinutes: escalationMinutes,
    );
    final nextMoveLabel = _canOpenOperationsPreviewAction
        ? 'SECURITY DESK'
        : _canOpenTacticalPreviewAction
        ? 'TACTICAL TRACK'
        : 'Copy command promise';
    final slaCommandHeadline = _canOpenOperationsPreviewAction
        ? 'Client promise is ready for operations briefing.'
        : _canOpenTacticalPreviewAction
        ? 'Client promise is ready for tactical briefing.'
        : 'Client promise is staged and ready to copy.';
    final slaCommandDetail = _canOpenOperationsPreviewAction
        ? 'Use operations as the primary handoff while the promise timings and promise panel stay visible here.'
        : _canOpenTacticalPreviewAction
        ? 'Tactical is the strongest live handoff while the client promise stays pinned for briefing.'
        : 'No route is available, so keep the command promise simple and portable from this workspace.';
    return AnimatedContainer(
      key: const ValueKey('site-onboarding-sla-promise-card'),
      duration: const Duration(milliseconds: 180),
      curve: Curves.easeOutCubic,
      width: double.infinity,
      padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
      decoration: BoxDecoration(
        gradient: LinearGradient(
          colors: [accent.withValues(alpha: 0.14), const Color(0xFFF8FBFF)],
          begin: Alignment.topLeft,
          end: Alignment.bottomRight,
        ),
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: accent.withValues(alpha: 0.8)),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Icon(Icons.verified_rounded, size: 15, color: accent),
              const SizedBox(width: 6),
              Expanded(
                child: Text(
                  'SLA Promise Preview',
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: 11.5,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
              Container(
                key: const ValueKey('site-onboarding-sla-next-move'),
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                decoration: BoxDecoration(
                  color: accent.withValues(alpha: 0.16),
                  borderRadius: BorderRadius.circular(999),
                  border: Border.all(color: accent.withValues(alpha: 0.65)),
                ),
                child: Text(
                  nextMoveLabel,
                  style: GoogleFonts.inter(
                    color: const Color(0xFFEAF4FF),
                    fontSize: 9.2,
                    fontWeight: FontWeight.w800,
                    letterSpacing: 0.3,
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 7),
          Wrap(
            spacing: 7,
            runSpacing: 7,
            children: [
              _riskMetricChip(
                icon: Icons.flash_on_rounded,
                label: 'First Action',
                value: _durationLabel(firstActionSeconds),
                accent: accent,
                hint: 'Controller acknowledgement',
                keyPrefix: 'site-onboarding-sla-first-action',
                readyMicroValue: 'Promise live',
              ),
              _riskMetricChip(
                icon: Icons.send_rounded,
                label: 'Dispatch',
                value: _durationLabel(dispatchSeconds),
                accent: accent,
                hint: 'Field unit launch',
                keyPrefix: 'site-onboarding-sla-dispatch',
                readyMicroValue: 'Dispatch live',
              ),
              _riskMetricChip(
                icon: Icons.sms_rounded,
                label: 'Client Advisory',
                value: _durationLabel(advisorySeconds),
                accent: accent,
                hint: 'Client-facing reassurance',
                keyPrefix: 'site-onboarding-sla-client-advisory',
                readyMicroValue: 'Advisory live',
              ),
              _riskMetricChip(
                icon: Icons.directions_car_filled_rounded,
                label: 'Arrival',
                value: _durationLabel(arrivalSeconds),
                accent: accent,
                hint: 'Expected unit arrival',
                keyPrefix: 'site-onboarding-sla-arrival',
                readyMicroValue: 'Arrival live',
              ),
            ],
          ),
          const SizedBox(height: 7),
          Text(
            _clientPromiseNarrative(
              firstActionSeconds: firstActionSeconds,
              dispatchSeconds: dispatchSeconds,
              advisorySeconds: advisorySeconds,
              arrivalSeconds: arrivalSeconds,
              geofenceMeters: geofenceMeters,
              escalationMinutes: escalationMinutes,
            ),
            style: GoogleFonts.inter(
              color: const Color(0xFFCEE4FA),
              fontSize: 10.6,
              fontWeight: FontWeight.w600,
              height: 1.28,
            ),
          ),
          const SizedBox(height: 7),
          _siteOnboardingActionDeck(
            keyPrefix: 'site-onboarding-sla-command',
            accent: accent,
            label: 'PROMISE COMMAND',
            headline: slaCommandHeadline,
            detail: slaCommandDetail,
            nextMoveLabel: nextMoveLabel,
            chips: [
              _OnboardingCommandChipData(
                label: 'Profile',
                value: _riskProfile.replaceAll('_', ' ').toUpperCase(),
                color: accent,
              ),
              _OnboardingCommandChipData(
                label: 'Route',
                value: _canOpenOperationsPreviewAction
                    ? 'ops-live'
                    : _canOpenTacticalPreviewAction
                    ? 'tactical'
                    : 'copy',
                color: _canOpenOperationsPreviewAction
                    ? const Color(0xFF8FD1FF)
                    : _canOpenTacticalPreviewAction
                    ? const Color(0xFFBFD7F2)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Proof',
                value: 'timings-live',
                color: const Color(0xFF7EF2C3),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey('site-onboarding-sla-operations-action'),
              label: _canOpenOperationsPreviewAction
                  ? 'OPEN SECURITY DESK'
                  : _canOpenTacticalPreviewAction
                  ? 'OPEN TACTICAL TRACK'
                  : 'Copy Demo Script',
              icon: _canOpenOperationsPreviewAction
                  ? Icons.space_dashboard_rounded
                  : _canOpenTacticalPreviewAction
                  ? Icons.map_rounded
                  : Icons.content_copy_rounded,
              onPressed: _canOpenOperationsPreviewAction
                  ? _openOperationsPreview
                  : _canOpenTacticalPreviewAction
                  ? _openTacticalPreview
                  : () => _copyClientPromiseScript(script),
              foregroundColor: const Color(0xFFEAF4FF),
              borderColor: accent.withValues(alpha: 0.85),
              backgroundColor: accent.withValues(alpha: 0.88),
              filled: true,
            ),
            secondaryActions: [
              if (_canOpenOperationsPreviewAction &&
                  _canOpenTacticalPreviewAction)
                _OnboardingCommandActionConfig(
                  key: const ValueKey('site-onboarding-sla-tactical-action'),
                  label: 'OPEN TACTICAL TRACK',
                  icon: Icons.map_rounded,
                  onPressed: _openTacticalPreview,
                  foregroundColor: const Color(0xFFEAF4FF),
                  borderColor: accent.withValues(alpha: 0.68),
                ),
              _OnboardingCommandActionConfig(
                key: const ValueKey('site-onboarding-sla-copy-action'),
                label: 'Copy Demo Script',
                icon: Icons.content_copy_rounded,
                onPressed: () => _copyClientPromiseScript(script),
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: accent.withValues(alpha: 0.68),
              ),
            ],
          ),
        ],
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final compact = MediaQuery.sizeOf(context).width < 640;
    final readyCount = _previewGates.where((gate) => gate.ready).length;
    final nextGapStep = _nextIncompleteStep;
    final telegramPrefill = widget.initialPrefill;
    final telegramSeeded = telegramPrefill != null;
    final telegramVendor = (telegramPrefill?.vendor ?? '').trim();
    final telegramCaptureSummary = <String>[
      if (telegramPrefill?.cameraCount != null)
        '${telegramPrefill!.cameraCount} cameras',
      if (telegramVendor.isNotEmpty) telegramVendor,
      if (telegramPrefill?.wantsTelegramBinding ?? false)
        'Telegram bridge intent',
    ].join(', ');
    final siteCommandHeadline = telegramSeeded
        ? _allGatesReady
              ? 'Telegram-approved site intake is ready for live route handoff.'
              : nextGapStep != null
              ? 'Telegram-approved site intake is staged and recoverable.'
              : 'Telegram-approved site intake is staged for deployment review.'
        : _siteTemplatePending
        ? '${_siteScenarioLabel(_selectedSiteScenario)} footprint is queued for deployment seeding.'
        : _allGatesReady
        ? 'Site deployment pack is ready for live route handoff.'
        : 'Site footprint is still being shaped and can recover in place.';
    final siteCommandDetail = telegramSeeded
        ? telegramCaptureSummary.isEmpty
              ? 'Approved Telegram intake already staged the site scope. Verify the footprint pack here, then hand into the next live desk.'
              : 'Approved Telegram intake already staged $telegramCaptureSummary. Verify the footprint pack here, then hand into the next live desk.'
        : _allGatesReady
        ? 'Identity, location, risk timing, and route posture are aligned so the operator can pivot straight into the next live desk.'
        : 'The top shell keeps the strongest next move obvious while the geo and risk workflow stays visible underneath.';
    final siteNextMoveLabel = telegramSeeded
        ? nextGapStep != null
              ? 'VERIFY TELEGRAM INTAKE'
              : _canOpenOperationsPreviewAction
              ? 'SECURITY DESK'
              : _canOpenTacticalPreviewAction
              ? 'TACTICAL TRACK'
              : 'Finish site setup'
        : _siteTemplatePending
        ? 'Seed footprint'
        : nextGapStep != null
        ? 'Recover Step ${nextGapStep + 1}'
        : _canOpenOperationsPreviewAction
        ? 'SECURITY DESK'
        : _canOpenTacticalPreviewAction
        ? 'TACTICAL TRACK'
        : 'Lock deployment review';
    final siteWorkflowHeadline = _siteTemplatePending
        ? '${_siteScenarioLabel(_selectedSiteScenario)} template pack is waiting for footprint seeding.'
        : nextGapStep != null
        ? 'Workflow tools are lined up around Step ${nextGapStep + 1} recovery.'
        : _canOpenOperationsPreviewAction
        ? 'Workflow tools are aligned for an operations handoff.'
        : _canOpenTacticalPreviewAction
        ? 'Workflow tools are aligned for a tactical handoff.'
        : 'Workflow tools are aligned for final review.';
    final siteWorkflowNextMove = _siteTemplatePending
        ? 'Apply template'
        : nextGapStep != null
        ? 'Recover Step ${nextGapStep + 1}'
        : _canOpenOperationsPreviewAction
        ? 'Launch ops review'
        : _canOpenTacticalPreviewAction
        ? 'Launch tactical review'
        : 'Run demo ready';
    Future<void> copySitePitchBrief() async {
      await Clipboard.setData(ClipboardData(text: _sitePitchText()));
      if (!context.mounted) return;
      _showOnboardingSnackBar(context, 'Site pitch copied for command review.');
    }

    Future<void> copySiteSnapshotBrief() async {
      await Clipboard.setData(ClipboardData(text: _siteSnapshotText()));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Site snapshot copied for command review.',
      );
    }

    Future<void> copyTelegramSiteOperationalSeedBrief() async {
      final scopeSummary = [
        _clientId.trim(),
        _siteIdController.text.trim().toUpperCase(),
      ].where((entry) => entry.isNotEmpty).join(' / ');
      final intakeSummary = <String>[
        if (telegramPrefill?.cameraCount != null)
          '${telegramPrefill!.cameraCount} cameras',
        if (telegramVendor.isNotEmpty) telegramVendor,
        if (telegramPrefill?.wantsTelegramBinding ?? false)
          'Telegram bridge requested',
      ].join(', ');
      final brief = [
        'Approved Telegram Site Intake',
        if (scopeSummary.isNotEmpty) 'Scope: $scopeSummary',
        if (intakeSummary.isNotEmpty) 'Captured: $intakeSummary',
        'Next operational setup:',
        '1. Confirm physical address, geofence, and entry protocol.',
        '2. Lock the risk cadence before opening the live desk.',
        '3. Validate the camera bridge / CCTV review path for the staged vendor pack.',
      ].join('\n');
      await Clipboard.setData(ClipboardData(text: brief));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Telegram site setup brief copied for command review.',
      );
    }

    void focusSiteNextGap() {
      final target = _nextIncompleteStep;
      if (target == null) {
        _showOnboardingSnackBar(
          context,
          'All readiness gates are already complete.',
        );
        return;
      }
      setState(() => _step = target);
      _showOnboardingSnackBar(
        context,
        'Jumped to Step ${target + 1} for missing inputs.',
      );
    }

    void focusSiteLocationFromTelegram() {
      setState(() => _step = 1);
      _showOnboardingSnackBar(
        context,
        'Jumped to Location to verify footprint and geofence.',
      );
    }

    void focusSiteRiskFromTelegram() {
      setState(() => _step = 2);
      _showOnboardingSnackBar(
        context,
        'Jumped to Risk to verify response cadence.',
      );
    }

    void openCameraBridgeFromTelegramSeed() {
      final callback = widget.onOpenCameraBridgeSystemSetup;
      if (callback == null) {
        unawaited(copyTelegramSiteOperationalSeedBrief());
        return;
      }
      final resolvedSiteId =
          _siteIdController.text.trim().toUpperCase().isNotEmpty
          ? _siteIdController.text.trim().toUpperCase()
          : (telegramPrefill?.siteId ?? 'SITE-PENDING').trim().toUpperCase();
      final resolvedSiteName = _siteNameController.text.trim().isNotEmpty
          ? _siteNameController.text.trim()
          : (telegramPrefill?.siteName ?? 'Pending Site').trim();
      Navigator.of(context).pop();
      WidgetsBinding.instance.addPostFrameCallback((_) {
        callback(
          resolvedSiteId,
          resolvedSiteName,
          telegramVendor,
          telegramPrefill?.cameraCount,
        );
      });
    }

    final sitePrimaryAction = _OnboardingCommandActionConfig(
      key: const ValueKey('site-onboarding-primary-action'),
      readyKey: _allGatesReady && _step == 2
          ? siteOnboardingCreateReadyButtonKey
          : null,
      label: telegramSeeded
          ? nextGapStep != null
                ? 'Verify Intake'
                : _canOpenOperationsPreviewAction
                ? 'Ops Focus'
                : _canOpenTacticalPreviewAction
                ? 'Map Focus'
                : 'Finish Setup'
          : _siteTemplatePending
          ? 'Prime Footprint'
          : nextGapStep != null
          ? 'Recover Flow'
          : _canOpenOperationsPreviewAction
          ? 'Ops Focus'
          : _canOpenTacticalPreviewAction
          ? 'Map Focus'
          : 'Ready Lock',
      icon: telegramSeeded
          ? nextGapStep != null
                ? Icons.verified_rounded
                : _canOpenOperationsPreviewAction
                ? Icons.space_dashboard_rounded
                : _canOpenTacticalPreviewAction
                ? Icons.map_rounded
                : Icons.task_alt_rounded
          : _siteTemplatePending
          ? Icons.auto_awesome_rounded
          : nextGapStep != null
          ? Icons.track_changes_rounded
          : _canOpenOperationsPreviewAction
          ? Icons.space_dashboard_rounded
          : _canOpenTacticalPreviewAction
          ? Icons.map_rounded
          : Icons.task_alt_rounded,
      onPressed: telegramSeeded
          ? nextGapStep != null
                ? focusSiteNextGap
                : _canOpenOperationsPreviewAction
                ? _openOperationsPreview
                : _canOpenTacticalPreviewAction
                ? _openTacticalPreview
                : () => _showOnboardingSnackBar(
                    context,
                    'Telegram-approved site intake is staged for final setup review.',
                  )
          : _siteTemplatePending
          ? () {
              _applyDemoTemplate();
              _showOnboardingSnackBar(
                context,
                '${_siteScenarioLabel(_selectedSiteScenario)} template applied.',
              );
            }
          : nextGapStep != null
          ? focusSiteNextGap
          : _canOpenOperationsPreviewAction
          ? _openOperationsPreview
          : _canOpenTacticalPreviewAction
          ? _openTacticalPreview
          : () => _showOnboardingSnackBar(
              context,
              widget.demoMode
                  ? _runDemoReady()
                  : 'Site deployment pack is ready for final review.',
            ),
      foregroundColor: const Color(0xFFEAF4FF),
      borderColor: const Color(0xFF1D4ED8),
      backgroundColor: _allGatesReady
          ? const Color(0xFF0F766E)
          : const Color(0xFF1D4ED8),
      filled: true,
    );
    final siteSecondaryActions = <_OnboardingCommandActionConfig>[
      if (_canOpenOperationsPreviewAction && nextGapStep == null)
        _OnboardingCommandActionConfig(
          key: const ValueKey('site-onboarding-ops-focus'),
          label: 'Security Desk',
          icon: Icons.space_dashboard_rounded,
          onPressed: _openOperationsPreview,
          foregroundColor: const Color(0xFFBFD7F2),
          borderColor: const Color(0xFF35506F),
        ),
      if (_canOpenTacticalPreviewAction &&
          (_siteTemplatePending ||
              nextGapStep != null ||
              !_canOpenOperationsPreviewAction))
        _OnboardingCommandActionConfig(
          key: const ValueKey('site-onboarding-tactical-focus'),
          label: 'Tactical Track',
          icon: Icons.map_rounded,
          onPressed: _openTacticalPreview,
          foregroundColor: const Color(0xFF9FE8FF),
          borderColor: const Color(0xFF35506F),
        ),
      _OnboardingCommandActionConfig(
        key: const ValueKey('site-onboarding-snapshot-brief'),
        label: 'Snapshot Brief',
        icon: Icons.receipt_long_rounded,
        onPressed: copySiteSnapshotBrief,
        foregroundColor: const Color(0xFFD5EBFF),
        borderColor: const Color(0xFF35506F),
      ),
      _OnboardingCommandActionConfig(
        key: const ValueKey('site-onboarding-voice-brief'),
        label: 'Voice Brief',
        icon: Icons.mic_rounded,
        onPressed: copySitePitchBrief,
        foregroundColor: const Color(0xFFBFE6FF),
        borderColor: const Color(0xFF35506F),
      ),
    ];
    return _adminDialogShell(
      width: _responsiveDialogWidth(context),
      padding: const EdgeInsets.all(12),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _onboardingHero(
            context: context,
            title: 'New Site Onboarding',
            subtitle:
                'Configure location intelligence, entry protocols, and risk-driven automation defaults.',
            accent: const Color(0xFF0E8B8F),
            responseTarget: 'Risk profile + geofence under 75s',
            confidenceLabel: 'Geo validation confidence 97.8%',
            talkTrackTitle: 'Site Demo Talk Track',
            talkTrackLines: const [
              'Here we define the physical deployment footprint for dispatch logic.',
              'Risk profile auto-tunes nudge and escalation timers for this site.',
              'Entry protocol and map metadata remove guesswork during live incidents.',
              'The result is faster, safer response execution from first signal.',
            ],
            compact: compact,
            chips: const ['Location', 'Risk Profiler', 'Geofence & Protocol'],
          ),
          const SizedBox(height: 8),
          _onboardingCommandDeck(
            key: const ValueKey('site-onboarding-command-deck'),
            nextMoveKey: const ValueKey('site-onboarding-next-move'),
            accent: const Color(0xFF0E8B8F),
            label: 'SITE COMMAND',
            headline: siteCommandHeadline,
            detail: siteCommandDetail,
            nextMoveLabel: siteNextMoveLabel,
            chips: [
              if (telegramSeeded)
                const _OnboardingCommandChipData(
                  label: 'Source',
                  value: 'telegram-approved',
                  color: Color(0xFF7FD8A5),
                ),
              if (telegramPrefill?.cameraCount != null)
                _OnboardingCommandChipData(
                  label: 'Cameras',
                  value: '${telegramPrefill!.cameraCount}',
                  color: const Color(0xFF8FD1FF),
                ),
              if (telegramVendor.isNotEmpty)
                _OnboardingCommandChipData(
                  label: 'Vendor',
                  value: telegramVendor,
                  color: const Color(0xFF67E8F9),
                ),
              if (telegramPrefill?.wantsTelegramBinding ?? false)
                const _OnboardingCommandChipData(
                  label: 'Bridge',
                  value: 'bind-ready',
                  color: Color(0xFF7FD8A5),
                ),
              _OnboardingCommandChipData(
                label: 'Step',
                value: '${_step + 1}/3',
                color: const Color(0xFF8FD1FF),
              ),
              _OnboardingCommandChipData(
                label: 'Readiness',
                value: '$readyCount/${_previewGates.length}',
                color: _allGatesReady
                    ? const Color(0xFF34D399)
                    : const Color(0xFFF59E0B),
              ),
              _OnboardingCommandChipData(
                label: 'Risk',
                value: _riskProfile.replaceAll('_', ' '),
                color: const Color(0xFFBFD7F2),
              ),
              _OnboardingCommandChipData(
                label: 'Scenario',
                value: widget.demoMode
                    ? _siteScenarioLabel(_selectedSiteScenario)
                    : 'live',
                color: const Color(0xFF67E8F9),
              ),
            ],
            primaryAction: sitePrimaryAction,
            secondaryActions: siteSecondaryActions,
