  String _suggestedPsiraNumber() {
    final source = _employeeCodeController.text.trim().isNotEmpty
        ? _employeeCodeController.text.trim()
        : (_selectedEmployeeScenario == 'controller'
              ? 'CTRL'
              : _selectedEmployeeScenario == 'static_guard'
              ? 'GUARD'
              : 'REACT');
    final normalized = source
        .toUpperCase()
        .replaceAll(RegExp(r'[^A-Z0-9]+'), '-')
        .replaceAll(RegExp(r'-+'), '-')
        .replaceAll(RegExp(r'^-|-$'), '');
    final suffix = normalized.isEmpty ? 'DEMO' : normalized;
    return 'PSI-$suffix';
  }

