            secondaryActions: [
              _OnboardingCommandActionConfig(
                key: const ValueKey('employee-onboarding-compliance-clear'),
                label: 'Clear Compliance',
                icon: Icons.backspace_rounded,
                onPressed: compliant || hasPsiraNumber || hasExpiry
                    ? () => setState(() {
                        _psiraNumberController.clear();
                        _psiraExpiry = null;
                      })
                    : null,
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: const Color(0x665C66D6),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Widget _employeeIdentityQuickPickStrip() {
    final suggestedRole = _suggestedEmployeeRoleForScenario();
    final suggestedCode = _suggestedEmployeeCode();
    final suggestedFullName = _suggestedEmployeeFullName();
    final suggestedSurname = _suggestedEmployeeSurname();
    final suggestedId = _suggestedEmployeeIdentityNumber();
    final roleAligned = _role == suggestedRole;
    final codeAligned = _employeeCodeController.text.trim() == suggestedCode;
    final identityAligned =
        _fullNameController.text.trim() == suggestedFullName &&
        _surnameController.text.trim() == suggestedSurname &&
        _idNumberController.text.trim() == suggestedId;
    return _onboardingControlShell(
      keyPrefix: 'employee-onboarding-identity-quick-picks',
      label: 'Identity quick picks',
      modeLabel: 'ROLE FLOW',
      icon: Icons.badge_rounded,
      detail:
          'Stage the strongest identity defaults here before dropping into the raw registry fields below.',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _onboardingCommandDeck(
            key: const ValueKey(
              'employee-onboarding-identity-quick-focus-shell',
            ),
            nextMoveKey: const ValueKey(
              'employee-onboarding-identity-quick-focus-next-move',
            ),
            accent: roleAligned && codeAligned && identityAligned
                ? const Color(0xFF5C66D6)
                : const Color(0xFFF59E0B),
            label: 'IDENTITY QUICK FOCUS',
            headline: roleAligned && codeAligned && identityAligned
                ? 'Scenario identity pack is staged'
                : 'Scenario identity pack is waiting',
            detail: roleAligned && codeAligned && identityAligned
                ? 'The active employee identity already matches the selected scenario. Use the cards below only if one part of the pack needs a manual pivot.'
                : 'Stage the full scenario pack here first, then use the cards below when role, code, or identity details need a more specific pivot.',
            nextMoveLabel: roleAligned && codeAligned && identityAligned
                ? 'Refine pack'
                : 'Stage pack',
            chips: [
              _OnboardingCommandChipData(
                label: 'Role',
                value: _selectedEmployeeRoleLabel(),
                color: roleAligned
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
