              _OnboardingCommandChipData(
                label: 'Code',
                value: codeAligned ? 'ALIGNED' : 'PENDING',
                color: codeAligned
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey(
                'employee-onboarding-identity-quick-focus-stage-pack',
              ),
              label: 'Stage Scenario Pack',
              icon: Icons.badge_rounded,
              onPressed: () => setState(() {
                _role = suggestedRole;
                _employeeCodeController.text = suggestedCode;
                _fullNameController.text = suggestedFullName;
                _surnameController.text = suggestedSurname;
                _idNumberController.text = suggestedId;
              }),
              foregroundColor: const Color(0xFFEAF4FF),
              borderColor: const Color(0x665C66D6),
              backgroundColor: const Color(0xFF5C66D6),
              filled: true,
            ),
            secondaryActions: [
              _OnboardingCommandActionConfig(
                key: const ValueKey(
                  'employee-onboarding-identity-quick-focus-stage-role',
                ),
                label: 'Stage Role',
                icon: Icons.work_rounded,
                onPressed: () => setState(() => _role = suggestedRole),
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: const Color(0x665C66D6),
              ),
              _OnboardingCommandActionConfig(
                key: const ValueKey(
                  'employee-onboarding-identity-quick-focus-stage-code',
                ),
                label: 'Stage Code',
                icon: Icons.password_rounded,
                onPressed: () => setState(
                  () => _employeeCodeController.text = suggestedCode,
                ),
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: const Color(0x665C66D6),
              ),
              _OnboardingCommandActionConfig(
                key: const ValueKey(
                  'employee-onboarding-identity-quick-focus-stage-identity',
                ),
                label: 'Stage Identity',
                icon: Icons.person_pin_rounded,
                onPressed: () => setState(() {
                  _fullNameController.text = suggestedFullName;
                  _surnameController.text = suggestedSurname;
                  _idNumberController.text = suggestedId;
                }),
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: const Color(0x665C66D6),
              ),
