            runSpacing: 7,
            children: [
              _employeeQuickPickCard(
                keyPrefix: 'employee-onboarding-identity-role',
                icon: Icons.work_rounded,
                label: 'Scenario Role',
                value: suggestedRole.replaceAll('_', ' ').toUpperCase(),
                hint: _role == suggestedRole
                    ? 'Current role matches the active scenario.'
                    : 'Tap to align role with the selected scenario.',
                active: _role == suggestedRole,
                onTap: () => setState(() => _role = suggestedRole),
                microLabel: 'NEXT',
                microValue: _role == suggestedRole
                    ? 'Scope live'
                    : 'Drive scope',
                microColor: _role == suggestedRole
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _employeeQuickPickCard(
                keyPrefix: 'employee-onboarding-identity-code',
                icon: Icons.password_rounded,
                label: 'Suggested Code',
                value: suggestedCode,
                hint: _employeeCodeController.text.trim() == suggestedCode
                    ? 'Current employee code is aligned.'
                    : 'Tap to stage the scenario-aligned employee code.',
                active: _employeeCodeController.text.trim() == suggestedCode,
                onTap: () => setState(
                  () => _employeeCodeController.text = suggestedCode,
                ),
