                microValue: _employeeCodeController.text.trim() == suggestedCode
                    ? 'Registry live'
                    : 'Seed registry',
                microColor: _employeeCodeController.text.trim() == suggestedCode
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _employeeQuickPickCard(
                keyPrefix: 'employee-onboarding-identity-pack',
                icon: Icons.person_pin_rounded,
                label: 'Identity Pack',
                value: '$suggestedFullName $suggestedSurname',
                hint: identityAligned
                    ? 'Current identity pack is aligned.'
                    : 'Tap to stage name and ID details from the active scenario.',
                active: identityAligned,
                onTap: () => setState(() {
                  _fullNameController.text = suggestedFullName;
                  _surnameController.text = suggestedSurname;
                  _idNumberController.text = suggestedId;
                }),
                activeLabel: 'LIVE',
                idleLabel: 'PACK',
                microLabel: 'NEXT',
                microValue: identityAligned ? 'Proof live' : 'Seed proof',
                microColor: identityAligned
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
            ],
          ),
        ],
      ),
    );
  }

  String _employeeOptionKey(String value) {
    return value
        .toLowerCase()
        .replaceAll(RegExp(r'[^a-z0-9]+'), '-')
        .replaceAll(RegExp(r'-+'), '-')
        .replaceAll(RegExp(r'^-|-$'), '');
  }

  Widget _employeeClientQuickPickStrip() {
    final quickClients = widget.clients.take(3).toList(growable: false);
    final hasClient = _clientId.trim().isNotEmpty;
    final firstClientId = quickClients.isEmpty ? null : quickClients.first.id;
    return _onboardingControlShell(
      keyPrefix: 'employee-onboarding-client-quick-picks',
      label: 'Client quick picks',
      modeLabel: 'CLIENT FLOW',
      icon: Icons.apartment_rounded,
      detail:
          'Scope the employee to the right client here before the raw client selector below.',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _onboardingCommandDeck(
            key: const ValueKey('employee-onboarding-client-quick-focus-shell'),
            nextMoveKey: const ValueKey(
              'employee-onboarding-client-quick-focus-next-move',
            ),
            accent: hasClient
                ? const Color(0xFF5C66D6)
                : const Color(0xFFF59E0B),
            label: 'CLIENT QUICK FOCUS',
            headline: hasClient
                ? 'Client scope is already anchored'
                : 'Stage a client before routing the employee',
            detail: hasClient
                ? 'Use the client cards below to pivot scope fast, but the current client is already ready for the identity and assignment flows.'
                : 'Pick the fastest client scope here first, then use the cards below if you need a more specific scope.',
            nextMoveLabel: hasClient ? 'Refine scope' : 'Stage first client',
            chips: [
              _OnboardingCommandChipData(
                label: 'Current',
                value: _selectedEmployeeClientLabel(),
                color: hasClient
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Scenario',
                value: _employeeScenarioLabel(_selectedEmployeeScenario),
                color: const Color(0xFFB6C9DF),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey(
                'employee-onboarding-client-quick-focus-stage-first',
              ),
              label: hasClient ? 'Re-stage First Client' : 'Stage First Client',
              icon: Icons.apartment_rounded,
              onPressed: firstClientId == null
                  ? null
                  : () => setState(() {
                      _clientId = firstClientId;
                      _assignedSiteId = '';
                    }),
              foregroundColor: const Color(0xFFEAF4FF),
              borderColor: const Color(0x665C66D6),
              backgroundColor: const Color(0xFF5C66D6),
              filled: true,
            ),
            secondaryActions: [
              _OnboardingCommandActionConfig(
                key: const ValueKey(
                  'employee-onboarding-client-quick-focus-hold-site',
                ),
                label: 'Hold Site',
                icon: Icons.pause_circle_rounded,
                onPressed: _assignedSiteId.trim().isNotEmpty
                    ? () => setState(() => _assignedSiteId = '')
                    : null,
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: const Color(0x665C66D6),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 7,
            runSpacing: 7,
            children: [
              for (final client in quickClients)
                _employeeQuickPickCard(
                  keyPrefix:
                      'employee-onboarding-client-${_employeeOptionKey(client.id)}',
                  icon: Icons.apartment_rounded,
                  label: client.name,
                  value: client.id,
                  hint: _clientId == client.id
                      ? 'Current operating client.'
                      : 'Tap to scope this employee to ${client.name}.',
                  active: _clientId == client.id,
                  onTap: () => setState(() {
                    _clientId = client.id;
                    _assignedSiteId = '';
                  }),
                  microLabel: 'NEXT',
                  microValue: _clientId == client.id
                      ? 'Stage identity'
                      : 'Drive scope',
                  microColor: _clientId == client.id
                      ? const Color(0xFF8FD1FF)
                      : const Color(0xFFF1B872),
                ),
            ],
          ),
        ],
      ),
    );
