  Widget _employeeScopeOverrideConsoleCard() {
    return _onboardingControlShell(
      keyPrefix: 'employee-onboarding-scope-override',
      label: 'Scope override console',
      modeLabel: _clientId.trim().isNotEmpty && _role.trim().isNotEmpty
          ? 'SCOPE LIVE'
          : 'SCOPE HOLD',
      icon: Icons.tune_rounded,
      detail:
          'Keep the raw client and role selectors together here so scope overrides feel deliberate instead of loose.',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _dropdownField(
            label: 'Client',
            value: _clientId,
            items: widget.clients.map((client) => client.id).toList(),
            labels: {
              for (final client in widget.clients)
                client.id: '${client.name} (${client.id})',
            },
            onChanged: (value) {
              if (value == null) return;
              setState(() {
                _clientId = value;
                _assignedSiteId = '';
              });
            },
          ),
          const SizedBox(height: 8),
          _dropdownField(
            label: 'Primary Role',
            value: _role,
            items: const [
              'controller',
              'supervisor',
              'guard',
              'reaction_officer',
              'manager',
              'admin',
            ],
            onChanged: (value) {
              if (value == null) return;
              setState(() => _role = value);
            },
          ),
        ],
      ),
    );
  }

