          const SizedBox(height: 8),
          _textField(_idNumberController, 'ID / Passport Number'),
        ],
      ),
    );
  }

  String _employeeSiteKey(String siteId) {
    return siteId
        .toLowerCase()
        .replaceAll(RegExp(r'[^a-z0-9]+'), '-')
        .replaceAll(RegExp(r'-+'), '-')
        .replaceAll(RegExp(r'^-|-$'), '');
  }

  Widget _employeeQuickPickCard({
    required String keyPrefix,
    required IconData icon,
    required String label,
    required String value,
    required String hint,
    required bool active,
    required VoidCallback onTap,
    String activeLabel = 'LIVE',
    String idleLabel = 'STAGE',
    String? microLabel,
    String? microValue,
    Color? microColor,
  }) {
    final accent = active ? const Color(0xFF5C66D6) : const Color(0xFF35506F);
    return InkWell(
      key: ValueKey('$keyPrefix-card'),
      borderRadius: BorderRadius.circular(12),
      onTap: onTap,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 180),
        curve: Curves.easeOutCubic,
        width: 178,
        padding: const EdgeInsets.fromLTRB(8, 7, 8, 7),
        decoration: BoxDecoration(
          color: _adminDialogRaisedColor,
          borderRadius: BorderRadius.circular(12),
          border: Border.all(
            color: accent.withValues(alpha: active ? 0.7 : 0.5),
            width: active ? 1.3 : 1,
          ),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                Container(
                  width: 20,
                  height: 20,
                  decoration: BoxDecoration(
                    color: accent.withValues(alpha: 0.16),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: Icon(
                    icon,
                    size: 12.5,
                    color: _adminAccentTextColor(accent, strength: 0.5),
                  ),
                ),
                const SizedBox(width: 6),
                Expanded(
                  child: Text(
                    label,
                    style: GoogleFonts.inter(
                      color: _adminDialogTitleColor,
                      fontSize: 10.2,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
                Container(
                  key: ValueKey('$keyPrefix-status'),
                  padding: const EdgeInsets.symmetric(
                    horizontal: 6,
                    vertical: 2,
                  ),
                  decoration: BoxDecoration(
                    color: accent.withValues(alpha: 0.18),
                    borderRadius: BorderRadius.circular(999),
                    border: Border.all(color: accent.withValues(alpha: 0.5)),
                  ),
                  child: Text(
                    active ? activeLabel : idleLabel,
                    style: GoogleFonts.inter(
                      color: _adminDialogTitleColor,
                      fontSize: 8.6,
                      fontWeight: FontWeight.w800,
                      letterSpacing: 0.45,
                    ),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 6),
            Text(
              value,
              key: ValueKey('$keyPrefix-value'),
              style: GoogleFonts.inter(
                color: _adminDialogTitleColor,
                fontSize: 10.8,
                fontWeight: FontWeight.w700,
              ),
            ),
            const SizedBox(height: 3),
            Text(
              hint,
              style: GoogleFonts.inter(
                color: _adminDialogBodyColor,
                fontSize: 9.1,
                fontWeight: FontWeight.w600,
                height: 1.2,
              ),
            ),
            if (microValue != null) ...[
              const SizedBox(height: 6),
              Container(
                key: ValueKey('$keyPrefix-micro-shell'),
                width: double.infinity,
                padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 5),
                decoration: BoxDecoration(
                  color: _adminDialogAltColor,
                  borderRadius: BorderRadius.circular(8),
                  border: Border.all(
                    color: (microColor ?? accent).withValues(alpha: 0.36),
                  ),
                ),
                child: Row(
                  children: [
                    Text(
                      microLabel ?? 'NEXT',
                      style: GoogleFonts.inter(
                        color: microColor ?? accent,
                        fontSize: 8.7,
                        fontWeight: FontWeight.w800,
                        letterSpacing: 0.5,
                      ),
                    ),
                    const SizedBox(width: 6),
                    Expanded(
                      child: Text(
                        microValue,
                        key: ValueKey('$keyPrefix-micro-value'),
                        textAlign: TextAlign.right,
                        style: GoogleFonts.inter(
                          color: _adminDialogTitleColor,
                          fontSize: 9.1,
                          fontWeight: FontWeight.w700,
                        ),
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ],
        ),
      ),
    );
  }

