  Widget _employeeAssignmentQuickPickStrip() {
    final quickSites = _siteOptions.take(3).toList(growable: false);
    final hasAssignment = _assignedSiteId.trim().isNotEmpty;
    final firstSiteId = quickSites.isEmpty ? null : quickSites.first.id;
    return _onboardingControlShell(
      keyPrefix: 'employee-onboarding-assignment-quick-picks',
      label: 'Assignment quick picks',
      modeLabel: 'ROUTE PICKS',
      icon: Icons.approval_rounded,
      detail:
          'Keep the strongest site handoff visible here so roster placement feels immediate and deliberate.',
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          _onboardingCommandDeck(
            key: const ValueKey(
              'employee-onboarding-assignment-quick-focus-shell',
            ),
            nextMoveKey: const ValueKey(
              'employee-onboarding-assignment-quick-focus-next-move',
            ),
            accent: hasAssignment
                ? const Color(0xFF5C66D6)
                : const Color(0xFFF59E0B),
            label: 'ASSIGNMENT QUICK FOCUS',
            headline: hasAssignment
                ? 'Primary site route is already anchored'
                : 'Stage a primary site before final create',
            detail: hasAssignment
                ? 'Use the cards below to pivot routes fast, but the current route is already ready for roster handoff.'
                : 'Pick the fastest site route here, then use the route cards below if you need a more specific site.',
            nextMoveLabel: hasAssignment ? 'Refine scope' : 'Stage first site',
            chips: [
              _OnboardingCommandChipData(
                label: 'Current',
                value: _assignedEmployeeSiteLabel(),
                color: hasAssignment
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
              _OnboardingCommandChipData(
                label: 'Client',
                value: _selectedEmployeeClientLabel(),
                color: const Color(0xFFB6C9DF),
              ),
            ],
            primaryAction: _OnboardingCommandActionConfig(
              key: const ValueKey(
                'employee-onboarding-assignment-quick-focus-stage-first',
              ),
              label: hasAssignment ? 'Re-stage First Site' : 'Stage First Site',
              icon: Icons.domain_rounded,
              onPressed: firstSiteId == null
                  ? null
                  : () => setState(() => _assignedSiteId = firstSiteId),
              foregroundColor: const Color(0xFFEAF4FF),
              borderColor: const Color(0x665C66D6),
              backgroundColor: const Color(0xFF5C66D6),
              filled: true,
            ),
            secondaryActions: [
              _OnboardingCommandActionConfig(
                key: const ValueKey(
                  'employee-onboarding-assignment-quick-focus-standby',
                ),
                label: 'Hold Standby',
                icon: Icons.pause_circle_rounded,
                onPressed: hasAssignment
                    ? () => setState(() => _assignedSiteId = '')
                    : null,
                foregroundColor: const Color(0xFFEAF4FF),
                borderColor: const Color(0x665C66D6),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 7,
            runSpacing: 7,
            children: [
              for (final site in quickSites)
                _employeeQuickPickCard(
                  keyPrefix:
                      'employee-onboarding-assignment-site-${_employeeSiteKey(site.id)}',
                  icon: Icons.domain_rounded,
                  label: site.name,
                  value: site.id,
                  hint: _assignedSiteId == site.id
                      ? 'Current primary roster site.'
                      : 'Tap to stage this site as the primary assignment.',
                  active: _assignedSiteId == site.id,
                  onTap: () => setState(() => _assignedSiteId = site.id),
                  microLabel: 'NEXT',
                  microValue: _assignedSiteId == site.id
                      ? 'Route live'
                      : 'Stage route',
                  microColor: _assignedSiteId == site.id
                      ? const Color(0xFF8FD1FF)
                      : const Color(0xFFF1B872),
                ),
              _employeeQuickPickCard(
                keyPrefix: 'employee-onboarding-assignment-site-unassigned',
                icon: Icons.pause_circle_rounded,
                label: 'Standby',
                value: 'Unassigned',
                hint: _assignedSiteId.trim().isEmpty
                    ? 'Current roster is held in standby.'
                    : 'Tap to clear the primary assignment.',
                active: _assignedSiteId.trim().isEmpty,
                onTap: () => setState(() => _assignedSiteId = ''),
                activeLabel: 'HOLD',
                idleLabel: 'CLEAR',
                microLabel: 'NEXT',
                microValue: _assignedSiteId.trim().isEmpty
                    ? 'Roster held'
                    : 'Clear route',
                microColor: _assignedSiteId.trim().isEmpty
                    ? const Color(0xFF8FD1FF)
                    : const Color(0xFFF1B872),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Widget _employeeComplianceOverrideConsoleCard() {
