      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Wrap(
            spacing: 7,
            runSpacing: 7,
            children: [
              OutlinedButton.icon(
                key: const ValueKey(
                  'employee-onboarding-compliance-override-stage-number',
                ),
                onPressed: () => setState(
                  () => _psiraNumberController.text = _suggestedPsiraNumber(),
                ),
                icon: const Icon(Icons.badge_rounded, size: 14),
                style: _onboardingInlineActionStyle(
                  accent: const Color(0xFF5C66D6),
                ),
                label: Text(
