                  style: GoogleFonts.inter(
                    fontSize: 10.6,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
              OutlinedButton.icon(
                key: const ValueKey(
                  'employee-onboarding-compliance-override-stage-grade',
                ),
                onPressed: () =>
                    setState(() => _psiraGrade = _suggestedPsiraGradeForRole()),
                icon: const Icon(Icons.shield_rounded, size: 14),
                style: _onboardingInlineActionStyle(
                  accent: const Color(0xFF5C66D6),
                ),
                label: Text(
                  gradeAligned ? 'Role Grade Live' : 'Stage Role Grade',
                  style: GoogleFonts.inter(
                    fontSize: 10.6,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
              OutlinedButton.icon(
                key: const ValueKey(
                  'employee-onboarding-compliance-override-clear',
                ),
                onPressed: hasOverrides
                    ? () => setState(() {
                        _psiraNumberController.clear();
                        _psiraGrade = 'C';
                      })
                    : null,
                icon: const Icon(Icons.backspace_rounded, size: 14),
                style: _onboardingInlineActionStyle(
                  accent: const Color(0xFF5C66D6),
                ),
                label: Text(
                  'Clear Overrides',
                  style: GoogleFonts.inter(
                    fontSize: 10.6,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 8),
          _textField(_psiraNumberController, 'PSIRA Number'),
          const SizedBox(height: 8),
          _dropdownField(
            label: 'PSIRA Grade',
            value: _psiraGrade,
            items: const ['A', 'B', 'C', 'D', 'E'],
            onChanged: (value) {
              if (value == null) return;
              setState(() => _psiraGrade = value);
            },
          ),
        ],
      ),
    );
  }

