  void _applyEmployeeScenario(String scenario) {
    final stamp = DateTime.now().millisecondsSinceEpoch % 10000;
    final firstSite = _siteOptions.isEmpty ? '' : _siteOptions.first.id;
    setState(() {
      _selectedEmployeeScenario = scenario;
      _appliedEmployeeScenario = scenario;
      switch (scenario) {
        case 'static_guard':
          _employeeCodeController.text = 'DEMO-EMP-G$stamp';
          _fullNameController.text = 'Lerato';
          _surnameController.text = 'Nkosi';
          _idNumberController.text = 'PASS-DEMO-GUARD';
          _role = 'guard';
          _dob = DateTime(1992, 5, 15);
          _psiraNumberController.text = 'PSI-DEMO-G$stamp';
          _psiraGrade = 'C';
          _psiraExpiry = DateTime.now().add(const Duration(days: 460));
          _hasDriverLicense = false;
          _driverCodeController.clear();
          _licenseExpiry = null;
          _hasPdp = false;
          _pdpExpiry = null;
          _deviceUidController.text = 'BV5300P-GRD-$stamp';
          _phoneController.text = '+27 84 611 3301';
          _emailController.text = 'lerato.guard@onyx-security.co.za';
          _assignedSiteId = firstSite;
          break;
        case 'controller':
          _employeeCodeController.text = 'DEMO-EMP-C$stamp';
          _fullNameController.text = 'Anele';
          _surnameController.text = 'Jacobs';
          _idNumberController.text = 'PASS-DEMO-CONTROLLER';
          _role = 'controller';
          _dob = DateTime(1990, 3, 3);
          _psiraNumberController.text = '';
          _psiraGrade = 'C';
          _psiraExpiry = null;
          _hasDriverLicense = false;
          _driverCodeController.clear();
          _licenseExpiry = null;
          _hasPdp = false;
          _pdpExpiry = null;
          _deviceUidController.text = 'ONYX-CONSOLE-$stamp';
          _phoneController.text = '+27 83 740 1144';
          _emailController.text = 'anele.controller@onyx-security.co.za';
          _assignedSiteId = '';
          break;
        case 'reaction_officer':
        default:
          _employeeCodeController.text = 'DEMO-EMP-$stamp';
          _fullNameController.text = 'Kagiso';
          _surnameController.text = 'Molefe';
          _idNumberController.text = 'PASS-DEMO-REACTION';
          _role = 'reaction_officer';
          _dob = DateTime(1988, 8, 8);
          _psiraNumberController.text = 'PSI-DEMO-$stamp';
          _psiraGrade = 'B';
          _psiraExpiry = DateTime.now().add(const Duration(days: 540));
          _hasDriverLicense = true;
          _driverCodeController.text = 'Code 10';
          _licenseExpiry = DateTime.now().add(const Duration(days: 900));
          _hasPdp = true;
          _pdpExpiry = DateTime.now().add(const Duration(days: 700));
          _deviceUidController.text = 'BV5300P-DEMO-$stamp';
          _phoneController.text = '+27 82 711 2233';
          _emailController.text = 'kagiso.demo@onyx-security.co.za';
          _assignedSiteId = firstSite;
          break;
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    final compact = MediaQuery.sizeOf(context).width < 640;
    final readyCount = _previewGates.where((gate) => gate.ready).length;
    final nextGapStep = _nextIncompleteStep;
    final assignmentLabel = _assignedSiteId.trim().isEmpty
        ? 'standby'
        : _assignedSiteId.trim();
    final employeeCommandHeadline = _employeeTemplatePending
        ? '${_employeeScenarioLabel(_selectedEmployeeScenario)} profile is queued for readiness seeding.'
        : _allGatesReady
        ? 'Employee readiness pack is ready for live roster handoff.'
        : 'Employee readiness is active and recoverable in place.';
    final employeeCommandDetail = _allGatesReady
        ? 'Identity, compliance, contact posture, and assignment are aligned so the operator can pivot straight into the next live desk.'
        : 'The command shell keeps the strongest next move visible while the deeper registry workflow stays open below.';
    final employeeNextMoveLabel = _employeeTemplatePending
        ? 'Seed readiness'
        : nextGapStep != null
        ? 'Recover Step ${nextGapStep + 1}'
        : _canOpenEmployeeOperationsPreview
        ? 'SECURITY DESK'
        : _canOpenEmployeeTacticalPreview
        ? 'TACTICAL TRACK'
        : 'Lock roster review';
    final employeeWorkflowHeadline = _employeeTemplatePending
        ? '${_employeeScenarioLabel(_selectedEmployeeScenario)} template pack is waiting for readiness seeding.'
        : nextGapStep != null
        ? 'Workflow tools are lined up around Step ${nextGapStep + 1} recovery.'
        : _canOpenEmployeeOperationsPreview
        ? 'Workflow tools are aligned for an operations handoff.'
        : _canOpenEmployeeTacticalPreview
        ? 'Workflow tools are aligned for a tactical handoff.'
        : 'Workflow tools are aligned for final review.';
    final employeeWorkflowNextMove = _employeeTemplatePending
        ? 'Apply template'
        : nextGapStep != null
        ? 'Recover Step ${nextGapStep + 1}'
        : _canOpenEmployeeOperationsPreview
        ? 'Launch ops review'
        : _canOpenEmployeeTacticalPreview
        ? 'Launch tactical review'
        : 'Run demo ready';
    Future<void> copyEmployeePitchBrief() async {
      await Clipboard.setData(ClipboardData(text: _employeePitchText()));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Employee pitch copied for command review.',
      );
    }

    Future<void> copyEmployeeSnapshotBrief() async {
      await Clipboard.setData(ClipboardData(text: _employeeSnapshotText()));
      if (!context.mounted) return;
      _showOnboardingSnackBar(
        context,
        'Employee snapshot copied for command review.',
      );
    }

    void focusEmployeeNextGap() {
      final target = _nextIncompleteStep;
      if (target == null) {
        _showOnboardingSnackBar(
          context,
          'All readiness gates are already complete.',
        );
        return;
      }
      setState(() => _step = target);
      _showOnboardingSnackBar(
        context,
        'Jumped to Step ${target + 1} for missing inputs.',
      );
    }

    final employeePrimaryAction = _OnboardingCommandActionConfig(
      key: const ValueKey('employee-onboarding-primary-action'),
      readyKey: _allGatesReady && _step == 2
          ? employeeOnboardingCreateReadyButtonKey
          : null,
      label: _employeeTemplatePending
          ? 'Prime Readiness'
          : nextGapStep != null
          ? 'Recover Flow'
          : _canOpenEmployeeOperationsPreview
          ? 'Ops Focus'
          : _canOpenEmployeeTacticalPreview
          ? 'Map Focus'
          : 'Ready Lock',
      icon: _employeeTemplatePending
          ? Icons.auto_awesome_rounded
          : nextGapStep != null
          ? Icons.track_changes_rounded
          : _canOpenEmployeeOperationsPreview
          ? Icons.space_dashboard_rounded
          : _canOpenEmployeeTacticalPreview
          ? Icons.map_rounded
          : Icons.task_alt_rounded,
      onPressed: _employeeTemplatePending
          ? () {
              _applyDemoTemplate();
              _showOnboardingSnackBar(
                context,
                '${_employeeScenarioLabel(_selectedEmployeeScenario)} template applied.',
              );
            }
          : nextGapStep != null
          ? focusEmployeeNextGap
          : _canOpenEmployeeOperationsPreview
          ? _openEmployeeOperationsPreview
          : _canOpenEmployeeTacticalPreview
          ? _openEmployeeTacticalPreview
          : () => _showOnboardingSnackBar(
              context,
              widget.demoMode
                  ? _runDemoReady()
                  : 'Employee readiness pack is ready for final review.',
            ),
      foregroundColor: const Color(0xFFEAF4FF),
      borderColor: const Color(0xFF1D4ED8),
      backgroundColor: _allGatesReady
          ? const Color(0xFF0F766E)
          : const Color(0xFF1D4ED8),
      filled: true,
    );
    final employeeSecondaryActions = <_OnboardingCommandActionConfig>[
      if (_canOpenEmployeeOperationsPreview && nextGapStep == null)
        _OnboardingCommandActionConfig(
          key: const ValueKey('employee-onboarding-ops-focus'),
          label: 'Security Desk',
          icon: Icons.space_dashboard_rounded,
          onPressed: _openEmployeeOperationsPreview,
          foregroundColor: const Color(0xFFBFD7F2),
          borderColor: const Color(0xFF35506F),
        ),
      if (_canOpenEmployeeTacticalPreview &&
          (_employeeTemplatePending ||
              nextGapStep != null ||
              !_canOpenEmployeeOperationsPreview))
        _OnboardingCommandActionConfig(
          key: const ValueKey('employee-onboarding-tactical-focus'),
          label: 'Tactical Track',
          icon: Icons.map_rounded,
          onPressed: _openEmployeeTacticalPreview,
          foregroundColor: const Color(0xFF9FE8FF),
          borderColor: const Color(0xFF35506F),
        ),
      _OnboardingCommandActionConfig(
        key: const ValueKey('employee-onboarding-snapshot-brief'),
        label: 'Snapshot Brief',
        icon: Icons.receipt_long_rounded,
        onPressed: copyEmployeeSnapshotBrief,
        foregroundColor: const Color(0xFFD5EBFF),
        borderColor: const Color(0xFF35506F),
      ),
      _OnboardingCommandActionConfig(
        key: const ValueKey('employee-onboarding-voice-brief'),
        label: 'Voice Brief',
        icon: Icons.mic_rounded,
        onPressed: copyEmployeePitchBrief,
