_AdministrationPageState? _findAdministrationPageState(BuildContext context) {
  if (context is StatefulElement && context.state is _AdministrationPageState) {
    return context.state as _AdministrationPageState;
  }
  return context.findAncestorStateOfType<_AdministrationPageState>();
}

void _showAdminFeedback(
  BuildContext context,
  String message, {
  String? sourceLabel,
  String? detail,
  Color accent = const Color(0xFF8FD1FF),
}) {
  final adminState = _findAdministrationPageState(context);
  if (adminState != null) {
    adminState._handleAdminFeedback(
      feedbackContext: context,
      message: message,
      sourceLabel: sourceLabel,
      detail: detail,
      accent: accent,
    );
    return;
  }
  _showAdminFeedbackSnackBar(context, message);
}

_OnboardingFeedbackHost? _findOnboardingFeedbackHost(BuildContext context) {
  if (context is StatefulElement && context.state is _OnboardingFeedbackHost) {
    return context.state as _OnboardingFeedbackHost;
  }
  _OnboardingFeedbackHost? host;
  context.visitAncestorElements((element) {
    if (element is StatefulElement &&
        element.state is _OnboardingFeedbackHost) {
      host = element.state as _OnboardingFeedbackHost;
      return false;
    }
    return true;
  });
  return host;
}

