Widget _onboardingCommandActionButton(
  _OnboardingCommandActionConfig action, {
  bool light = true,
}) {
  if (action.filled) {
    final resolvedBackgroundColor = action.backgroundColor == null
        ? Color.alphaBlend(
            Colors.white.withValues(alpha: 0.62),
            action.foregroundColor.withValues(alpha: 0.12),
          )
        : Color.alphaBlend(
            Colors.white.withValues(alpha: 0.36),
            action.backgroundColor!,
          );
    final resolvedForegroundColor = light
        ? _adminAccentTextColor(action.foregroundColor, strength: 0.48)
        : action.foregroundColor;
    final child = FilledButton.icon(
      key: action.readyKey ?? action.key,
      onPressed: action.onPressed,
      icon: Icon(action.icon, size: 16),
      style: FilledButton.styleFrom(
        backgroundColor: resolvedBackgroundColor,
        foregroundColor: resolvedForegroundColor,
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(10),
          side: BorderSide(color: action.borderColor.withValues(alpha: 0.24)),
        ),
      ),
      label: Text(
        action.label,
        style: GoogleFonts.inter(fontWeight: FontWeight.w700),
      ),
    );
    if (action.readyKey == null) {
      return child;
    }
    return KeyedSubtree(key: action.key, child: child);
  }
  final resolvedForegroundColor = light
      ? _adminAccentTextColor(action.foregroundColor, strength: 0.3)
      : action.foregroundColor;
  return OutlinedButton.icon(
    key: action.key,
    onPressed: action.onPressed,
    icon: Icon(action.icon, size: 16),
    style: OutlinedButton.styleFrom(
      foregroundColor: resolvedForegroundColor,
      side: BorderSide(color: action.borderColor),
      backgroundColor: _adminDialogRaisedColor,
    ),
    label: Text(
      action.label,
      style: GoogleFonts.inter(fontWeight: FontWeight.w700),
    ),
  );
}

