void _showAdminFeedbackSnackBar(BuildContext context, String message) {
  if (!context.mounted) {
    return;
  }
  final messenger = ScaffoldMessenger.maybeOf(context);
  if (messenger == null) {
    return;
  }
  messenger.showSnackBar(
    SnackBar(
      backgroundColor: _adminDialogSurfaceColor,
      behavior: SnackBarBehavior.floating,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(14),
        side: const BorderSide(color: _adminDialogBorderColor),
      ),
      content: Text(
        message,
        style: GoogleFonts.inter(
          color: _adminDialogTitleColor,
          fontWeight: FontWeight.w700,
        ),
      ),
    ),
  );
}

void _showOnboardingSnackBar(BuildContext context, String message) {
  final host = _findOnboardingFeedbackHost(context);
  host?.pinOnboardingFeedback(message);
  _showAdminFeedback(
    host?.adminFeedbackContext ?? context,
    message,
    sourceLabel: 'ONBOARDING PREVIEW',
    detail:
        'The latest onboarding drill action stays visible in the desktop command rail.',
    accent: const Color(0xFF67E8F9),
  );
}

