Widget _heroSignalStrip({
  required Color accent,
  required String responseTarget,
  required String confidenceLabel,
  required bool compact,
}) {
  return StreamBuilder<int>(
    stream: Stream.periodic(const Duration(seconds: 1), (tick) => tick),
    initialData: 0,
    builder: (context, snapshot) {
      final now = DateTime.now();
      final pulseOn = ((snapshot.data ?? 0) % 2 == 0);
      return Wrap(
        spacing: 8,
        runSpacing: 8,
        children: [
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 7),
            decoration: BoxDecoration(
              color: _adminDialogRaisedColor,
              borderRadius: BorderRadius.circular(999),
              border: Border.all(color: accent.withValues(alpha: 0.24)),
            ),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                AnimatedOpacity(
                  duration: const Duration(milliseconds: 300),
                  opacity: pulseOn ? 1 : 0.45,
                  child: Icon(
                    Icons.circle,
                    size: 8,
                    color: accent.withValues(alpha: 0.95),
                  ),
                ),
                const SizedBox(width: 6),
                Text(
                  'Live ${_timeStamp(now)} SAST',
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: compact ? 10 : 11,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ],
            ),
          ),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 7),
            decoration: BoxDecoration(
              color: _adminDialogRaisedColor,
              borderRadius: BorderRadius.circular(999),
              border: Border.all(color: accent.withValues(alpha: 0.24)),
            ),
            child: Text(
              responseTarget,
              style: GoogleFonts.inter(
                color: _adminDialogBodyColor,
                fontSize: compact ? 10 : 11,
                fontWeight: FontWeight.w700,
              ),
            ),
          ),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 7),
            decoration: BoxDecoration(
              color: accent.withValues(alpha: 0.24),
              borderRadius: BorderRadius.circular(999),
              border: Border.all(color: accent.withValues(alpha: 0.75)),
            ),
            child: Text(
              confidenceLabel,
              style: GoogleFonts.inter(
                color: _adminDialogTitleColor,
                fontSize: compact ? 10 : 11,
                fontWeight: FontWeight.w800,
              ),
            ),
          ),
        ],
      );
    },
  );
}

Widget _demoScenarioPicker({
  required String label,
  String? selectedValue,
  required ValueChanged<String> onSelected,
  required List<_DemoScenarioOption> options,
  bool isApplied = true,
}) {
  _DemoScenarioOption? activeOption;
  for (final option in options) {
    if (option.value == selectedValue) {
      activeOption = option;
      break;
    }
  }
  final triggerLabel = activeOption == null
      ? label
      : '$label: ${activeOption.label}';
  return PopupMenuButton<String>(
    onSelected: onSelected,
    color: _adminDialogSurfaceColor,
    itemBuilder: (context) {
      return options
          .map((option) {
            final selected = option.value == selectedValue;
            return PopupMenuItem<String>(
              value: option.value,
              child: Container(
                padding: const EdgeInsets.fromLTRB(6, 5, 6, 5),
                decoration: BoxDecoration(
                  color: selected ? const Color(0x1634D399) : null,
                  borderRadius: BorderRadius.circular(8),
                  border: selected
                      ? Border.all(color: const Color(0xAA34D399))
                      : null,
                ),
                child: Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    SizedBox(
                      width: 18,
                      child: selected
                          ? const Icon(
                              Icons.check_circle_rounded,
                              size: 14,
                              color: Color(0xFF34D399),
                            )
                          : const SizedBox.shrink(),
                    ),
                    const SizedBox(width: 4),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Text(
                            option.label,
                            style: GoogleFonts.inter(
                              color: _adminDialogTitleColor,
                              fontSize: 12,
                              fontWeight: FontWeight.w800,
                            ),
                          ),
                          const SizedBox(height: 2),
                          Text(
                            option.detail,
                            style: GoogleFonts.inter(
                              color: _adminDialogBodyColor,
                              fontSize: 10.5,
                              fontWeight: FontWeight.w600,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ],
                ),
              ),
            );
          })
          .toList(growable: false);
    },
    child: Container(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 9),
      decoration: BoxDecoration(
        color: _adminDialogRaisedColor,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: _adminDialogBorderColor),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          const Icon(
            Icons.layers_clear_rounded,
            size: 16,
            color: Color(0xFF8FD1FF),
          ),
          const SizedBox(width: 6),
          Text(
            triggerLabel,
            style: GoogleFonts.inter(
              color: _adminDialogTitleColor,
              fontSize: 12,
              fontWeight: FontWeight.w800,
            ),
          ),
          if (activeOption != null) ...[
            const SizedBox(width: 6),
            Container(
              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
              decoration: BoxDecoration(
                color: isApplied
                    ? const Color(0x2234D399)
                    : const Color(0x22F59E0B),
                borderRadius: BorderRadius.circular(999),
                border: Border.all(
                  color: isApplied
                      ? const Color(0xAA34D399)
                      : const Color(0xAAF59E0B),
                ),
              ),
              child: Text(
                isApplied ? 'Applied' : 'Pending',
                style: GoogleFonts.inter(
                  color: _adminDialogTitleColor,
                  fontSize: 9.5,
                  fontWeight: FontWeight.w800,
                ),
              ),
            ),
          ],
          const SizedBox(width: 6),
          const Icon(
            Icons.expand_more_rounded,
            size: 16,
            color: Color(0xFF8FD1FF),
          ),
        ],
      ),
    ),
  );
}

