Future<bool> _confirmIncompleteReadiness(
  BuildContext context, {
  required String entityLabel,
  required List<_PreviewGate> gates,
  required Color accent,
}) async {
  final blockers = gates.where((gate) => !gate.ready).toList(growable: false);
  if (blockers.isEmpty) return true;
  final result = await showDialog<bool>(
    context: context,
    builder: (dialogContext) {
      return _adminDialogShell(
        width: _responsiveDialogWidth(context, maxWidth: 580),
        borderColor: accent.withValues(alpha: 0.42),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              'Create $entityLabel With Missing Inputs?',
              style: GoogleFonts.inter(
                color: _adminDialogTitleColor,
                fontSize: 15,
                fontWeight: FontWeight.w800,
              ),
            ),
            const SizedBox(height: 10),
            Text(
              'The following readiness gates are incomplete:',
              style: GoogleFonts.inter(
                color: _adminDialogBodyColor,
                fontSize: 12,
                fontWeight: FontWeight.w600,
              ),
            ),
            const SizedBox(height: 8),
            Container(
              width: double.infinity,
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: _adminDialogAltColor,
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: _adminDialogBorderColor),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  for (final gate in blockers.take(6)) ...[
                    Text(
                      '• ${gate.label} (Step ${gate.step + 1})',
                      style: GoogleFonts.inter(
                        color:
                            Color.lerp(_adminDialogTitleColor, accent, 0.28) ??
                            _adminDialogTitleColor,
                        fontSize: 11.5,
                        fontWeight: FontWeight.w700,
                      ),
                    ),
                    const SizedBox(height: 4),
                  ],
                ],
              ),
            ),
            const SizedBox(height: 8),
            Text(
              'Select "Review Missing" to jump back and complete inputs, or "Create Anyway" to continue.',
              style: GoogleFonts.inter(
                color: _adminDialogBodyColor,
                fontSize: 11,
                fontWeight: FontWeight.w600,
              ),
            ),
            const SizedBox(height: 14),
            Row(
              children: [
                TextButton.icon(
                  onPressed: () => Navigator.of(dialogContext).pop(false),
                  icon: const Icon(Icons.visibility_rounded, size: 16),
                  style: TextButton.styleFrom(
                    foregroundColor:
                        Color.lerp(_adminDialogTitleColor, accent, 0.18) ??
                        _adminDialogTitleColor,
                  ),
                  label: Text(
                    'Review Missing',
                    style: GoogleFonts.inter(fontWeight: FontWeight.w800),
                  ),
                ),
                const Spacer(),
                FilledButton.icon(
                  onPressed: () => Navigator.of(dialogContext).pop(true),
                  icon: const Icon(Icons.warning_amber_rounded, size: 16),
                  style: FilledButton.styleFrom(
                    backgroundColor: accent,
                    foregroundColor: const Color(0xFFEAF4FF),
                  ),
                  label: Text(
                    'Create Anyway',
                    style: GoogleFonts.inter(fontWeight: FontWeight.w800),
                  ),
                ),
              ],
            ),
          ],
        ),
      );
    },
  );
  return result ?? false;
}

Widget _demoPaceMeter({
  required DateTime startedAt,
  required int targetSeconds,
  required Color accent,
  required bool compact,
  VoidCallback? onRecover,
  String recoverLabel = 'Recover Pace',
}) {
  return StreamBuilder<int>(
    stream: Stream.periodic(const Duration(seconds: 1), (tick) => tick),
    initialData: 0,
    builder: (context, snapshot) {
      final elapsed = DateTime.now().difference(startedAt).inSeconds;
      final progress = (elapsed / targetSeconds).clamp(0.0, 1.0);
      final bool ahead = elapsed <= (targetSeconds * 0.8).round();
      final bool onTrack = elapsed <= targetSeconds;
      final delaySeconds = elapsed - targetSeconds;
      final statusLabel = ahead ? 'Ahead' : (onTrack ? 'On Track' : 'Behind');
      final statusColor = ahead
          ? const Color(0xFF34D399)
          : (onTrack ? const Color(0xFF8FD1FF) : const Color(0xFFF59E0B));
      final mm = (elapsed ~/ 60).toString().padLeft(2, '0');
      final ss = (elapsed % 60).toString().padLeft(2, '0');
      return Container(
        width: double.infinity,
        padding: const EdgeInsets.fromLTRB(10, 8, 10, 8),
        decoration: BoxDecoration(
          color: _adminDialogRaisedColor,
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: accent.withValues(alpha: 0.28)),
        ),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              children: [
                const Icon(
                  Icons.timer_rounded,
                  size: 14,
                  color: Color(0xFF8FD1FF),
                ),
                const SizedBox(width: 6),
                Text(
                  'Demo Pace',
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: compact ? 11 : 12,
                    fontWeight: FontWeight.w800,
                  ),
                ),
                const Spacer(),
                Text(
                  '$mm:$ss / ${targetSeconds}s',
                  style: GoogleFonts.robotoMono(
                    color: _adminDialogTitleColor,
                    fontSize: compact ? 10.5 : 11,
                    fontWeight: FontWeight.w700,
                  ),
                ),
              ],
            ),
            const SizedBox(height: 7),
            ClipRRect(
              borderRadius: BorderRadius.circular(999),
              child: LinearProgressIndicator(
                minHeight: 5,
                value: progress,
                backgroundColor: _adminDialogBorderColor,
                valueColor: AlwaysStoppedAnimation<Color>(statusColor),
              ),
            ),
            const SizedBox(height: 6),
            Row(
              children: [
                Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 3,
                  ),
                  decoration: BoxDecoration(
                    color: statusColor.withValues(alpha: 0.18),
                    borderRadius: BorderRadius.circular(999),
                    border: Border.all(
                      color: statusColor.withValues(alpha: 0.65),
                    ),
                  ),
                  child: Text(
                    statusLabel,
                    style: GoogleFonts.inter(
                      color: _adminDialogTitleColor,
                      fontSize: 10.5,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ),
                if (!onTrack) ...[
                  const SizedBox(width: 6),
                  Text(
                    '+${delaySeconds}s',
                    style: GoogleFonts.robotoMono(
                      color: const Color(0xFFFBBF24),
                      fontSize: compact ? 10 : 10.5,
                      fontWeight: FontWeight.w800,
                    ),
                  ),
                ],
              ],
            ),
            if (!onTrack && onRecover != null) ...[
              const SizedBox(height: 7),
              FilledButton.icon(
                onPressed: onRecover,
                icon: const Icon(Icons.flash_on_rounded, size: 15),
                style: FilledButton.styleFrom(
                  backgroundColor: const Color(0xFF9A4D08),
                  foregroundColor: const Color(0xFFEAF4FF),
                  visualDensity: VisualDensity.compact,
                  padding: const EdgeInsets.symmetric(
                    horizontal: 10,
                    vertical: 7,
                  ),
                ),
                label: Text(
                  recoverLabel,
                  style: GoogleFonts.inter(
                    fontSize: compact ? 10.5 : 11,
                    fontWeight: FontWeight.w800,
                  ),
                ),
              ),
            ],
            const SizedBox(height: 6),
            Text(
              'Target: keep onboarding within ${targetSeconds}s for live demo impact.',
              style: GoogleFonts.inter(
                color: _adminDialogBodyColor,
                fontSize: compact ? 10 : 10.5,
                fontWeight: FontWeight.w600,
              ),
            ),
          ],
        ),
      );
    },
  );
}

Widget _demoCoachCard({
  required BuildContext context,
  required Color accent,
  required int currentStep,
  required List<_DemoCoachCue> cues,
  required bool compact,
  required String keyPrefix,
  ValueChanged<int>? onStageTap,
}) {
  if (cues.isEmpty) return const SizedBox.shrink();
  final clamped = currentStep.clamp(0, cues.length - 1);
  final cue = cues[clamped];
  final hasPrevious = clamped > 0;
  final hasNext = clamped < cues.length - 1;
  final nextCue = hasNext ? cues[clamped + 1] : null;
  final coachHeadline = hasNext
      ? '${cue.stage} cue is active. ${nextCue!.stage} is next.'
      : '${cue.stage} cue is active and closes the walkthrough.';
  final coachDetail = hasNext
      ? 'Use the coach band to keep the narration tight while the next stage stays one move away.'
      : 'This cue closes the walkthrough, so the operator can hold here or pivot back into an earlier stage.';
  final nextMoveLabel = hasNext
      ? 'Advance to ${nextCue!.stage}'
      : hasPrevious
      ? 'Revisit ${cues[clamped - 1].stage}'
      : 'Hold opening cue';
  final copyText =
      'Stage: ${cue.stage}\nNarration: ${cue.narration}\nProof: ${cue.proofPoint}';
  return Container(
    key: ValueKey('$keyPrefix-card'),
    width: double.infinity,
    padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
    decoration: BoxDecoration(
      color: _adminDialogRaisedColor,
      borderRadius: BorderRadius.circular(10),
      border: Border.all(color: accent.withValues(alpha: 0.28)),
    ),
    child: AnimatedSwitcher(
      duration: const Duration(milliseconds: 220),
      switchInCurve: Curves.easeOutCubic,
      switchOutCurve: Curves.easeInCubic,
      child: Column(
        key: ValueKey<String>('${cue.stage}-$clamped'),
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Container(
            key: ValueKey('$keyPrefix-command'),
            width: double.infinity,
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: _adminDialogAltColor,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: accent.withValues(alpha: 0.24)),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(
                            'PRESENTER COMMAND',
                            style: GoogleFonts.inter(
                              color: accent,
                              fontSize: 9.5,
                              fontWeight: FontWeight.w800,
                              letterSpacing: 0.8,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            coachHeadline,
                            style: GoogleFonts.inter(
                              color: _adminDialogTitleColor,
                              fontSize: 11.5,
                              fontWeight: FontWeight.w800,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            coachDetail,
                            style: GoogleFonts.inter(
                              color: _adminDialogBodyColor,
                              fontSize: 10.5,
                              fontWeight: FontWeight.w600,
                              height: 1.35,
                            ),
                          ),
                        ],
                      ),
                    ),
                    const SizedBox(width: 12),
                    Container(
                      key: ValueKey('$keyPrefix-next-move'),
                      padding: const EdgeInsets.symmetric(
                        horizontal: 10,
                        vertical: 8,
                      ),
                      decoration: BoxDecoration(
                        color: accent.withValues(alpha: 0.12),
                        borderRadius: BorderRadius.circular(9),
                        border: Border.all(
                          color: accent.withValues(alpha: 0.35),
                        ),
                      ),
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.end,
                        children: [
                          Text(
                            'NEXT MOVE',
                            style: GoogleFonts.inter(
                              color: accent,
                              fontSize: 9,
                              fontWeight: FontWeight.w800,
                              letterSpacing: 0.8,
                            ),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            nextMoveLabel,
                            style: GoogleFonts.inter(
                              color: _adminDialogTitleColor,
                              fontSize: 10.5,
                              fontWeight: FontWeight.w700,
                            ),
                          ),
                        ],
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 10),
                Wrap(
                  spacing: 8,
                  runSpacing: 8,
                  children: [
                    _onboardingCommandChip(
                      _OnboardingCommandChipData(
                        label: 'Cue',
                        value: '${clamped + 1}/${cues.length}',
                        color: const Color(0xFF8FD1FF),
                      ),
                    ),
                    _onboardingCommandChip(
                      _OnboardingCommandChipData(
                        label: 'Stage',
                        value: cue.stage,
                        color: const Color(0xFFBFD7F2),
                      ),
                    ),
                    _onboardingCommandChip(
                      _OnboardingCommandChipData(
                        label: 'Proof',
                        value: hasNext ? 'live' : 'final',
                        color: accent,
                      ),
                    ),
                  ],
                ),
                const SizedBox(height: 10),
                Wrap(
                  spacing: 8,
                  runSpacing: 8,
                  children: [
                    _onboardingCommandActionButton(
                      _OnboardingCommandActionConfig(
                        key: ValueKey('$keyPrefix-primary-action'),
                        label: hasNext
                            ? 'Advance Cue'
                            : hasPrevious
                            ? 'Previous Cue'
                            : 'Cue Locked',
                        icon: hasNext
                            ? Icons.arrow_forward_rounded
                            : hasPrevious
                            ? Icons.arrow_back_rounded
                            : Icons.task_alt_rounded,
                        onPressed: onStageTap == null
                            ? null
                            : hasNext
                            ? () => onStageTap(clamped + 1)
                            : hasPrevious
                            ? () => onStageTap(clamped - 1)
                            : null,
                        foregroundColor: const Color(0xFFEAF4FF),
                        borderColor: accent.withValues(alpha: 0.85),
                        backgroundColor: accent.withValues(alpha: 0.88),
                        filled: true,
                      ),
                    ),
                    if (hasPrevious)
                      _onboardingCommandActionButton(
                        _OnboardingCommandActionConfig(
                          key: ValueKey('$keyPrefix-previous-action'),
                          label: 'Previous Stage',
                          icon: Icons.skip_previous_rounded,
                          onPressed: onStageTap == null
                              ? null
                              : () => onStageTap(clamped - 1),
                          foregroundColor: const Color(0xFFBFD7F2),
                          borderColor: const Color(0xFF35506F),
                        ),
                      ),
                    _onboardingCommandActionButton(
                      _OnboardingCommandActionConfig(
                        key: ValueKey('$keyPrefix-copy-action'),
                        label: 'Copy Cue',
                        icon: Icons.content_copy_rounded,
                        onPressed: () async {
                          await Clipboard.setData(
                            ClipboardData(text: copyText),
                          );
                          if (!context.mounted) return;
                          _showAdminFeedback(
                            context,
                            'Presenter cue copied for command review.',
                            sourceLabel: 'ONBOARDING PREVIEW',
                            detail:
                                'Presenter notes stay pinned in the desktop rail while you continue the admin walkthrough.',
                            accent: accent,
                          );
                        },
                        foregroundColor: const Color(0xFF9FE8FF),
                        borderColor: const Color(0xFF35506F),
                      ),
                    ),
                  ],
                ),
              ],
            ),
          ),
          const SizedBox(height: 8),
          Container(
            key: ValueKey('$keyPrefix-focus'),
            width: double.infinity,
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: _adminDialogAltColor,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: accent.withValues(alpha: 0.24)),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  'ACTIVE TALK TRACK',
                  style: GoogleFonts.inter(
                    color: accent,
                    fontSize: 9.5,
                    fontWeight: FontWeight.w800,
                    letterSpacing: 0.8,
                  ),
                ),
                const SizedBox(height: 8),
                Text(
                  cue.narration,
                  style: GoogleFonts.inter(
                    color: _adminDialogTitleColor,
                    fontSize: compact ? 10.5 : 11.5,
                    fontWeight: FontWeight.w700,
                    height: 1.25,
                  ),
                ),
                const SizedBox(height: 6),
                Text(
                  'Proof: ${cue.proofPoint}',
                  style: GoogleFonts.inter(
                    color: _adminDialogBodyColor,
                    fontSize: compact ? 10 : 10.5,
                    fontWeight: FontWeight.w600,
                    height: 1.25,
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(height: 8),
          Wrap(
            spacing: 6,
            runSpacing: 6,
            children: [
              for (var i = 0; i < cues.length; i++)
                _summaryChip(
                  key: ValueKey('$keyPrefix-stage-${i + 1}'),
                  number: i + 1,
                  label: cues[i].stage,
                  state: i == clamped
                      ? _SummaryChipState.active
                      : i < clamped
                      ? _SummaryChipState.done
                      : _SummaryChipState.pending,
                  onPressed: onStageTap == null ? null : () => onStageTap(i),
                ),
            ],
          ),
        ],
      ),
    ),
  );
}

Widget _onboardingLivePreview({
  required BuildContext context,
  required String title,
  required String entityLabel,
  required String keyPrefix,
  required Color accent,
  required List<String> lines,
  required List<_PreviewGate> gates,
  required double completion,
  required bool compact,
  required Map<String, dynamic> payload,
  required String sqlTable,
  List<String> sqlConflictColumns = const [],
  List<String> sqlExtraStatements = const [],
  int Function()? onAutoFillMissing,
  String autoFillLabel = 'Auto-Fill Missing',
  ValueChanged<int>? onJumpToStep,
}) {
  final pct = (completion.clamp(0.0, 1.0) * 100).round();
  final formattedPayload = _prettyJson(payload);
  final sqlUpsert = _buildUpsertSql(
    table: sqlTable,
    payload: payload,
    conflictColumns: sqlConflictColumns,
  );
  final filteredSqlExtras = sqlExtraStatements
      .where((statement) => statement.trim().isNotEmpty)
      .toList(growable: false);
  final sqlBundle = [sqlUpsert, ...filteredSqlExtras].join('\n\n');
  final sqlActionLabel = filteredSqlExtras.isEmpty
      ? 'Copy SQL Upsert'
      : 'Copy SQL Bundle';
  final sourceLabel = '${entityLabel.toUpperCase()} PREVIEW';
  final readyCount = gates.where((gate) => gate.ready).length;
  final gateTotal = gates.length;
  final blockers = gates.where((gate) => !gate.ready).toList(growable: false);
  final nextBlocker = blockers.isEmpty ? null : blockers.first;
  final gatesByStep = <int, List<_PreviewGate>>{};
  for (final gate in gates) {
    gatesByStep.putIfAbsent(gate.step, () => <_PreviewGate>[]).add(gate);
  }
  final sortedSteps = gatesByStep.keys.toList()..sort();
  final demoReady = gateTotal == 0
      ? completion >= 0.9
      : readyCount == gateTotal;
  final verdictLabel = demoReady ? 'Demo Ready' : 'Needs Inputs';
  final previewHeadline = demoReady
      ? '$title is command-ready.'
      : nextBlocker != null
      ? '${nextBlocker.label} is blocking $title.'
      : '$title is still staging.';
  final previewDetail = demoReady
      ? 'Payload, readiness, and SQL handoff are aligned so the operator can move straight into the final create step.'
      : nextBlocker != null
      ? 'Use the preview command layer to either auto-fill the remaining blockers or jump straight into Step ${nextBlocker.step + 1} without leaving this board.'
      : 'The preview board keeps the strongest move visible while the deeper onboarding steps stay active below.';
  final previewNextMoveLabel = blockers.isNotEmpty && onAutoFillMissing != null
      ? 'Auto-fill blockers'
      : nextBlocker != null && onJumpToStep != null
      ? 'Resolve Step ${nextBlocker.step + 1}'
      : 'Stage handoff';
  final handoffHeadline = demoReady
      ? 'Preview handoff bundle is live for command review.'
      : blockers.isNotEmpty
      ? 'Preview handoff bundle is staged while blockers remain.'
      : 'Preview handoff bundle is ready to stage.';
  final handoffDetail = demoReady
      ? 'Briefing, SQL, and payload exports stay grouped here so the operator can hand off or provision without leaving the walkthrough.'
      : blockers.isNotEmpty
      ? 'Briefing, SQL, and payload exports stay grouped here while the remaining blockers are being closed.'
      : 'Preview exports stay grouped here so the operator can hand off or provision without leaving the current walkthrough.';
  final handoffNextMoveLabel =
      blockers.isNotEmpty && nextBlocker != null && onJumpToStep != null
      ? 'Resolve Step ${nextBlocker.step + 1}'
      : demoReady
      ? 'Copy demo brief'
      : sqlActionLabel;
  final primaryHighlight = lines.isEmpty
      ? '$entityLabel preview is waiting for the first live signal.'
      : lines.first;
  final supportingHighlights = lines.length > 1
      ? lines.sublist(1)
      : const <String>[];
  final highlightsHeadline = demoReady
      ? '$entityLabel preview is carrying live deployment signals.'
      : blockers.isNotEmpty
      ? '$entityLabel preview is surfacing the clearest live blockers.'
      : '$entityLabel preview is collecting live deployment signals.';
  final highlightsDetail = blockers.isNotEmpty
      ? 'The lead signal keeps the most important blocker or readiness cue surfaced while the rest of the board stays active.'
      : 'The lead signal keeps the most important preview cue surfaced while the rest of the board stays active.';
  final highlightsNextMoveLabel =
      blockers.isNotEmpty && nextBlocker != null && onJumpToStep != null
      ? 'Resolve Step ${nextBlocker.step + 1}'
      : supportingHighlights.isNotEmpty
      ? 'Review ${lines.length} signals'
      : 'Hold lead signal';
  final readinessHeadline = demoReady
      ? '$entityLabel readiness rail is fully aligned.'
      : blockers.isNotEmpty
      ? '$entityLabel readiness rail is surfacing the top blockers.'
      : '$entityLabel readiness rail is still staging.';
  final readinessDetail = blockers.isNotEmpty
      ? 'Gate, step, and blocker signals stay grouped here so the operator can recover the preview without leaving the board.'
      : 'Gate and step signals stay grouped here so the operator can track readiness without leaving the board.';
  final readinessNextMoveLabel =
      blockers.isNotEmpty && nextBlocker != null && onJumpToStep != null
      ? 'Resolve Step ${nextBlocker.step + 1}'
      : sortedSteps.isNotEmpty
      ? 'Review ${sortedSteps.length} steps'
      : 'Hold readiness rail';
  final progressHeadline = demoReady
      ? '$entityLabel preview progress is locked for handoff.'
      : blockers.isNotEmpty
      ? '$entityLabel preview progress is advancing through active blockers.'
      : '$entityLabel preview progress is still staging.';
  final previewMoveDetail = blockers.isNotEmpty
      ? 'Primary recovery route'
      : demoReady
      ? 'Primary handoff route'
      : 'Primary staging route';
  final commandSupportHeadline =
      blockers.isNotEmpty && onJumpToStep != null && onAutoFillMissing != null
      ? 'Recovery support stays adjacent to the primary preview move.'
      : 'Handoff support stays adjacent to the primary preview move.';
  final commandSupportDetail =
      blockers.isNotEmpty && onJumpToStep != null && onAutoFillMissing != null
      ? 'Use this support rail to jump straight into the blocking step while keeping the main preview action fixed on auto-fill or handoff.'
      : 'Use this support rail for the lighter update path while the main preview action stays fixed on the strongest briefing or recovery move.';
  final blockersText = blockers.isEmpty
      ? 'None'
      : blockers.map((gate) => gate.label).join(', ');
  final gateStatus = gates
      .map(
        (gate) =>
            '- [${gate.ready ? 'x' : ' '}] ${gate.label} (Step ${gate.step + 1})',
      )
      .join('\n');
  final highlights = lines.map((line) => '- $line').join('\n');
  final clientUpdateText =
      '$title\n'
      'Status: $verdictLabel ($readyCount/$gateTotal readiness gates complete)\n'
      'Configured:\n$highlights\n\n'
      'Outstanding: ${blockersText == 'None' ? 'None' : blockersText}\n'
      'Next: ${nextBlocker == null ? 'Proceed to create this record.' : 'Complete "${nextBlocker.label}" in Step ${nextBlocker.step + 1}.'}';
  final briefText =
      '$title\n'
      'Readiness: $verdictLabel ($readyCount/$gateTotal)\n'
      'Blockers: $blockersText\n\n'
      'Gate Status:\n$gateStatus\n\n'
      'Highlights:\n$highlights\n\n'
      'Payload:\n$formattedPayload';
  Future<void> copyEntityUpdate() async {
    await Clipboard.setData(ClipboardData(text: clientUpdateText));
    if (!context.mounted) return;
    _showAdminFeedback(
      context,
      '$entityLabel update copied for command review.',
      sourceLabel: sourceLabel,
      detail:
          'The drafted $entityLabel update stays pinned in the desktop rail for the current walkthrough.',
      accent: accent,
    );
  }

  Future<void> copyDemoBrief() async {
    await Clipboard.setData(ClipboardData(text: briefText));
    if (!context.mounted) return;
    _showAdminFeedback(
      context,
      'Demo brief copied for command review.',
      sourceLabel: sourceLabel,
      detail:
          'The walkthrough brief stays visible in the desktop rail while you keep shaping the demo flow.',
      accent: accent,
    );
  }

  Future<void> copySqlBundle() async {
    await Clipboard.setData(ClipboardData(text: sqlBundle));
    if (!context.mounted) return;
    _showAdminFeedback(
      context,
      filteredSqlExtras.isEmpty
          ? 'SQL upsert copied for command review.'
          : 'SQL bundle copied for command review.',
      sourceLabel: sourceLabel,
      detail:
          'The SQL handoff stays visible in the desktop rail while you continue the provisioning pass.',
      accent: accent,
    );
  }

  Future<void> copyPayloadJson() async {
    await Clipboard.setData(ClipboardData(text: formattedPayload));
    if (!context.mounted) return;
    _showAdminFeedback(
      context,
      'Payload JSON copied for command review.',
      sourceLabel: sourceLabel,
      detail:
          'The payload snapshot stays visible in the desktop rail while you keep the onboarding sequence in view.',
      accent: accent,
    );
  }

  final primaryAction = _OnboardingCommandActionConfig(
    key: ValueKey('$keyPrefix-primary-action'),
    label: blockers.isNotEmpty && onAutoFillMissing != null
        ? autoFillLabel
        : nextBlocker != null && onJumpToStep != null
        ? 'Resolve Next'
        : 'Copy Demo Brief',
    icon: blockers.isNotEmpty && onAutoFillMissing != null
        ? Icons.auto_fix_high_rounded
        : nextBlocker != null && onJumpToStep != null
        ? Icons.play_arrow_rounded
        : Icons.summarize_rounded,
    onPressed: blockers.isNotEmpty && onAutoFillMissing != null
        ? () {
            final filledCount = onAutoFillMissing();
            final message = filledCount <= 0
                ? 'No missing fields to auto-fill.'
                : filledCount == 1
                ? '1 field auto-filled for demo flow.'
                : '$filledCount fields auto-filled for demo flow.';
            _showAdminFeedback(
              context,
              message,
              sourceLabel: sourceLabel,
              detail:
                  'Auto-fill results stay visible in the desktop rail while you finish the remaining demo blockers.',
              accent: accent,
            );
          }
        : nextBlocker != null && onJumpToStep != null
        ? () => onJumpToStep(nextBlocker.step)
        : copyDemoBrief,
    foregroundColor: const Color(0xFFEAF4FF),
    borderColor: accent.withValues(alpha: 0.85),
    backgroundColor: accent.withValues(alpha: 0.88),
    filled: true,
  );
  final secondaryActions = <_OnboardingCommandActionConfig>[
    if (blockers.isNotEmpty &&
        onJumpToStep != null &&
        onAutoFillMissing != null)
      _OnboardingCommandActionConfig(
        key: ValueKey('$keyPrefix-resolve-action'),
        label: 'Resolve Step',
        icon: Icons.track_changes_rounded,
        onPressed: nextBlocker == null
            ? null
            : () => onJumpToStep(nextBlocker.step),
        foregroundColor: const Color(0xFFFFE1B8),
        borderColor: const Color(0xFFB3742C),
      ),
    if (!(blockers.isNotEmpty && onAutoFillMissing != null))
      _OnboardingCommandActionConfig(
        key: ValueKey('$keyPrefix-update-action'),
        label: 'Copy $entityLabel Update',
        icon: Icons.chat_bubble_rounded,
        onPressed: copyEntityUpdate,
        foregroundColor: const Color(0xFFBFD7F2),
        borderColor: const Color(0xFF35506F),
      ),
  ];
  return Container(
    key: ValueKey('$keyPrefix-card'),
    width: double.infinity,
    padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
    decoration: BoxDecoration(
      color: _adminDialogRaisedColor,
      borderRadius: BorderRadius.circular(10),
      border: Border.all(color: accent.withValues(alpha: 0.55)),
    ),
    child: Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _onboardingCommandDeck(
          key: ValueKey('$keyPrefix-command'),
          nextMoveKey: ValueKey('$keyPrefix-next-move'),
          accent: accent,
          label: '${entityLabel.toUpperCase()} PREVIEW',
          headline: previewHeadline,
          detail: previewDetail,
          contextKey: ValueKey('$keyPrefix-command-context'),
          contextLabel: 'LIVE CONTEXT',
          nextMoveLabel: previewNextMoveLabel,
          nextMoveDetail: previewMoveDetail,
          nextMoveDetailKey: ValueKey('$keyPrefix-next-move-detail'),
          emphasizeContext: true,
          emphasizeNextMove: true,
          chips: const <_OnboardingCommandChipData>[],
          primaryAction: primaryAction,
          secondaryActions: const <_OnboardingCommandActionConfig>[],
        ),
        if (secondaryActions.isNotEmpty) ...[
          const SizedBox(height: 8),
          Container(
            key: ValueKey('$keyPrefix-command-support-shell'),
            width: double.infinity,
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: _adminDialogAltColor,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: accent.withValues(alpha: 0.26)),
            ),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  'COMMAND SUPPORT',
                  style: GoogleFonts.inter(
                    color: accent,
                    fontSize: 9.5,
                    fontWeight: FontWeight.w800,
                    letterSpacing: 0.8,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  commandSupportHeadline,
                  style: GoogleFonts.inter(
                    color: const Color(0xFFEAF4FF),
                    fontSize: 10.8,
                    fontWeight: FontWeight.w800,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  commandSupportDetail,
                  style: GoogleFonts.inter(
                    color: _adminDialogBodyColor,
                    fontSize: 10.2,
                    fontWeight: FontWeight.w600,
                    height: 1.35,
                  ),
                ),
                const SizedBox(height: 10),
                Wrap(
                  key: ValueKey('$keyPrefix-command-support-actions'),
                  spacing: 8,
                  runSpacing: 8,
                  children: secondaryActions
                      .map(_onboardingCommandActionButton)
                      .toList(growable: false),
                ),
              ],
            ),
          ),
        ],
        const SizedBox(height: 8),
        Container(
          key: ValueKey('$keyPrefix-snapshot-band'),
          width: double.infinity,
          padding: const EdgeInsets.all(12),
          decoration: BoxDecoration(
            color: _adminDialogAltColor,
            borderRadius: BorderRadius.circular(10),
            border: Border.all(color: accent.withValues(alpha: 0.26)),
          ),
          child: Wrap(
            spacing: 8,
            runSpacing: 8,
            children: [
              _previewSnapshotCard(
                key: ValueKey('$keyPrefix-snapshot-status'),
                accent: accent,
                label: 'Status',
                value: verdictLabel,
                detail: demoReady ? 'Ready' : 'Staging',
                valueColor: demoReady
                    ? const Color(0xFF34D399)
                    : const Color(0xFFF59E0B),
              ),
              _previewSnapshotCard(
                key: ValueKey('$keyPrefix-snapshot-readiness'),
                accent: accent,
                label: 'Readiness',
                value: '$readyCount/$gateTotal',
                detail: 'Gates live',
                valueColor: const Color(0xFF8FD1FF),
              ),
              _previewSnapshotCard(
                key: ValueKey('$keyPrefix-snapshot-completion'),
                accent: accent,
                label: 'Completion',
                value: '$pct%',
                detail: 'Progress locked',
                valueColor: const Color(0xFFBFD7F2),
              ),
              _previewSnapshotCard(
                key: ValueKey('$keyPrefix-snapshot-bundle'),
                accent: accent,
