Widget _readinessStatusChip({
  required String label,
  required bool ready,
  required Color accent,
}) {
  final resolvedAccent = ready ? const Color(0xFF34D399) : accent;
  final foreground = _adminAccentTextColor(resolvedAccent, strength: 0.52);
  return Container(
    padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
    decoration: BoxDecoration(
      color: ready ? const Color(0x2234D399) : accent.withValues(alpha: 0.15),
      borderRadius: BorderRadius.circular(999),
      border: Border.all(
        color: ready ? const Color(0x8834D399) : accent.withValues(alpha: 0.34),
      ),
    ),
    child: Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        Icon(
          ready ? Icons.verified_rounded : Icons.warning_amber_rounded,
          size: 13,
          color: ready ? const Color(0xFF34D399) : foreground,
        ),
        const SizedBox(width: 5),
        Text(
          label,
          style: GoogleFonts.inter(
            color: foreground,
            fontSize: 10.0,
            fontWeight: FontWeight.w700,
          ),
        ),
      ],
    ),
  );
}

Widget _previewSnapshotCard({
  required Key key,
  required Color accent,
  required String label,
  required String value,
  required String detail,
  required Color valueColor,
  bool light = true,
}) {
  return Container(
    key: key,
    constraints: const BoxConstraints(minWidth: 132),
    padding: const EdgeInsets.fromLTRB(10, 9, 10, 9),
    decoration: BoxDecoration(
      color: light ? const Color(0xFF13131E) : _adminDialogAltColor,
      borderRadius: BorderRadius.circular(10),
      border: Border.all(color: accent.withValues(alpha: 0.18)),
    ),
    child: Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          label.toUpperCase(),
          style: GoogleFonts.inter(
            color: accent,
            fontSize: 8.6,
            fontWeight: FontWeight.w700,
            letterSpacing: 0.42,
          ),
        ),
        const SizedBox(height: 6),
        Text(
          value,
          style: GoogleFonts.inter(
            color: valueColor,
            fontSize: 11.0,
            fontWeight: FontWeight.w700,
          ),
        ),
        const SizedBox(height: 4),
        Text(
          detail,
          style: GoogleFonts.inter(
            color: _adminDialogBodyColor,
            fontSize: 9.8,
            fontWeight: FontWeight.w600,
            height: 1.36,
          ),
        ),
      ],
    ),
  );
}

Widget _blockerChip({
  required _PreviewGate gate,
  required Color accent,
  VoidCallback? onPressed,
}) {
  return ActionChip(
    onPressed: onPressed,
    backgroundColor: const Color(0xFFFFF4E8),
    side: BorderSide(color: accent.withValues(alpha: 0.55)),
    avatar: const Icon(
      Icons.error_outline_rounded,
      size: 14,
      color: Color(0xFFB36A18),
    ),
    label: Text(
      onPressed == null ? gate.label : '${gate.label} (Step ${gate.step + 1})',
      style: GoogleFonts.inter(
        color: const Color(0xFF8B4B0F),
        fontSize: 10.5,
        fontWeight: FontWeight.w700,
      ),
    ),
    labelPadding: const EdgeInsets.symmetric(horizontal: 2),
  );
}

Widget _stepReadinessChip({
  required int step,
  required int ready,
  required int total,
  required Color accent,
  VoidCallback? onPressed,
}) {
  final complete = total > 0 && ready == total;
  return ActionChip(
    onPressed: onPressed,
    backgroundColor: complete
        ? const Color(0x1634D399)
        : accent.withValues(alpha: 0.1),
    side: BorderSide(
      color: complete
          ? const Color(0xAA34D399)
          : accent.withValues(alpha: 0.55),
    ),
    avatar: Icon(
      complete ? Icons.task_alt_rounded : Icons.tune_rounded,
      size: 14,
      color: complete ? const Color(0xFF34D399) : const Color(0xFF8FD1FF),
    ),
    label: Text(
      'Step ${step + 1}: $ready/$total',
      style: GoogleFonts.inter(
        color: _adminDialogTitleColor,
        fontSize: 10.5,
        fontWeight: FontWeight.w700,
      ),
    ),
    labelPadding: const EdgeInsets.symmetric(horizontal: 2),
  );
}

Widget _previewGateChip({required _PreviewGate gate, required Color accent}) {
  final ready = gate.ready;
  return Container(
    padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
    decoration: BoxDecoration(
      color: ready ? const Color(0x1634D399) : accent.withValues(alpha: 0.1),
      borderRadius: BorderRadius.circular(999),
      border: Border.all(
        color: ready ? const Color(0xAA34D399) : accent.withValues(alpha: 0.45),
      ),
    ),
    child: Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        Icon(
          ready ? Icons.check_circle_rounded : Icons.pending_rounded,
          size: 13,
          color: ready ? const Color(0xFF34D399) : const Color(0xFF8FD1FF),
        ),
        const SizedBox(width: 5),
        Text(
          gate.label,
          style: GoogleFonts.inter(
            color: _adminDialogTitleColor,
            fontSize: 10.5,
            fontWeight: FontWeight.w700,
          ),
        ),
      ],
    ),
  );
}

Widget _stepSummary({
  required int currentStep,
  required List<String> labels,
  required Color accent,
  required String keyPrefix,
  ValueChanged<int>? onStepTap,
  List<_PreviewGate> readinessGates = const [],
}) {
  final activeIndex = currentStep.clamp(0, labels.length - 1);
  final progress = (activeIndex + 1) / labels.length;
  final gatesByStep = <int, List<_PreviewGate>>{};
  for (final gate in readinessGates) {
    gatesByStep.putIfAbsent(gate.step, () => <_PreviewGate>[]).add(gate);
  }
  final stepStatuses = labels
      .asMap()
      .entries
      .map((entry) {
        final stepGates = gatesByStep[entry.key];
        final hasStepGates = stepGates != null && stepGates.isNotEmpty;
        final readyCount = hasStepGates
            ? stepGates.where((gate) => gate.ready).length
            : 0;
        final total = stepGates?.length ?? 0;
        final complete = hasStepGates && readyCount == total;
        return (readyCount: readyCount, total: total, complete: complete);
      })
      .toList(growable: false);
  final readySteps = stepStatuses.where((status) => status.complete).length;
  final activeStatus = stepStatuses[activeIndex];
  int? nextIncompleteStep;
  for (final entry in labels.asMap().entries) {
    final status = stepStatuses[entry.key];
    if (status.total > 0 && !status.complete) {
      nextIncompleteStep = entry.key;
      break;
    }
  }
  final canAdvanceStage =
      onStepTap != null &&
      activeStatus.complete &&
      activeIndex < labels.length - 1;
  final primaryTarget = canAdvanceStage
      ? activeIndex + 1
      : onStepTap != null
      ? nextIncompleteStep
      : null;
  final flowHeadline = activeStatus.complete
      ? '${labels[activeIndex]} is command-ready.'
      : '${labels[activeIndex]} still needs operator input.';
  final flowDetail = activeStatus.complete
      ? canAdvanceStage
            ? 'The current stage is locked, so the flow band can hand you directly into the next stage without losing context.'
            : 'Every stage that exposes readiness gates is now aligned, so the flow is ready for final review.'
      : nextIncompleteStep != null
      ? 'The flow band keeps the strongest recovery visible while the full stage pivots stay one tap away below.'
      : 'The current stage is still active, and the surrounding chips remain available for direct jumps.';
  final nextMoveLabel = canAdvanceStage
      ? 'Open Step ${activeIndex + 2}'
      : nextIncompleteStep != null
      ? 'Recover Step ${nextIncompleteStep + 1}'
      : 'Final review';
  final primaryAction = _OnboardingCommandActionConfig(
    key: ValueKey('$keyPrefix-primary-action'),
    label: canAdvanceStage
        ? 'Advance Stage'
        : nextIncompleteStep != null
        ? 'Resolve Blocker'
        : 'Flow Locked',
    icon: canAdvanceStage
        ? Icons.arrow_forward_rounded
        : nextIncompleteStep != null
        ? Icons.track_changes_rounded
        : Icons.task_alt_rounded,
    onPressed: primaryTarget == null
        ? null
        : () => onStepTap?.call(primaryTarget),
    foregroundColor: const Color(0xFFEAF4FF),
    borderColor: accent.withValues(alpha: 0.85),
    backgroundColor: activeStatus.complete
        ? const Color(0xFF0F766E)
        : accent.withValues(alpha: 0.88),
    filled: true,
  );
  final secondaryActions = <_OnboardingCommandActionConfig>[
    if (onStepTap != null && activeIndex > 0)
      _OnboardingCommandActionConfig(
        key: ValueKey('$keyPrefix-previous-action'),
        label: 'Previous Stage',
        icon: Icons.arrow_back_rounded,
        onPressed: () => onStepTap(activeIndex - 1),
        foregroundColor: const Color(0xFFBFD7F2),
        borderColor: const Color(0xFF35506F),
      ),
    if (onStepTap != null && activeIndex != labels.length - 1)
      _OnboardingCommandActionConfig(
        key: ValueKey('$keyPrefix-final-action'),
        label: 'Final Stage',
        icon: Icons.flag_rounded,
        onPressed: () => onStepTap(labels.length - 1),
        foregroundColor: const Color(0xFF9FE8FF),
        borderColor: const Color(0xFF35506F),
      ),
  ];
  return Container(
    key: ValueKey('$keyPrefix-card'),
    width: double.infinity,
    padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 11),
    decoration: BoxDecoration(
      color: _adminDialogSurfaceColor,
      borderRadius: BorderRadius.circular(10),
      border: Border.all(color: _adminDialogStrongBorderColor),
    ),
    child: Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Container(
          key: ValueKey('$keyPrefix-command'),
          width: double.infinity,
          padding: const EdgeInsets.all(12),
          decoration: BoxDecoration(
            color: _adminDialogAltColor,
            borderRadius: BorderRadius.circular(10),
            border: Border.all(color: accent.withValues(alpha: 0.35)),
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          'FLOW COMMAND',
                          style: GoogleFonts.inter(
                            color: accent,
                            fontSize: 9.5,
                            fontWeight: FontWeight.w800,
                            letterSpacing: 0.8,
                          ),
                        ),
                        const SizedBox(height: 4),
                        Text(
                          flowHeadline,
                          style: GoogleFonts.inter(
                            color: _adminDialogTitleColor,
                            fontSize: 11.5,
                            fontWeight: FontWeight.w800,
                          ),
                        ),
                        const SizedBox(height: 4),
                        Text(
                          flowDetail,
                          style: GoogleFonts.inter(
                            color: _adminDialogBodyColor,
                            fontSize: 10.5,
                            fontWeight: FontWeight.w600,
                            height: 1.35,
                          ),
                        ),
                      ],
                    ),
                  ),
                  const SizedBox(width: 12),
                  Container(
                    key: ValueKey('$keyPrefix-next-move'),
                    padding: const EdgeInsets.symmetric(
                      horizontal: 10,
                      vertical: 8,
                    ),
                    decoration: BoxDecoration(
                      color: accent.withValues(alpha: 0.12),
                      borderRadius: BorderRadius.circular(9),
                      border: Border.all(color: accent.withValues(alpha: 0.35)),
                    ),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.end,
                      children: [
                        Text(
                          'NEXT MOVE',
                          style: GoogleFonts.inter(
                            color: accent,
                            fontSize: 9,
                            fontWeight: FontWeight.w800,
                            letterSpacing: 0.8,
                          ),
                        ),
                        const SizedBox(height: 4),
                        Text(
                          nextMoveLabel,
                          style: GoogleFonts.inter(
                            color: _adminDialogTitleColor,
                            fontSize: 10.5,
                            fontWeight: FontWeight.w700,
                          ),
                        ),
                      ],
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 10),
              Wrap(
                spacing: 8,
                runSpacing: 8,
                children: [
                  _onboardingCommandChip(
                    _OnboardingCommandChipData(
                      label: 'Current',
                      value: labels[activeIndex],
                      color: const Color(0xFF8FD1FF),
                    ),
                  ),
                  _onboardingCommandChip(
                    _OnboardingCommandChipData(
                      label: 'Step',
                      value: '${activeIndex + 1}/${labels.length}',
                      color: const Color(0xFFBFD7F2),
                    ),
                  ),
                  _onboardingCommandChip(
                    _OnboardingCommandChipData(
                      label: 'Stage Gates',
                      value: activeStatus.total == 0
                          ? 'n/a'
                          : '${activeStatus.readyCount}/${activeStatus.total}',
                      color: activeStatus.complete
                          ? const Color(0xFF34D399)
                          : const Color(0xFFF59E0B),
                    ),
                  ),
                  _onboardingCommandChip(
                    _OnboardingCommandChipData(
                      label: 'Ready',
                      value: '$readySteps/${labels.length}',
                      color: accent,
                    ),
                  ),
                ],
              ),
              const SizedBox(height: 10),
              Wrap(
                spacing: 8,
                runSpacing: 8,
                children: [
                  _onboardingCommandActionButton(primaryAction),
                  for (final action in secondaryActions)
                    _onboardingCommandActionButton(action),
                ],
              ),
            ],
          ),
        ),
        const SizedBox(height: 8),
        Wrap(
          spacing: 6,
          runSpacing: 6,
          children: [
            for (var i = 0; i < labels.length; i++)
              () {
                final status = stepStatuses[i];
                final hasStepGates = status.total > 0;
                final state = i == activeIndex
                    ? _SummaryChipState.active
                    : (status.complete || i < activeIndex)
                    ? _SummaryChipState.done
                    : _SummaryChipState.pending;
                final readinessMeta = hasStepGates
                    ? '${status.readyCount}/${status.total}'
                    : null;
                return _summaryChip(
                  key: ValueKey('$keyPrefix-stage-${i + 1}'),
                  number: i + 1,
                  label: labels[i],
                  state: state,
                  readinessMeta: readinessMeta,
                  onPressed: onStepTap == null ? null : () => onStepTap(i),
                );
              }(),
          ],
        ),
        if (onStepTap != null) ...[
          const SizedBox(height: 6),
          Text(
            'Tap any stage chip to jump directly.',
            style: GoogleFonts.inter(
              color: _adminDialogBodyColor,
              fontSize: 10.5,
              fontWeight: FontWeight.w600,
            ),
          ),
        ],
        const SizedBox(height: 9),
        TweenAnimationBuilder<double>(
          duration: const Duration(milliseconds: 260),
          curve: Curves.easeOutCubic,
          tween: Tween<double>(begin: 0, end: progress),
          builder: (context, value, _) {
            return ClipRRect(
              key: ValueKey('$keyPrefix-progress'),
              borderRadius: BorderRadius.circular(999),
              child: LinearProgressIndicator(
                minHeight: 6,
                value: value,
                backgroundColor: _adminDialogBorderColor,
                valueColor: const AlwaysStoppedAnimation<Color>(
                  Color(0xFF5FAAFF),
                ),
              ),
            );
          },
        ),
      ],
    ),
  );
}

