StepState _stepStateFor({required int stepIndex, required int currentStep}) {
  if (stepIndex < currentStep) return StepState.complete;
  if (stepIndex == currentStep) return StepState.editing;
  return StepState.indexed;
}

Widget _stepTitle(
  String label, {
  required int stepIndex,
  required int currentStep,
}) {
  final done = stepIndex < currentStep;
  final active = stepIndex == currentStep;
  final statusLabel = done
      ? 'READY'
      : active
      ? 'LIVE'
      : 'QUEUED';
  final statusDetail = done
      ? 'Stage sealed for revisit'
      : active
      ? 'Inputs live now'
      : 'Waiting in flow';
  final Color background;
  final Color border;
  final Color text;
  if (done) {
    background = const Color(0x1634D399);
    border = const Color(0xAA34D399);
    text = _adminDialogTitleColor;
  } else if (active) {
    background = const Color(0x143C79BB);
    border = const Color(0xFF5FAAFF);
    text = _adminDialogTitleColor;
  } else {
    background = _adminDialogAltColor;
    border = _adminDialogBorderColor;
    text = _adminDialogTitleColor;
  }
  final icon = done
      ? Icons.check_circle_rounded
      : (active ? Icons.play_circle_fill_rounded : Icons.circle_outlined);
  final iconColor = done
      ? const Color(0xFF7EF2C3)
      : (active ? const Color(0xFF9FD6FF) : const Color(0xFFD3E6FA));
  return AnimatedScale(
    duration: const Duration(milliseconds: 220),
    curve: Curves.easeOutCubic,
    scale: done ? 1.02 : 1.0,
    child: AnimatedContainer(
      key: ValueKey('onboarding-step-title-$stepIndex'),
      duration: const Duration(milliseconds: 220),
      curve: Curves.easeOutCubic,
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 7),
      decoration: BoxDecoration(
        color: background,
        borderRadius: BorderRadius.circular(999),
        border: Border.all(color: border),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          AnimatedSwitcher(
            duration: const Duration(milliseconds: 180),
            switchInCurve: Curves.easeOutBack,
            switchOutCurve: Curves.easeInCubic,
            transitionBuilder: (child, animation) {
              return ScaleTransition(
                scale: animation,
                child: FadeTransition(opacity: animation, child: child),
              );
            },
            child: Icon(icon, key: ValueKey(icon), size: 14, color: iconColor),
          ),
          const SizedBox(width: 8),
          Flexible(
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  '${stepIndex + 1}. $label',
                  style: GoogleFonts.inter(
                    color: text,
                    fontSize: 12,
                    fontWeight: FontWeight.w700,
                    letterSpacing: 0.08,
                  ),
                ),
                const SizedBox(height: 1),
                Text(
                  statusDetail,
                  style: GoogleFonts.inter(
                    color: done
                        ? _adminDialogBodyColor
                        : active
                        ? _adminAccentTextColor(
                            const Color(0xFF3C79BB),
                            strength: 0.42,
                          )
                        : _adminDialogMutedColor,
                    fontSize: 9.5,
                    fontWeight: FontWeight.w700,
                    height: 1.15,
                  ),
                ),
              ],
            ),
          ),
          const SizedBox(width: 8),
          Container(
            key: ValueKey('onboarding-step-title-status-$stepIndex'),
            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 5),
            decoration: BoxDecoration(
              color: done
                  ? const Color(0x1634D399)
                  : active
                  ? const Color(0x145FAAFF)
                  : const Color(0xFF13131E),
              borderRadius: BorderRadius.circular(999),
              border: Border.all(
                color: done
                    ? const Color(0xAA34D399)
                    : active
                    ? const Color(0xFF5FAAFF)
                    : _adminDialogBorderColor,
              ),
            ),
            child: Text(
              statusLabel,
              style: GoogleFonts.inter(
                color: text,
                fontSize: 9.1,
                fontWeight: FontWeight.w700,
                letterSpacing: 0.24,
              ),
            ),
          ),
        ],
      ),
    ),
  );
}

ThemeData _onboardingStepperTheme(BuildContext context) {
  final base = Theme.of(context);
  return base.copyWith(
    disabledColor: _adminDialogMutedColor,
    dividerColor: _adminDialogBorderColor,
    hintColor: _adminDialogMutedColor,
    canvasColor: _adminDialogSurfaceColor,
    colorScheme: base.colorScheme.copyWith(
      primary: const Color(0xFF3C79BB),
      onPrimary: const Color(0xFFEAF4FF),
      onSurface: _adminDialogTitleColor,
      surface: _adminDialogSurfaceColor,
    ),
    textTheme: base.textTheme.apply(
      bodyColor: _adminDialogTitleColor,
      displayColor: _adminDialogTitleColor,
    ),
  );
}

ButtonStyle _onboardingPrimaryActionStyle({
  required Color accent,
  required bool isFinalStep,
  required bool readyForCreate,
}) {
  final background = isFinalStep
      ? (readyForCreate ? const Color(0xFF0F766E) : const Color(0xFFB45309))
      : accent;
  return FilledButton.styleFrom(
    backgroundColor: background,
    foregroundColor: const Color(0xFFEAF4FF),
    elevation: 0.6,
    minimumSize: const Size(172, 42),
    padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 11),
    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
  );
}

ButtonStyle _onboardingSecondaryActionStyle() {
  return OutlinedButton.styleFrom(
    foregroundColor: const Color(0xFF365E94),
    backgroundColor: _adminDialogRaisedColor,
    side: const BorderSide(color: _adminDialogStrongBorderColor),
    minimumSize: const Size(112, 42),
    padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 11),
    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
  );
}

ButtonStyle _onboardingMissingStepActionStyle() {
  return OutlinedButton.styleFrom(
    foregroundColor: const Color(0xFF9A4D08),
    backgroundColor: const Color(0xFFFFF4E8),
    side: const BorderSide(color: Color(0xFFE3B16D)),
    minimumSize: const Size(178, 42),
    padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 11),
    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
  );
}

Widget _onboardingStepperShell({
  required BuildContext context,
  required int currentStep,
  required int finalStep,
  required Color accent,
  required String entityLabel,
  required bool readyForCreate,
  required VoidCallback onAdvance,
  required VoidCallback onCancel,
  required ValueChanged<int> onStepSelected,
  required int? nextIncompleteStep,
  required List<Step> steps,
  Key? readySubmitKey,
}) {
  final isFinalStep = currentStep == finalStep;
  return Theme(
    data: _onboardingStepperTheme(context),
    child: Stepper(
      currentStep: currentStep,
      onStepTapped: onStepSelected,
      controlsBuilder: (context, _) {
        return Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            FilledButton.icon(
              key: isFinalStep && readyForCreate ? readySubmitKey : null,
              onPressed: onAdvance,
              icon: Icon(
                isFinalStep
                    ? (readyForCreate
                          ? Icons.check_circle_rounded
                          : Icons.error_outline_rounded)
                    : Icons.arrow_forward_rounded,
                size: 16,
              ),
              style: _onboardingPrimaryActionStyle(
                accent: accent,
                isFinalStep: isFinalStep,
                readyForCreate: readyForCreate,
              ),
              label: Text(
                isFinalStep
                    ? (readyForCreate
                          ? 'Create $entityLabel (Ready)'
                          : 'Create $entityLabel (Needs Inputs)')
                    : 'Next',
                style: GoogleFonts.inter(fontWeight: FontWeight.w700),
              ),
            ),
            const SizedBox(width: 8),
            OutlinedButton.icon(
              onPressed: currentStep == 0
                  ? onCancel
                  : () => onStepSelected(currentStep - 1),
              icon: Icon(
                currentStep == 0
                    ? Icons.close_rounded
                    : Icons.arrow_back_rounded,
                size: 16,
              ),
              style: _onboardingSecondaryActionStyle(),
              label: Text(
                currentStep == 0 ? 'Cancel' : 'Back',
                style: GoogleFonts.inter(fontWeight: FontWeight.w700),
              ),
            ),
            if (isFinalStep && !readyForCreate)
              OutlinedButton.icon(
                onPressed: nextIncompleteStep == null
                    ? null
                    : () => onStepSelected(nextIncompleteStep),
                icon: const Icon(Icons.track_changes_rounded, size: 16),
                style: _onboardingMissingStepActionStyle(),
                label: Text(
                  'Go To Missing Step',
                  style: GoogleFonts.inter(fontWeight: FontWeight.w700),
                ),
              ),
          ],
        );
      },
      steps: steps,
    ),
  );
}

Widget _creationPulseBanner({
  required bool visible,
  required Color accent,
  required String label,
  required String keyPrefix,
}) {
  return AnimatedSwitcher(
    duration: const Duration(milliseconds: 260),
    switchInCurve: Curves.easeOutBack,
    switchOutCurve: Curves.easeInCubic,
    transitionBuilder: (child, animation) {
      return SizeTransition(
        sizeFactor: animation,
        axisAlignment: -1,
        child: FadeTransition(opacity: animation, child: child),
      );
    },
    child: visible
