String _onboardingFieldKeySegment(String label) {
  final normalized = label
      .split('(')
      .first
      .trim()
      .toLowerCase()
      .replaceAll(RegExp(r'[^a-z0-9]+'), '-')
      .replaceAll(RegExp(r'-+'), '-')
      .replaceAll(RegExp(r'^-|-$'), '');
  return normalized.isEmpty ? 'field' : normalized;
}

